const titlebar_glyph_new_tab = std.unicode.utf8ToUtf16LeStringLiteral("\u{E710}");
const titlebar_glyph_dropdown = std.unicode.utf8ToUtf16LeStringLiteral("\u{E70D}");
const host_banner_inspector_inactive = "Inspector hidden. Terminal view is active.";
const search_results_idle = "Type to search";
const search_results_pending = "Searching";
const search_results_none = "No matches";
const opengl32_name: [*:0]const u8 = "opengl32.dll";
const shell_open: LPCWSTR = std.unicode.utf8ToUtf16LeStringLiteral("open");

var opengl32_module: HMODULE = null;

const ForwardedArgIterator = struct {
    args: []const [:0]const u8,
    idx: usize = 0,

    pub fn next(self: *ForwardedArgIterator) ?[]const u8 {
        if (self.idx >= self.args.len) return null;
        defer self.idx += 1;
        return self.args[self.idx];
    }
};

const GlobalHotkeySpec = struct {
    modifiers: UINT,
    vk: UINT,
};

const RegisteredGlobalHotkey = struct {
    id: i32,
    trigger: input.Binding.Trigger,
    binding: *const input.Binding.Set.Value,
};

fn hostWindowStyle() u32 {
    // Keep the host hidden until child controls and initial layout are ready,
    // then show it explicitly from createHost.
    return WS_OVERLAPPEDWINDOW | WS_CLIPCHILDREN;
}

fn surfaceWindowStyle() u32 {
    // Keep the terminal child surface hidden until GL + core init complete,
    // then show it explicitly from Surface.init.
    return WS_CHILD | WS_CLIPSIBLINGS;
}

fn effectiveHostWindowStyle(
    decorations_visible: bool,
    fullscreen: bool,
    hosted: bool,
) u32 {
    if (fullscreen) {
        return if (hosted)
            WS_VISIBLE | WS_POPUP | WS_CLIPCHILDREN
        else
            WS_VISIBLE | WS_POPUP;
    }

    if (decorations_visible) {
        return if (hosted)
            WS_VISIBLE | WS_OVERLAPPEDWINDOW | WS_CLIPCHILDREN
        else
            WS_VISIBLE | WS_OVERLAPPEDWINDOW;
    }

    return if (hosted)
        WS_VISIBLE | WS_OVERLAPPED | WS_CLIPCHILDREN
    else
        WS_VISIBLE | WS_OVERLAPPED;
}

fn shouldApplyInheritedWindowState(dst_host_id: ?u32, src_host_id: ?u32) bool {
    return !(dst_host_id != null and src_host_id != null and dst_host_id.? == src_host_id.?);
}

fn shouldShowSurfaceImmediately(host_id: ?u32) bool {
    return host_id == null;
}

fn shouldResizeHostForInitialSize(host_surface_count: usize) bool {
    return host_surface_count == 1;
}

fn hostPresentShowCommand(is_zoomed: bool) i32 {
    return if (is_zoomed) SW_MAXIMIZE else SW_SHOW;
}

fn intResource(id: usize) INTRESOURCE {
    return @as(INTRESOURCE, @ptrFromInt(id));
}

fn appIconResource() INTRESOURCE {
    return intResource(ID_ICON_GHOSTTY);
}

fn loadAppIcon(hinstance: HINSTANCE, small: bool) HICON {
    const cx = if (small) GetSystemMetrics(SM_CXSMICON) else GetSystemMetrics(SM_CXICON);
    const cy = if (small) GetSystemMetrics(SM_CYSMICON) else GetSystemMetrics(SM_CYICON);
    return LoadImageW(
        hinstance,
        appIconResource(),
        IMAGE_ICON,
        if (cx > 0) cx else if (small) 16 else 32,
        if (cy > 0) cy else if (small) 16 else 32,
        LR_SHARED,
    );
}

fn setWindowIcon(hwnd: HWND, hinstance: HINSTANCE) void {
    if (loadAppIcon(hinstance, false)) |icon| {
        _ = SendMessageW(hwnd, WM_SETICON, ICON_BIG, @as(LPARAM, @bitCast(@intFromPtr(icon))));
    }
    if (loadAppIcon(hinstance, true)) |icon| {
        _ = SendMessageW(hwnd, WM_SETICON, ICON_SMALL, @as(LPARAM, @bitCast(@intFromPtr(icon))));
    }
}

fn shouldDispatchOcclusion(current: ?bool, visible: bool) bool {
    return current == null or current.? != visible;
}

fn applyProfileSurfaceConfig(
    config: *configpkg.Config,
    profile: *const windows_shell.Profile,
) !void {
    try applyProfileCommandConfig(config, profile);
    config.@"working-directory" = .home;
}

fn applyProfileCommandConfig(
    config: *configpkg.Config,
    profile: *const windows_shell.Profile,
) !void {
    const alloc = config._arena.?.allocator();

    // newConfig() returns a shallow clone, so aliased fields such as
    // command remain owned by the source config arena. Replacing command on
    // the clone must not deinit the inherited value.
    config.command = try profile.command.clone(alloc);
}

fn splitWorkingDirectoryCandidate(live_pwd: ?[]const u8, cached_pwd: ?[]const u8) ?[]const u8 {
    if (live_pwd) |pwd| {
        if (pwd.len > 0) return pwd;
    }
    if (cached_pwd) |pwd| {
        if (pwd.len > 0) return pwd;
    }
    return null;
}

fn applySplitWorkingDirectoryPath(
    config: *configpkg.Config,
    source_pwd: ?[]const u8,
) !bool {
    if (!config.@"split-inherit-working-directory") return false;
    const pwd = source_pwd orelse return false;
    if (pwd.len == 0) return false;

    const alloc = config._arena.?.allocator();
    config.@"working-directory" = .{ .path = try alloc.dupe(u8, pwd) };
    return true;
}

fn shouldTreatWslSplitPwdAsStartupFallback(
    alloc: Allocator,
    command: ?configpkg.Command,
    candidate: []const u8,
    startup_cwd: ?[]const u8,
) !bool {
    const cmd = command orelse return false;
    if (!windows_shell.isWslCommand(cmd)) return false;
    const startup = startup_cwd orelse return false;
    if (candidate.len == 0 or startup.len == 0) return false;

    if (std.ascii.eqlIgnoreCase(candidate, startup)) return true;
    const startup_wsl = (try windows_shell.pathToWsl(alloc, startup)) orelse return false;
    defer alloc.free(startup_wsl);
    return std.mem.eql(u8, candidate, startup_wsl);
}

fn applySplitWorkingDirectoryFromSource(
    config: *configpkg.Config,
    source: *Surface,
    startup_cwd: ?[]const u8,
) !bool {
    if (!config.@"split-inherit-working-directory") return false;

    const alloc = config._arena.?.allocator();
    const live_pwd = source.core().pwd(alloc) catch |err| blk: {
        log.warn("win32 split cwd inheritance could not query live cwd err={}", .{err});
        break :blk null;
    };

    if (live_pwd) |pwd| {
        if (try shouldTreatWslSplitPwdAsStartupFallback(
            alloc,
            config.command,
            pwd,
            startup_cwd,
        )) {
            if (source.pwd) |cached| {
                if (cached.len > 0) return try applySplitWorkingDirectoryPath(config, cached);
            }
            config.@"working-directory" = .home;
            return true;
        }
    }

    const candidate = splitWorkingDirectoryCandidate(live_pwd, source.pwd) orelse return false;
    if (live_pwd) |pwd| {
        if (candidate.ptr == pwd.ptr and candidate.len == pwd.len) {
            config.@"working-directory" = .{ .path = pwd };
            return true;
        }
    }
    return try applySplitWorkingDirectoryPath(config, candidate);
}

fn defaultIpcNamespace() []const u8 {
    return if (builtin.mode == .Debug)
        "io.github.amanthanvi.winghostty-debug"
    else
        "io.github.amanthanvi.winghostty";
}

fn sanitizeIpcNamespace(alloc: Allocator, raw: ?[]const u8) ![]const u8 {
    const trimmed = std.mem.trim(u8, raw orelse defaultIpcNamespace(), &std.ascii.whitespace);
    const source = if (trimmed.len == 0) defaultIpcNamespace() else trimmed;

    var buf: std.ArrayList(u8) = .empty;
    errdefer buf.deinit(alloc);

    for (source) |c| {
        if (std.ascii.isAlphanumeric(c) or c == '.' or c == '-' or c == '_') {
            try buf.append(alloc, c);
        } else {
            try buf.append(alloc, '_');
        }
    }

    if (buf.items.len == 0) try buf.appendSlice(alloc, defaultIpcNamespace());
    return try buf.toOwnedSlice(alloc);
}

fn allocIpcPipeName(alloc: Allocator, raw_namespace: ?[]const u8) ![:0]const u16 {
    const namespace = try sanitizeIpcNamespace(alloc, raw_namespace);
    defer alloc.free(namespace);

    const pipe_name_utf8 = try std.fmt.allocPrint(alloc, "{s}{s}", .{
        ipc_pipe_prefix,
        namespace,
    });
    defer alloc.free(pipe_name_utf8);

    return try std.unicode.utf8ToUtf16LeAllocZ(alloc, pipe_name_utf8);
}

fn resolveIpcPipeNameForTarget(
    alloc: Allocator,
    target: apprt.ipc.Target,
) ![:0]const u16 {
    return switch (target) {
        .class => |class| allocIpcPipeName(alloc, class),
        .detect => allocIpcPipeName(alloc, null),
    };
}

fn appendU32(dst: *std.ArrayList(u8), alloc: Allocator, value: u32) !void {
    var buf: [4]u8 = undefined;
    std.mem.writeInt(u32, &buf, value, .little);
    try dst.appendSlice(alloc, &buf);
}

fn readU32(src: []const u8) u32 {
    return std.mem.readInt(u32, src[0..4], .little);
}

fn freeOwnedArguments(alloc: Allocator, arguments: ?[]const [:0]const u8) void {
    if (arguments) |owned| {
        for (owned) |arg| alloc.free(arg);
        alloc.free(owned);
    }
}

fn encodeNewWindowIpcRequest(
    alloc: Allocator,
    arguments: ?[]const [:0]const u8,
) ![]u8 {
    var encoded: std.ArrayList(u8) = .empty;
    errdefer encoded.deinit(alloc);

    try appendU32(&encoded, alloc, ipc_wire_version);
    try encoded.append(alloc, 1);

    const argc: u32 = if (arguments) |argv| @intCast(argv.len) else 0;
    try appendU32(&encoded, alloc, argc);

    if (arguments) |argv| {
        for (argv) |arg| {
            try appendU32(&encoded, alloc, @intCast(arg.len));
            try encoded.appendSlice(alloc, arg);
        }
    }

    return try encoded.toOwnedSlice(alloc);
}

fn decodeNewWindowIpcRequest(
    alloc: Allocator,
    pipe: windows.HANDLE,
) !?[]const [:0]const u8 {
    var header: [9]u8 = undefined;
    try readExactHandle(pipe, &header);

    if (readU32(header[0..4]) != ipc_wire_version) return error.InvalidIpcRequest;
    if (header[4] != 1) return error.InvalidIpcRequest;

    const argc = readU32(header[5..9]);
    if (argc == 0) return null;

    const argv = try alloc.alloc([:0]const u8, argc);
    errdefer freeOwnedArguments(alloc, argv);

    for (argv, 0..) |*slot, i| {
        _ = i;
        var len_buf: [4]u8 = undefined;
        try readExactHandle(pipe, &len_buf);
        const len = readU32(&len_buf);

        const arg = try alloc.allocSentinel(u8, len, 0);
        try readExactHandle(pipe, arg[0..len]);
        slot.* = arg;
    }

    return argv;
}

fn writeIpcAck(pipe: windows.HANDLE, success: bool) !void {
    var response: [5]u8 = undefined;
    std.mem.writeInt(u32, response[0..4], ipc_wire_version, .little);
    response[4] = if (success) ipc_ack_success else ipc_ack_failure;
    try writeAllHandle(pipe, &response);
}

fn readIpcAck(pipe: windows.HANDLE) !bool {
    var response: [5]u8 = undefined;
    try readExactHandle(pipe, &response);
    if (readU32(response[0..4]) != ipc_wire_version) return error.InvalidIpcResponse;
    return switch (response[4]) {
        ipc_ack_success => true,
        ipc_ack_failure => error.IPCFailed,
        else => error.InvalidIpcResponse,
    };
}

fn readExactHandle(pipe: windows.HANDLE, dst: []u8) !void {
    var offset: usize = 0;
    while (offset < dst.len) {
        var read_len: u32 = 0;
        if (windows.kernel32.ReadFile(
            pipe,
            dst[offset..].ptr,
            @intCast(dst.len - offset),
            &read_len,
            null,
        ) == 0) {
            return switch (windows.kernel32.GetLastError()) {
                .BROKEN_PIPE => error.EndOfStream,
                else => |err| windows.unexpectedError(err),
            };
        }

        if (read_len == 0) return error.EndOfStream;
        offset += read_len;
    }
}

fn writeAllHandle(pipe: windows.HANDLE, src: []const u8) !void {
    var offset: usize = 0;
    while (offset < src.len) {
        var write_len: u32 = 0;
        if (windows.kernel32.WriteFile(
            pipe,
            src[offset..].ptr,
            @intCast(src.len - offset),
            &write_len,
            null,
        ) == 0) return windows.unexpectedError(windows.kernel32.GetLastError());
        if (write_len == 0) return error.WriteFailed;
        offset += write_len;
    }
}

fn connectToIpcPipe(pipe_name: [:0]const u16) !windows.HANDLE {
    var retries: u8 = 0;
    while (true) {
        const handle = windows.kernel32.CreateFileW(
            pipe_name.ptr,
            windows.GENERIC_READ | windows.GENERIC_WRITE,
            0,
            null,
            windows.OPEN_EXISTING,
            windows.FILE_ATTRIBUTE_NORMAL,
            null,
        );
        if (handle != windows.INVALID_HANDLE_VALUE) return handle;

        const err = windows.kernel32.GetLastError();
        switch (err) {
            .FILE_NOT_FOUND => return error.FileNotFound,
            .PIPE_BUSY => {
                if (retries == 0 and WaitNamedPipeW(pipe_name.ptr, 1000) != 0) {
                    retries += 1;
                    continue;
                }
                return error.PipeBusy;
            },
            else => return windows.unexpectedError(err),
        }
    }
}

fn sendNewWindowIpc(
    alloc: Allocator,
    pipe_name: [:0]const u16,
    arguments: ?[]const [:0]const u8,
) !bool {
    const pipe = connectToIpcPipe(pipe_name) catch |err| switch (err) {
        error.FileNotFound => return false,
        error.PipeBusy => return error.IPCFailed,
        else => return err,
    };
    defer _ = windows.CloseHandle(pipe);

    const request = try encodeNewWindowIpcRequest(alloc, arguments);
    defer alloc.free(request);

    try writeAllHandle(pipe, request);
    return try readIpcAck(pipe);
}

fn applyNewWindowArguments(
    alloc_gpa: Allocator,
    config: *configpkg.Config,
    arguments: ?[]const [:0]const u8,
) !void {
    const argv = arguments orelse return;
    if (argv.len == 0) return;

    var iter: ForwardedArgIterator = .{ .args = argv };
    try config.loadIter(alloc_gpa, &iter);
    try config.finalize();
}

fn normalizeForwardedStartupArg(
    alloc: Allocator,
    arg: []const u8,
) !?[:0]const u8 {
    if (std.mem.startsWith(u8, arg, "--class=") or
        std.mem.startsWith(u8, arg, "--single-instance=") or
        std.mem.startsWith(u8, arg, "--gtk-single-instance="))
    {
        return null;
    }

    if (std.mem.startsWith(u8, arg, "--working-directory=")) {
        const raw = arg["--working-directory=".len..];
        const trimmed = std.mem.trim(u8, raw, &std.ascii.whitespace);
        if (std.mem.eql(u8, trimmed, "home") or std.mem.eql(u8, trimmed, "inherit")) {
            return try alloc.dupeZ(u8, arg);
        }

        const cwd = std.fs.cwd();
        var home_buf: [std.fs.max_path_bytes]u8 = undefined;
        const expanded = homedir.expandHome(trimmed, &home_buf) catch trimmed;
        var realpath_buf: [std.fs.max_path_bytes]u8 = undefined;
        const normalized = cwd.realpath(expanded, &realpath_buf) catch expanded;
        return try std.fmt.allocPrintSentinel(
            alloc,
            "--working-directory={s}",
            .{normalized},
            0,
        );
    }

    return try alloc.dupeZ(u8, arg);
}

fn collectStartupForwardArguments(alloc: Allocator) !?[]const [:0]const u8 {
    var iter = try cli_args.argsIterator(alloc);
    defer iter.deinit();

    var argv: std.ArrayList([:0]const u8) = .empty;
    var working_directory_seen = false;
    errdefer {
        for (argv.items) |arg| alloc.free(arg);
        argv.deinit(alloc);
    }

    while (iter.next()) |arg| {
        if (std.mem.startsWith(u8, arg, "--working-directory=")) {
            working_directory_seen = true;
        }
        if (try normalizeForwardedStartupArg(alloc, arg)) |normalized| {
            try argv.append(alloc, normalized);
        }
    }

    if (!working_directory_seen) {
        const cwd = std.fs.cwd();
        var cwd_buf: [std.fs.max_path_bytes]u8 = undefined;
        const wd = try cwd.realpath(".", &cwd_buf);
        try argv.insert(alloc, 0, try std.fmt.allocPrintSentinel(
            alloc,
            "--working-directory={s}",
            .{wd},
            0,
        ));
    }

    if (argv.items.len == 0) {
        argv.deinit(alloc);
        return null;
    }

    return try argv.toOwnedSlice(alloc);
}

fn ipcServerMain(app: *App) void {
    const pipe_name = app.ipc_pipe_name orelse return;

    while (!app.ipc_stop_requested.load(.acquire)) {
        const pipe = CreateNamedPipeW(
            pipe_name.ptr,
            PIPE_ACCESS_DUPLEX,
            windows.PIPE_TYPE_BYTE | PIPE_READMODE_BYTE | PIPE_WAIT,
            PIPE_UNLIMITED_INSTANCES,
            16 * 1024,
            16 * 1024,
            0,
            null,
        );
        if (pipe == windows.INVALID_HANDLE_VALUE) {
            log.warn("failed to create win32 IPC pipe err={}", .{
                windows.kernel32.GetLastError(),
            });
            return;
        }

        const connected = ConnectNamedPipe(pipe, null);
        if (connected == 0) {
            const err = windows.kernel32.GetLastError();
            if (err != .PIPE_CONNECTED) {
                _ = windows.CloseHandle(pipe);
                if (!app.ipc_stop_requested.load(.acquire)) {
                    log.warn("failed to connect win32 IPC client err={}", .{err});
                }
                continue;
            }
        }

        if (app.ipc_stop_requested.load(.acquire)) {
            _ = windows.CloseHandle(pipe);
            break;
        }

        handleIpcClient(app, pipe) catch |err| {
            log.warn("failed to process win32 IPC client err={}", .{err});
            writeIpcAck(pipe, false) catch {};
        };

        _ = FlushFileBuffers(pipe);
        _ = DisconnectNamedPipe(pipe);
        _ = windows.CloseHandle(pipe);
    }
}

fn handleIpcClient(app: *App, pipe: windows.HANDLE) !void {
    const arguments = try decodeNewWindowIpcRequest(app.core_app.alloc, pipe);
    errdefer freeOwnedArguments(app.core_app.alloc, arguments);

    const mailbox: CoreApp.Mailbox = .{
        .rt_app = app,
        .mailbox = &app.core_app.mailbox,
    };
    _ = mailbox.push(.{ .new_window = .{
        .arguments = arguments,
    } }, .forever);

    try writeIpcAck(pipe, true);
}

pub fn getProcAddress(name: [*:0]const u8) callconv(.c) ?*const anyopaque {
    if (wglGetProcAddress(name)) |ptr| {
        const raw = @intFromPtr(ptr);
        if (raw > 3 and raw != std.math.maxInt(usize)) return ptr;
    }

    if (opengl32_module == null) {
        opengl32_module = LoadLibraryA(opengl32_name);
    }

    const module = opengl32_module orelse return null;
    return GetProcAddress(module, name);
}

const UpdateNotice = struct {
    version_text: ?[]u8 = null,
    release_url: ?[]u8 = null,
    message_text: ?[]u8 = null,

    fn init(alloc: Allocator, version_text: []const u8, release_url: []const u8) !UpdateNotice {
        return .{
            .version_text = try alloc.dupe(u8, version_text),
            .release_url = try alloc.dupe(u8, release_url),
            .message_text = try std.fmt.allocPrint(
                alloc,
                "Update available: winghostty {s} is ready on GitHub Releases.",
                .{version_text},
            ),
        };
    }

    fn deinit(self: *UpdateNotice, alloc: Allocator) void {
        if (self.version_text) |value| alloc.free(value);
        if (self.release_url) |value| alloc.free(value);
        if (self.message_text) |value| alloc.free(value);
        self.* = undefined;
    }
};

const UpdateCheckRequest = struct {
    alloc: Allocator,
    ui_thread_id: DWORD,
    state_path: []u8,
    current_version: std.SemanticVersion,
    current_version_string: []u8,
    force: bool,
    manual: bool,
    respect_dismissal: bool,

    fn deinit(self: *UpdateCheckRequest) void {
        self.alloc.free(self.state_path);
        self.alloc.free(self.current_version_string);
        self.* = undefined;
    }
};

const UpdateCheckCompletion = struct {
    alloc: Allocator,
    release: ?updatepkg.Release = null,
    manual_message: ?[]u8 = null,

    fn deinit(self: *UpdateCheckCompletion) void {
        if (self.release) |*value| value.deinit(self.alloc);
        if (self.manual_message) |value| self.alloc.free(value);
        self.* = undefined;
    }
};

pub const App = struct {
    pub const must_draw_from_app_thread = true;

    core_app: *CoreApp,
    config: configpkg.Config,
    resolved_theme: ThemeColors = darkTheme(),
    hinstance: HINSTANCE,
    class_atom: ATOM = 0,
    host_class_atom: ATOM = 0,
    palette_list_class_atom: ATOM = 0,
    scrollbar_class_atom: ATOM = 0,
    hosts: std.ArrayListUnmanaged(*Host) = .empty,
    windows: std.ArrayListUnmanaged(*Surface) = .empty,
    /// Internal test seam so action-path tests can drive real
    /// `performAction(.new_tab, ...)` logic without requiring HWND/GL
    /// surface bring-up.
    test_create_window_surface: ?*const fn (
        app: *App,
        config: *const configpkg.Config,
        title: LPCWSTR,
        opts: SurfaceInitOptions,
    ) anyerror!*Surface = null,
    next_host_id: u32 = 1,
    launcher_profile_key: ?[:0]const u8 = null,
    launcher_profile_hint: ?[:0]const u8 = null,
    launcher_profile_order_hint: ?[:0]const u8 = null,
    launcher_quick_slot_keys: [3]?[:0]const u8 = .{ null, null, null },
    launcher_profile_target: ProfileOpenTarget = .tab,
    startup_profile_picker: bool = false,
    wheel_settings: SystemWheelSettings = .{},
    system_dynamic_scrollbars: bool = true,
    ipc_pipe_name: ?[:0]const u16 = null,
    ipc_thread: ?std.Thread = null,
    ipc_stop_requested: std.atomic.Value(bool) = .init(false),
    global_hotkeys: std.ArrayListUnmanaged(RegisteredGlobalHotkey) = .empty,
    global_hotkeys_dirty: bool = false,
    ui_thread_id: DWORD = 0,
    quit_timer_id: ?UINT_PTR = null,
    undo_prune_timer_id: ?UINT_PTR = null,
    running: bool = false,
    windows_hidden: bool = false,
    update_check_running: std.atomic.Value(bool) = .init(false),
    update_notice: ?UpdateNotice = null,
    update_auto_check_started: bool = false,
    /// Most-recently-used command palette actions; newest first. Strings
    /// are owned by `core_app.alloc` and freed in `App.deinit`. Surfaced
    /// by `commandPaletteBannerText` when the query is empty so users
    /// see their own recent picks instead of the static onboarding hint.
    palette_mru: [5]?[:0]const u8 = .{null} ** 5,
    /// Singleton settings window. Lazily created by the `open_config`
    /// action; `App.terminate` destroys the HWND if still alive.
    settings_window: win32_settings.SettingsWindow = undefined,
    /// Whether `CoInitializeEx` actually took responsibility for the
    /// apartment on this thread. `CoUninitialize` only pairs with a
    /// successful init (`S_OK` / `S_FALSE`) — `RPC_E_CHANGED_MODE`
    /// means another component already set up COM and we must not
    /// touch it on the way down.
    com_initialized: bool = false,
    /// Kernel build number from `RtlGetVersion`. 0 if probe failed.
    /// 22000 = Win11 21H2 (first Mica build); 22621 = Win11 22H2
    /// (Snap Layouts; `DWMSBT_TABBEDWINDOW`). Future chrome gates
    /// read this directly; no runtime config flag, per §12 Q1.
    os_build: u32 = 0,
    /// Top-level switch for the integrated-titlebar path
    /// (`WM_NCCALCSIZE` / `WM_NCHITTEST` state machine). Derived
    /// from the Win11 build floor via `shouldUseIntegratedTitlebar`;
    /// false keeps the stock non-client caption path.
    use_integrated_titlebar: bool = false,
    // Live-resize state is tracked PER HOST (`Host.is_live_resize`),
    // not per App. Dragging window A must NOT freeze renderer
    // invalidations for unrelated background windows B/C.
    /// Cached CF_HTML clipboard format ID — lazy-registered on
    /// first HTML copy. Process-local so one cache per App is
    /// enough; re-registering on every copy is documented as
    /// cheap by MS but still pointless work.
    cf_html_format: UINT = 0,
    /// Hyperlink hover-dwell tracker. Reset via `dismiss()` whenever
    /// focus leaves a surface or a click arrives.
    link_hover_tracker: win32_link_preview.HoverTracker = undefined,
    /// Windows Action Center toast notifier. `null` when WinRT init
    /// fails (e.g. corporate lockdown, missing combase.dll), in which
    /// case `showDesktopNotification` falls back to the in-app banner
    /// path. One notifier per App, released in `App.terminate`.
    winrt_toast: ?win32_toast_winrt.WinrtToast = null,
    /// Taskbar progress COM object. `null` when the taskbar API is
    /// unavailable, in which case progress continues to render only in
    /// the window title/status text.
    taskbar_progress: ?win32_taskbar_progress.TaskbarProgress = null,
    toast_activation_post_pending: std.atomic.Value(bool) = .init(false),
    /// Absolute path supplied via `--config-file <path>` on the CLI.
    /// Resolved ONCE against the startup cwd during `App.init` — that's
    /// important because `run()` later calls `sanitizeCurrentDirectory()`,
    /// which can reset cwd to `%USERPROFILE%`. If we resolved the
    /// relative path at save time, we'd end up writing to a different
    /// file than the one `Config.load()` used at launch.
    cli_config_override_path: ?[]u8 = null,
    /// Startup-time cwd snapshot. `Config.load()` resolves relative
    /// `--config-file` argv entries via realpath-against-cwd, so any
    /// reload that happens after `sanitizeCurrentDirectory()` would
    /// resolve those entries against the sanitized cwd and end up
    /// reading a different file than launch did. We `std.fs.cwd()`
    /// chdir back to this value around `settingsSaveAndReload`'s
    /// reload so argv-relative paths re-resolve identically.
    startup_cwd: ?[]u8 = null,
    /// Parsed `wgh://activate?...` launch argument from a cold-start
    /// toast activation. `null` when no such argv entry is present.
    /// Consumed once after the first window spawns. We first try the
    /// requested surface/window identity and fall back to the newly
    /// created primary surface when the IDs came from a prior process.
    pending_toast_activation: ?win32_toast_activation.ActivationTarget = null,

    pub fn init(
        self: *App,
        core_app: *CoreApp,
        opts: struct {},
    ) !void {
        _ = opts;

        self.* = .{
            .core_app = core_app,
            .config = try configpkg.Config.load(core_app.alloc),
            .hinstance = GetModuleHandleW(null),
            .launcher_profile_hint = detectDefaultProfileHint(core_app.alloc),
            .launcher_profile_order_hint = windows_shell.profileOrderHint(core_app.alloc),
            .launcher_profile_target = detectDefaultProfileTarget(core_app.alloc),
            .startup_profile_picker = detectStartupProfilePicker(core_app.alloc),
        };
        // Snapshot the CLI --config-file override BEFORE any code has
        // a chance to chdir. See the field comment above.
        self.cli_config_override_path = cliConfigFileOverride(core_app.alloc) catch null;
        // Snapshot the startup cwd for reload-time restoration.
        self.startup_cwd = std.process.getCwdAlloc(core_app.alloc) catch null;
        // Scan argv for a cold-start toast activation arg. Silent on
        // absence or malformed input — activation is opt-in.
        self.pending_toast_activation = scanToastActivationArg(core_app.alloc);
        if (self.pending_toast_activation) |target| {
            log.info("toast activation received surface={?} tab={?} window={?} action={?}", .{
                target.surface_id,
                target.tab_id,
                target.window_id,
                target.action,
            });
        }
        // AUMID registration MUST precede any HWND creation so
        // taskbar-grouping / toast attribution picks up our identity
        // on the first window. Both calls swallow failures (warn +
        // continue) — toasts and taskbar grouping are non-essential
        // for basic terminal function.
        win32_aumid.setProcessAumid();
        win32_aumid.registerAumidDisplayName(core_app.alloc);

        // Boot the WinRT toast notifier. Failure falls back to the
        // host banner/log path in `showDesktopNotificationWithLaunch`.
        // MUST run AFTER `setProcessAumid` so `CreateToastNotifierWithId`
        // attributes toasts to our AUMID.
        const aumid_utf16 = std.unicode.utf8ToUtf16LeStringLiteral("com.ghostty.winghostty");
        self.winrt_toast = win32_toast_winrt.WinrtToast.init(core_app.alloc, aumid_utf16) catch |err| blk: {
            std.log.warn("winrt toast init failed err={}; falling back to host notifications", .{err});
            break :blk null;
        };
        if (self.winrt_toast) |*toast| {
            toast.setActivationCallback(self, winrtToastActivationCallback);
        }

        // Install the PowerShell shell-integration script into
        // %LOCALAPPDATA%\winghostty\shell-integration\powershell\
        // if missing or the on-disk hash doesn't match the embedded
        // payload (forces updates when we ship a new version). This
        // keeps the manual `$PROFILE` fallback on a stable path even
        // though automatic injection now uses the resources-tree copy
        // for interactive PowerShell launches.
        if (win32_powershell_install.resolveInstallPath(core_app.alloc)) |ps1_path| {
            defer core_app.alloc.free(ps1_path);
            const result = win32_powershell_install.installIfStale(core_app.alloc, ps1_path);
            log.info("powershell integration install path={s} result={s}", .{ ps1_path, @tagName(result) });
        } else |err| {
            std.log.warn("powershell integration install path resolve failed err={}", .{err});
        }

        // Windows version probe. Win11 build 22000+ enables the
        // integrated-titlebar path; older builds stay on the stock
        // non-client caption/buttons path.
        self.os_build = probeWindowsBuild();
        self.use_integrated_titlebar = shouldUseIntegratedTitlebar(
            self.os_build,
            self.config.@"window-show-tab-bar",
        );
        log.info("win32 os_build={d} integrated_titlebar={}", .{
            self.os_build,
            self.use_integrated_titlebar,
        });

        self.initComApartment();
        self.taskbar_progress = win32_taskbar_progress.TaskbarProgress.init() catch |err| blk: {
            std.log.warn("taskbar progress init failed err={}; falling back to title-only progress", .{err});
            break :blk null;
        };
        self.refreshSystemWheelSettings();
        self.refreshSystemScrollbarPreference();
        self.resolved_theme = resolveTheme(&self.config);
        self.loadPaletteMru();
        self.settings_window = win32_settings.SettingsWindow.init(.{
            .ctx = @ptrCast(self),
            .alloc = core_app.alloc,
            .hinstance = self.hinstance,
            .chromeBg = &settingsChromeBgThunk,
            .textPrimary = &settingsTextPrimaryThunk,
            .openInEditor = &settingsOpenInEditorThunk,
            .currentConfig = &settingsCurrentConfigThunk,
            .saveAndReload = &settingsSaveAndReloadThunk,
            .notifySuccess = &settingsNotifySuccessThunk,
            .onClosed = &settingsOnClosedThunk,
        });
        self.link_hover_tracker = win32_link_preview.HoverTracker.init();
    }

    /// Bring the STA apartment online for in-process COM consumers
    /// (settings path picker via `IFileOpenDialog`, WinRT toast setup,
    /// OLE drag-drop). Safe to call multiple times —
    /// `S_FALSE` means "already initialised in this mode", and
    /// `RPC_E_CHANGED_MODE` means "already initialised in a different
    /// mode" (a library probably did it first; still usable for STA
    /// interop paths that don't care about the apartment type).
    fn initComApartment(self: *App) void {
        const hr = CoInitializeEx(null, COINIT_APARTMENTTHREADED);
        switch (hr) {
            0, 1 => self.com_initialized = true, // S_OK, S_FALSE
            RPC_E_CHANGED_MODE => {
                std.log.warn("COM apartment: already MTA on this thread; STA consumers may fail", .{});
            },
            else => {
                std.log.warn("COM apartment: CoInitializeEx failed hr=0x{x:0>8}", .{@as(u32, @bitCast(hr))});
            },
        }
    }

    pub fn run(self: *App) !void {
        try self.sanitizeCurrentDirectory();
        const cwd = std.process.getCwdAlloc(self.core_app.alloc) catch null;
        defer if (cwd) |v| self.core_app.alloc.free(v);
        if (cwd) |v| {
            log.debug("win32 current directory cwd={s}", .{v});
        }

        try self.ensureWindowClass();

        if (try self.tryForwardStartupToExistingInstance()) {
            return;
        }

        self.running = true;
        @atomicStore(DWORD, &self.ui_thread_id, GetCurrentThreadId(), .release);
        self.ensureMessageQueue();
        defer {
            self.stopUndoPruneTimer();
            self.stopQuitTimer();
            @atomicStore(DWORD, &self.ui_thread_id, 0, .release);
            self.running = false;
        }

        try self.startIpcServer();

        if (self.config.@"initial-window") {
            try self.createWindow(default_title);
            if (self.startup_profile_picker) {
                if (self.primarySurface()) |surface| {
                    if (surface.host) |host| _ = host.toggleProfileOverlay();
                }
                self.startup_profile_picker = false;
            }
        } else {
            log.info("initial-window is disabled; win32 runtime waiting without a window", .{});
        }

        self.scheduleGlobalHotkeySync();
        if (self.global_hotkeys_dirty and self.windows.items.len == 0) {
            self.global_hotkeys_dirty = false;
            self.syncGlobalHotkeys() catch |err| {
                log.err("failed to sync win32 global hotkeys err={}", .{err});
            };
        }
        if (self.windows.items.len == 0) self.startQuitTimer();

        var msg: MSG = undefined;
        while (true) {
            const result = GetMessageW(&msg, null, 0, 0);
            if (result == -1) return windows.unexpectedError(windows.kernel32.GetLastError());
            if (result == 0) break;

            if (msg.message == WM_WINHOSTTY_WAKE) {
                if (self.global_hotkeys_dirty) {
                    self.global_hotkeys_dirty = false;
                    self.syncGlobalHotkeys() catch |err| {
                        log.err("failed to sync win32 global hotkeys err={}", .{err});
                    };
                }
                try self.core_app.tick(self);
                if (!self.running and self.windows.items.len == 0) break;
                continue;
            }

            if (msg.message == WM_WINHOSTTY_UPDATE) {
                const completion: *UpdateCheckCompletion = @ptrFromInt(@as(usize, @bitCast(msg.lParam)));
                defer {
                    completion.deinit();
                    self.core_app.alloc.destroy(completion);
                }
                self.handleUpdateCheckCompletion(completion);
                try self.core_app.tick(self);
                if (!self.running and self.windows.items.len == 0) break;
                continue;
            }

            if (msg.message == WM_WINHOSTTY_TOAST_ACTIVATION) {
                const activation: *win32_toast_activation.ActivationTarget = @ptrFromInt(@as(usize, @bitCast(msg.lParam)));
                defer std.heap.page_allocator.destroy(activation);
                defer self.toast_activation_post_pending.store(false, .release);
                if (!self.handleToastActivation(activation.*)) {
                    self.pending_toast_activation = activation.*;
                }
                try self.core_app.tick(self);
                if (!self.running and self.windows.items.len == 0) break;
                continue;
            }

            if (msg.message == WM_TIMER) {
                if (self.quit_timer_id) |timer_id| {
                    if (msg.wParam == timer_id) {
                        self.stopQuitTimer();
                        if (self.running and !self.hasLiveUiWindows() and self.config.@"quit-after-last-window-closed") {
                            self.running = false;
                            PostQuitMessage(0);
                        }
                        continue;
                    }
                }
                if (self.undo_prune_timer_id) |timer_id| {
                    if (msg.wParam == timer_id) {
                        self.stopUndoPruneTimer();
                        self.pruneUndoHistoryNow();
                        continue;
                    }
                }
            }

            if (msg.message == WM_HOTKEY) {
                self.handleGlobalHotkey(@intCast(msg.wParam));
                continue;
            }

            _ = TranslateMessage(&msg);
            _ = DispatchMessageW(&msg);

            if (self.global_hotkeys_dirty) {
                self.global_hotkeys_dirty = false;
                self.syncGlobalHotkeys() catch |err| {
                    log.err("failed to sync win32 global hotkeys err={}", .{err});
                };
            }

            try self.core_app.tick(self);

            if (!self.running and self.windows.items.len == 0) break;
        }
    }

    pub fn terminate(self: *App) void {
        self.stopUndoPruneTimer();
        self.stopQuitTimer();
        self.update_check_running.store(false, .release);
        if (self.update_notice) |*notice| {
            notice.deinit(self.core_app.alloc);
            self.update_notice = null;
        }
        self.unregisterGlobalHotkeys();
        self.stopIpcServer();
        self.destroyAllWindows();
        self.hosts.deinit(self.core_app.alloc);
        self.windows.deinit(self.core_app.alloc);
        self.global_hotkeys.deinit(self.core_app.alloc);
        if (self.launcher_profile_key) |value| self.core_app.alloc.free(value);
        if (self.launcher_profile_hint) |value| self.core_app.alloc.free(value);
        if (self.launcher_profile_order_hint) |value| self.core_app.alloc.free(value);
        for (self.launcher_quick_slot_keys) |value| {
            if (value) |owned| self.core_app.alloc.free(owned);
        }
        self.savePaletteMru();
        for (&self.palette_mru) |*slot| {
            if (slot.*) |owned| self.core_app.alloc.free(owned);
            slot.* = null;
        }
        self.settings_window.deinit();
        if (self.winrt_toast) |*toast| {
            toast.deinit();
            self.winrt_toast = null;
        }
        if (self.taskbar_progress) |*taskbar| {
            taskbar.deinit();
            self.taskbar_progress = null;
        }
        if (self.cli_config_override_path) |path| {
            self.core_app.alloc.free(path);
            self.cli_config_override_path = null;
        }
        if (self.startup_cwd) |path| {
            self.core_app.alloc.free(path);
            self.startup_cwd = null;
        }
        self.config.deinit();
        if (self.com_initialized) {
            CoUninitialize();
            self.com_initialized = false;
        }
    }

    /// Resolve `%LOCALAPPDATA%\winghostty\palette-mru.txt`. Caller frees
    /// with `core_app.alloc`. Returns null if `LOCALAPPDATA` is
    /// unreadable or allocation fails.
    fn paletteMruPath(self: *const App) ?[]u8 {
        const local = std.process.getEnvVarOwned(
            self.core_app.alloc,
            "LOCALAPPDATA",
        ) catch return null;
        defer self.core_app.alloc.free(local);
        const dir = std.fs.path.join(self.core_app.alloc, &.{
            local,
            "winghostty",
        }) catch return null;
        defer self.core_app.alloc.free(dir);
        return std.fs.path.join(self.core_app.alloc, &.{
            dir,
            "palette-mru.txt",
        }) catch null;
    }

    /// Populate `palette_mru` from the on-disk file, one action per line
    /// (newest first). Missing file, I/O errors, and parse failures all
    /// degrade to "start empty" — the MRU is a UX nicety, not a
    /// correctness invariant.
    fn loadPaletteMru(self: *App) void {
        const path = self.paletteMruPath() orelse return;
        defer self.core_app.alloc.free(path);

        const file = std.fs.openFileAbsolute(path, .{}) catch return;
        defer file.close();

        // Cap read size at 64 KB — way more than the 5 × ~200-char
        // actions we expect, but bounded so a corrupted file can't OOM.
        const raw = file.readToEndAlloc(self.core_app.alloc, 64 * 1024) catch return;
        defer self.core_app.alloc.free(raw);

        var it = std.mem.tokenizeAny(u8, raw, "\r\n");
        var slot: usize = 0;
        while (it.next()) |line| {
            if (slot >= self.palette_mru.len) break;
            const trimmed = std.mem.trim(u8, line, " \t");
            if (trimmed.len == 0) continue;
            const duped = self.core_app.alloc.dupeZ(u8, trimmed) catch continue;
            self.palette_mru[slot] = duped;
            slot += 1;
        }
    }

    /// Write `palette_mru` to the on-disk file (newest first). Failure
    /// is silently logged — losing recent history is fine, blocking
    /// termination on file-system problems is not.
    fn savePaletteMru(self: *const App) void {
        // Fast path: nothing to persist.
        if (self.palette_mru[0] == null) return;

        const path = self.paletteMruPath() orelse return;
        defer self.core_app.alloc.free(path);

        if (std.fs.path.dirname(path)) |dir| {
            std.fs.makeDirAbsolute(dir) catch |err| switch (err) {
                error.PathAlreadyExists => {},
                else => {
                    std.log.warn("palette MRU: mkdir failed path={s} err={}", .{ dir, err });
                    return;
                },
            };
        }

        const file = std.fs.createFileAbsolute(path, .{ .truncate = true }) catch |err| {
            std.log.warn("palette MRU: create failed path={s} err={}", .{ path, err });
            return;
        };
        defer file.close();

        var fbuf: [1024]u8 = undefined;
        var fw = file.writer(&fbuf);
        for (self.palette_mru) |slot| {
            if (slot) |owned| {
                fw.interface.print("{s}\n", .{owned}) catch return;
            }
        }
        fw.interface.flush() catch {};
    }

    /// Push an action string onto the palette MRU list, dedup'd by
    /// exact match, rotating the oldest slot out. `action` is not owned
    /// by the caller; this dups it into the app allocator. Safe to call
    /// with an action that may be the same as an existing MRU entry —
    /// that entry is moved to the front without reallocating.
    fn pushPaletteMru(self: *App, action: []const u8) !void {
        // If action already exists, move it to slot 0.
        var existing_index: ?usize = null;
        for (self.palette_mru, 0..) |slot, i| {
            if (slot) |owned| {
                if (std.mem.eql(u8, owned, action)) {
                    existing_index = i;
                    break;
                }
            }
        }
        if (existing_index) |i| {
            if (i == 0) return;
            const top = self.palette_mru[i];
            var j: usize = i;
            while (j > 0) : (j -= 1) self.palette_mru[j] = self.palette_mru[j - 1];
            self.palette_mru[0] = top;
            return;
        }
        // Insert as new head. Free whatever falls off the end.
        const duped = try self.core_app.alloc.dupeZ(u8, action);
        errdefer self.core_app.alloc.free(duped);
        if (self.palette_mru[self.palette_mru.len - 1]) |oldest| {
            self.core_app.alloc.free(oldest);
        }
        var j: usize = self.palette_mru.len - 1;
        while (j > 0) : (j -= 1) self.palette_mru[j] = self.palette_mru[j - 1];
        self.palette_mru[0] = duped;
    }

    /// View of the MRU list as a slice of non-null entries, newest first.
    /// Shared storage; caller must not free or retain past the next
    /// `pushPaletteMru` call.
    fn paletteMruSlice(self: *const App, buf: *[5][]const u8) []const []const u8 {
        var n: usize = 0;
        for (self.palette_mru) |slot| {
            if (slot) |owned| {
                buf[n] = owned;
                n += 1;
            }
        }
        return buf[0..n];
    }

    fn tryForwardStartupToExistingInstance(self: *App) !bool {
        if (self.config.@"single-instance" != .true) return false;

        const arguments = try collectStartupForwardArguments(self.core_app.alloc);
        defer freeOwnedArguments(self.core_app.alloc, arguments);

        const pipe_name = try self.resolveIpcPipeName(self.core_app.alloc);
        defer self.core_app.alloc.free(pipe_name);

        return try sendNewWindowIpc(
            self.core_app.alloc,
            pipe_name,
            arguments,
        );
    }

    fn startIpcServer(self: *App) !void {
        if (self.config.@"single-instance" != .true) return;
        if (self.ipc_thread != null) return;

        self.ipc_pipe_name = try self.resolveIpcPipeName(self.core_app.alloc);
        errdefer {
            if (self.ipc_pipe_name) |pipe_name| self.core_app.alloc.free(pipe_name);
            self.ipc_pipe_name = null;
        }

        self.ipc_stop_requested.store(false, .release);
        self.ipc_thread = try std.Thread.spawn(.{}, ipcServerMain, .{self});
    }

    fn resolveIpcPipeName(self: *const App, alloc: Allocator) ![:0]const u16 {
        return allocIpcPipeName(alloc, self.config.class);
    }

    fn stopIpcServer(self: *App) void {
        if (self.ipc_thread) |thread| {
            self.ipc_stop_requested.store(true, .release);
            if (self.ipc_pipe_name) |pipe_name| {
                if (connectToIpcPipe(pipe_name)) |pipe| {
                    _ = windows.CloseHandle(pipe);
                } else |_| {}
            }
            thread.join();
            self.ipc_thread = null;
        }

        if (self.ipc_pipe_name) |pipe_name| {
            self.core_app.alloc.free(pipe_name);
            self.ipc_pipe_name = null;
        }
        self.ipc_stop_requested.store(false, .release);
    }

    fn unregisterGlobalHotkeys(self: *App) void {
        for (self.global_hotkeys.items) |hotkey| {
            _ = UnregisterHotKey(null, hotkey.id);
        }
        self.global_hotkeys.clearRetainingCapacity();
    }

    fn syncGlobalHotkeys(self: *App) !void {
        self.unregisterGlobalHotkeys();

        var next_id: i32 = 1;
        var it = self.config.keybind.set.bindings.iterator();
        while (it.next()) |entry| {
            const generic = switch (entry.value_ptr.*) {
                .leader => continue,
                .leaf => |*leaf| leaf.generic(),
                .leaf_chained => |*leaf| leaf.generic(),
            };
            if (!generic.flags.global) continue;

            const spec = hotkeySpecForTrigger(entry.key_ptr.*) orelse {
                log.debug("skipping unsupported win32 global keybind", .{});
                continue;
            };

            if (RegisterHotKey(null, next_id, spec.modifiers, spec.vk) == 0) {
                log.warn("failed to register win32 global hotkey id={} mods=0x{x} vk=0x{x} err={}", .{
                    next_id,
                    spec.modifiers,
                    spec.vk,
                    windows.kernel32.GetLastError(),
                });
                continue;
            }

            try self.global_hotkeys.append(self.core_app.alloc, .{
                .id = next_id,
                .trigger = entry.key_ptr.*,
                .binding = entry.value_ptr,
            });
            next_id += 1;
        }
    }

    fn scheduleGlobalHotkeySync(self: *App) void {
        self.global_hotkeys_dirty = true;
        self.wakeup();
    }

    fn handleGlobalHotkey(self: *App, id: i32) void {
        for (self.global_hotkeys.items) |hotkey| {
            if (hotkey.id != id) continue;

            switch (hotkey.binding.*) {
                .leader => unreachable,
                .leaf => |*leaf| self.core_app.performAllChainedAction(self, leaf.generic().actionsSlice()),
                .leaf_chained => |*leaf| self.core_app.performAllChainedAction(self, leaf.generic().actionsSlice()),
            }
            return;
        }
    }

    pub fn wakeup(self: *App) void {
        if (self.windows.items.len > 0) {
            const hwnd = self.windows.items[0].hwnd orelse return;
            _ = PostMessageW(hwnd, WM_WINHOSTTY_WAKE, 0, 0);
            return;
        }

        if (self.ui_thread_id != 0) {
            _ = PostThreadMessageW(self.ui_thread_id, WM_WINHOSTTY_WAKE, 0, 0);
        }
    }

    fn maybeScheduleAutomaticUpdateCheck(self: *App) void {
        if (self.update_auto_check_started) return;
        if (self.config.@"auto-update" == .off) return;
        if (self.config.@"auto-update-channel" != .stable) return;
        if (self.ui_thread_id == 0) return;

        self.update_auto_check_started = true;
        self.scheduleUpdateCheck(.{
            .force = false,
            .manual = false,
            .respect_dismissal = true,
        }) catch |err| {
            log.warn("failed to start automatic update check err={}", .{err});
        };
    }

    fn scheduleUpdateCheck(
        self: *App,
        opts: struct {
            force: bool,
            manual: bool,
            respect_dismissal: bool,
        },
    ) !void {
        if (self.ui_thread_id == 0) return;

        const current = self.update_check_running.cmpxchgStrong(false, true, .acq_rel, .acquire);
        if (current != null) {
            if (opts.manual) try self.showUpdateInfo("Update check already running.");
            return;
        }
        errdefer self.update_check_running.store(false, .release);

        const request = try self.core_app.alloc.create(UpdateCheckRequest);
        errdefer self.core_app.alloc.destroy(request);

        request.* = .{
            .alloc = self.core_app.alloc,
            .ui_thread_id = self.ui_thread_id,
            .state_path = try updatepkg.defaultStatePath(self.core_app.alloc),
            .current_version = build_config.version,
            .current_version_string = try self.core_app.alloc.dupe(u8, build_config.version_string),
            .force = opts.force,
            .manual = opts.manual,
            .respect_dismissal = opts.respect_dismissal,
        };

        const thread = try std.Thread.spawn(.{}, updateCheckThreadMain, .{request});
        thread.detach();
    }

    fn handleUpdateCheckCompletion(self: *App, completion: *UpdateCheckCompletion) void {
        self.update_check_running.store(false, .release);

        if (completion.release) |release| {
            self.setUpdateNotice(release.version_text, release.release_url) catch |err| {
                log.warn("failed to surface update notice err={}", .{err});
            };
            if (completion.manual_message) |_| {}
            return;
        }

        if (completion.manual_message) |message| {
            self.showUpdateInfo(message) catch |err| {
                log.warn("failed to show updater status message err={}", .{err});
            };
        }
    }

    fn setUpdateNotice(self: *App, version_text: []const u8, release_url: []const u8) !void {
        if (self.update_notice) |*notice| {
            if (ownedBytesEquals(notice.version_text, version_text) and
                ownedBytesEquals(notice.release_url, release_url))
            {
                return;
            }
            notice.deinit(self.core_app.alloc);
            self.update_notice = null;
        }

        self.update_notice = try UpdateNotice.init(self.core_app.alloc, version_text, release_url);
        for (self.hosts.items) |host| host.invalidateBannerText();
    }

    fn clearUpdateNotice(self: *App) void {
        if (self.update_notice) |*notice| {
            notice.deinit(self.core_app.alloc);
            self.update_notice = null;
            for (self.hosts.items) |host| host.invalidateBannerText();
        }
    }

    fn openUpdateNotice(self: *App) !void {
        const notice = self.update_notice orelse return;
        try self.openUrl(notice.release_url.?);
    }

    fn dismissUpdateNotice(self: *App) void {
        const notice = self.update_notice orelse return;
        const version_text = notice.version_text orelse {
            self.clearUpdateNotice();
            return;
        };

        const state_path = updatepkg.defaultStatePath(self.core_app.alloc) catch |err| {
            log.warn("failed to resolve updater state path err={}", .{err});
            self.clearUpdateNotice();
            return;
        };
        defer self.core_app.alloc.free(state_path);

        updatepkg.recordDismissal(self.core_app.alloc, state_path, version_text) catch |err| {
            log.warn("failed to record updater dismissal err={}", .{err});
        };
        self.clearUpdateNotice();
    }

    fn showUpdateInfo(self: *App, message: []const u8) !void {
        if (self.primarySurface()) |surface| {
            if (surface.host) |host| {
                try host.setBanner(.info, message);
                return;
            }
        }
        try self.showInfoMessage(.app, "winghostty", message);
    }

    /// True when any user-facing top-level UI window is still alive —
    /// either a terminal Host or the settings window. The quit timer
    /// and message-loop exit check both use this so the app doesn't
    /// tear down while the settings window holds an unsaved pending
    /// draft. Palette / confirm overlays are owned by their Host and
    /// therefore don't need their own count.
    fn hasLiveUiWindows(self: *const App) bool {
        if (self.windows.items.len != 0) return true;
        if (self.settings_window.hwnd != null) return true;
        return false;
    }

    pub fn startQuitTimer(self: *App) void {
        if (!self.running) return;
        if (self.hasLiveUiWindows()) {
            self.stopQuitTimer();
            return;
        }
        if (!self.config.@"quit-after-last-window-closed") {
            self.stopQuitTimer();
            return;
        }

        const delay = self.config.@"quit-after-last-window-closed-delay" orelse {
            self.stopQuitTimer();
            self.running = false;
            PostQuitMessage(0);
            return;
        };

        self.stopQuitTimer();
        const delay_ms = quitTimerDelayMs(delay);
        const timer_id = SetTimer(null, 0, delay_ms, null);
        if (timer_id == 0) {
            log.err("failed to start win32 quit timer delay_ms={} err={}", .{
                delay_ms,
                windows.kernel32.GetLastError(),
            });
            return;
        }
        self.quit_timer_id = timer_id;
    }

    fn stopQuitTimer(self: *App) void {
        if (self.quit_timer_id) |timer_id| {
            _ = KillTimer(null, timer_id);
            self.quit_timer_id = null;
        }
    }

    fn stopUndoPruneTimer(self: *App) void {
        if (self.undo_prune_timer_id) |timer_id| {
            _ = KillTimer(null, timer_id);
            self.undo_prune_timer_id = null;
        }
    }

    fn undoTimeoutMs(self: *const App) u64 {
        return std.math.divCeil(
            u64,
            self.config.@"undo-timeout".duration,
            std.time.ns_per_ms,
        ) catch std.math.maxInt(u64);
    }

    fn oldestUndoTimestamp(self: *const App) ?u64 {
        var oldest: ?u64 = null;
        for (self.windows.items) |surface| {
            if (surface.undo_stack.oldestTimestamp()) |timestamp| {
                if (oldest == null or timestamp < oldest.?) oldest = timestamp;
            }
        }
        for (self.hosts.items) |host| {
            if (host.oldestStructuralTimestamp()) |timestamp| {
                if (oldest == null or timestamp < oldest.?) oldest = timestamp;
            }
        }
        return oldest;
    }

    fn scheduleUndoPruneTimer(self: *App) void {
        if (!self.running) return;
        self.stopUndoPruneTimer();

        const oldest = self.oldestUndoTimestamp() orelse return;
        const now = GetTickCount64();
        const expires_at = oldest +| self.undoTimeoutMs() +| 1;
        const delay_ms = if (expires_at <= now) 1 else expires_at - now;
        const timer_id = SetTimer(
            null,
            0,
            @intCast(@min(delay_ms, std.math.maxInt(UINT))),
            null,
        );
        if (timer_id == 0) {
            log.warn("failed to start win32 undo prune timer err={}", .{
                windows.kernel32.GetLastError(),
            });
            return;
        }
        self.undo_prune_timer_id = timer_id;
    }

    fn pruneUndoHistoryBefore(self: *App, min_timestamp_ms: u64) void {
        for (self.windows.items) |surface| {
            surface.undo_stack.discardExpired(min_timestamp_ms);
        }

        var i: usize = 0;
        while (i < self.hosts.items.len) {
            const host = self.hosts.items[i];
            host.pruneStructuralHistoryBefore(min_timestamp_ms);
            if (host.destroy_after_structural_dispose and host.tabs.items.len == 0) {
                if (host.hwnd) |hwnd| {
                    _ = DestroyWindow(hwnd);
                    self.removeHost(host);
                    continue;
                }
                host.destroy_after_structural_dispose = false;
            }
            if (i < self.hosts.items.len and self.hosts.items[i] == host) {
                i += 1;
            }
        }
    }

    fn pruneUndoHistoryNow(self: *App) void {
        self.pruneUndoHistoryBefore(self.undoCutoffTimestampMs());
        self.scheduleUndoPruneTimer();
        if (self.running and !self.hasLiveUiWindows()) self.startQuitTimer();
    }

    fn ensureMessageQueue(self: *App) void {
        _ = self;
        var msg: MSG = undefined;
        _ = PeekMessageW(&msg, null, 0, 0, PM_NOREMOVE);
    }

    pub fn keyboardLayout(self: *const App) input.KeyboardLayout {
        _ = self;
        return .unknown;
    }

    pub fn performAction(
        self: *App,
        target: apprt.Target,
        comptime action: apprt.Action.Key,
        value: apprt.Action.Value(action),
    ) !bool {
        switch (action) {
            .quit => {
                self.stopQuitTimer();
                self.running = false;
                self.destroyAllWindows();
                if (self.windows.items.len == 0) PostQuitMessage(0);
                return true;
            },

            .new_window => {
                var forwarded_arguments = value.arguments;
                switch (scanForwardedToastActivation(value.arguments)) {
                    .none => {},
                    .malformed => {
                        std.log.warn("dropping malformed forwarded toast activation argv", .{});
                        return true;
                    },
                    .activation => |activation| {
                        const dropped_args = forwardedActivationExtraArgCount(value.arguments);
                        if (dropped_args > 0) {
                            std.log.warn("dropping {d} forwarded argv item(s) bundled with toast activation", .{dropped_args});
                        }
                        if (self.handleToastActivation(activation)) return true;
                        self.pending_toast_activation = activation;
                        forwarded_arguments = null;
                    },
                }
                var config = try apprt.surface.newConfig(
                    self.core_app,
                    &self.config,
                    .window,
                );
                defer config.deinit();
                try applyNewWindowArguments(self.core_app.alloc, &config, forwarded_arguments);
                _ = try self.createWindowSurface(&config, default_title, .{
                    .clone_state_from = self.findSurfaceForTarget(target),
                });
                return true;
            },

            .new_tab => {
                var config = try apprt.surface.newConfig(
                    self.core_app,
                    &self.config,
                    .tab,
                );
                defer config.deinit();
                const source = self.findSurfaceForTarget(target);
                const surface = try self.createWindowSurface(&config, default_title, .{
                    .host_id = if (source) |v| v.host_id else null,
                    .clone_state_from = source,
                });
                if (source) |v| {
                    v.invalidateRedoForUnsupportedTabStructuralAction();
                }
                self.activateSurface(surface);
                return true;
            },

            .new_split => {
                var config = try apprt.surface.newConfig(
                    self.core_app,
                    &self.config,
                    .split,
                );
                defer config.deinit();
                const source = self.findSurfaceForTarget(target) orelse return false;
                const tab_info = self.findTabForSurface(source) orelse return false;
                const inherited_profile_key = try self.applySplitProfileConfigFromSource(&config, source);
                _ = try applySplitWorkingDirectoryFromSource(&config, source, self.startup_cwd);
                const split_direction = splitDirectionFromAction(value);
                const surface = try self.createWindowSurface(&config, default_title, .{
                    .host_id = source.host_id,
                    .tab_id = tab_info.tab.id,
                    .clone_state_from = source,
                    .split_direction = split_direction,
                });
                if (inherited_profile_key) |key| {
                    try appendOwnedString(self.core_app.alloc, &surface.launch_profile_key, key);
                }
                tab_info.tab.clearRedoHistory();
                if (tab_info.host.pushStructuralUndo(.{
                    .kind = .split_create,
                    .timestamp_ms = GetTickCount64(),
                    .payload = .{ .split_create = .{
                        .source_surface = source,
                        .created_surface = surface,
                        .direction = split_direction,
                    } },
                })) |_| {} else |err| {
                    log.warn("new_split undo snapshot failed err={}", .{err});
                    tab_info.host.clearStructuralRedo();
                }
                self.activateSurface(surface);
                return true;
            },

            .close_tab => {
                return try self.closeTab(target, value);
            },

            .close_all_windows => {
                self.stopQuitTimer();
                self.running = false;
                self.destroyAllWindows();
                if (self.windows.items.len == 0) PostQuitMessage(0);
                return true;
            },

            .close_window => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    if (surface.host) |host| host.close();
                    return true;
                }

                return false;
            },

            .config_change => {
                switch (target) {
                    .app => {
                        const config = try value.config.clone(self.core_app.alloc);
                        self.unregisterGlobalHotkeys();
                        self.config.deinit();
                        self.config = config;
                        self.scheduleGlobalHotkeySync();
                        self.reconfigureTheme();
                        for (self.windows.items) |surface| {
                            try surface.applyRuntimeConfig(&self.config);
                        }
                        if (self.windows.items.len == 0) {
                            self.startQuitTimer();
                        } else {
                            self.stopQuitTimer();
                        }
                    },
                    .surface => |core_surface| {
                        const surface = self.findSurfaceByCore(core_surface) orelse return false;
                        try surface.applyRuntimeConfig(value.config);
                        try self.syncHostWindowState(surface);
                    },
                }
                return true;
            },

            .reload_config => {
                if (target != .app) return false;
                if (value.soft) {
                    try self.core_app.updateConfig(self, &self.config);
                    if (self.config.@"app-notifications".@"config-reload") {
                        try self.showDesktopNotification(.app, "winghostty", "Configuration reloaded");
                    }
                    return true;
                }

                // Same startup-cwd restoration dance as
                // `settingsSaveAndReload`: `Config.load` calls
                // `loadCliArgs`, which realpaths `--config-file
                // <relative>` against current cwd. After
                // `sanitizeCurrentDirectory()` ran, relative overrides
                // would resolve to a different file than launch used,
                // silently swapping the config source on every manual
                // reload. Scoped to this path — non-reload code keeps
                // seeing the sanitized cwd.
                const cwd_before: ?[]u8 = std.process.getCwdAlloc(self.core_app.alloc) catch null;
                defer if (cwd_before) |p| self.core_app.alloc.free(p);

                // `defer` + flag so the restore fires even when
                // `Config.load` returns an error — otherwise a
                // broken include leaves the process pinned to
                // `startup_cwd` (same class of bug as the one
                // fixed in `settingsSaveAndReload`). Relative-path
                // lookups + child processes spawned after a failed
                // reload would inherit the wrong cwd.
                var did_chdir_to_startup: bool = false;
                if (self.startup_cwd) |cwd| {
                    if (std.process.changeCurDir(cwd)) |_| {
                        did_chdir_to_startup = true;
                    } else |err| {
                        std.log.warn("reload_config: couldn't restore startup cwd path={s} err={}", .{ cwd, err });
                    }
                }
                defer {
                    if (did_chdir_to_startup) {
                        if (cwd_before) |cwd| {
                            std.process.changeCurDir(cwd) catch |err| {
                                std.log.warn("reload_config: couldn't restore sanitized cwd path={s} err={}", .{ cwd, err });
                            };
                        }
                    }
                }

                var config = try configpkg.Config.load(self.core_app.alloc);
                defer config.deinit();
                try self.core_app.updateConfig(self, &config);
                if (self.config.@"app-notifications".@"config-reload") {
                    try self.showDesktopNotification(.app, "winghostty", "Configuration reloaded");
                }
                return true;
            },

            .present_terminal,
            .renderer_health,
            .color_change,
            .mouse_over_link,
            => {
                if (action == .present_terminal) {
                    if (self.findSurfaceForTarget(target)) |surface| {
                        surface.present();
                        return true;
                    }
                    return false;
                }
                return true;
            },

            .quit_timer => {
                if (target != .app) return false;
                switch (value) {
                    .start => self.startQuitTimer(),
                    .stop => self.stopQuitTimer(),
                }
                return true;
            },

            .toggle_visibility => {
                self.windows_hidden = !self.windows_hidden;
                if (self.windows_hidden) {
                    for (self.hosts.items) |host| host.setVisible(false);
                } else {
                    for (self.hosts.items) |host| {
                        host.setVisible(true);
                        try host.layout();
                    }
                    if (self.findSurfaceForTarget(target)) |surface| {
                        self.activateSurface(surface);
                    } else if (self.primarySurface()) |surface| {
                        self.activateSurface(surface);
                    }
                }
                return true;
            },

            .toggle_background_opacity => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    const changed = try surface.toggleBackgroundOpacity();
                    if (!changed) return false;
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .goto_window => {
                return try self.gotoWindow(target, value);
            },

            .goto_split => {
                return try self.gotoSplitFallback(target, value);
            },

            .resize_split => {
                return try self.resizeSplitFallback(target, value);
            },

            .equalize_splits => {
                return try self.equalizeSplitsFallback(target);
            },

            .move_tab => {
                return try self.moveTab(target, value);
            },

            .goto_tab => {
                return try self.gotoTab(target, value);
            },

            .toggle_tab_overview => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    return try surface.toggleTabOverview();
                }
                return false;
            },

            .toggle_quick_terminal => {
                try self.toggleQuickTerminal();
                return true;
            },

            .toggle_maximize => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.toggleMaximize();
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .toggle_fullscreen => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.toggleFullscreen(value);
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .toggle_window_decorations => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.toggleDecorations();
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .float_window => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setFloatWindow(value);
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .initial_size => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setInitialSize(value);
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .reset_window_size => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.resetWindowSize();
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .size_limit => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.setSizeLimit(value);
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .cell_size => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.setCellSize(value);
                    try self.syncHostWindowState(surface);
                    return true;
                }
                return false;
            },

            .toggle_split_zoom => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    const found = self.findTabForSurface(surface) orelse return false;
                    const handle = found.tab.findHandle(surface) orelse found.tab.focused;
                    found.tab.tree.zoom(if (found.tab.tree.zoomed != null) null else handle);
                    surface.invalidateRedoForUnsupportedTabStructuralAction();
                    try found.host.layout();
                    return true;
                }
                return false;
            },

            .render => {
                return switch (target) {
                    .app => blk: {
                        for (self.windows.items) |surface| try surface.requestRepaint();
                        break :blk true;
                    },
                    .surface => if (self.findSurfaceForTarget(target)) |surface| blk: {
                        try surface.requestRepaint();
                        break :blk true;
                    } else false,
                };
            },

            .render_inspector => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.redrawInspector();
                    return true;
                }

                return false;
            },

            .inspector => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    return try self.setInspectorActionForSurface(surface, value);
                }
                return false;
            },

            .show_gtk_inspector => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    return try self.setInspectorActionForSurface(surface, .show);
                }
                return false;
            },

            .set_title => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setTitle(value.title);
                    return true;
                }

                return false;
            },

            .set_tab_title => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setTabTitleOverride(if (value.title.len == 0) null else value.title);
                    return true;
                }

                return false;
            },

            .prompt_title => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.promptTitle(value);
                    return true;
                }

                return false;
            },

            .toggle_command_palette => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    return try surface.toggleCommandPalette();
                }
                return false;
            },

            .pwd => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setPwd(value.pwd);
                    return true;
                }

                return false;
            },

            .mouse_shape => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.setMouseShape(value);
                    return true;
                }
                return false;
            },

            .mouse_visibility => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    surface.setMouseVisibility(value);
                    return true;
                }
                return false;
            },

            .progress_report => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setProgressReport(value);
                    return true;
                }
                return false;
            },

            .command_finished => {
                try self.showCommandFinished(target, value);
                return true;
            },

            .start_search => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.showSearchOverlay(value.needle);
                    return true;
                }
                return false;
            },

            .end_search => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.closeDockedSearchBar(false, false);
                    return true;
                }
                return false;
            },

            .search_total => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setSearchTotal(value.total);
                    return true;
                }
                return false;
            },

            .search_selected => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setSearchSelected(value.selected);
                    return true;
                }
                return false;
            },

            .search_match_rows => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setSearchMatchRows(value.rows);
                    return true;
                }
                return false;
            },

            .secure_input => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setSecureInput(value);
                    return true;
                }
                return false;
            },

            .readonly => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setReadonly(value == .on);
                    return true;
                }
                return false;
            },

            .key_sequence => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setKeySequenceActive(switch (value) {
                        .trigger => true,
                        .end => false,
                    });
                    return true;
                }
                return false;
            },

            .key_table => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setKeyTable(value);
                    return true;
                }
                return false;
            },

            .scrollbar => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    try surface.setScrollbar(value);
                    return true;
                }
                return false;
            },

            .undo => {
                self.pruneUndoHistoryNow();
                const surface = self.undoRedoSurfaceForTarget(target) orelse {
                    const host = self.structuralUndoHostForTarget(target) orelse return false;
                    while (host.peekStructuralUndo() != null) {
                        const message = try host.applyLatestStructuralUndo() orelse continue;
                        try host.setBanner(.info, message);
                        return true;
                    }
                    try host.setBanner(.info, "Nothing to undo.");
                    return true;
                };

                while (true) {
                    const host_entry = if (surface.host) |host| host.peekStructuralUndo() else null;
                    const local_entry = surface.undo_stack.peekUndo();

                    if (host_entry == null and local_entry == null) break;
                    const use_host = host_entry != null and
                        (local_entry == null or host_entry.?.timestamp_ms > local_entry.?.timestamp_ms);

                    if (use_host) {
                        const host = surface.host orelse break;
                        const message = try host.applyLatestStructuralUndo() orelse continue;
                        _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, message);
                        return true;
                    }

                    const message = try surface.applyLatestLocalUndo() orelse continue;
                    _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, message);
                    return true;
                }

                _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, "Nothing to undo.");
                return true;
            },

            .redo => {
                self.pruneUndoHistoryNow();
                const surface = self.undoRedoSurfaceForTarget(target) orelse {
                    const host = self.structuralRedoHostForTarget(target) orelse return false;
                    while (host.peekStructuralRedo() != null) {
                        const message = try host.applyLatestStructuralRedo() orelse continue;
                        try host.setBanner(.info, message);
                        return true;
                    }
                    try host.setBanner(.info, "Nothing to redo.");
                    return true;
                };

                while (true) {
                    const host_entry = if (surface.host) |host| host.peekStructuralRedo() else null;
                    const local_entry = surface.undo_stack.peekRedo();

                    if (host_entry == null and local_entry == null) break;
                    const use_host = host_entry != null and
                        (local_entry == null or host_entry.?.timestamp_ms > local_entry.?.timestamp_ms);

                    if (use_host) {
                        const host = surface.host orelse break;
                        const message = try host.applyLatestStructuralRedo() orelse continue;
                        _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, message);
                        return true;
                    }

                    const message = try surface.applyLatestLocalRedo() orelse continue;
                    _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, message);
                    return true;
                }

                _ = try self.showHostBanner(.{ .surface = surface.core() }, .info, "Nothing to redo.");
                return true;
            },

            .check_for_updates => {
                if (self.config.@"auto-update-channel" != .stable) {
                    _ = try self.showHostBanner(target, .info, "Automatic prerelease update checks are not supported yet. Opening releases.");
                    try self.openUrl(releases_url);
                    return true;
                }

                try self.scheduleUpdateCheck(.{
                    .force = true,
                    .manual = true,
                    .respect_dismissal = false,
                });
                return true;
            },

            .open_url => {
                try self.openUrl(value.url);
                return true;
            },

            .show_on_screen_keyboard => {
                try self.showOnScreenKeyboard();
                return true;
            },

            .open_config => {
                try self.openConfig();
                return true;
            },

            .copy_title_to_clipboard => {
                if (self.findSurfaceForTarget(target)) |surface| {
                    const title = surface.getTitle() orelse return false;
                    try surface.writeClipboardText(title);
                    return true;
                }
                return false;
            },

            .ring_bell => {
                self.ringBell(target);
                return true;
            },

            .desktop_notification => {
                try self.showDesktopNotification(target, value.title, value.body);
                return true;
            },

            .show_child_exited => {
                try self.showChildExited(target, value);
                return true;
            },
        }
    }

    pub fn performIpc(
        alloc: Allocator,
        target: apprt.ipc.Target,
        comptime action: apprt.ipc.Action.Key,
        value: apprt.ipc.Action.Value(action),
    ) !bool {
        switch (action) {
            .new_window => {
                const pipe_name = try resolveIpcPipeNameForTarget(alloc, target);
                defer alloc.free(pipe_name);

                if (try sendNewWindowIpc(alloc, pipe_name, value.arguments)) return true;
                return try spawnWindowProcess(alloc, target, value);
            },
        }
    }

    fn spawnWindowProcess(
        alloc: Allocator,
        target: apprt.ipc.Target,
        value: apprt.ipc.Action.NewWindow,
    ) !bool {
        const exe_path = try std.fs.selfExePathAlloc(alloc);
        defer alloc.free(exe_path);

        var argv: std.ArrayList([]const u8) = .empty;
        defer argv.deinit(alloc);

        try argv.append(alloc, exe_path);
        if (target == .class) {
            const class_arg = try std.fmt.allocPrint(alloc, "--class={s}", .{target.class});
            defer alloc.free(class_arg);
            try argv.append(alloc, class_arg);
        }
        if (value.arguments) |arguments| {
            for (arguments) |arg| try argv.append(alloc, arg);
        }

        var child = std.process.Child.init(argv.items, alloc);
        child.stdin_behavior = .Ignore;
        child.stdout_behavior = .Ignore;
        child.stderr_behavior = .Ignore;
        try child.spawn();
        return true;
    }

    fn ensureWindowClass(self: *App) !void {
        if (self.class_atom != 0) return;

        var wc: WNDCLASSEXW = .{
            .cbSize = @sizeOf(WNDCLASSEXW),
            .style = CS_OWNDC,
            .lpfnWndProc = &windowProc,
            .cbClsExtra = 0,
            .cbWndExtra = 0,
            .hInstance = self.hinstance,
            .hIcon = loadAppIcon(self.hinstance, false),
            .hCursor = LoadCursorW(null, IDC_ARROW),
            .hbrBackground = null,
            .lpszMenuName = null,
            .lpszClassName = class_name,
            .hIconSm = loadAppIcon(self.hinstance, true),
        };

        self.class_atom = RegisterClassExW(&wc);
        if (self.class_atom == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

