    fn createWindowSurface(
        self: *App,
        config: *const configpkg.Config,
        title: LPCWSTR,
        opts: SurfaceInitOptions,
    ) !*Surface {
        if (self.test_create_window_surface) |hook| {
            return try hook(self, config, title, opts);
        }
        const surface = try self.core_app.alloc.create(Surface);
        errdefer self.core_app.alloc.destroy(surface);

        try surface.init(self, title, config, opts);
        if (opts.host_id == null) self.consumePendingToastActivation();
        return surface;
    }

    fn applySplitProfileConfigFromSource(
        self: *App,
        config: *configpkg.Config,
        source: *Surface,
    ) !?[]const u8 {
        _ = self;
        const key = source.launch_profile_key orelse return null;
        const host = source.host orelse return null;
        const profile = (try host.profileForKey(key)) orelse return null;
        try applyProfileCommandConfig(config, profile);
        return profile.key;
    }

    fn createProfileSurface(
        self: *App,
        target: apprt.Target,
        profile: *const windows_shell.Profile,
        open_target: ProfileOpenTarget,
    ) !*Surface {
        const source = self.findSurfaceForTarget(target);
        var config = try apprt.surface.newConfig(
            self.core_app,
            &self.config,
            switch (open_target) {
                .tab => .tab,
                .window => .window,
                .split => .split,
            },
        );
        defer config.deinit();
        try applyProfileSurfaceConfig(&config, profile);

        const tab_id = switch (open_target) {
            .split => blk: {
                const source_surface = source orelse return error.NoActiveSurface;
                const tab_info = self.findTabForSurface(source_surface) orelse return error.NoActiveSurface;
                break :blk tab_info.tab.id;
            },
            else => null,
        };

        const title_w = try std.unicode.utf8ToUtf16LeAllocZ(self.core_app.alloc, profile.label);
        defer self.core_app.alloc.free(title_w);
        const surface = try self.createWindowSurface(&config, title_w.ptr, .{
            .host_id = if (open_target == .window) null else if (source) |v| v.host_id else null,
            .tab_id = tab_id,
            .clone_state_from = source,
        });
        try appendOwnedString(self.core_app.alloc, &surface.launch_profile_key, profile.key);
        return surface;
    }

    fn createWindow(self: *App, title: LPCWSTR) !void {
        _ = try self.createWindowSurface(&self.config, title, .{});
    }

    fn refreshSystemWheelSettings(self: *App) void {
        self.wheel_settings = .{
            .lines = readSystemWheelSetting(SPI_GETWHEELSCROLLLINES, self.wheel_settings.lines),
            .chars = readSystemWheelSetting(SPI_GETWHEELSCROLLCHARS, self.wheel_settings.chars),
        };
    }

    fn refreshSystemScrollbarPreference(self: *App) void {
        self.system_dynamic_scrollbars = readDynamicScrollbars(self.system_dynamic_scrollbars);
        for (self.windows.items) |surface| {
            surface.refreshScrollbarWindow() catch |err| {
                log.warn("win32 scrollbar refresh failed err={}", .{err});
            };
        }
    }

    fn reconfigureTheme(self: *App) void {
        const previous_integrated_titlebar = self.use_integrated_titlebar;
        self.use_integrated_titlebar = shouldUseIntegratedTitlebar(
            self.os_build,
            self.config.@"window-show-tab-bar",
        );
        const frame_mode_changed = previous_integrated_titlebar != self.use_integrated_titlebar;
        self.resolved_theme = resolveTheme(&self.config);
        for (self.hosts.items) |host| {
            host.rebuildThemeBrushes();
            host.recreateChromeFont();
            if (frame_mode_changed) {
                // A stock<->integrated frame flip can cancel the old
                // NC hover tracking without delivering
                // WM_NCMOUSELEAVE. Clear both fields eagerly so
                // re-enabling integrated chrome doesn't resurrect a
                // stale hovered button.
                host.handleNcMouseLeave();
            }
            if (host.hwnd) |hwnd| {
                applyDwmThemeWithBuild(hwnd, &self.resolved_theme, &self.config, self.os_build);
                if (frame_mode_changed) {
                    _ = SetWindowPos(
                        hwnd,
                        null,
                        0,
                        0,
                        0,
                        0,
                        SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_NOACTIVATE | SWP_FRAMECHANGED,
                    );
                    host.layout() catch {};
                    host.invalidateChrome();
                }
            }
        }
        for (self.windows.items) |surface| surface.invalidateScrollbarWindow();
    }

    fn applyLauncherQuickSlotPreferences(self: *App, profiles: []windows_shell.Profile) void {
        applyQuickSlotPreferenceOrder(profiles, .{
            self.launcher_quick_slot_keys[0],
            self.launcher_quick_slot_keys[1],
            self.launcher_quick_slot_keys[2],
        });
    }

    fn launcherQuickSlotOrdinal(self: *const App, key: []const u8) ?usize {
        return findLauncherQuickSlotOrdinal(self.launcher_quick_slot_keys, key);
    }

    fn setLauncherQuickSlotPreference(self: *App, slot_ordinal: usize, key: []const u8) !void {
        if (slot_ordinal >= self.launcher_quick_slot_keys.len) return;
        if (!launcherQuickSlotAssignmentNeedsChange(self.launcher_quick_slot_keys, slot_ordinal, key)) return;
        var duplicate_slot: ?usize = null;
        for (self.launcher_quick_slot_keys, 0..) |existing, index| {
            if (existing) |value| {
                if (std.ascii.eqlIgnoreCase(value, key)) {
                    duplicate_slot = index;
                    break;
                }
            }
        }

        if (duplicate_slot) |index| {
            if (index != slot_ordinal) {
                if (self.launcher_quick_slot_keys[slot_ordinal]) |current| {
                    if (self.launcher_quick_slot_keys[index]) |dupe| self.core_app.alloc.free(dupe);
                    self.launcher_quick_slot_keys[index] = try self.core_app.alloc.dupeZ(u8, current);
                } else {
                    appendOwnedString(self.core_app.alloc, &self.launcher_quick_slot_keys[index], null) catch {};
                }
            }
        }

        try appendOwnedString(self.core_app.alloc, &self.launcher_quick_slot_keys[slot_ordinal], key);

        for (self.hosts.items) |host| {
            host.reapplyLauncherProfilePreferences() catch {};
            host.refreshProfileChrome();
        }
    }

    fn clearLauncherQuickSlotPreferences(self: *App) void {
        if (launcherQuickSlotPinsAlreadyClear(self.launcher_quick_slot_keys)) return;
        for (&self.launcher_quick_slot_keys) |*value| {
            appendOwnedString(self.core_app.alloc, value, null) catch {};
        }

        for (self.hosts.items) |host| {
            if (host.profiles != null) {
                _ = host.reloadProfiles() catch false;
            }
            host.refreshProfileChrome();
        }
    }

    fn allocateHostId(self: *App) u32 {
        const id = self.next_host_id;
        self.next_host_id +%= 1;
        if (self.next_host_id == 0) self.next_host_id = 1;
        return id;
    }

    fn createHost(self: *App, title: LPCWSTR, clone_state_from: ?*const Surface, passive_show: bool) !*Host {
        try self.ensureHostWindowClass();
        try self.ensurePaletteListClass();
        try self.ensureScrollbarClass();

        const host = try self.core_app.alloc.create(Host);
        errdefer self.core_app.alloc.destroy(host);
        host.* = .{
            .app = self,
            .id = self.allocateHostId(),
        };
        host.tween_sched.init(self.core_app.alloc);
        if (self.launcher_profile_key) |key| {
            try appendOwnedString(self.core_app.alloc, &host.selected_profile_key, key);
        }

        const position = configuredHostWindowPosition(&self.config);

        const hwnd = CreateWindowExW(
            0,
            host_class_name,
            title,
            hostWindowStyle(),
            if (position) |v| v.x else CW_USEDEFAULT,
            if (position) |v| v.y else CW_USEDEFAULT,
            1280,
            800,
            null,
            null,
            self.hinstance,
            host,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        host.hwnd = hwnd;
        setWindowIcon(hwnd, self.hinstance);
        applyDwmThemeWithBuild(hwnd, &self.resolved_theme, &self.config, self.os_build);
        host.current_dpi = GetDpiForWindow(hwnd);
        if (host.current_dpi == 0) host.current_dpi = 96;
        host.chrome_font = host.createChromeFont();
        host.recreateTitlebarIconFonts();
        errdefer _ = DestroyWindow(hwnd);

        try self.hosts.append(self.core_app.alloc, host);
        if (clone_state_from) |source| {
            if (source.host) |existing| try self.inheritHostWindowState(host, existing);
        }

        // Passive first-show for quick-terminal-keyboard-interactivity
        // = none: `SW_SHOWNOACTIVATE` makes the window visible but
        // does NOT bring it to the foreground, so the user's current
        // typing context stays intact. `SW_SHOW` would activate the
        // new HWND and steal focus.
        _ = ShowWindow(hwnd, if (passive_show) SW_SHOWNOACTIVATE else SW_SHOW);
        _ = UpdateWindow(hwnd);
        self.maybeScheduleAutomaticUpdateCheck();
        return host;
    }

    fn findHostById(self: *App, id: u32) ?*Host {
        for (self.hosts.items) |host| {
            if (host.id == id) return host;
        }
        return null;
    }

    fn activeTab(self: *App, host: *Host) ?*Tab {
        _ = self;
        if (host.tabs.items.len == 0 or host.active_tab >= host.tabs.items.len) return null;
        return &host.tabs.items[host.active_tab];
    }

    fn activeSurfaceForHost(self: *App, host_id: u32) ?*Surface {
        const host = self.findHostById(host_id) orelse return null;
        const tab = self.activeTab(host) orelse return null;
        return tab.focusedSurface();
    }

    fn findSurfaceById(self: *App, surface_id: u64) ?*Surface {
        for (self.windows.items) |surface| {
            if (surface.core().id == surface_id) return surface;
        }

        for (self.hosts.items) |host| {
            for (host.tabs.items) |*tab| {
                if (tab.findSurfaceByCoreId(surface_id)) |surface| return surface;
            }
        }

        return null;
    }

    fn inheritHostWindowState(_: *App, destination: *Host, source: *Host) !void {
        const dst_hwnd = destination.hwnd orelse return;
        const src_hwnd = source.hwnd orelse return;
        var rect: RECT = undefined;
        if (GetWindowRect(src_hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        if (SetWindowPos(
            dst_hwnd,
            null,
            rect.left,
            rect.top,
            rect.right - rect.left,
            rect.bottom - rect.top,
            SWP_NOACTIVATE,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn findSurfaceForTarget(self: *App, target: apprt.Target) ?*Surface {
        return switch (target) {
            .app => self.primarySurface(),
            .surface => |core_surface| self.findSurfaceByCore(core_surface),
        };
    }

    fn focusedSurfaceForUndoRedo(self: *App) ?*Surface {
        for (self.hosts.items) |host| {
            if (host.activeSurface()) |surface| {
                if (surface.window_focused) return surface;
            }
        }

        for (self.windows.items) |surface| {
            if (surface.window_focused) return surface;
        }

        return null;
    }

    fn undoRedoSurfaceForTarget(self: *App, target: apprt.Target) ?*Surface {
        return switch (target) {
            .app => self.focusedSurfaceForUndoRedo() orelse self.primarySurface(),
            .surface => |core_surface| self.findSurfaceByCore(core_surface),
        };
    }

    fn structuralUndoHostForTarget(self: *App, target: apprt.Target) ?*Host {
        if (self.undoRedoSurfaceForTarget(target)) |surface| {
            if (surface.host) |host| return host;
        }

        return switch (target) {
            .app => self.hostWithNewestStructuralUndo() orelse if (self.hosts.items.len > 0) self.hosts.items[0] else null,
            .surface => null,
        };
    }

    fn structuralRedoHostForTarget(self: *App, target: apprt.Target) ?*Host {
        if (self.undoRedoSurfaceForTarget(target)) |surface| {
            if (surface.host) |host| return host;
        }

        return switch (target) {
            .app => self.hostWithNewestStructuralRedo() orelse if (self.hosts.items.len > 0) self.hosts.items[0] else null,
            .surface => null,
        };
    }

    fn primarySurface(self: *App) ?*Surface {
        if (self.hosts.items.len == 0) return null;
        return self.activeSurfaceForHost(self.hosts.items[0].id);
    }

    fn hostWithNewestStructuralUndo(self: *App) ?*Host {
        var best: ?*Host = null;
        var best_ts: u64 = 0;
        for (self.hosts.items) |host| {
            const entry = host.peekStructuralUndo() orelse continue;
            if (best == null or entry.timestamp_ms > best_ts) {
                best = host;
                best_ts = entry.timestamp_ms;
            }
        }
        return best;
    }

    fn hostWithNewestStructuralRedo(self: *App) ?*Host {
        var best: ?*Host = null;
        var best_ts: u64 = 0;
        for (self.hosts.items) |host| {
            const entry = host.peekStructuralRedo() orelse continue;
            if (best == null or entry.timestamp_ms > best_ts) {
                best = host;
                best_ts = entry.timestamp_ms;
            }
        }
        return best;
    }

    fn undoCutoffTimestampMs(self: *const App) u64 {
        return GetTickCount64() -| self.undoTimeoutMs();
    }

    fn findSurfaceByCore(self: *App, core_surface: *CoreSurface) ?*Surface {
        for (self.windows.items) |surface| {
            if (surface.core() == core_surface) return surface;
        }

        return null;
    }

    fn collectHostIds(self: *App, alloc: Allocator) !std.ArrayListUnmanaged(u32) {
        var ids: std.ArrayListUnmanaged(u32) = .empty;
        errdefer ids.deinit(alloc);
        for (self.hosts.items) |host| try ids.append(alloc, host.id);
        return ids;
    }

    fn collectHostSurfaces(self: *App, alloc: Allocator, host_id: u32) !std.ArrayListUnmanaged(*Surface) {
        var surfaces: std.ArrayListUnmanaged(*Surface) = .empty;
        errdefer surfaces.deinit(alloc);
        const host = self.findHostById(host_id) orelse return surfaces;
        for (host.tabs.items) |*tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                try surfaces.append(alloc, entry.view);
            }
        }
        return surfaces;
    }

    fn findTabForSurface(_: *App, surface: *Surface) ?struct { host: *Host, index: usize, tab: *Tab } {
        const host = surface.host orelse return null;
        for (host.tabs.items, 0..) |*tab, index| {
            if (tab.findHandle(surface) != null) {
                return .{ .host = host, .index = index, .tab = tab };
            }
        }
        return null;
    }

    fn tabHasInspectorForSurface(self: *App, surface: *Surface) bool {
        const found = self.findTabForSurface(surface) orelse return surface.inspector_visible;
        var it = found.tab.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view.inspector_visible) return true;
        }
        return false;
    }

    fn setTabInspectorVisibleForSurface(self: *App, surface: *Surface, visible: bool) !bool {
        const found = self.findTabForSurface(surface) orelse return try surface.setInspectorVisible(visible);
        var changed = false;
        var it = found.tab.tree.iterator();
        while (it.next()) |entry| {
            if (try entry.view.setInspectorVisible(visible)) changed = true;
        }
        return changed;
    }

    fn setInspectorActionForSurface(self: *App, surface: *Surface, mode: apprt.action.Inspector) !bool {
        return try self.setTabInspectorVisibleForSurface(
            surface,
            nextTabInspectorVisible(self.tabHasInspectorForSurface(surface), mode),
        );
    }

    fn toggleInspectorForSurface(self: *App, surface: *Surface) !bool {
        return try self.setInspectorActionForSurface(surface, .toggle);
    }

    fn hostTabStatus(self: *App, surface: *const Surface) HostTabStatus {
        const host = surface.host orelse return .{};
        const total = host.tabs.items.len;
        var index: usize = 0;
        if (self.findTabForSurface(@constCast(surface))) |found| index = found.index;
        return .{
            .index = index,
            .total = if (total == 0) 1 else total,
        };
    }

    fn showHostSurface(self: *App, surface: *Surface, focus: bool) void {
        const host = surface.host orelse return;
        const tab_info = self.findTabForSurface(surface) orelse return;
        host.active_tab = tab_info.index;
        host.prepareActiveTabVisibility(tab_info.index);
        var active_it = tab_info.tab.tree.iterator();
        while (active_it.next()) |entry| entry.view.setVisible(true);
        host.layout() catch {};
        host.refreshChrome() catch {};
        if (focus) {
            surface.presentWindow();
        } else {
            surface.setVisible(true);
        }
    }

    fn activateSurface(self: *App, surface: *Surface) void {
        const was_windows_hidden = self.windows_hidden;
        self.windows_hidden = false;
        if (self.findTabForSurface(surface)) |found| {
            const handle = found.tab.findHandle(surface) orelse found.tab.focused;
            const host_window_visible = if (found.host.hwnd) |hwnd|
                IsWindowVisible(hwnd) != 0
            else
                false;
            const needs_host_sync = surfaceFocusedActivationNeedsHostSync(
                was_windows_hidden,
                host_window_visible,
                found.index,
                found.host.active_tab,
                surface.window_visible,
                surface.window_focused,
            );
            if (found.tab.focused != handle) found.tab.focused = handle;
            if (!needs_host_sync) {
                surface.presentWindow();
                self.syncTaskbarProgressForHost(surface.host_id);
                return;
            }
        }
        self.showHostSurface(surface, true);
        self.syncTaskbarProgressForHost(surface.host_id);
    }

    fn syncTaskbarProgressForHost(self: *App, host_id: u32) void {
        const taskbar = if (self.taskbar_progress) |*value| value else return;
        const host = self.findHostById(host_id) orelse return;
        const hwnd = host.hwnd orelse return;
        const report = if (self.activeSurfaceForHost(host_id)) |surface|
            surface.taskbar_progress
        else
            null;
        const state_name = if (report) |value| @tagName(value.state) else "remove";
        std.log.debug("taskbar progress sync host_id={d} state={s}", .{ host_id, state_name });
        taskbar.apply(hwnd, report) catch |err| {
            std.log.warn("taskbar progress sync failed host_id={d} err={}; disabling native taskbar progress", .{ host_id, err });
            taskbar.deinit();
            self.taskbar_progress = null;
        };
    }

    fn focusedSurfaceForHostTab(_: *App, host: *Host, tab_id: u32) ?*Surface {
        for (host.tabs.items) |*tab| {
            if (tab.id != tab_id) continue;
            return tab.focusedSurface();
        }

        return null;
    }

    fn resolveToastActivationSurface(
        self: *App,
        activation: win32_toast_activation.ActivationTarget,
    ) ?*Surface {
        if (activation.surface_id) |surface_id| {
            if (self.findSurfaceById(surface_id)) |surface| {
                return surface;
            }
        }

        if (activation.window_id) |window_id| {
            if (self.findHostById(window_id)) |host| {
                if (activation.tab_id) |tab_id| {
                    if (self.focusedSurfaceForHostTab(host, tab_id)) |surface| {
                        return surface;
                    }
                }
                if (self.activeTab(host)) |tab| {
                    if (tab.focusedSurface()) |surface| {
                        return surface;
                    }
                }
            }
        }

        return self.primarySurface();
    }

    fn handleToastActivation(self: *App, activation: win32_toast_activation.ActivationTarget) bool {
        if (activation.action) |action| switch (action) {
            .focus => {},
        };

        const surface = self.resolveToastActivationSurface(activation) orelse return false;
        surface.present();
        return true;
    }

    fn consumePendingToastActivation(self: *App) void {
        const activation = self.pending_toast_activation orelse return;
        if (self.handleToastActivation(activation)) {
            self.pending_toast_activation = null;
        }
    }

    fn activateSurfaceNoFocus(self: *App, surface: *Surface) void {
        const was_windows_hidden = self.windows_hidden;
        self.windows_hidden = false;
        if (self.findTabForSurface(surface)) |found| {
            const handle = found.tab.findHandle(surface) orelse found.tab.focused;
            const host_window_visible = if (found.host.hwnd) |hwnd|
                IsWindowVisible(hwnd) != 0
            else
                false;
            const needs_host_sync = surfaceActivationNeedsHostSync(
                was_windows_hidden,
                host_window_visible,
                found.index,
                found.host.active_tab,
                surface.window_visible,
            );
            if (found.tab.focused != handle) found.tab.focused = handle;
            if (!needs_host_sync) {
                surface.setVisible(true);
                self.syncTaskbarProgressForHost(surface.host_id);
                return;
            }
        }
        self.showHostSurface(surface, false);
        self.syncTaskbarProgressForHost(surface.host_id);
    }

    fn noteSurfaceFocused(self: *App, surface: *Surface) bool {
        const found = self.findTabForSurface(surface) orelse return false;
        const handle = found.tab.findHandle(surface) orelse return false;
        const changed = surfaceFocusStateChanged(
            found.host.active_tab,
            found.tab.focused,
            found.index,
            handle,
        );
        found.host.active_tab = found.index;
        found.tab.focused = handle;
        return changed;
    }

    fn syncHostWindowState(self: *App, source: *Surface) !void {
        var host_surfaces = try self.collectHostSurfaces(self.core_app.alloc, source.host_id);
        defer host_surfaces.deinit(self.core_app.alloc);
        for (host_surfaces.items) |candidate| {
            if (candidate == source) continue;
            try candidate.inheritWindowStateFrom(source);
        }
    }

    fn removeWindow(self: *App, surface: *Surface) void {
        for (self.windows.items, 0..) |item, i| {
            if (item == surface) {
                _ = self.windows.swapRemove(i);
                break;
            }
        }
    }

    fn removeHost(self: *App, host: *Host) void {
        for (self.hosts.items, 0..) |item, i| {
            if (item == host) {
                _ = self.hosts.swapRemove(i);
                host.deinit();
                self.core_app.alloc.destroy(host);
                break;
            }
        }
    }

    fn windowDestroyed(self: *App, surface: *Surface) void {
        self.removeWindow(surface);
        if (surface.host) |host| {
            surface.invalidateStructuralHistoryForDestroy();
            host.discardStructuralEntriesReferencing(surface);

            // Clear stale hover/drag state that may reference the destroyed surface's tab button
            host.setHoveredButton(null);
            host.tab_drag_index = null;
            host.tab_drag_active = false;

            for (host.tabs.items, 0..) |*tab, i| {
                if (tab.findHandle(surface)) |handle| {
                    if (tab.tree.nodes.len == 1) {
                        // Remove first, then deinit the detached tab value. This
                        // avoids shifting the live array after poisoning the slot
                        // with `undefined` during Tab.deinit().
                        var removed = host.tabs.orderedRemove(i);
                        removed.deinit();
                        if (host.active_tab >= host.tabs.items.len and host.tabs.items.len > 0) {
                            host.active_tab = host.tabs.items.len - 1;
                        }
                    } else {
                        const next_tree = tab.tree.remove(self.core_app.alloc, handle) catch break;
                        tab.tree.deinit();
                        tab.tree = next_tree;
                        var it = tab.tree.iterator();
                        tab.focused = it.next().?.handle;
                    }
                    break;
                }
            }

            if (host.tabs.items.len == 0) {
                if (host.structural_history_disposing) {
                    host.destroy_after_structural_dispose = true;
                } else {
                    if (host.hwnd) |hwnd| _ = DestroyWindow(hwnd);
                    self.removeHost(host);
                }
            } else if (self.running) {
                if (self.activeTab(host)) |tab| if (tab.focusedSurface()) |replacement| self.activateSurface(replacement);
                // Relayout after tab removal because the chrome
                // reservation may have changed. In this fork,
                // `.auto` still shows the row since it carries the
                // essential host controls (+, overflow).
                host.layout() catch {};
            }
        }

        if (self.windows.items.len == 0 and self.running) self.startQuitTimer();
    }

    fn gotoWindow(self: *App, target: apprt.Target, direction: apprt.action.GotoWindow) !bool {
        var host_ids = try self.collectHostIds(self.core_app.alloc);
        defer host_ids.deinit(self.core_app.alloc);
        if (host_ids.items.len <= 1) return false;

        const current = self.findSurfaceForTarget(target) orelse self.windows.items[0];
        var current_host_idx: usize = 0;
        for (host_ids.items, 0..) |host_id, i| {
            if (host_id == current.host_id) {
                current_host_idx = i;
                break;
            }
        }

        const next_idx = switch (direction) {
            .next => (current_host_idx + 1) % host_ids.items.len,
            .previous => (current_host_idx + host_ids.items.len - 1) % host_ids.items.len,
        };
        const next_surface = self.activeSurfaceForHost(host_ids.items[next_idx]) orelse return false;
        self.activateSurface(next_surface);
        return true;
    }

    fn gotoSplitFallback(self: *App, target: apprt.Target, to: apprt.action.GotoSplit) !bool {
        const current = self.findSurfaceForTarget(target) orelse return false;
        const found = self.findTabForSurface(current) orelse return false;
        const from = found.tab.findHandle(current) orelse found.tab.focused;
        const goto: SplitTreeSurface.Goto = switch (to) {
            .previous => .previous_wrapped,
            .next => .next_wrapped,
            .left => .{ .spatial = .left },
            .right => .{ .spatial = .right },
            .up => .{ .spatial = .up },
            .down => .{ .spatial = .down },
        };
        const next_handle = (try found.tab.tree.goto(self.core_app.alloc, from, goto)) orelse return false;
        found.tab.focused = next_handle;
        const next_surface = found.tab.focusedSurface() orelse return false;
        self.activateSurface(next_surface);
        return true;
    }

    fn gotoSplitFallbackDirection(to: apprt.action.GotoSplit) ?apprt.action.GotoWindow {
        return switch (to) {
            .previous => .previous,
            .next => .next,
            .up, .down, .left, .right => null,
        };
    }

    fn resizeSplitFallback(self: *App, target: apprt.Target, value: apprt.action.ResizeSplit) !bool {
        const surface = self.findSurfaceForTarget(target) orelse return false;
        const found = self.findTabForSurface(surface) orelse return false;
        const handle = found.tab.findHandle(surface) orelse found.tab.focused;
        const layout: SplitTreeSurface.Split.Layout = switch (value.direction) {
            .left, .right => .horizontal,
            .up, .down => .vertical,
        };
        const delta_sign: f16 = switch (value.direction) {
            .left, .up => -1,
            .right, .down => 1,
        };
        const delta = std.math.clamp((@as(f16, @floatFromInt(value.amount)) / 100.0) * delta_sign, -1, 1);
        const next_tree = try found.tab.tree.resize(self.core_app.alloc, handle, layout, delta);
        if (splitTreeEquivalent(&found.tab.tree, &next_tree)) {
            var unchanged = next_tree;
            unchanged.deinit();
            return false;
        }
        found.tab.clearRedoHistory();
        found.host.clearStructuralHistory(.normal);
        found.tab.tree.deinit();
        found.tab.tree = next_tree;
        try found.host.layout();
        return true;
    }

    fn equalizeSplitsFallback(self: *App, target: apprt.Target) !bool {
        const surface = self.findSurfaceForTarget(target) orelse return false;
        const found = self.findTabForSurface(surface) orelse return false;
        const next_tree = try found.tab.tree.equalize(self.core_app.alloc);
        if (splitTreeEquivalent(&found.tab.tree, &next_tree)) {
            var unchanged = next_tree;
            unchanged.deinit();
            return false;
        }
        found.tab.clearRedoHistory();
        found.host.clearStructuralHistory(.normal);
        found.tab.tree.deinit();
        found.tab.tree = next_tree;
        try found.host.layout();
        return true;
    }

    fn closeTab(self: *App, target: apprt.Target, mode: apprt.action.CloseTabMode) !bool {
        const current = self.findSurfaceForTarget(target) orelse return false;
        const found = self.findTabForSurface(current) orelse return false;
        const host = found.host;
        const current_idx = found.index;

        switch (mode) {
            .this => {
                const entry = host.detachTabForUndo(current_idx) orelse return false;
                const stored_entry = host.pushStructuralUndo(entry) catch |err| {
                    log.warn("close_tab undo snapshot failed err={}", .{err});
                    var failed = entry;
                    errdefer failed.dispose(host, .normal);
                    _ = try host.restoreClosedTabEntry(&failed.payload.close_tab);
                    if (host.activeSurface()) |restored| self.activateSurface(restored);
                    return err;
                };
                if (stored_entry.payload.close_tab.tab) |*tab| tab.clearRedoHistory();
                if (host.activeSurface()) |replacement| {
                    self.activateSurface(replacement);
                } else {
                    host.refocusHostWindow();
                    host.layout() catch {};
                    host.refreshChrome() catch {};
                    host.setBanner(.info, "Tab closed. Use undo to restore it.") catch {};
                }
                return true;
            },

            .other => {
                if (host.tabs.items.len <= 1) return false;
                found.tab.clearRedoHistory();
                host.clearStructuralHistory(.normal);
                var closed = false;
                var i = host.tabs.items.len;
                while (i > 0) {
                    i -= 1;
                    if (i == current_idx) continue;
                    var it = host.tabs.items[i].tree.iterator();
                    while (it.next()) |entry| entry.view.close(false);
                    closed = true;
                }
                if (closed) self.activateSurface(current);
                return closed;
            },

            .right => {
                if (current_idx + 1 >= host.tabs.items.len) return false;
                found.tab.clearRedoHistory();
                host.clearStructuralHistory(.normal);
                var closed = false;
                var i = host.tabs.items.len;
                while (i > current_idx + 1) {
                    i -= 1;
                    var it = host.tabs.items[i].tree.iterator();
                    while (it.next()) |entry| entry.view.close(false);
                    closed = true;
                }
                if (closed) self.activateSurface(current);
                return closed;
            },
        }
    }

    fn gotoTab(self: *App, target: apprt.Target, goto: apprt.action.GotoTab) !bool {
        if (self.windows.items.len == 0) return false;
        const current = self.findSurfaceForTarget(target) orelse self.windows.items[0];
        const found = self.findTabForSurface(current) orelse return false;
        const desired = desiredTabIndex(found.host.tabs.items.len, found.index, goto) orelse return false;
        const current_idx = found.index;
        if (desired == current_idx) return false;
        const tab = &found.host.tabs.items[desired];
        const surface = tab.focusedSurface() orelse return false;
        self.activateSurface(surface);
        return true;
    }

    fn moveTab(self: *App, target: apprt.Target, move: apprt.action.MoveTab) !bool {
        if (self.windows.items.len <= 1 or move.amount == 0) return false;
        const current = self.findSurfaceForTarget(target) orelse return false;
        const found = self.findTabForSurface(current) orelse return false;
        if (found.host.tabs.items.len <= 1) return false;
        const current_idx = found.index;
        const desired = desiredMoveIndex(found.host.tabs.items.len, current_idx, move.amount) orelse return false;
        if (desired == current_idx) return false;
        found.tab.clearRedoHistory();
        found.host.clearStructuralHistory(.normal);
        const tab = found.host.tabs.orderedRemove(current_idx);
        try found.host.tabs.insert(self.core_app.alloc, desired, tab);
        found.host.active_tab = desired;
        const surface = found.host.tabs.items[desired].focusedSurface() orelse return false;
        self.activateSurface(surface);
        return true;
    }

    fn quickTerminalSurface(self: *App) ?*Surface {
        for (self.windows.items) |surface| {
            if (surface.quick_terminal) return surface;
        }
        return null;
    }

    fn toggleQuickTerminal(self: *App) !void {
        // `quick-terminal-keyboard-interactivity`:
        //   * on-demand → show + focus (our `.present()` path)
        //   * exclusive → show + focus (no global input grab)
        //   * none      → show WITHOUT stealing focus; the window
        //                 becomes a visible passive log / reference
        //                 the user can glance at without losing their
        //                 typing context.
        // The snapshot + branch below centralises the focus-or-not
        // decision so both the reuse path and the create path honour
        // the config.
        const want_focus = switch (self.config.@"quick-terminal-keyboard-interactivity") {
            .@"on-demand", .exclusive => true,
            .none => false,
        };

        if (self.quickTerminalSurface()) |surface| {
            // The quick terminal is a child surface inside a real
            // top-level host window. Visibility + geometry must be
            // applied to the HOST hwnd (the outer frame); the child
            // surface HWND is only the GL content area. Using the
            // child hwnd would leave an empty host window on screen
            // when hidden, and would run `MonitorFromWindow` /
            // `SetWindowPos` against the wrong target when showing.
            const top_level = surface.windowHwnd() orelse return;
            const visible = IsWindowVisible(top_level) != 0;
            if (visible) {
                // Raw `ShowWindow(SW_HIDE)` on the top-level HWND
                // is not enough — the child Surface still tracks
                // `window_visible = true` and keeps the renderer
                // thread waking, and `core_surface.occlusionCallback`
                // never fires. Per AGENTS.md 2026-04-14, that can
                // crash the WGL/NVIDIA present path. Route through
                // `setVisible` which: updates `window_visible`,
                // hides via `applyChildVisibility`, and calls
                // `occlusionCallback(false)`. The outer top-level
                // HWND is separately hidden below.
                surface.setVisible(false);
                _ = ShowWindow(top_level, SW_HIDE);
            } else {
                self.windows_hidden = false;
                self.applyQuickTerminalGeometry(top_level) catch |err| {
                    std.log.warn("QT geometry failed err={}", .{err});
                };
                _ = ShowWindow(
                    top_level,
                    if (want_focus) SW_SHOW else SW_SHOWNOACTIVATE,
                );
                // Mirror the hide-side invariant: tell the surface
                // it's visible so the renderer wakes and the
                // occlusion callback flips back to "not occluded".
                surface.setVisible(true);
                if (want_focus) surface.present();
            }
            return;
        }

        var config = try apprt.surface.newConfig(
            self.core_app,
            &self.config,
            .window,
        );
        defer config.deinit();
        const surface = try self.createWindowSurface(&config, quick_terminal_title, .{
            .quick_terminal = true,
            // Passive first-show: `createHost` uses `SW_SHOWNOACTIVATE`
            // so the new HWND appears without taking focus. Without
            // this, the very first toggle-on with
            // `keyboard-interactivity = none` would still activate
            // the window even though the later `present()` call is
            // skipped.
            .passive_show = !want_focus,
        });
        try surface.setFloatWindow(.on);
        if (surface.windowHwnd()) |top_level| {
            self.applyQuickTerminalGeometry(top_level) catch |err| {
                std.log.warn("QT geometry failed err={}", .{err});
            };
        }
        if (want_focus) surface.present();
    }

    /// Resolve the 7 `quick-terminal-*` config fields into a concrete
    /// end rect via `win32_quick_terminal` and apply it immediately
    /// with `SetWindowPos`.
    fn applyQuickTerminalGeometry(self: *App, hwnd: HWND) !void {
        const qt_cfg = win32_quick_terminal.QuickTerminalConfig{
            .position = switch (self.config.@"quick-terminal-position") {
                .top => .top,
                .bottom => .bottom,
                .left => .left,
                .right => .right,
                .center => .center,
            },
            .size = sizeFromConfig(self.config.@"quick-terminal-size"),
            .size_secondary = sizeSecondaryFromConfig(self.config.@"quick-terminal-size"),
            .screen = switch (self.config.@"quick-terminal-screen") {
                .main => .main,
                // `mouse` config value → our module's `.focused` semantic:
                // pick the monitor containing the current input focus /
                // cursor. Matches the documented config intent.
                .mouse => .focused,
            },
            .animation_duration_s = self.config.@"quick-terminal-animation-duration",
            .autohide = self.config.@"quick-terminal-autohide",
            .space_behavior = switch (self.config.@"quick-terminal-space-behavior") {
                .move => .move,
                // `remain` config value → our module's `.ignore`:
                // don't follow virtual-desktop changes.
                .remain => .ignore,
            },
            .keyboard_interactivity = switch (self.config.@"quick-terminal-keyboard-interactivity") {
                .@"on-demand" => .on_demand,
                .exclusive => .always,
                .none => .never,
            },
        };

        // Resolve monitor per the config's documented semantic:
        //   * `.main`   → the OS PRIMARY monitor, regardless of
        //                 where this window last was. Uses
        //                 `MonitorFromPoint({0,0}, MONITOR_DEFAULTTOPRIMARY)`;
        //                 the primary monitor's work-area always
        //                 contains origin. `MonitorFromWindow(hwnd)`
        //                 would return the window's current
        //                 monitor, which re-selects whatever
        //                 display the QT last landed on — wrong
        //                 semantic.
        //   * `.focused` (config's `mouse`) → the monitor under
        //                 the cursor via `GetCursorPos` +
        //                 `MonitorFromPoint(MONITOR_DEFAULTTONEAREST)`.
        //   * `.all`    → caller's current monitor; the current path
        //                 does not span the virtual desktop.
        const monitor = switch (qt_cfg.screen) {
            .focused => blk: {
                var pt: POINT = .{ .x = 0, .y = 0 };
                if (GetCursorPos(&pt) == 0) {
                    break :blk MonitorFromWindow(hwnd, MONITOR_DEFAULTTONEAREST) orelse
                        return error.MonitorLookupFailed;
                }
                break :blk MonitorFromPoint(pt, MONITOR_DEFAULTTONEAREST) orelse
                    return error.MonitorLookupFailed;
            },
            .main => MonitorFromPoint(.{ .x = 0, .y = 0 }, MONITOR_DEFAULTTOPRIMARY) orelse
                return error.MonitorLookupFailed,
            .all => MonitorFromWindow(hwnd, MONITOR_DEFAULTTONEAREST) orelse
                return error.MonitorLookupFailed,
        };
        var info: MONITORINFO = .{
            .cbSize = @sizeOf(MONITORINFO),
            .rcMonitor = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
            .rcWork = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
            .dwFlags = 0,
        };
        if (GetMonitorInfoW(monitor, &info) == 0) return error.MonitorInfoFailed;

        const mi = win32_quick_terminal.MonitorInfo{
            .work_area = .{
                .left = info.rcWork.left,
                .top = info.rcWork.top,
                .right = info.rcWork.right,
                .bottom = info.rcWork.bottom,
            },
            .full_rect = .{
                .left = info.rcMonitor.left,
                .top = info.rcMonitor.top,
                .right = info.rcMonitor.right,
                .bottom = info.rcMonitor.bottom,
            },
        };

        const end = win32_quick_terminal.computeEndRect(qt_cfg, mi);
        _ = SetWindowPos(
            hwnd,
            HWND_TOPMOST,
            end.left,
            end.top,
            end.right - end.left,
            end.bottom - end.top,
            SWP_NOACTIVATE,
        );
    }

    fn showOnScreenKeyboard(self: *App) !void {
        const osk_w = try std.unicode.utf8ToUtf16LeAllocZ(self.core_app.alloc, "osk.exe");
        defer self.core_app.alloc.free(osk_w);
        const result = ShellExecuteW(null, shell_open, osk_w.ptr, null, null, SW_SHOW);
        if (@intFromPtr(result) <= 32) return error.OpenUrlFailed;
    }

    fn destroyAllWindows(self: *App) void {
        while (self.hosts.items.len > 0) {
            const host = self.hosts.items[self.hosts.items.len - 1];
            const hwnd = host.hwnd orelse {
                self.removeHost(host);
                continue;
            };
            host.clearStructuralHistory(.normal);
            _ = DestroyWindow(hwnd);
        }
    }

    fn sanitizeCurrentDirectory(self: *App) !void {
        const cwd = std.process.getCwdAlloc(self.core_app.alloc) catch null;
        defer if (cwd) |v| self.core_app.alloc.free(v);

        if (cwd) |v| {
            if (isSafeStartupCwd(v)) return;
            log.warn("win32 current directory is unsafe, resetting cwd={s}", .{v});
        } else {
            log.warn("win32 current directory unavailable, resetting to profile", .{});
        }

        var buf: [std.fs.max_path_bytes]u8 = undefined;
        const profile = (try internal_os.windows.knownFolderPathUtf8(
            &internal_os.windows.FOLDERID_Profile,
            &buf,
        )) orelse return error.NoHomeDir;
        const profile_w = try std.unicode.utf8ToUtf16LeAllocZ(self.core_app.alloc, profile);
        defer self.core_app.alloc.free(profile_w);

        if (SetCurrentDirectoryW(profile_w.ptr) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        log.debug("win32 current directory reset cwd={s}", .{profile});
    }

    fn clientSize(self: *App, hwnd: HWND) !apprt.SurfaceSize {
        _ = self;
        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        return .{
            .width = @max(0, rect.right - rect.left),
            .height = @max(0, rect.bottom - rect.top),
        };
    }

    fn resolveSurfaceSizeWithContext(
        ctx: anytype,
        fallback: apprt.SurfaceSize,
        hwnd: ?HWND,
        client_size_fn: anytype,
    ) !apprt.SurfaceSize {
        const live_hwnd = hwnd orelse return fallback;
        return try client_size_fn(ctx, live_hwnd);
    }

    fn defaultPixelFormatDescriptor() PIXELFORMATDESCRIPTOR {
        return .{
            .nSize = @sizeOf(PIXELFORMATDESCRIPTOR),
            .nVersion = 1,
            .dwFlags = PFD_DRAW_TO_WINDOW | PFD_SUPPORT_OPENGL | PFD_DOUBLEBUFFER,
            .iPixelType = PFD_TYPE_RGBA,
            .cColorBits = 32,
            .cRedBits = 0,
            .cRedShift = 0,
            .cGreenBits = 0,
            .cGreenShift = 0,
            .cBlueBits = 0,
            .cBlueShift = 0,
            .cAlphaBits = 8,
            .cAlphaShift = 0,
            .cAccumBits = 0,
            .cAccumRedBits = 0,
            .cAccumGreenBits = 0,
            .cAccumBlueBits = 0,
            .cAccumAlphaBits = 0,
            .cDepthBits = 24,
            .cStencilBits = 8,
            .cAuxBuffers = 0,
            .iLayerType = PFD_MAIN_PLANE,
            .bReserved = 0,
            .dwLayerMask = 0,
            .dwVisibleMask = 0,
            .dwDamageMask = 0,
        };
    }

    fn createGLContext(self: *App, hwnd: HWND) !struct { hdc: HDC, hglrc: HGLRC } {
        _ = self;

        const hdc = GetDC(hwnd) orelse return error.GetDCFailed;
        errdefer _ = ReleaseDC(hwnd, hdc);

        const pfd = defaultPixelFormatDescriptor();
        const pixel_format = ChoosePixelFormat(hdc, &pfd);
        if (pixel_format == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        if (SetPixelFormat(hdc, pixel_format, &pfd) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        const hglrc = wglCreateContext(hdc) orelse
            return windows.unexpectedError(windows.kernel32.GetLastError());
        errdefer _ = wglDeleteContext(hglrc);

        if (wglMakeCurrent(hdc, hglrc) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        return .{ .hdc = hdc, .hglrc = hglrc };
    }

    fn openUrl(self: *App, url: []const u8) !void {
        const url_w = try std.unicode.utf8ToUtf16LeAllocZ(self.core_app.alloc, url);
        defer self.core_app.alloc.free(url_w);

        const result = ShellExecuteW(null, shell_open, url_w.ptr, null, null, SW_SHOW);
        if (@intFromPtr(result) <= 32) return error.OpenUrlFailed;
    }

    fn openConfig(self: *App) !void {
        // Route to the in-app settings window. Users who prefer a text
        // editor can still reach `config.ghostty` via the Advanced
        // section's "Open in default editor" button.
        //
        // Fallback: if the settings window can't be brought up (e.g.
        // headless / service session with no desktop, `CreateWindowExW`
        // refusing window creation, etc.), fall back to the legacy
        // shell-out path so `open_config` never becomes a dead action.
        // Skipping the fallback would regress CI / sandboxed flows
        // that previously worked.
        self.settings_window.open() catch |err| {
            std.log.warn("settings window unavailable (err={}); falling back to editor", .{err});
            try self.openConfigInEditor();
        };
    }

    /// Serialise `pending` into a temp file adjacent to the target,
    /// then atomic-rename via `ReplaceFileW` (falls back to
    /// `MoveFileExW` when the target is new). Finally re-load the
    /// config from disk and push it through `CoreApp.updateConfig`
    /// so every surface picks up the change on its next repaint.
    ///
    /// Returns on error; caller (settings window) is responsible for
    /// surfacing the failure. `pending` is borrowed, not consumed —
    /// the caller still owns its arena.
    fn settingsSaveAndReload(self: *App, pending: *const configpkg.Config, original: *const configpkg.Config) win32_settings.SaveError!void {
        const alloc = self.core_app.alloc;

        // Target file selection:
        //   1. If the process was started with `--config-file <path>`
        //      on the CLI, write to THAT file. Writing to the default
        //      `ghostty.conf` when the user explicitly specified a
        //      custom config would either edit the wrong file or let
        //      the CLI-provided config mask the saved value on reload.
        //   2. Otherwise, fall back to the per-user default path
        //      (`config_edit.openPath`), which also handles the
        //      first-run "create the file" case.
        const target_path = blk: {
            // Use the startup-time resolved override — never call
            // `cliConfigFileOverride` from here, because cwd may have
            // been reset by `sanitizeCurrentDirectory` and a relative
            // CLI path would resolve to the wrong absolute file.
            if (self.cli_config_override_path) |cli_path| break :blk try alloc.dupe(u8, cli_path);
            break :blk config_edit.openPath(alloc) catch return error.PathResolveFailed;
        };
        defer alloc.free(target_path);

        const tmp_path = try std.fmt.allocPrint(alloc, "{s}.tmp", .{target_path});
        defer alloc.free(tmp_path);

        // Build a file-only baseline: `Config.default()` merged with
        // `loadDefaultFiles()` but WITHOUT `loadCliArgs()` or
        // `loadRecursiveFiles()`. This avoids three previously
        // shipping-day bugs:
        //   1. `-e`, `--working-directory`, `--class` and similar CLI
        //      overrides from the current process launch would bake
        //      into `ghostty.conf` the first time the user saved
        //      (`Config.load()` already applied them to `pending`).
        //   2. `config-file` includes would get flattened into the
        //      primary file, leaving duplicate directives that fight
        //      each other on the next reload.
        //   3. Future new CLI-only flags would silently persist.
        //
        // Then copy every field the GUI user actually edited from
        // `pending` into `file_cfg`, and use that as the source for
        // patching the raw target file. The raw-text patcher below
        // preserves comments, formatting, relative include paths, and
        // unrelated fields.
        //
        // Field types we currently support as GUI edits are all value
        // types (bool, int, float, enum, packed struct, tagged union
        // with no pointer variants). Assigning via `@field` is a
        // shallow bit-copy and is safe without arena-transfer. Any
        // GUI-exposed pointer field (string / slice) needs an explicit
        // string-dupe branch here.
        var file_cfg = configpkg.Config.default(alloc) catch return error.SerializeFailed;
        defer file_cfg.deinit();
        // Seed the baseline from the ACTUAL target file, not the
        // per-user default search path. When launched with
        // `--config-file custom.conf`, `target_path` resolves to
        // `custom.conf` (see `cliConfigFileOverride`), and we must
        // load THAT file — loading `loadDefaultFiles` would write
        // back a merge of `ghostty.conf` defaults + GUI edits into
        // the custom file, dropping every key that existed only in
        // the custom file.
        //
        // `loadFile` accepts an absolute path and merges its
        // contents on top of `file_cfg` (already `default()`), so
        // we get: defaults + target-file overrides, then the GUI
        // edits patched on top below. If the target file doesn't
        // exist yet (first-save case), `loadFile` returns early
        // with a warn; `file_cfg` stays at defaults, which is the
        // intended behaviour.
        blk: {
            const path_abs = std.fs.realpathAlloc(alloc, target_path) catch |err| {
                if (err == error.FileNotFound) break :blk;
                // Other real-path errors (permission denied, not-a-
                // dir) leave us with the default-only baseline; log
                // and proceed rather than erroring the save.
                std.log.warn("settings: couldn't realpath target_path err={}; using default baseline", .{err});
                break :blk;
            };
            defer alloc.free(path_abs);
            file_cfg.loadFile(alloc, path_abs) catch |err| {
                std.log.warn("settings: loadFile on target failed err={}; using default baseline", .{err});
            };
        }

        const ConfigKey = @import("../config/key.zig").Key;
        // Diff pending against `original` (the snapshot from when
        // the settings window opened), NOT against the live
        // `self.config`. Otherwise a concurrent `reload_config` or
        // external file edit that happens while the window is open
        // would cause this save to silently revert the newer values
        // for every GUI-exposed field whose stale draft differs
        // from the refreshed runtime config.
        // Determine which fields the GUI user explicitly edited so
        // we can force-emit them below even when they happen to
        // equal `Config.default()`. Without this, resetting an
        // included `config-file`'s override back to the stock
        // default in Settings would NOT stick — FileFormatter's
        // default-drop would strip the reset line, and the include
        // would re-apply its non-default value on next reload.
        var user_edited: std.StaticBitSet(std.enums.values(ConfigKey).len) = .initEmpty();
        var any_edit = false;
        inline for (@typeInfo(configpkg.Config).@"struct".fields) |field| {
            if (field.name[0] == '_') continue;
            switch (@typeInfo(field.type)) {
                .bool, .int, .float, .@"enum", .@"struct", .@"union" => {
                    const key = @field(ConfigKey, field.name);
                    if (original.changed(pending, key)) {
                        @field(file_cfg, field.name) = @field(pending, field.name);
                        user_edited.set(@intFromEnum(key));
                        any_edit = true;
                    }
                },
                else => {}, // skip pointer / optional-pointer / array fields
            }
        }
        // No-op short-circuit: if the user pressed Save without
        // changing anything, don't touch the filesystem. On a
        // first-run machine with no existing config file, the write
        // would otherwise create a zero-byte file that then fires
        // `error.FileIsEmpty` warnings on every subsequent load.
        // On an existing file, skipping also avoids an unnecessary
        // mtime bump.
        if (!any_edit) return;

        // SURGICAL SAVE: read the raw target file text and patch
        // only GUI-edited field lines in place. This preserves
        // (a) comments, (b) relative `config-file` paths (not
        // canonicalised), (c) the user's formatting / blank lines,
        // (d) fields we can't round-trip through the Config type
        // (RepeatableString, etc).
        //
        // For each GUI-edited field: scan the raw text for a line
        // matching `^<key> =` at column 0 (PLUS optional leading
        // whitespace) and replace the WHOLE line with the new
        // serialised `key = value` emission. If no matching line
        // exists, append to the file end.
        //
        // For fields NOT on disk but in `file_cfg` non-default
        // (first-save case with no prior file content), emit them
        // after the preserved content. `file_cfg` retains this
        // information because `loadFile` already applied the
        // target file; subtracting the raw-text lines from what
        // `file_cfg` holds tells us what needs appending.
        const raw_before: []u8 = blk: {
            const f = std.fs.cwd().openFile(target_path, .{}) catch |err| switch (err) {
                error.FileNotFound => break :blk try alloc.dupe(u8, ""),
                else => return error.SerializeFailed,
            };
            defer f.close();
            const stat = f.stat() catch return error.SerializeFailed;
            const size = @min(stat.size, 16 * 1024 * 1024);
            const slice = alloc.alloc(u8, @intCast(size)) catch return error.OutOfMemory;
            errdefer alloc.free(slice);
            const n = f.readAll(slice) catch return error.SerializeFailed;
            break :blk try alloc.realloc(slice, n);
        };
        defer alloc.free(raw_before);

        var patched: std.ArrayListUnmanaged(u8) = .{};
        defer patched.deinit(alloc);
        patchOrAppendEdits(
            alloc,
            raw_before,
            pending,
            user_edited,
            &patched,
        ) catch return error.SerializeFailed;

        // Ensure target's parent directory exists. `config_edit.openPath`
        // creates `%APPDATA%\ghostty\` for the default path, but a user
        // launched with `--config-file D:\new-dir\custom.conf` could
        // target a directory that has never been created. Without this
        // step the first Save against that path would fail here with
        // `TempCreateFailed`.
        if (std.fs.path.dirname(target_path)) |parent| {
            std.fs.cwd().makePath(parent) catch |err| {
                std.log.warn("settings save: couldn't create parent dir path={s} err={}", .{ parent, err });
                return error.TempCreateFailed;
            };
        }

        // Write to the sibling temp file, close, then rename. Scoped
        // block so the file is closed BEFORE ReplaceFileW — Windows
        // blocks the replace while the temp handle is open.
        {
            const tmp = std.fs.cwd().createFile(tmp_path, .{}) catch return error.TempCreateFailed;
            defer tmp.close();
            var write_buf: [4096]u8 = undefined;
            var fw = tmp.writer(&write_buf);
            fw.interface.writeAll(patched.items) catch return error.SerializeFailed;
            fw.interface.flush() catch return error.SerializeFailed;
        }

        const target_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, target_path) catch return error.OutOfMemory;
        defer alloc.free(target_w);
        const tmp_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, tmp_path) catch return error.OutOfMemory;
        defer alloc.free(tmp_w);

        if (ReplaceFileW(target_w, tmp_w, null, 0, null, null) == 0) {
            // Likely ERROR_FILE_NOT_FOUND if the user didn't have a
            // config file yet. Fall back to MoveFileExW.
            if (MoveFileExW(tmp_w, target_w, MOVEFILE_REPLACE_EXISTING) == 0) {
                std.fs.cwd().deleteFile(tmp_path) catch {};
                return error.ReplaceFailed;
            }
        }

        // Mirror the `.reload_config` hard-reload path at win32.zig
        // line ~2106: re-read from disk + push through CoreApp so
        // every surface's next frame picks up the new values.
        //
        // Temporarily restore the startup cwd around `Config.load`.
        // `loadCliArgs` resolves relative `--config-file` argv entries
        // via realpath-against-cwd; after `sanitizeCurrentDirectory()`
        // ran, cwd is typically `%USERPROFILE%`, and a user who
        // launched with `--config-file custom.conf` would see the
        // reload pick up `%USERPROFILE%\custom.conf` instead of the
        // file we just wrote. Save lands correctly, but the live
        // config would immediately diverge from disk — "my edits
        // didn't take effect until restart" is exactly this bug.
        // Capture the current (sanitized) cwd so we can restore it
        // after the reload. Leaking a cwd change into the rest of
        // process lifetime would change where other code resolves
        // relative paths — for example, a subsequent surface spawn
        // could inherit the wrong working directory.
        const cwd_before: ?[]u8 = std.process.getCwdAlloc(alloc) catch null;
        defer if (cwd_before) |p| alloc.free(p);

        // `defer` (NOT inline restore) for the cwd rollback so BOTH the
        // happy path AND the `ReloadFailed` error path run it. Earlier
        // code had `Config.load catch return error.ReloadFailed`
        // followed by an inline restore; the return short-circuited
        // the restore, leaving the process pinned to `startup_cwd`
        // whenever a reload hit a broken config file. Downstream
        // surface spawns then inherited the wrong cwd until restart.
        var did_chdir_to_startup: bool = false;
        if (self.startup_cwd) |cwd| {
            std.fs.cwd().makePath(cwd) catch {}; // no-op if exists
            if (std.process.changeCurDir(cwd)) |_| {
                did_chdir_to_startup = true;
            } else |err| {
                std.log.warn("settings save: couldn't restore startup cwd path={s} err={}", .{ cwd, err });
            }
        }
        defer {
            if (did_chdir_to_startup) {
                if (cwd_before) |cwd| {
                    std.process.changeCurDir(cwd) catch |err| {
                        std.log.warn("settings save: couldn't restore sanitized cwd path={s} err={}", .{ cwd, err });
                    };
                }
            }
        }

        var reloaded = configpkg.Config.load(alloc) catch return error.ReloadFailed;
        defer reloaded.deinit();

        // Post-save validation: detect fields the user GUI-edited
        // whose persisted value gets MASKED by a later layer on
        // reload (included `config-file` + subsequent CLI
        // `--config-file` flag + `--config-default-files=false`).
        // The persisted-on-disk value is correct, but the effective
        // runtime value doesn't match. Track whether ANY field is
        // masked so we can return a distinct error variant; the
        // settings-window caller surfaces this differently from a
        // generic write failure.
        var any_masked = false;
        inline for (@typeInfo(configpkg.Config).@"struct".fields) |field| {
            if (field.name[0] == '_') continue;
            switch (@typeInfo(field.type)) {
                .bool, .int, .float, .@"enum", .@"struct", .@"union" => {
                    const key = @field(ConfigKey, field.name);
                    if (user_edited.isSet(@intFromEnum(key))) {
                        if (pending.changed(&reloaded, key)) {
                            std.log.warn(
                                "settings save: field '{s}' was saved but is masked by a later config-file layer; the effective value after reload differs",
                                .{field.name},
                            );
                            any_masked = true;
                        }
                    }
                },
                else => {},
            }
        }

        self.core_app.updateConfig(self, &reloaded) catch return error.ReloadFailed;
        if (any_masked) return error.SavedButMasked;
    }

    /// The legacy `ShellExecuteW` path. Kept alive for Advanced pane
    /// consumption and for users running `open_config` on CI / headless
    /// runs where the settings window is unreachable.
    fn openConfigInEditor(self: *App) !void {
        // If the process was launched with `--config-file <path>`,
        // that file is the one we Save to from the Settings UI and
        // the one that masks the per-user default on reload. Opening
        // the per-user default from the escape-hatch would let the
        // user edit a file they'd then see no effect from (the CLI
        // override still masks it), so route to the same file the
        // Save path targets.
        const path = blk: {
            if (self.cli_config_override_path) |cli_path|
                break :blk try self.core_app.alloc.dupe(u8, cli_path);
            break :blk try config_edit.openPath(self.core_app.alloc);
        };
        defer self.core_app.alloc.free(path);
        try self.openUrl(path);
    }

    fn ringBell(self: *App, target: apprt.Target) void {
        _ = self;
        _ = target;
        _ = MessageBeep(MB_ICONINFORMATION);
    }

    fn showDesktopNotificationWithLaunch(
        self: *App,
        target: apprt.Target,
        title: []const u8,
        body: []const u8,
        launch: ?[]const u8,
    ) !void {
        const caption = if (title.len > 0) title else "winghostty";
        const message = if (title.len > 0 and !std.mem.eql(u8, title, "winghostty"))
            try std.fmt.allocPrint(self.core_app.alloc, "{s}: {s}", .{ caption, body })
        else
            try self.core_app.alloc.dupe(u8, body);
        defer self.core_app.alloc.free(message);

        // Primary path: Action Center toast via WinRT. This persists
        // in Action Center history and surfaces system-level badging.
        // On success we SKIP the in-app banner — showing both would
        // double-notify on the same event. Any show error (Focus
        // Assist, notifications disabled, runtime unavailable) falls
        // back to the banner so the user still gets feedback.
        if (self.winrt_toast) |*toast| {
            const result = if (launch) |value|
                toast.showWithLaunch(caption, body, .info, value)
            else
                toast.show(caption, body, .info);
            if (result) |_| {
                return;
            } else |err| {
                std.log.warn("winrt toast show failed err={}; falling back to banner", .{err});
            }
        }

        if (try self.showHostBanner(target, .info, message)) return;
        // Final local fallback: pass the composed `message` as the body so
        // notifications with an empty `body` (e.g. settings-save
        // success, where title alone carries the signal) still render
        // something readable.
        try self.showInfoMessage(target, caption, message);
    }

    fn showDesktopNotification(
        self: *App,
        target: apprt.Target,
        title: [:0]const u8,
        body: [:0]const u8,
    ) !void {
        try self.showDesktopNotificationWithLaunch(target, title, body, null);
    }

    fn showChildExited(
        self: *App,
        target: apprt.Target,
        exited: apprt.surface.Message.ChildExited,
    ) !void {
        const seconds = @as(f64, @floatFromInt(exited.runtime_ms)) / @as(f64, std.time.ms_per_s);
        const message = try std.fmt.allocPrint(
            self.core_app.alloc,
            "Child exited with code {d} | Runtime: {d:.2}s",
            .{ exited.exit_code, seconds },
        );
        defer self.core_app.alloc.free(message);
        if (try self.showHostBanner(target, .info, message)) return;
        try self.showInfoMessage(target, "winghostty", message);
    }

    const CommandFinishPlan = struct {
        bell: bool = false,
        notify: bool = false,

        fn any(self: CommandFinishPlan) bool {
            return self.bell or self.notify;
        }
    };

    fn commandFinishPlan(
        notify_on_command_finish: configpkg.Config.NotifyOnCommandFinish,
        notify_on_command_finish_action: configpkg.Config.NotifyOnCommandFinishAction,
        desktop_notifications: bool,
        notify_on_command_finish_after: configpkg.Config.Duration,
        is_focused: bool,
        duration: configpkg.Config.Duration,
    ) CommandFinishPlan {
        if (duration.duration < notify_on_command_finish_after.duration) return .{};

        const allow = switch (notify_on_command_finish) {
            .never => false,
            .always => true,
            .unfocused => !is_focused,
        };
        if (!allow) return .{};

        return .{
            .bell = notify_on_command_finish_action.bell,
            .notify = notify_on_command_finish_action.notify and desktop_notifications,
        };
    }

    fn showCommandFinished(
        self: *App,
        target: apprt.Target,
        finished: apprt.action.CommandFinished,
    ) !void {
        const surface = self.findSurfaceForTarget(target) orelse return;
        const config = &surface.core().config;
        const plan = commandFinishPlan(
            config.notify_on_command_finish,
            config.notify_on_command_finish_action,
            config.desktop_notifications,
            config.notify_on_command_finish_after,
            self.isSurfaceFocused(surface),
            finished.duration,
        );
        if (!plan.any()) return;

        if (plan.bell) self.ringBell(target);
        if (!plan.notify) return;

        const seconds = @as(f64, @floatFromInt(finished.duration.duration)) / @as(f64, std.time.ns_per_s);
        const body = if (finished.exit_code) |code|
            try std.fmt.allocPrint(
                self.core_app.alloc,
                "Command finished with exit code {d} | Runtime: {d:.2}s",
                .{ code, seconds },
            )
        else
            try std.fmt.allocPrint(
                self.core_app.alloc,
                "Command finished | Runtime: {d:.2}s",
                .{seconds},
            );
        defer self.core_app.alloc.free(body);

        const launch = try buildToastLaunchForSurface(self.core_app.alloc, surface);
        defer self.core_app.alloc.free(launch);
        try self.showDesktopNotificationWithLaunch(target, "Command finished", body, launch);
    }

    fn isSurfaceFocused(self: *App, surface: *Surface) bool {
        return self.core_app.focused and
            surface.host_active and
            surface.window_focused and
            self.core_app.focusedSurface() == surface.core();
    }

    fn showInfoMessage(
        self: *App,
        target: apprt.Target,
        title: []const u8,
        message: []const u8,
    ) !void {
        _ = self;
        _ = target;
        // Final fallback for notification paths that cannot surface a
        // host banner. Keep failures observable without blocking the UI
        // thread.
        std.log.info("info notification (no visible target): {s} — {s}", .{ title, message });
    }

    fn showHostBanner(
        self: *App,
        target: apprt.Target,
        kind: HostBannerKind,
        message: []const u8,
    ) !bool {
        const surface = self.findSurfaceForTarget(target) orelse return false;
        const host = surface.host orelse return false;
        try host.setBanner(kind, message);
        return true;
    }
};

fn updateCheckThreadMain(request: *UpdateCheckRequest) void {
    const alloc = request.alloc;
    defer {
        request.deinit();
        alloc.destroy(request);
    }

    const completion = alloc.create(UpdateCheckCompletion) catch {
        return;
    };
    completion.* = .{ .alloc = alloc };
    errdefer {
        completion.deinit();
        alloc.destroy(completion);
    }

    const result = updatepkg.checkLatestStableRelease(alloc, request.state_path, .{
        .current_version = request.current_version,
        .force = request.force,
        .respect_dismissal = request.respect_dismissal,
    }) catch |err| {
        if (request.manual) {
            completion.manual_message = std.fmt.allocPrint(
                alloc,
                "Unable to check GitHub Releases right now ({s}).",
                .{@errorName(err)},
            ) catch null;
        }
        postUpdateCheckCompletion(request.ui_thread_id, completion);
        return;
    };
    defer {
        var owned = result;
        owned.deinit(alloc);
    }

    switch (result) {
        .update_available => |release| {
            const version_text = tryOrNull(alloc, release.version_text);
            const release_url = tryOrNull(alloc, release.release_url);
            if (version_text != null and release_url != null) {
                completion.release = .{
                    .version_text = version_text.?,
                    .release_url = release_url.?,
                };
            } else {
                if (version_text) |value| alloc.free(value);
                if (release_url) |value| alloc.free(value);
                completion.manual_message = if (request.manual)
                    std.fmt.allocPrint(
                        alloc,
                        "Unable to prepare the update notice for winghostty {s}.",
                        .{release.version_text},
                    ) catch null
                else
                    null;
            }
        },
        .up_to_date, .throttled => {
            if (request.manual) {
                completion.manual_message = std.fmt.allocPrint(
                    alloc,
                    "winghostty {s} is already current on the stable channel.",
                    .{request.current_version_string},
                ) catch null;
            }
        },
    }

    postUpdateCheckCompletion(request.ui_thread_id, completion);
}

fn tryOrNull(alloc: Allocator, text: []const u8) ?[]u8 {
    return alloc.dupe(u8, text) catch null;
}

fn postUpdateCheckCompletion(ui_thread_id: DWORD, completion: *UpdateCheckCompletion) void {
    if (PostThreadMessageW(
        ui_thread_id,
        WM_WINHOSTTY_UPDATE,
        0,
        @as(LPARAM, @bitCast(@as(usize, @intFromPtr(completion)))),
    ) == 0) {
        completion.deinit();
        completion.alloc.destroy(completion);
    }
}

fn winrtToastActivationCallback(ctx: *anyopaque, launch: []const u8) void {
    const self: *App = @ptrCast(@alignCast(ctx));
    const ui_thread_id = @atomicLoad(DWORD, &self.ui_thread_id, .acquire);
    if (ui_thread_id == 0) {
        std.log.warn("dropping winrt toast activation before ui thread id is available", .{});
        return;
    }

    const parsed = win32_toast_activation.parseLaunchArg(launch) catch |err| {
        std.log.warn("dropping malformed winrt toast activation launch err={}", .{err});
        return;
    };

    if (self.toast_activation_post_pending.swap(true, .acq_rel)) {
        std.log.warn("dropping winrt toast activation while another activation is queued", .{});
        return;
    }

    const activation = std.heap.page_allocator.create(win32_toast_activation.ActivationTarget) catch |err| {
        std.log.warn("dropping winrt toast activation allocation failed err={}", .{err});
        self.toast_activation_post_pending.store(false, .release);
        return;
    };
    activation.* = parsed;

    if (PostThreadMessageW(
        ui_thread_id,
        WM_WINHOSTTY_TOAST_ACTIVATION,
        0,
        @as(LPARAM, @bitCast(@as(usize, @intFromPtr(activation)))),
    ) == 0) {
        std.log.warn("dropping winrt toast activation post failed err={}", .{
            windows.kernel32.GetLastError(),
        });
        std.heap.page_allocator.destroy(activation);
        self.toast_activation_post_pending.store(false, .release);
    }
}

const SearchStatus = struct {
    active: bool = false,
    needle: ?[]const u8 = null,
    total: ?usize = null,
    selected: ?usize = null,
};

/// Which caption button (integrated titlebar) the cursor is hovering.
const CaptionButton = enum { none, minimize, maximize, close };

const TitlebarButtonRole = enum {
    none,
    minimize,
    maximize,
    close,
    new_tab,
    dropdown,
};

const TitlebarGlyphKind = enum {
    minimize,
    maximize,
    restore,
    close,
    new_tab,
    dropdown,
};

const titlebar_hover_fade_ms: u16 = 150;

const TitlebarHoverFade = struct {
    active: bool = false,
    started_ms: u64 = 0,
    duration_ms: u16 = 0,

    fn start(self: *TitlebarHoverFade, now_ms: u64, duration_ms: u16) void {
        self.* = .{
            .active = duration_ms > 0,
            .started_ms = now_ms,
            .duration_ms = duration_ms,
        };
    }

    fn alphaAt(self: TitlebarHoverFade, now_ms: u64) f32 {
        if (!self.active or self.duration_ms == 0) return 0.0;
        if (now_ms <= self.started_ms) return 1.0;
        const elapsed = now_ms - self.started_ms;
        if (elapsed >= self.duration_ms) return 0.0;
        const t = @as(f32, @floatFromInt(elapsed)) / @as(f32, @floatFromInt(self.duration_ms));
        return 1.0 - std.math.clamp(t, 0.0, 1.0);
    }

    fn animating(self: TitlebarHoverFade, now_ms: u64) bool {
        if (!self.active or self.duration_ms == 0) return false;
        if (now_ms <= self.started_ms) return true;
        return now_ms - self.started_ms < self.duration_ms;
    }
};

const TitlebarButtonVisual = struct {
    bg: ?u32 = null,
    glyph: u32,
};

fn titlebarGlyphCodepoint(kind: TitlebarGlyphKind) u16 {
    return switch (kind) {
        .minimize => 0xE921,
        .maximize => 0xE922,
        .restore => 0xE923,
        .close => 0xE8BB,
        .new_tab => 0xE710,
        .dropdown => 0xE70D,
    };
}

fn titlebarGlyphText(kind: TitlebarGlyphKind) [*:0]const u16 {
    return switch (kind) {
        .minimize => titlebar_glyph_minimize,
        .maximize => titlebar_glyph_maximize,
        .restore => titlebar_glyph_restore,
        .close => titlebar_glyph_close,
        .new_tab => titlebar_glyph_new_tab,
        .dropdown => titlebar_glyph_dropdown,
    };
}

fn titlebarFallbackIcon(kind: TitlebarGlyphKind) win32_icons.Kind {
    return switch (kind) {
        .minimize => .minimize,
        .maximize => .maximize,
        .restore => .restore,
        .close => .close,
        .new_tab => .plus,
        .dropdown => .arrow_down,
    };
}

fn titlebarRoleFromCaption(button: CaptionButton) TitlebarButtonRole {
    return switch (button) {
        .none => .none,
        .minimize => .minimize,
        .maximize => .maximize,
        .close => .close,
    };
}

fn titlebarCaptionFromHitTest(ht: i32) CaptionButton {
    return switch (ht) {
        HTMINBUTTON => .minimize,
        HTMAXBUTTON => .maximize,
        HTCLOSE => .close,
        else => .none,
    };
}

fn captionButtonSysCommand(ht: i32, is_zoomed: bool) ?WPARAM {
    return switch (ht) {
        HTMINBUTTON => SC_MINIMIZE,
        HTMAXBUTTON => if (is_zoomed) SC_RESTORE else SC_MAXIMIZE,
        else => null,
    };
}

fn titlebarSubtleFill(parent_bg: u32, is_dark: bool, pressed: bool) u32 {
    const overlay = if (is_dark) rgb(0xFF, 0xFF, 0xFF) else rgb(0x00, 0x00, 0x00);
    const alpha: f32 = if (pressed) 0.04 else 0.06;
    return blendColorRGB(parent_bg, overlay, alpha);
}

fn titlebarButtonVisual(
    theme: *const ThemeColors,
    role: TitlebarButtonRole,
    parent_bg: u32,
    hover_alpha: f32,
    pressed: bool,
    high_contrast: bool,
) TitlebarButtonVisual {
    const active = pressed or hover_alpha > 0.0;
    if (high_contrast) {
        return .{
            .bg = if (active) theme.button_active_bg else null,
            .glyph = if (active) theme.button_active_fg else theme.text_primary,
        };
    }

    const idle_glyph = switch (role) {
        .new_tab, .dropdown => theme.button_chrome_fg,
        else => theme.text_primary,
    };
    if (!active) return .{ .bg = null, .glyph = idle_glyph };

    const target_bg = switch (role) {
        .close => rgb(0xC4, 0x2B, 0x1C),
        .minimize, .maximize, .new_tab, .dropdown => titlebarSubtleFill(parent_bg, theme.is_dark, pressed),
        .none => parent_bg,
    };
    const target_glyph = switch (role) {
        .close => if (pressed) blendColorRGB(target_bg, rgb(0xFF, 0xFF, 0xFF), 0.70) else rgb(0xFF, 0xFF, 0xFF),
        .minimize, .maximize => theme.text_primary,
        .new_tab, .dropdown => theme.text_primary,
        .none => idle_glyph,
    };

    const alpha: f32 = if (pressed) 1.0 else std.math.clamp(hover_alpha, 0.0, 1.0);
    return .{
        .bg = blendColorRGB(parent_bg, target_bg, alpha),
        .glyph = blendColorRGB(idle_glyph, target_glyph, alpha),
    };
}

/// Deep-copy of one `apprt.ClipboardContent` entry so it can survive an
/// async confirm-overlay roundtrip. Freed via `PendingClipboardOp.deinit`.
const OwnedClipboardContent = struct {
    mime: [:0]u8,
    data: [:0]u8,
};

/// A clipboard operation awaiting user confirmation via
/// `HostOverlayMode.confirm`. The owning `Surface` dupes all caller
/// payload bytes into `core_app.alloc` when queuing the op so the
/// confirm overlay's async callback sees valid data regardless of when
/// the original caller's buffers go out of scope.
const PendingClipboardOp = union(enum) {
    /// Deferred paste. `request` tells the core path to complete once
    /// the user accepts; `data` is the duplicated payload.
    paste: struct {
        request: apprt.ClipboardRequest,
        data: [:0]u8,
    },
    /// Deferred clipboard write (one or more mime/data pairs).
    write: struct {
        clipboard: apprt.Clipboard,
        contents: []OwnedClipboardContent,
    },

    pub fn deinit(self: *PendingClipboardOp, alloc: Allocator) void {
        switch (self.*) {
            .paste => |*p| alloc.free(p.data),
            .write => |*w| {
                for (w.contents) |*c| {
                    alloc.free(c.mime);
                    alloc.free(c.data);
                }
                alloc.free(w.contents);
            },
        }
    }
};

const SurfaceStatus = struct {
    pwd: ?[]const u8 = null,
    scrollbar: terminal.Scrollbar = .zero,
    readonly: bool = false,
    secure_input: bool = false,
    key_sequence_active: bool = false,
    key_table_name: ?[]const u8 = null,
    search: SearchStatus = .{},
    progress: ?[]const u8 = null,
};

const HostTabStatus = struct {
    index: usize = 0,
    total: usize = 1,
};

/// Payload for a non-modal confirm overlay. The callbacks receive the
/// `userdata` pointer passed at construction time so the issuer can
/// bind state (e.g. which Surface's close is pending). Callbacks are
/// invoked exactly once — either `on_accept` or `on_cancel` — and the
/// payload is dropped immediately after. Owned byte slices
/// (`title`, `body`, `accept_label`, `cancel_label`) live on the Host's
/// allocator; `deinit` frees them.
const ConfirmPayload = struct {
    title: []u8,
    body: []u8,
    accept_label: []u8,
    cancel_label: []u8,
    on_accept: *const fn (userdata: ?*anyopaque) void,
    on_cancel: ?*const fn (userdata: ?*anyopaque) void = null,
    userdata: ?*anyopaque = null,

    fn deinit(self: *ConfirmPayload, alloc: std.mem.Allocator) void {
        alloc.free(self.title);
        alloc.free(self.body);
        alloc.free(self.accept_label);
        alloc.free(self.cancel_label);
    }
};

const ChildPlacement = struct {
    hwnd: ?HWND = null,
    rect: RECT = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
    rect_known: bool = false,
    visible: bool = false,
    visible_known: bool = false,
};

const ScrollbarPolicy = enum {
    never,
    dynamic,
    always,
};

const VisibleTabRange = struct {
    start: usize,
    count: usize,
};

const TabOverviewEntry = struct {
    title: ?[]const u8 = null,
    pane_count: usize = 1,
    active: bool = false,
};

const SplitTreeSurface = SplitTree(Surface);

const Tab = struct {
    alloc: Allocator,
    id: u32,
    tree: SplitTreeSurface,
    focused: SplitTreeSurface.Node.Handle = .root,
    button_hwnd: ?HWND = null,
    button_prev_proc: ?*const anyopaque = null,
    cached_button_title: ?[:0]const u8 = null,
    cached_button_label: ?[:0]const u8 = null,
    cached_button_index: usize = 0,
    cached_button_active: bool = false,
    cached_button_pane_count: usize = 0,
    cached_button_label_max_len: usize = 0,
    cached_button_show_pane_count: bool = false,
    button_label_cache_valid: bool = false,
    button_placement: ChildPlacement = .{},

    fn init(alloc: Allocator, id: u32, surface: *Surface) !Tab {
        return .{
            .alloc = alloc,
            .id = id,
            .tree = try SplitTreeSurface.init(alloc, surface),
            .focused = .root,
        };
    }

    fn deinit(self: *Tab) void {
        if (self.cached_button_title) |value| self.alloc.free(value);
        if (self.cached_button_label) |value| self.alloc.free(value);
        destroySubclassedWindow(&self.button_hwnd, &self.button_prev_proc);
        self.tree.deinit();
        self.* = undefined;
    }

    fn focusedSurface(self: *const Tab) ?*Surface {
        if (self.tree.nodes.len == 0) return null;
        return switch (self.tree.nodes[self.focused.idx()]) {
            .leaf => |surface| surface,
            .split => null,
        };
    }

    fn findHandle(self: *const Tab, surface: *Surface) ?SplitTreeSurface.Node.Handle {
        var it = self.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view == surface) return entry.handle;
        }
        return null;
    }

    fn findSurfaceByCoreId(self: *const Tab, surface_id: u64) ?*Surface {
        var it = self.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view.core().id == surface_id) return entry.view;
        }
        return null;
    }

    fn leafCount(self: *const Tab) usize {
        var count: usize = 0;
        var it = self.tree.iterator();
        while (it.next()) |_| count += 1;
        return count;
    }

    fn clearRedoHistory(self: *Tab) void {
        var it = self.tree.iterator();
        while (it.next()) |entry| {
            entry.view.undo_stack.clearRedo();
        }
    }

    fn clearRedoHistoryExcept(self: *Tab, skip: *Surface) void {
        var it = self.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view == skip) continue;
            entry.view.undo_stack.clearRedo();
        }
    }
};

const ChromeTextDirty = packed struct(u8) {
    overlay: bool = true,
    inspector: bool = true,
    banner: bool = true,
    status: bool = true,
    _padding: u4 = 0,

    fn markTop(self: *ChromeTextDirty) void {
        self.overlay = true;
        self.inspector = true;
        self.banner = true;
    }

    fn markAll(self: *ChromeTextDirty) void {
        self.markTop();
        self.status = true;
    }
};

const ChromeRepaintMask = packed struct(u8) {
    top: bool = false,
    content: bool = false,
    status: bool = false,
    search_frames: bool = false,
    _padding: u4 = 0,

    fn markChrome(self: *ChromeRepaintMask) void {
        self.top = true;
        self.status = true;
        self.search_frames = true;
    }

    fn isEmpty(self: ChromeRepaintMask) bool {
        return !self.top and !self.content and !self.status and !self.search_frames;
    }
};

const Host = struct {
    app: *App,
    id: u32,
    hwnd: ?HWND = null,
    tabs: std.ArrayListUnmanaged(Tab) = .empty,
    active_tab: usize = 0,
    next_tab_id: u32 = 1,
    /// True while THIS host is drag-resizing (between its own
    /// `WM_ENTERSIZEMOVE` and `WM_EXITSIZEMOVE`). Surfaces owned by
    /// this Host short-circuit `requestRepaint` while the flag is
    /// set. Per-host rather than per-App so dragging window A does
    /// not freeze unrelated background windows B / C. Atomic
    /// because the renderer thread reads it from outside the UI
    /// pump.
    is_live_resize: std.atomic.Value(bool) = .init(false),
    /// One-shot guard used by `WM_EXITSIZEMOVE`: the final layout
    /// must still defer terminal surface repaints so the explicit
    /// post-layout flush owns the single repaint request.
    defer_surface_repaints_until_flush: bool = false,
    /// Tab-drag state machine. `beginPress` fires on tab mousedown;
    /// `onMouseMove` promotes to `drag_tab` once movement exceeds
    /// the 5 px L1 threshold; `onMouseUp` returns the gesture
    /// (activate / drop). Cross-window OLE drag/drop is intentionally
    /// outside this host-local gesture state.
    drag_state: win32_tab_drag.DragState = .{},
    overlay_mode: HostOverlayMode = .none,
    /// Active confirm overlay payload when `overlay_mode == .confirm`.
    /// Owned byte slices (`title`, `body`, `accept_label`,
    /// `cancel_label`) are allocated via `app.core_app.alloc` and
    /// freed when the overlay closes or the Host deinits.
    confirm_payload: ?ConfirmPayload = null,
    overlay_label_hwnd: ?HWND = null,
    overlay_edit_hwnd: ?HWND = null,
    overlay_edit_prev_proc: ?*const anyopaque = null,
    cached_overlay_edit: ?[:0]const u8 = null,
    /// Guard flag: set true while `setOverlayEditText` drives a
    /// programmatic `SetWindowTextW` on the overlay EDIT. That call
    /// synchronously fires `EN_CHANGE`; without this gate the nested
    /// handler would invalidate `cached_overlay_edit`, re-run
    /// `rebuildPaletteList` / `syncOverlay*` mid-write, and leave the
    /// outer caller racing its own sync. Matches the precedent in
    /// `win32_settings.zig` (AGENTS.md:75).
    suppress_edit_events: bool = false,
    overlay_hint_hwnd: ?HWND = null,
    overlay_accept_hwnd: ?HWND = null,
    overlay_cancel_hwnd: ?HWND = null,
    overlay_button_prev_proc: ?*const anyopaque = null,
    cached_overlay_label: ?[:0]const u8 = null,
    cached_overlay_hint: ?[:0]const u8 = null,
    cached_overlay_accept: ?[:0]const u8 = null,
    cached_overlay_cancel: ?[:0]const u8 = null,
    overlay_completion_seed: ?[:0]const u8 = null,
    overlay_completion_value: ?[:0]const u8 = null,
    profiles: ?[]windows_shell.Profile = null,
    selected_profile: usize = 0,
    selected_profile_key: ?[:0]const u8 = null,
    chrome_brush: HBRUSH = null,
    overlay_brush: HBRUSH = null,
    edit_brush: HBRUSH = null,
    status_brush: HBRUSH = null,
    current_dpi: u32 = 96,
    pending_dpi_update: bool = false,
    chrome_font: ?*anyopaque = null, // HFONT, owned
    titlebar_caption_icon_font: ?*anyopaque = null, // HFONT, owned
    titlebar_action_icon_font: ?*anyopaque = null, // HFONT, owned

    // Cached chrome paint strings — rebuilt only when their per-zone
    // dirty bits are set, so WM_PAINT can skip unrelated UTF-16 churn.
    chrome_repaint_dirty: bool = true,
    chrome_paint_pending: bool = false,
    chrome_paint_mask: ChromeRepaintMask = .{},
    chrome_text_dirty: ChromeTextDirty = .{},
    cached_status_w: ?[:0]const u16 = null,
    cached_detail_w: ?[:0]const u16 = null,
    cached_banner_w: ?[:0]const u16 = null,
    cached_inspector_title_w: ?[:0]const u16 = null,
    cached_inspector_hint_w: ?[:0]const u16 = null,
    cached_overlay_paint_badge_w: ?[:0]const u16 = null,
    cached_overlay_paint_label_w: ?[:0]const u16 = null,
    cached_overlay_paint_feedback_w: ?[:0]const u16 = null,
    cached_launcher_selected_chip_w: ?[:0]const u16 = null,
    cached_launcher_quick_slot_chip_w: [3]?[:0]const u16 = .{ null, null, null },
    cached_window_title: ?[:0]const u8 = null,

    overflow_hwnd: ?HWND = null, // dropdown chevron (▾)
    overflow_placement: ChildPlacement = .{},
    chrome_button_prev_proc: ?*const anyopaque = null,
    new_tab_hwnd: ?HWND = null,
    new_tab_placement: ChildPlacement = .{},
    overlay_label_placement: ChildPlacement = .{},
    overlay_edit_placement: ChildPlacement = .{},
    overlay_hint_placement: ChildPlacement = .{},
    overlay_accept_placement: ChildPlacement = .{},
    overlay_cancel_placement: ChildPlacement = .{},
    hovered_button_hwnd: ?HWND = null,
    /// Fade state for the tab the user is currently hovering. Paint
    /// reads `alphaAt(now)` + pre-composites the glyph colour against
    /// the tab bg so the close X visibly fades in with
    /// `win32_tab_visual.close_fade_ms` (120 ms) cubic ease-in-out.
    tab_close_hover: win32_tab_visual.CloseState = .{},
    tab_close_hover_hwnd: ?HWND = null,
    /// Focused-tab underline slide state. Retargeted by
    /// `layoutChromeForRect` whenever the active tab's on-screen rect
    /// changes. Slides over `win32_tab_visual.underline_slide_ms`
    /// (160 ms) cubic ease-in-out; snaps instantly on the first
    /// layout (slide_started_ms == 0) and under reduced-motion
    /// (AGENTS.md:58).
    tab_underline: win32_tab_visual.UnderlineState = .{},
    /// Which caption button the cursor is currently hovering, when
    /// this host is actively using the integrated titlebar. Drives
    /// hover-tint paint in `paintChrome` and is cleared on
    /// `WM_NCMOUSELEAVE`.
    caption_hover: CaptionButton = .none,
    caption_pressed: CaptionButton = .none,
    /// Registered for WM_NCMOUSELEAVE via `TrackMouseEvent(TME_NONCLIENT
    /// | TME_LEAVE)` so we can clear `caption_hover` when the cursor
    /// exits the non-client area. Only re-armed when it becomes false.
    caption_track_armed: bool = false,
    titlebar_hover_fade: TitlebarHoverFade = .{},
    titlebar_hover_fade_role: TitlebarButtonRole = .none,
    /// Fade-OUT state for the tab the user JUST left, so rapid
    /// A → B hover transitions animate BOTH tabs concurrently
    /// (A fades out 1 → 0 while B fades in 0 → 1) instead of A
    /// snapping to 0 the moment the mouse enters B. One slot is
    /// enough in practice — at 120 ms per fade, the user would need
    /// sub-frame hover chains to require more parallel animations.
    tab_close_prev: win32_tab_visual.CloseState = .{},
    tab_close_prev_hwnd: ?HWND = null,
    hovered_quick_slot: ?usize = null,
    focused_quick_slot: ?usize = null,
    banner_kind: HostBannerKind = .none,
    banner_text: ?[:0]const u8 = null,
    update_open_rect: RECT = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
    update_dismiss_rect: RECT = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
    tab_drag_index: ?usize = null,
    tab_drag_start_x: i32 = 0,
    tab_drag_active: bool = false,

    // Command palette list UI. Backed by a custom child HWND shown
    // only while the palette is open. `palette_list_ranked` caches the
    // current query's ranked matches so the paint path doesn't re-rank
    // on every WM_PAINT; rebuilt on EDIT text change.
    palette_list_hwnd: ?HWND = null,
    palette_list_placement: ChildPlacement = .{},
    palette_list_ranked: [win32_palette.max_ranked]win32_palette.RankedIndex = undefined,
    palette_list_ranked_count: usize = 0,
    palette_list_scroll: usize = 0,
    /// Currently-selected row (absolute index into ranked). Enter runs
    /// this entry; click overrides both selection and invocation.
    palette_list_selected: usize = 0,

    // Single SetTimer-driven tween scheduler; see Tween scheduler block
    // in the method section. Matches Win32's main-thread-paint model.
    tween_sched: win32_tween.Scheduler = .{},
    tween_timer_active: bool = false,
    search_timer_active: bool = false,
    scrollbar_timer_active: bool = false,
    resize_settle_timer_active: bool = false,
    resize_settle_repaint_ticks: u8 = 0,
    structural_history_disposing: bool = false,
    destroy_after_structural_dispose: bool = false,
    structural_undo_entries: std.ArrayListUnmanaged(StructuralUndoEntry) = .empty,
    structural_redo_entries: std.ArrayListUnmanaged(StructuralUndoEntry) = .empty,

    const StructuralHistoryDisposeMode = enum {
        normal,
        host_destroy,
    };

    const StructuralUndoKind = enum {
        close_tab,
        split_create,
    };

    const CloseTabUndo = struct {
        tab: ?Tab = null,
        index: usize,
        tab_id: u32,
    };

    const SplitCreateUndo = struct {
        source_surface: *Surface,
        created_surface: *Surface,
        direction: SplitTreeSurface.Split.Direction = .right,
        detached: bool = false,
    };

    const StructuralUndoEntry = struct {
        kind: StructuralUndoKind,
        timestamp_ms: u64,
        payload: union(StructuralUndoKind) {
            close_tab: CloseTabUndo,
            split_create: SplitCreateUndo,
        },

        fn dispose(
            self: *StructuralUndoEntry,
            host: *Host,
            mode: StructuralHistoryDisposeMode,
        ) void {
            switch (self.payload) {
                .close_tab => |*value| {
                    if (value.tab) |*tab| {
                        switch (mode) {
                            .normal => host.disposeDetachedUndoTab(tab),
                            .host_destroy => tab.deinit(),
                        }
                        value.tab = null;
                    }
                },

                .split_create => |*value| {
                    if (!value.detached) return;
                    switch (mode) {
                        .normal => host.disposeDetachedUndoSurface(value.created_surface),
                        .host_destroy => {},
                    }
                    value.detached = false;
                },
            }
        }

        fn referencesSurface(
            self: *const StructuralUndoEntry,
            host: *Host,
            surface: *Surface,
        ) bool {
            return switch (self.payload) {
                .close_tab => |value| close_tab: {
                    if (value.tab) |tab| break :close_tab tab.findHandle(surface) != null;
                    const index = host.findTabIndexById(value.tab_id) orelse return false;
                    break :close_tab host.tabs.items[index].findHandle(surface) != null;
                },

                .split_create => |value| value.source_surface == surface or value.created_surface == surface,
            };
        }
    };

    fn nextTabId(self: *Host) u32 {
        const id = self.next_tab_id;
        self.next_tab_id +%= 1;
        if (self.next_tab_id == 0) self.next_tab_id = 1;
        return id;
    }

    fn findTabIndexById(self: *const Host, id: u32) ?usize {
        for (self.tabs.items, 0..) |tab, i| {
            if (tab.id == id) return i;
        }
        return null;
    }

    fn disposeDetachedUndoSurface(self: *Host, surface: *Surface) void {
        self.structural_history_disposing = true;
        defer self.structural_history_disposing = false;
        surface.close(false);
    }

    fn disposeDetachedUndoTab(self: *Host, tab: *Tab) void {
        self.structural_history_disposing = true;
        defer self.structural_history_disposing = false;

        var it = tab.tree.iterator();
        while (it.next()) |entry| {
            entry.view.close(false);
        }
        tab.deinit();
    }

    fn discardNewestStructuralUndo(self: *Host) void {
        var entry = self.structural_undo_entries.pop() orelse return;
        entry.dispose(self, .normal);
    }

    fn discardNewestStructuralRedo(self: *Host) void {
        var entry = self.structural_redo_entries.pop() orelse return;
        entry.dispose(self, .normal);
    }

    fn clearStructuralRedo(self: *Host) void {
        while (self.structural_redo_entries.items.len > 0) {
            self.discardNewestStructuralRedo();
        }
    }

    fn clearStructuralHistory(
        self: *Host,
        mode: StructuralHistoryDisposeMode,
    ) void {
        while (self.structural_undo_entries.items.len > 0) {
            var entry = self.structural_undo_entries.pop().?;
            entry.dispose(self, mode);
        }
        while (self.structural_redo_entries.items.len > 0) {
            var entry = self.structural_redo_entries.pop().?;
            entry.dispose(self, mode);
        }
    }

    fn discardExpiredStructuralEntries(
        self: *Host,
        list: *std.ArrayListUnmanaged(StructuralUndoEntry),
        min_timestamp_ms: u64,
    ) void {
        var i: usize = 0;
        while (i < list.items.len) {
            if (list.items[i].timestamp_ms >= min_timestamp_ms) {
                i += 1;
                continue;
            }

            var expired = list.orderedRemove(i);
            expired.dispose(self, .normal);
        }
    }

    fn oldestStructuralTimestamp(self: *const Host) ?u64 {
        var oldest: ?u64 = null;
        for (self.structural_undo_entries.items) |entry| {
            if (oldest == null or entry.timestamp_ms < oldest.?) oldest = entry.timestamp_ms;
        }
        for (self.structural_redo_entries.items) |entry| {
            if (oldest == null or entry.timestamp_ms < oldest.?) oldest = entry.timestamp_ms;
        }
        return oldest;
    }

    fn pruneStructuralHistoryBefore(self: *Host, min_timestamp_ms: u64) void {
        self.discardExpiredStructuralEntries(&self.structural_undo_entries, min_timestamp_ms);
        self.discardExpiredStructuralEntries(&self.structural_redo_entries, min_timestamp_ms);
    }

    fn pruneStructuralHistory(self: *Host) void {
        self.pruneStructuralHistoryBefore(self.app.undoCutoffTimestampMs());
    }

    fn pushStructuralUndo(self: *Host, entry: StructuralUndoEntry) Allocator.Error!*StructuralUndoEntry {
        self.pruneStructuralHistory();
        try self.structural_undo_entries.ensureUnusedCapacity(self.app.core_app.alloc, 1);
        self.clearStructuralRedo();
        while (self.structural_undo_entries.items.len >= win32_undo.max_entries) {
            var oldest = self.structural_undo_entries.orderedRemove(0);
            oldest.dispose(self, .normal);
        }
        self.structural_undo_entries.appendAssumeCapacity(entry);
        self.app.scheduleUndoPruneTimer();
        return &self.structural_undo_entries.items[self.structural_undo_entries.items.len - 1];
    }

    fn peekStructuralUndo(self: *const Host) ?*const StructuralUndoEntry {
        if (self.structural_undo_entries.items.len == 0) return null;
        return &self.structural_undo_entries.items[self.structural_undo_entries.items.len - 1];
    }

    fn peekStructuralRedo(self: *const Host) ?*const StructuralUndoEntry {
        if (self.structural_redo_entries.items.len == 0) return null;
        return &self.structural_redo_entries.items[self.structural_redo_entries.items.len - 1];
    }

    fn popStructuralUndo(self: *Host) Allocator.Error!?*StructuralUndoEntry {
        const entry = self.structural_undo_entries.pop() orelse return null;
        self.structural_redo_entries.append(self.app.core_app.alloc, entry) catch |err| {
            self.structural_undo_entries.append(self.app.core_app.alloc, entry) catch unreachable;
            return err;
        };
        return &self.structural_redo_entries.items[self.structural_redo_entries.items.len - 1];
    }

    fn popStructuralRedo(self: *Host) Allocator.Error!?*StructuralUndoEntry {
        const entry = self.structural_redo_entries.pop() orelse return null;
        self.structural_undo_entries.append(self.app.core_app.alloc, entry) catch |err| {
            self.structural_redo_entries.append(self.app.core_app.alloc, entry) catch unreachable;
            return err;
        };
        return &self.structural_undo_entries.items[self.structural_undo_entries.items.len - 1];
    }

    fn restoreLastStructuralUndoPop(self: *Host) void {
        const entry = self.structural_redo_entries.pop() orelse return;
        self.structural_undo_entries.append(self.app.core_app.alloc, entry) catch unreachable;
    }

    fn restoreLastStructuralRedoPop(self: *Host) void {
        const entry = self.structural_undo_entries.pop() orelse return;
        self.structural_redo_entries.append(self.app.core_app.alloc, entry) catch unreachable;
    }

    fn discardStructuralEntriesReferencing(self: *Host, surface: *Surface) void {
        if (self.structural_history_disposing) return;

        var i: usize = 0;
        while (i < self.structural_undo_entries.items.len) {
            if (!self.structural_undo_entries.items[i].referencesSurface(self, surface)) {
                i += 1;
                continue;
            }

            var removed = self.structural_undo_entries.orderedRemove(i);
            removed.dispose(self, .normal);
        }

        i = 0;
        while (i < self.structural_redo_entries.items.len) {
            if (!self.structural_redo_entries.items[i].referencesSurface(self, surface)) {
                i += 1;
                continue;
            }

            var removed = self.structural_redo_entries.orderedRemove(i);
            removed.dispose(self, .normal);
        }
    }

    fn detachTabForUndo(self: *Host, index: usize) ?StructuralUndoEntry {
        // Load-bearing guard: detached tabs retain their surface
        // allocations + host pointers so undo can reinsert them
        // without replaying process startup. Detaching the last tab
        // leaves an empty Host alive as the keybinding target for
        // undo/redo; the app-level prune timer owns the timeout path
        // so hidden surfaces cannot live past `undo-timeout`.
        if (index >= self.tabs.items.len) return null;

        var removed = self.tabs.orderedRemove(index);
        const tab_id = removed.id;
        destroySubclassedWindow(&removed.button_hwnd, &removed.button_prev_proc);
        removed.button_placement = .{};
        removed.button_label_cache_valid = false;

        var it = removed.tree.iterator();
        while (it.next()) |entry| {
            entry.view.host_active = false;
            entry.view.setVisible(false);
        }

        self.active_tab = if (self.tabs.items.len == 0)
            0
        else if (index >= self.tabs.items.len)
            self.tabs.items.len - 1
        else
            index;

        return .{
            .kind = .close_tab,
            .timestamp_ms = GetTickCount64(),
            .payload = .{ .close_tab = .{
                .tab = removed,
                .index = index,
                .tab_id = tab_id,
            } },
        };
    }

    fn restoreClosedTabEntry(self: *Host, value: *CloseTabUndo) Allocator.Error!bool {
        const tab = value.tab orelse return false;
        const insert_index = @min(value.index, self.tabs.items.len);
        try self.tabs.insert(self.app.core_app.alloc, insert_index, tab);
        value.tab = null;
        value.index = insert_index;
        self.active_tab = insert_index;
        return self.activeSurface() != null;
    }

    fn redoClosedTabEntry(self: *Host, value: *CloseTabUndo) bool {
        if (value.tab != null) return false;
        const index = self.findTabIndexById(value.tab_id) orelse return false;
        var removed = self.tabs.orderedRemove(index);
        destroySubclassedWindow(&removed.button_hwnd, &removed.button_prev_proc);
        removed.button_placement = .{};
        removed.button_label_cache_valid = false;

        var it = removed.tree.iterator();
        while (it.next()) |entry| {
            entry.view.host_active = false;
            entry.view.setVisible(false);
        }

        value.index = index;
        value.tab = removed;
        self.active_tab = if (self.tabs.items.len == 0)
            0
        else if (index >= self.tabs.items.len)
            self.tabs.items.len - 1
        else
            index;
        return true;
    }

    fn undoSplitCreateEntry(self: *Host, value: *SplitCreateUndo) !bool {
        if (value.detached) return false;
        const found = self.app.findTabForSurface(value.source_surface) orelse return false;
        if (found.host != self) return false;
        const created_handle = found.tab.findHandle(value.created_surface) orelse return false;
        const next_tree = try found.tab.tree.remove(self.app.core_app.alloc, created_handle);
        found.tab.tree.deinit();
        found.tab.tree = next_tree;
        found.tab.focused = found.tab.findHandle(value.source_surface) orelse found.tab.focused;
        value.created_surface.host_active = false;
        value.created_surface.setVisible(false);
        value.detached = true;
        self.active_tab = found.index;
        return true;
    }

    fn redoSplitCreateEntry(self: *Host, value: *SplitCreateUndo) !bool {
        if (!value.detached) return false;
        const found = self.app.findTabForSurface(value.source_surface) orelse return false;
        if (found.host != self) return false;

        const source_handle = found.tab.findHandle(value.source_surface) orelse return false;
        const inserted = try SplitTreeSurface.init(self.app.core_app.alloc, value.created_surface);
        defer {
            var cleanup = inserted;
            cleanup.deinit();
        }

        const next_tree = try found.tab.tree.split(
            self.app.core_app.alloc,
            source_handle,
            value.direction,
            0.5,
            &inserted,
        );
        found.tab.tree.deinit();
        found.tab.tree = next_tree;
        found.tab.focused = found.tab.findHandle(value.created_surface) orelse source_handle;
        value.detached = false;
        self.active_tab = found.index;
        return true;
    }

    fn applyLatestStructuralUndo(self: *Host) !?[]const u8 {
        const entry = (try self.popStructuralUndo()) orelse return null;
        errdefer self.restoreLastStructuralUndoPop();

        switch (entry.payload) {
            .close_tab => |*value| {
                if (!(try self.restoreClosedTabEntry(value))) {
                    self.discardNewestStructuralRedo();
                    return null;
                }
                const surface = self.activeSurface() orelse {
                    self.discardNewestStructuralRedo();
                    return null;
                };
                self.app.activateSurface(surface);
                return "Tab restored.";
            },

            .split_create => |*value| {
                if (!(try self.undoSplitCreateEntry(value))) {
                    self.discardNewestStructuralRedo();
                    return null;
                }
                self.app.activateSurface(value.source_surface);
                return "New split undone.";
            },
        }
    }

    fn applyLatestStructuralRedo(self: *Host) !?[]const u8 {
        const entry = (try self.popStructuralRedo()) orelse return null;
        errdefer self.restoreLastStructuralRedoPop();

        switch (entry.payload) {
            .close_tab => |*value| {
                if (!self.redoClosedTabEntry(value)) {
                    self.discardNewestStructuralUndo();
                    return null;
                }
                if (self.activeSurface()) |surface| {
                    self.app.activateSurface(surface);
                } else {
                    self.refocusHostWindow();
                    self.layout() catch {};
                    self.refreshChrome() catch {};
                }
                return "Tab closed again.";
            },

            .split_create => |*value| {
                if (!(try self.redoSplitCreateEntry(value))) {
                    self.discardNewestStructuralUndo();
                    return null;
                }
                self.app.activateSurface(value.created_surface);
                return "Split restored.";
            },
        }
    }

    // ── Tween scheduler plumbing ───────────────────────────────────────

    fn clientAnimationsEnabled() bool {
        var enabled: BOOL = 1;
        if (SystemParametersInfoW(
            SPI_GETCLIENTAREAANIMATION,
            0,
            @ptrCast(&enabled),
            0,
        ) == 0) {
            // Fail closed: if we can't read the accessibility setting,
            // honour reduced motion. Accessibility guarantees err toward
            // "less motion", never toward "more".
            return false;
        }
        return enabled != 0;
    }

    /// Reduced-motion and HC collapse `duration_ms` to 0 (snap).
    fn addTween(
        self: *Host,
        from: f32,
        to: f32,
        duration_ms: u16,
        easing: [4]f32,
    ) ?win32_tween.TweenId {
        const now = GetTickCount64();
        const reduced = !clientAnimationsEnabled() or isHighContrastActive();
        const effective_duration: u16 = if (reduced) 0 else duration_ms;

        const id = self.tween_sched.add(now, .{
            .from = from,
            .to = to,
            .duration_ms = effective_duration,
            .easing = easing,
        }) catch return null;

        self.ensureTweenTimer();
        return id;
    }

    fn ensureTweenTimer(self: *Host) void {
        if (self.tween_timer_active) return;
        const hwnd = self.hwnd orelse return;
        const prev = SetTimer(hwnd, TWEEN_TIMER_ID, TWEEN_TIMER_INTERVAL_MS, null);
        if (prev == 0) {
            std.log.warn("tween: SetTimer failed; animations will be static this tick", .{});
            return;
        }
        self.tween_timer_active = true;
    }

    fn killTweenTimer(self: *Host) void {
        if (!self.tween_timer_active) return;
        const hwnd = self.hwnd orelse {
            self.tween_timer_active = false;
            return;
        };
        _ = KillTimer(hwnd, TWEEN_TIMER_ID);
        self.tween_timer_active = false;
    }

    fn tickTweens(self: *Host) void {
        const now = GetTickCount64();
        const still_alive = self.tween_sched.tick(now);
        // Current host-level tweens only animate tab-strip chrome
        // (underline slide + close-button fade), so invalidating the
        // full host every 16 ms is avoidable overpaint.
        self.repaintTopChrome();
        // The Host-level InvalidateRect doesn't cascade to child
        // button HWNDs (flag = 0 so no WS_CLIPCHILDREN bubble).
        // Explicitly invalidate each fading tab button so its
        // WM_DRAWITEM path re-reads `CloseState.alphaAt(now)` each
        // frame. When both slots converge, we stop forcing repaints.
        if (self.tab_close_hover_hwnd) |tab_hwnd| {
            if (self.tab_close_hover.animating(now)) {
                _ = InvalidateRect(tab_hwnd, null, 0);
            } else {
                self.tab_close_hover_hwnd = null;
            }
        }
        if (self.tab_close_prev_hwnd) |prev_hwnd| {
            if (self.tab_close_prev.animating(now)) {
                _ = InvalidateRect(prev_hwnd, null, 0);
            } else {
                self.tab_close_prev_hwnd = null;
            }
        }
        if (self.titlebar_hover_fade_role != .none) {
            const role = self.titlebar_hover_fade_role;
            self.invalidateTitlebarButtonRole(role);
            if (!self.titlebar_hover_fade.animating(now)) {
                self.titlebar_hover_fade = .{};
                self.titlebar_hover_fade_role = .none;
                self.invalidateTitlebarButtonRole(role);
            }
        }
        if (!still_alive) self.killTweenTimer();
    }

    fn ensureResizeSettleTimer(self: *Host) void {
        if (self.resize_settle_timer_active) return;
        const hwnd = self.hwnd orelse return;
        const prev = SetTimer(hwnd, RESIZE_SETTLE_TIMER_ID, RESIZE_SETTLE_TIMER_INTERVAL_MS, null);
        if (prev == 0) {
            std.log.warn("resize-settle: SetTimer failed; final pane repaint may wait for input", .{});
            return;
        }
        self.resize_settle_timer_active = true;
    }

    fn killResizeSettleTimer(self: *Host) void {
        if (!self.resize_settle_timer_active) return;
        const hwnd = self.hwnd orelse {
            self.resize_settle_timer_active = false;
            return;
        };
        _ = KillTimer(hwnd, RESIZE_SETTLE_TIMER_ID);
        self.resize_settle_timer_active = false;
    }

    fn startResizeSettleRepaints(self: *Host) void {
        self.resize_settle_repaint_ticks = RESIZE_SETTLE_REPAINT_TICKS;
        self.ensureResizeSettleTimer();
    }

    fn tickResizeSettleRepaint(self: *Host) void {
        if (self.resize_settle_repaint_ticks == 0) {
            self.killResizeSettleTimer();
            return;
        }

        self.forceVisibleSurfaceRepaintsNow();
        self.forceHostCompositionPaint();
        self.resize_settle_repaint_ticks -= 1;
        if (self.resize_settle_repaint_ticks == 0) self.killResizeSettleTimer();
    }

    /// Retarget the focused-tab underline toward the pixel rect
    /// `(left, width)` (in parent HWND coords). Snaps on the first
    /// retarget (no slide-in from origin on window open) and under
    /// reduced-motion / HC. Otherwise slides over
    /// `win32_tab_visual.underline_slide_ms`; registers a timer-only tween
    /// so the 16 ms heartbeat stays alive for the slide duration.
    fn retargetTabUnderline(self: *Host, left: i32, width: i32) void {
        const new_left: f32 = @floatFromInt(left);
        const new_width: f32 = @floatFromInt(width);
        if (self.tab_underline.target_left == new_left and
            self.tab_underline.target_width == new_width) return;

        const reduced = !clientAnimationsEnabled() or isHighContrastActive();
        if (self.tab_underline.slide_started_ms == 0 or reduced) {
            // Snap: first layout, or the user opted out of motion.
            // slide_started_ms stays 0 so the next retarget also
            // snaps if the user hasn't re-enabled animations. On a
            // non-reduced path, the first REAL slide runs through
            // retargetTo below which sets the timestamp.
            self.tab_underline.target_left = new_left;
            self.tab_underline.target_width = new_width;
            self.tab_underline.start_left = new_left;
            self.tab_underline.start_width = new_width;
            self.repaintTopChrome();
            return;
        }

        const now = GetTickCount64();
        self.tab_underline.retargetTo(new_left, new_width, now);
        // Keep the 16 ms heartbeat alive for the slide duration so
        // `paintChrome` re-runs every frame and reads the interpolated
        // rect. Mirrors the close-button fade pattern.
        _ = self.addTween(
            0.0,
            1.0,
            @intCast(win32_tab_visual.underline_slide_ms),
            (win32_theme.ThemeMotion{}).easing_standard,
        );
    }

    // ── Integrated titlebar (Win11) ─────────────────────────────────────
    //
    // All four handlers below early-return `null` on Win10 / build <
    // 22000; the caller falls through to `DefWindowProcW` and the
    // system paints its default caption.

    fn handleNcCalcSize(
        self: *Host,
        hwnd: HWND,
        wParam: WPARAM,
        lParam: LPARAM,
    ) ?LRESULT {
        if (!self.usingIntegratedTitlebar()) return null;
        if (wParam == 0) return null; // FALSE case: untouched.
        const params: *NCCALCSIZE_PARAMS = @ptrFromInt(@as(usize, @bitCast(lParam)));
        const original = params.rgrc[0];
        // Let DWP compute the default side/bottom frame…
        _ = DefWindowProcW(hwnd, WM_NCCALCSIZE, wParam, lParam);
        // …then compute the top edge through the shared NC-layout
        // math. Side / bottom stay DWP-owned so the stock frame
        // widths survive, while the integrated-caption policy
        // (caption row inside client + maximized invisible-margin
        // compensation) stays centralized in `win32_nc_layout`.
        const metrics = win32_nc_layout.metricsDefault(self.current_dpi);
        const state: win32_nc_layout.WindowState = if (IsZoomed(hwnd) != 0) .maximized else .normal;
        const adjusted = win32_nc_layout.calcNcClientRect(.{
            .left = params.rgrc[0].left,
            .top = original.top,
            .right = params.rgrc[0].right,
            .bottom = params.rgrc[0].bottom,
        }, metrics, state);
        params.rgrc[0].top = adjusted.top;
        return 0;
    }

    fn handleNcHitTest(self: *Host, hwnd: HWND, lParam: LPARAM) ?LRESULT {
        if (!self.usingIntegratedTitlebar()) return null;

        // lParam is the cursor in SCREEN coords (WM_NCHITTEST is
        // special-cased — NOT client-relative).
        const bits: u32 = @truncate(@as(u64, @bitCast(lParam)));
        const cx: i32 = @as(i16, @bitCast(@as(u16, @truncate(bits))));
        const cy: i32 = @as(i16, @bitCast(@as(u16, @truncate(bits >> 16))));

        var win_rect: RECT = undefined;
        if (GetWindowRect(hwnd, &win_rect) == 0) return null;

        const window_rect: win32_nc_layout.Rect = .{
            .left = win_rect.left,
            .top = win_rect.top,
            .right = win_rect.right,
            .bottom = win_rect.bottom,
        };
        const cursor: win32_nc_layout.Point = .{ .x = cx, .y = cy };
        const metrics = win32_nc_layout.metricsDefault(self.current_dpi);
        const state: win32_nc_layout.WindowState =
            if (IsZoomed(hwnd) != 0) .maximized else .normal;
        const ht = win32_nc_layout.hitTest(window_rect, cursor, metrics, state);
        return switch (ht) {
            .nowhere => HTNOWHERE,
            .client => HTCLIENT,
            .caption => HTCAPTION,
            .sysmenu => HTSYSMENU,
            .minbutton => HTMINBUTTON,
            .maxbutton => HTMAXBUTTON,
            .left => HTLEFT,
            .right => HTRIGHT,
            .top => HTTOP,
            .topleft => HTTOPLEFT,
            .topright => HTTOPRIGHT,
            .bottom => HTBOTTOM,
            .bottomleft => HTBOTTOMLEFT,
            .bottomright => HTBOTTOMRIGHT,
            .close => HTCLOSE,
        };
    }

    fn handleNcMouseMove(self: *Host, hwnd: HWND, wParam: WPARAM) ?LRESULT {
        if (!self.usingIntegratedTitlebar()) return null;

        // wParam is the hit-test code returned by our WM_NCHITTEST.
        const ht: i32 = @intCast(@as(i64, @bitCast(wParam)));
        self.setCaptionHover(titlebarCaptionFromHitTest(ht));

        // Arm a one-shot WM_NCMOUSELEAVE so we can clear the hover
        // when the cursor exits the non-client area. Without this the
        // last-hovered button would paint highlighted indefinitely.
        if (!self.caption_track_armed) {
            var track: TRACKMOUSEEVENT = .{
                .cbSize = @sizeOf(TRACKMOUSEEVENT),
                .dwFlags = TME_LEAVE | TME_NONCLIENT,
                .hwndTrack = hwnd,
                .dwHoverTime = 0,
            };
            if (TrackMouseEvent(&track) != 0) {
                self.caption_track_armed = true;
            }
        }

        return null; // fall through to DefWindowProcW for native feedback
    }

    fn handleNcMouseLeave(self: *Host) void {
        self.caption_track_armed = false;
        self.setCaptionHover(.none);
        self.clearCaptionPressed();
    }

    /// Non-owning view over the palette command lists. Lifetime is tied
    /// to `app.config` — do not hold across a reload.
    fn paletteSnapshot(self: *const Host) PaletteSnapshot {
        return .{
            .commands = self.app.config.@"command-palette-entry".value.items,
            .cvals = self.app.config.@"command-palette-entry".value_c.items,
        };
    }

    // ── Palette list UI ───────────────────────────────────────────────

    /// Programmatically set the overlay EDIT's text and keep the
    /// cached UTF-8 view in sync. Wraps the write in
    /// `suppress_edit_events` so the synchronous `EN_CHANGE` that
    /// `SetWindowTextW` fires on the same thread does NOT re-run the
    /// cache-invalidate + sync cascade while the outer caller is
    /// mid-write. Callers must still drive their own
    /// `syncCommandPaletteBanner` / `syncOverlay*` after the write —
    /// the suppressed EN_CHANGE intentionally skips that default
    /// path. See AGENTS.md:75.
    fn setOverlayEditText(self: *Host, value: []const u8) !bool {
        const edit_hwnd = self.overlay_edit_hwnd orelse return false;
        self.suppress_edit_events = true;
        defer self.suppress_edit_events = false;
        return try syncWindowTextUtf8CachedAfterSet(
            self.app.core_app.alloc,
            edit_hwnd,
            &self.cached_overlay_edit,
            value,
        );
    }

    /// Rebuild the ranked match cache for the current EDIT query and
    /// invalidate the list so WM_PAINT redraws. Called from
    /// `syncCommandPaletteBanner` on every keystroke, and from
    /// `showOverlay(.command_palette)` when the palette opens.
    fn rebuildPaletteList(self: *Host) void {
        // `overlayEditText` returns either a literal "" or a borrowed
        // view of `self.cached_overlay_edit`; the Host owns the cache
        // and frees it in deinit. Do NOT free here — that either
        // undermines the literal (UB) or dangles the cache pointer,
        // so the next read returns freed memory.
        const text_raw = overlayEditText(self) catch "";
        const text = std.mem.trim(u8, text_raw, " \t\r\n");

        const snap = self.paletteSnapshot();
        // Bound the ranked-query inputs so debug logs can distinguish
        // malformed snapshots from ranker failures.
        log.debug(
            "palette rebuild begin text_len={d} cmds={d} cvals={d}",
            .{ text.len, snap.commands.len, snap.cvals.len },
        );

        const ranked = win32_palette.rankedForQuery(
            snap,
            text,
            &self.palette_list_ranked,
        );
        // Defensive cap: `rankedForQuery` is bounded by
        // `win32_palette.max_ranked` (256) by contract, but if anything
        // ever regresses that, a runaway `palette_list_ranked_count`
        // turns every paint/scroll/invoke into an OOB on the fixed
        // stack array. Clamp here instead of relying on the library
        // invariant alone.
        self.palette_list_ranked_count = @min(ranked.len, self.palette_list_ranked.len);
        self.palette_list_scroll = 0;
        self.palette_list_selected = 0;

        log.debug(
            "palette rebuild end ranked={d}",
            .{self.palette_list_ranked_count},
        );

        if (self.palette_list_hwnd) |h| _ = InvalidateRect(h, null, 0);
    }

    /// Move the list selection up/down one row, scrolling if the new
    /// selection is off-screen. Returns true if the key was consumed.
    fn moveListSelection(self: *Host, reverse: bool) bool {
        if (self.overlay_mode != .command_palette) return false;
        if (self.palette_list_ranked_count == 0) return false;
        var next: usize = self.palette_list_selected;
        if (reverse) {
            if (next == 0) {
                next = self.palette_list_ranked_count - 1;
            } else {
                next -= 1;
            }
        } else {
            next += 1;
            if (next >= self.palette_list_ranked_count) next = 0;
        }
        self.palette_list_selected = next;
        // Keep the selected row inside the visible window.
        if (next < self.palette_list_scroll) {
            self.palette_list_scroll = next;
        } else if (next >= self.palette_list_scroll + palette_max_visible_rows) {
            self.palette_list_scroll = next - palette_max_visible_rows + 1;
        }
        if (self.palette_list_hwnd) |h| _ = InvalidateRect(h, null, 0);
        self.announcePaletteSelection();
        return true;
    }

    /// Describe the palette list's current state as a single string
    /// suitable for `UIA_NamePropertyId`. The UIA host reads this
    /// whenever a client queries the palette list's name, and the
    /// selection-change path raises `NameChanged` so Narrator re-reads
    /// after each ↑/↓ keystroke.
    fn buildPaletteListName(self: *const Host, buf: []u8) []const u8 {
        if (self.palette_list_ranked_count == 0) {
            return std.fmt.bufPrint(
                buf,
                "Command palette, no matches",
                .{},
            ) catch "Command palette";
        }
        const snap = self.paletteSnapshot();
        const idx = @min(
            self.palette_list_selected,
            self.palette_list_ranked_count - 1,
        );
        const cmd_index = self.palette_list_ranked[idx].index;
        if (cmd_index >= snap.commands.len) return "Command palette";
        const cmd = snap.commands[cmd_index];
        const action = std.mem.span(snap.cvals[cmd_index].action);
        return std.fmt.bufPrint(
            buf,
            "Command palette, {d} of {d}: {s} — {s}",
            .{ idx + 1, self.palette_list_ranked_count, cmd.title, action },
        ) catch "Command palette";
    }

    fn paletteListUiaState(self: *const Host) win32_uia.PaletteListState {
        return .{
            .ctx = @ptrCast(@constCast(self)),
            .name = &paletteListNameThunk,
        };
    }

    fn announcePaletteSelection(self: *const Host) void {
        // Selection-change UIA events need a stable provider instance
        // to target. The current WM_GETOBJECT path creates a fresh one
        // per query, so there's nothing to raise against without
        // caching.
        _ = self;
    }

    /// Translate a y coordinate (client-area) into an absolute rank
    /// index, or null if the click landed outside a row.
    fn paletteRowAtY(self: *const Host, y: i32) ?usize {
        if (y < 0) return null;
        const row_h = self.scaled(palette_row_height);
        if (row_h <= 0) return null;
        const visible_row: usize = @intCast(@divTrunc(y, row_h));
        const absolute = visible_row + self.palette_list_scroll;
        if (absolute >= self.palette_list_ranked_count) return null;
        return absolute;
    }

    /// Dispatch the action at rank index `row`. Must be called from the
    /// palette list's WM_LBUTTONDOWN, where the Host is still alive;
    /// the dispatched action may free the host (`close_window`, etc.)
    /// so no `self` access after `performBindingAction`.
    fn invokePaletteRow(self: *Host, row: usize) !void {
        if (row >= self.palette_list_ranked_count) return;
        if (row >= self.palette_list_ranked.len) return;
        const snap = self.paletteSnapshot();
        const cmd_index = self.palette_list_ranked[row].index;
        if (cmd_index >= snap.commands.len) return;
        if (cmd_index >= snap.cvals.len) return;
        const action = snap.commands[cmd_index].action;
        const action_str = std.mem.span(snap.cvals[cmd_index].action);

        const surface = self.activeSurface() orelse return;
        self.app.pushPaletteMru(action_str) catch |err| {
            std.log.warn("palette MRU push failed err={}", .{err});
        };
        self.hideOverlay();
        self.layout() catch {};
        _ = try surface.core_surface.performBindingAction(action);
        // Do NOT touch `self` after dispatch — the host may be freed.
    }

    /// Scroll the visible window by `delta` wheel units (120 = one line).
    fn scrollPaletteList(self: *Host, delta: i16) void {
        if (self.palette_list_ranked_count <= palette_max_visible_rows) return;
        const lines_per_notch: i32 = 3;
        const step: i32 = @intFromFloat(@as(f32, @floatFromInt(delta)) / 120.0 * @as(f32, @floatFromInt(lines_per_notch)));
        if (step == 0) return;
        const max_scroll = self.palette_list_ranked_count - palette_max_visible_rows;
        var next: isize = @as(isize, @intCast(self.palette_list_scroll)) - step;
        if (next < 0) next = 0;
        if (next > @as(isize, @intCast(max_scroll))) next = @intCast(max_scroll);
        const new_scroll: usize = @intCast(next);
        if (new_scroll == self.palette_list_scroll) return;
        self.palette_list_scroll = new_scroll;
        // Clamp the selected row into the visible window. Without this,
        // Enter invokes whatever row the selection *used* to point at —
        // possibly an off-screen action the user has no idea they're
        // launching. UIA Name updates follow from the reassignment.
        const visible_end = new_scroll + palette_max_visible_rows;
        if (self.palette_list_selected < new_scroll) {
            self.palette_list_selected = new_scroll;
        } else if (self.palette_list_selected >= visible_end) {
            self.palette_list_selected = visible_end - 1;
        }
        if (self.palette_list_hwnd) |h| _ = InvalidateRect(h, null, 0);
    }

    /// BeginPaint/EndPaint over the list child HWND. Each row shows
    /// title | action | keybind hint. The selected row (Enter target)
    /// gets the accent highlight.
    fn paintPaletteList(self: *Host) void {
        const hwnd = self.palette_list_hwnd orelse return;
        var ps: PAINTSTRUCT = undefined;
        const hdc = BeginPaint(hwnd, &ps);
        defer _ = EndPaint(hwnd, &ps);

        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) return;

        const theme = &self.app.resolved_theme;
        fillSolidRect(hdc, rect, theme.overlay_bg);

        if (self.palette_list_ranked_count == 0) return;

        const snap = self.paletteSnapshot();
        const row_h = self.scaled(palette_row_height);
        const padding = self.scaled(12);
        const title_width = self.scaled(200);
        const hint_width = self.scaled(140);

        _ = SetBkMode(hdc, TRANSPARENT);
        const old_font: ?HGDIOBJ = if (self.chrome_font) |f| SelectObject(hdc, f) else null;
        defer {
            if (old_font) |f| _ = SelectObject(hdc, f);
        }

        const visible_end = @min(
            self.palette_list_scroll + palette_max_visible_rows,
            self.palette_list_ranked_count,
        );
        var i = self.palette_list_scroll;
        while (i < visible_end) : (i += 1) {
            const y_top: i32 = @intCast((i - self.palette_list_scroll) * @as(usize, @intCast(row_h)));
            const row_rect: RECT = .{
                .left = 0,
                .top = y_top,
                .right = rect.right,
                .bottom = y_top + row_h,
            };
            const is_selected = i == self.palette_list_selected;
            if (is_selected) {
                fillSolidRect(hdc, row_rect, theme.button_active_bg);
            }
            if (i >= self.palette_list_ranked.len) break;
            const cmd_index = self.palette_list_ranked[i].index;
            if (cmd_index >= snap.commands.len) continue;
            if (cmd_index >= snap.cvals.len) continue;
            const cmd = snap.commands[cmd_index];
            const action_str = std.mem.span(snap.cvals[cmd_index].action);

            const title_color = if (is_selected) theme.button_active_fg else theme.text_primary;
            const secondary_color = if (is_selected) theme.button_active_fg else theme.text_secondary;

            drawPaletteRowText(
                hdc,
                cmd.title,
                .{
                    .left = row_rect.left + padding,
                    .top = row_rect.top,
                    .right = row_rect.left + padding + title_width,
                    .bottom = row_rect.bottom,
                },
                title_color,
            );
            drawPaletteRowText(
                hdc,
                action_str,
                .{
                    .left = row_rect.left + padding + title_width,
                    .top = row_rect.top,
                    .right = row_rect.right - padding - hint_width,
                    .bottom = row_rect.bottom,
                },
                secondary_color,
            );

            // Keybind hint: look up the primary trigger for this action
            // in the reverse index that `Binding.Set` already maintains.
            // Format into a stack buffer — the per-frame allocation
            // would otherwise stack up at every keystroke's WM_PAINT.
            if (self.app.config.keybind.set.reverse.get(cmd.action)) |trigger| {
                var hint_buf: [96]u8 = undefined;
                const hint = std.fmt.bufPrint(&hint_buf, "{f}", .{trigger}) catch null;
                if (hint) |text| {
                    drawPaletteRowText(
                        hdc,
                        text,
                        .{
                            .left = row_rect.right - padding - hint_width,
                            .top = row_rect.top,
                            .right = row_rect.right - padding,
                            .bottom = row_rect.bottom,
                        },
                        secondary_color,
                    );
                }
            }
        }
    }

    fn deinit(self: *Host) void {
        // Stop the tween heartbeat timer before we tear down the
        // scheduler — leaving a SetTimer bound to a destroyed HWND
        // would panic the next time it fired.
        if (self.tween_timer_active) {
            if (self.hwnd) |h| _ = KillTimer(h, TWEEN_TIMER_ID);
            self.tween_timer_active = false;
        }
        if (self.search_timer_active) {
            if (self.hwnd) |h| _ = KillTimer(h, SEARCH_TIMER_ID);
            self.search_timer_active = false;
        }
        if (self.scrollbar_timer_active) {
            if (self.hwnd) |h| _ = KillTimer(h, SCROLLBAR_TIMER_ID);
            self.scrollbar_timer_active = false;
        }
        if (self.resize_settle_timer_active) {
            if (self.hwnd) |h| _ = KillTimer(h, RESIZE_SETTLE_TIMER_ID);
            self.resize_settle_timer_active = false;
        }
        self.tween_sched.deinit();

        self.destroyChildControls();

        if (self.banner_text) |value| self.app.core_app.alloc.free(value);
        if (self.overlay_completion_seed) |value| self.app.core_app.alloc.free(value);
        if (self.overlay_completion_value) |value| self.app.core_app.alloc.free(value);
        if (self.cached_overlay_edit) |value| self.app.core_app.alloc.free(value);
        if (self.cached_overlay_label) |value| self.app.core_app.alloc.free(value);
        if (self.cached_overlay_hint) |value| self.app.core_app.alloc.free(value);
        if (self.cached_overlay_accept) |value| self.app.core_app.alloc.free(value);
        if (self.cached_overlay_cancel) |value| self.app.core_app.alloc.free(value);
        if (self.profiles) |profiles| windows_shell.deinitProfiles(self.app.core_app.alloc, profiles);
        if (self.selected_profile_key) |value| self.app.core_app.alloc.free(value);
        if (self.cached_window_title) |value| self.app.core_app.alloc.free(value);
        self.freeCachedChromeStrings();
        if (self.chrome_brush) |brush| _ = DeleteObject(brush);
        if (self.overlay_brush) |brush| _ = DeleteObject(brush);
        if (self.edit_brush) |brush| _ = DeleteObject(brush);
        if (self.chrome_font) |font| _ = DeleteObject(font);
        if (self.titlebar_caption_icon_font) |font| _ = DeleteObject(font);
        if (self.titlebar_action_icon_font) |font| _ = DeleteObject(font);
        self.clearStructuralHistory(.host_destroy);
        self.structural_undo_entries.deinit(self.app.core_app.alloc);
        self.structural_redo_entries.deinit(self.app.core_app.alloc);
        for (self.tabs.items) |*tab| tab.deinit();
        self.tabs.deinit(self.app.core_app.alloc);
        self.* = undefined;
    }

    fn destroyChildControls(self: *Host) void {
        if (self.hwnd) |hwnd| {
            if (IsWindow(hwnd) != 0) {
                _ = SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
            }
        }

        destroyChildWindow(&self.overlay_label_hwnd);
        destroySubclassedWindow(&self.overlay_edit_hwnd, &self.overlay_edit_prev_proc);
        destroyChildWindow(&self.overlay_hint_hwnd);

        const overlay_prev = self.overlay_button_prev_proc;
        self.overlay_button_prev_proc = null;
        destroySubclassedWindowWithPrev(&self.overlay_accept_hwnd, overlay_prev);
        destroySubclassedWindowWithPrev(&self.overlay_cancel_hwnd, overlay_prev);

        const chrome_prev = self.chrome_button_prev_proc;
        self.chrome_button_prev_proc = null;
        destroySubclassedWindowWithPrev(&self.new_tab_hwnd, chrome_prev);
        destroySubclassedWindowWithPrev(&self.overflow_hwnd, chrome_prev);

        destroyChildWindow(&self.palette_list_hwnd);

        self.hovered_button_hwnd = null;
        self.tab_close_hover_hwnd = null;
        self.tab_close_prev_hwnd = null;
    }

    fn activeTab(self: *Host) ?*Tab {
        if (self.tabs.items.len == 0 or self.active_tab >= self.tabs.items.len) return null;
        return &self.tabs.items[self.active_tab];
    }

    fn activeSurface(self: *const Host) ?*Surface {
        if (self.tabs.items.len == 0 or self.active_tab >= self.tabs.items.len) return null;
        const tab: *const Tab = &self.tabs.items[self.active_tab];
        return tab.focusedSurface();
    }

    fn refocusHostWindow(self: *Host) void {
        if (self.hwnd) |hwnd| {
            _ = SetFocus(hwnd);
        }
    }

    fn handleEmptyHostKeyMessage(
        self: *Host,
        msg: UINT,
        wParam: WPARAM,
        lParam: LPARAM,
    ) bool {
        if (self.activeSurface() != null) return false;
        const event = keyEventFromWin32Message(msg, wParam, lParam) orelse return false;
        return self.app.core_app.keyEvent(self.app, event);
    }

    fn prepareActiveTabVisibility(self: *Host, active_index: usize) void {
        for (self.tabs.items, 0..) |*tab, i| {
            const active = i == active_index;
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                entry.view.host_active = active;
                if (!active) {
                    entry.view.setVisible(false);
                    _ = entry.view.hideSearchBarControls();
                }
            }
        }
    }

    fn invalidateActiveSearchBarLayoutCaches(self: *Host) void {
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                entry.view.invalidateSearchBarLayoutCache();
            }
        }
    }

    fn quickSlotProfileIndexAtPoint(self: *Host, point: POINT) ?usize {
        if (self.overlay_mode != .none) return null;
        const profiles = self.profiles orelse return null;
        if (profiles.len == 0) return null;
        const hwnd = self.hwnd orelse return null;

        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) return null;
        const sb_h = self.statusBarHeight();
        if (sb_h == 0) return null;
        const status_y = @max(self.scaled(host_tab_height) + self.scaled(2), rect.bottom - sb_h + self.scaled(4));
        var status_x: i32 = self.scaled(16);
        const selected_index = self.selectedProfileIndex();

        if (self.selectedProfile()) |profile| {
            const chip_len = profileStatusBadgeTextLen(
                profile,
                selected_index,
                self.app.launcherQuickSlotOrdinal(profile.key),
            );
            const chip_width = self.scaled(16) + @as(i32, @intCast(chip_len * @as(usize, @intCast(self.scaled(7)))));
            status_x += chip_width + self.scaled(10);
        }

        var slot_ordinal: usize = 0;
        while (slot_ordinal < 3) : (slot_ordinal += 1) {
            const profile_index = quickSlotProfileIndex(profiles.len, selected_index, slot_ordinal, 3) orelse break;
            const chip_len = profileQuickSlotChipTextLen(
                &profiles[profile_index],
                profile_index,
                self.app.launcherQuickSlotOrdinal(profiles[profile_index].key),
            );
            const chip_width = self.scaled(12) + @as(i32, @intCast(chip_len * @as(usize, @intCast(self.scaled(7)))));
            const chip_rect = RECT{
                .left = status_x,
                .top = status_y - self.scaled(1),
                .right = status_x + chip_width,
                .bottom = status_y + self.scaled(13),
            };
            if (point.x >= chip_rect.left and point.x < chip_rect.right and point.y >= chip_rect.top and point.y < chip_rect.bottom) {
                return profile_index;
            }
            status_x = chip_rect.right + self.scaled(6);
        }

        return null;
    }

    fn tabIndexForButton(self: *Host, button_hwnd: HWND) ?usize {
        for (self.tabs.items, 0..) |tab, i| {
            if (tab.button_hwnd == button_hwnd) return i;
        }
        return null;
    }

    fn tabIndexAtScreenX(self: *Host, screen_x: i32) ?usize {
        for (self.tabs.items, 0..) |tab, i| {
            const btn = tab.button_hwnd orelse continue;
            var rect: RECT = undefined;
            if (GetWindowRect(btn, &rect) == 0) continue;
            // Check if screen_x falls within the button's horizontal midpoint region
            if (screen_x >= rect.left and screen_x < rect.right) return i;
        }
        return null;
    }

    fn swapTabs(self: *Host, a: usize, b: usize) void {
        if (a == b) return;
        if (a >= self.tabs.items.len or b >= self.tabs.items.len) return;
        self.tabs.items[a].clearRedoHistory();
        self.tabs.items[b].clearRedoHistory();
        self.clearStructuralHistory(.normal);
        const tmp = self.tabs.items[a];
        self.tabs.items[a] = self.tabs.items[b];
        self.tabs.items[b] = tmp;
        // Update active tab index to follow the moved tab
        if (self.active_tab == a) {
            self.active_tab = b;
        } else if (self.active_tab == b) {
            self.active_tab = a;
        }
        self.layout() catch {};
    }

    fn activateTabIndex(self: *Host, index: usize) bool {
        if (index >= self.tabs.items.len) return false;
        if (self.active_tab != index) {
            // Hide inactive tab HWNDs/search controls before the active
            // index changes so rapid Ctrl+Tab repeats don't leave previous
            // tab toolbar fragments painted over the next tab.
            self.prepareActiveTabVisibility(index);
        }
        self.active_tab = index;
        // The underline retarget happens in `layoutTabStrip` —
        // `active_tab` is read there and fed to `retargetTabUnderline`
        // with precomputed coords. Invoking layout after the index
        // change ensures the slide kicks off immediately on activation
        // instead of waiting for the next incidental layout tick.
        self.layout() catch {};
        if (self.tabs.items[index].focusedSurface()) |surface| {
            self.app.activateSurface(surface);
            self.forceHostCompositionPaint();
            return true;
        }
        self.forceHostCompositionPaint();
        return false;
    }

    fn activateTabByDirection(self: *Host, goto: apprt.action.GotoTab) bool {
        if (self.tabs.items.len <= 1) return false;
        const index = desiredTabIndex(self.tabs.items.len, self.active_tab, goto) orelse return false;
        return self.activateTabIndex(index);
    }

    fn navigateActiveSearch(self: *Host, dir: input.Binding.Action.NavigateSearch) bool {
        const surface = self.activeSurface() orelse return false;
        if (!surface.search_active and !surface.search_bar.visible) return false;
        _ = surface.navigateDockedSearch(dir) catch return false;
        return true;
    }

    fn dismissActiveSearch(self: *Host) bool {
        const surface = self.activeSurface() orelse return false;
        if (!surface.search_active and !surface.search_bar.visible and self.overlay_mode != .search) return false;
        surface.closeDockedSearchBar(true, true) catch return false;
        return true;
    }

    fn toggleCommandPaletteFromButton(self: *Host) bool {
        const surface = self.activeSurface() orelse return false;
        _ = surface.toggleCommandPalette() catch return false;
        return true;
    }

    fn completeCommandPaletteFromButton(self: *Host, reverse: bool) bool {
        if (self.overlay_mode != .command_palette) {
            return self.toggleCommandPaletteFromButton();
        }
        _ = self.completeCommandPalette(reverse) catch return false;
        return true;
    }

    fn dismissCommandPalette(self: *Host) bool {
        if (self.overlay_mode != .command_palette) return false;
        self.hideOverlay();
        self.layout() catch {};
        self.forceHostCompositionPaint();
        refocusActiveSurface(self);
        return true;
    }

    fn reloadProfiles(self: *Host) !bool {
        if (self.profiles) |profiles| windows_shell.deinitProfiles(self.app.core_app.alloc, profiles);
        self.profiles = try windows_shell.listProfiles(self.app.core_app.alloc);
        self.app.applyLauncherQuickSlotPreferences(self.profiles.?);
        const profiles = self.profiles.?;
        if (profiles.len == 0) {
            self.selected_profile = 0;
            try appendOwnedString(self.app.core_app.alloc, &self.selected_profile_key, null);
            return false;
        }
        if (preferredProfileIndex(
            profiles,
            self.selected_profile_key,
            self.app.launcher_profile_key,
            self.app.launcher_profile_hint,
            self.selected_profile,
        )) |index| {
            _ = try self.setSelectedProfileIndex(index);
            return true;
        }
        if (self.selected_profile >= profiles.len) self.selected_profile = 0;
        _ = try self.setSelectedProfileIndex(self.selected_profile);
        return true;
    }

    fn reapplyLauncherProfilePreferences(self: *Host) !void {
        const profiles = self.profiles orelse return;
        if (profiles.len == 0) return;
        self.app.applyLauncherQuickSlotPreferences(profiles);
        if (preferredProfileIndex(
            profiles,
            self.selected_profile_key,
            self.app.launcher_profile_key,
            self.app.launcher_profile_hint,
            self.selected_profile,
        )) |index| {
            _ = try self.setSelectedProfileIndex(index);
            return;
        }
        if (self.selected_profile >= profiles.len) self.selected_profile = 0;
        _ = try self.setSelectedProfileIndex(self.selected_profile);
    }

    fn ensureProfiles(self: *Host) !bool {
        if (self.profiles == null) return try self.reloadProfiles();
        const profiles = self.profiles.?;
        if (profiles.len == 0) return false;
        if (self.selected_profile >= profiles.len) self.selected_profile = 0;
        return true;
    }

    fn selectedProfileIndex(self: *Host) ?usize {
        const profiles = self.profiles orelse return null;
        if (profiles.len == 0) return null;
        return @min(self.selected_profile, profiles.len - 1);
    }

    fn selectedProfile(self: *Host) ?*windows_shell.Profile {
        const profiles = self.profiles orelse return null;
        const index = self.selectedProfileIndex() orelse return null;
        return &profiles[index];
    }

    fn profileForKey(self: *Host, key: []const u8) !?*windows_shell.Profile {
        if (!(try self.ensureProfiles())) return null;
        const profiles = self.profiles orelse return null;
        const index = profileIndexByKey(profiles, key) orelse return null;
        return &profiles[index];
    }

    fn setSelectedProfileIndex(self: *Host, index: usize) !bool {
        const profiles = self.profiles orelse return false;
        if (profiles.len == 0) return false;
        const next_index = @min(index, profiles.len - 1);
        const next_key = profiles[next_index].key;
        if (!selectedProfileSelectionNeedsChange(
            self.selected_profile,
            next_index,
            self.focused_quick_slot,
            self.selected_profile_key,
            self.app.launcher_profile_key,
            next_key,
        )) return false;
        self.selected_profile = next_index;
        self.setFocusedQuickSlot(null);
        try appendOwnedString(self.app.core_app.alloc, &self.selected_profile_key, next_key);
        try appendOwnedString(self.app.core_app.alloc, &self.app.launcher_profile_key, next_key);
        return true;
    }

    fn setLauncherProfileTarget(self: *Host, target: ProfileOpenTarget) void {
        if (self.app.launcher_profile_target == target) return;
        self.app.launcher_profile_target = target;
        self.refreshProfileChrome();
    }

    fn refreshProfileChrome(self: *Host) void {
        const status_h = self.statusBarHeight();
        if (!profileChromeVisible(self.overlay_mode, status_h)) return;
        if (self.overlay_mode == .profile) {
            _ = self.syncOverlayLabel() catch false;
            _ = self.syncOverlayHint() catch false;
            _ = self.syncOverlayButtons() catch false;
        }
        if (profileChromeNeedsFullTextInvalidation(self.overlay_mode, status_h)) {
            self.invalidateChromeText();
        } else {
            self.invalidateOverlayText();
        }
    }

    fn cycleLauncherProfileTarget(self: *Host, reverse: bool) bool {
        self.setLauncherProfileTarget(cycleProfileOpenTarget(self.app.launcher_profile_target, reverse));
        return true;
    }

    fn toggleProfileOverlay(self: *Host) bool {
        if (!(self.reloadProfiles() catch false)) {
            self.setBanner(.err, "No supported Windows profiles detected.") catch {};
            return false;
        }
        if (self.overlay_mode == .profile) {
            self.hideOverlay();
            self.layout() catch {};
            self.forceHostCompositionPaint();
            return true;
        }
        const initial = self.overlayInitialText(.profile);
        defer if (initial) |value| self.app.core_app.alloc.free(value);
        self.hideOverlay();
        self.showOverlay(.profile, initial) catch return false;
        return true;
    }

    fn cycleSelectedProfile(self: *Host, reverse: bool) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const profiles = self.profiles.?;
        const next = nextTabOverviewSelection(self.selected_profile + 1, profiles.len, reverse) - 1;
        if (self.setSelectedProfileIndex(next) catch return false) {
            self.refreshProfileChrome();
        }
        return true;
    }

    fn stepProfileSelection(self: *Host, reverse: bool) !bool {
        if (self.overlay_mode != .profile) return false;
        if (!(try self.ensureProfiles())) return false;
        const profiles = self.profiles.?;
        const edit_hwnd = self.overlay_edit_hwnd orelse return false;
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        const fallback = self.selectedProfileIndex() orelse 0;
        const current_index = switch (resolveProfileSelection(profiles, text, fallback)) {
            .exact => |index| index,
            .ambiguous, .invalid => fallback,
        };
        const next = nextTabOverviewSelection(current_index + 1, profiles.len, reverse) - 1;
        const selection_changed = try self.setSelectedProfileIndex(next);
        _ = try self.setOverlayEditText(profiles[next].key);
        _ = SendMessageW(edit_hwnd, EM_SETSEL, 0, -1);
        if (selection_changed) self.refreshProfileChrome();
        return true;
    }

    fn openSelectedProfile(self: *Host, open_target: ProfileOpenTarget) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const profile = self.selectedProfile() orelse return false;
        const source = self.activeSurface() orelse return false;
        const surface = self.app.createProfileSurface(.{ .surface = source.core() }, profile, open_target) catch return false;
        if (self.overlay_mode == .profile) {
            self.hideOverlay();
            self.layout() catch {};
        }
        self.app.activateSurface(surface);
        return true;
    }

    fn quickOpenProfileIndex(self: *Host, index: usize, open_target: ProfileOpenTarget) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const profiles = self.profiles.?;
        if (index >= profiles.len) return false;
        if (self.setSelectedProfileIndex(index) catch return false) {
            self.refreshProfileChrome();
        }
        return self.openSelectedProfile(open_target);
    }

    fn openSelectedProfileOrFallback(self: *Host, open_target: ProfileOpenTarget) bool {
        if (self.openSelectedProfile(open_target)) return true;
        const surface = self.activeSurface() orelse return false;
        switch (open_target) {
            .tab => _ = self.app.performAction(.{ .surface = surface.core() }, .new_tab, {}) catch return false,
            .window => _ = self.app.performAction(.{ .surface = surface.core() }, .new_window, .{}) catch return false,
            .split => _ = self.app.performAction(.{ .surface = surface.core() }, .new_split, .right) catch return false,
        }
        return true;
    }

    fn submitProfileOverlay(self: *Host, open_target: ProfileOpenTarget) !bool {
        if (!(try self.ensureProfiles())) {
            try self.setBanner(.err, "No supported Windows profiles detected.");
            return false;
        }
        _ = self.overlay_edit_hwnd orelse return false;
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        const selection = resolveProfileSelection(self.profiles.?, text, self.selectedProfileIndex() orelse 0);
        switch (selection) {
            .exact => |index| {
                _ = try self.setSelectedProfileIndex(index);
            },
            .ambiguous => |count| {
                const message = try std.fmt.allocPrint(
                    self.app.core_app.alloc,
                    "{d} profiles match. Keep typing or use Up/Down to choose one.",
                    .{count},
                );
                defer self.app.core_app.alloc.free(message);
                try self.setBanner(.err, message);
                return false;
            },
            .invalid => {
                try self.setBanner(.err, "Unknown profile. Try a number or a profile name like pwsh, ubuntu, git, or cmd.");
                return false;
            },
        }
        if (!self.openSelectedProfile(open_target)) return false;
        return true;
    }

    fn inspectorPanelVisible(self: *Host) bool {
        return inspectorPanelVisibleForState(self.overlay_mode, self.activeTabHasInspector());
    }

    fn activeTabHasInspector(self: *Host) bool {
        const tab = self.activeTab() orelse return false;
        var it = tab.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view.inspector_visible) return true;
        }
        return false;
    }

    fn isActiveTabButton(self: *Host, child: HWND) bool {
        const tab = self.activeTab() orelse return false;
        return if (tab.button_hwnd) |hwnd| hwnd == child else false;
    }

    fn isTabButton(self: *Host, child: HWND) bool {
        for (self.tabs.items) |*tab| {
            if (tab.button_hwnd) |hwnd| {
                if (hwnd == child) return true;
            }
        }
        return false;
    }

    fn isHoveredButton(self: *Host, child: HWND) bool {
        return self.hovered_button_hwnd != null and child == self.hovered_button_hwnd.?;
    }

    fn titlebarActionButtonRole(self: *Host, child: HWND) TitlebarButtonRole {
        if (!self.app.use_integrated_titlebar) return .none;
        if (self.new_tab_hwnd != null and child == self.new_tab_hwnd.?) return .new_tab;
        if (self.overflow_hwnd != null and child == self.overflow_hwnd.?) return .dropdown;
        return .none;
    }

    fn titlebarHoverFadeDuration(self: *Host) u16 {
        _ = self;
        if (!clientAnimationsEnabled() or isHighContrastActive()) return 0;
        return titlebar_hover_fade_ms;
    }

    fn invalidateTitlebarButtonRole(self: *Host, role: TitlebarButtonRole) void {
        switch (role) {
            .minimize, .maximize, .close => self.repaintTopChrome(),
            .new_tab => {
                if (self.new_tab_hwnd) |hwnd| _ = InvalidateRect(hwnd, null, 0);
            },
            .dropdown => {
                if (self.overflow_hwnd) |hwnd| _ = InvalidateRect(hwnd, null, 0);
            },
            .none => {},
        }
    }

    fn startTitlebarHoverFade(self: *Host, role: TitlebarButtonRole) void {
        if (role == .none) return;
        const duration = self.titlebarHoverFadeDuration();
        if (duration == 0) {
            self.titlebar_hover_fade = .{};
            self.titlebar_hover_fade_role = .none;
            self.invalidateTitlebarButtonRole(role);
            return;
        }

        self.titlebar_hover_fade.start(GetTickCount64(), duration);
        self.titlebar_hover_fade_role = role;
        self.invalidateTitlebarButtonRole(role);
        _ = self.addTween(0.0, 1.0, duration, .{ 0.0, 0.0, 1.0, 1.0 });
    }

    fn titlebarHoverAlpha(self: *Host, role: TitlebarButtonRole, hovered: bool, now_ms: u64) f32 {
        if (hovered) return 1.0;
        if (self.titlebar_hover_fade_role == role) {
            return self.titlebar_hover_fade.alphaAt(now_ms);
        }
        return 0.0;
    }

    fn setCaptionHover(self: *Host, next: CaptionButton) void {
        if (self.caption_hover == next) return;
        const previous_role = titlebarRoleFromCaption(self.caption_hover);
        self.caption_hover = next;
        if (previous_role != .none) self.startTitlebarHoverFade(previous_role);
        self.repaintTopChrome();
    }

    fn clearCaptionPressed(self: *Host) void {
        if (self.caption_pressed == .none) return;
        self.caption_pressed = .none;
        self.repaintTopChrome();
    }

    fn setHoveredButton(self: *Host, child: ?HWND) void {
        if (self.hovered_button_hwnd == child) return;
        const previous = self.hovered_button_hwnd;
        self.hovered_button_hwnd = child;
        if (previous) |hwnd| _ = InvalidateRect(hwnd, null, 0);
        if (child) |hwnd| _ = InvalidateRect(hwnd, null, 0);

        const previous_titlebar_role = if (previous) |h| self.titlebarActionButtonRole(h) else .none;
        if (previous_titlebar_role != .none) self.startTitlebarHoverFade(previous_titlebar_role);

        // Tab close-button fade: when the hovered button transitions
        // into / out of a TAB button, drive CloseState + kick the
        // tween timer so the 16 ms tick drives repaints while the
        // alpha interpolates. Non-tab buttons (caption action buttons,
        // overlay accept/cancel) use the instant hover visuals.
        const prev_was_tab = if (previous) |h| self.isTabButton(h) else false;
        const new_is_tab = if (child) |h| self.isTabButton(h) else false;
        if (prev_was_tab or new_is_tab) {
            const now = GetTickCount64();

            if (prev_was_tab and new_is_tab) {
                // Adjacent tab transition: move the previous target
                // into the fade-out slot so both animations run in
                // parallel — fade A out while fading B in.
                self.tab_close_prev = self.tab_close_hover;
                self.tab_close_prev.setHovered(false, now);
                self.tab_close_prev_hwnd = previous;

                self.tab_close_hover = .{};
                self.tab_close_hover.setHovered(true, now);
                self.tab_close_hover_hwnd = child;
            } else {
                // Single-direction transition: (no tab → tab) fade in,
                // (tab → no tab) fade out. Previous-slot stays as-is
                // so an already-in-progress fade-out keeps animating.
                self.tab_close_hover.setHovered(new_is_tab, now);
                self.tab_close_hover_hwnd = if (new_is_tab) child else previous;
            }

            // Dummy tween keeps the 16 ms heartbeat alive for the
            // fade duration; paint reads `CloseState.alphaAt` each
            // frame directly.
            _ = self.addTween(
                0.0,
                1.0,
                @intCast(win32_tab_visual.close_fade_ms),
                (win32_theme.ThemeMotion{}).easing_standard,
            );
        }
    }

    fn setHoveredQuickSlot(self: *Host, slot: ?usize) void {
        if (self.hovered_quick_slot == slot) return;
        self.hovered_quick_slot = slot;
        self.repaintStatusBar();
    }

    fn setFocusedQuickSlot(self: *Host, slot: ?usize) void {
        if (self.focused_quick_slot == slot) return;
        self.focused_quick_slot = slot;
        self.repaintStatusBar();
    }

    fn focusQuickSlotEdge(self: *Host, toward_start: bool) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const next = nextQuickSlotFocus(
            self.profiles.?.len,
            self.selectedProfileIndex(),
            null,
            !toward_start,
            3,
        ) orelse return false;
        self.setFocusedQuickSlot(next);
        return true;
    }

    fn cycleFocusedQuickSlot(self: *Host, reverse: bool) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const next = nextQuickSlotFocus(
            self.profiles.?.len,
            self.selectedProfileIndex(),
            self.focused_quick_slot,
            reverse,
            3,
        ) orelse return false;
        self.setFocusedQuickSlot(next);
        return true;
    }

    fn openFocusedQuickSlot(self: *Host, open_target: ProfileOpenTarget) bool {
        const profile_index = self.focused_quick_slot orelse return false;
        return self.quickOpenProfileIndex(profile_index, open_target);
    }

    fn assignSelectedProfileToQuickSlot(self: *Host, slot_ordinal: usize) bool {
        if (!(self.ensureProfiles() catch false)) return false;
        const profile = self.selectedProfile() orelse return false;
        self.app.setLauncherQuickSlotPreference(slot_ordinal, profile.key) catch return false;
        const message = std.fmt.allocPrint(
            self.app.core_app.alloc,
            "Pinned {s} to quick slot {d}.",
            .{ profile.label, slot_ordinal + 1 },
        ) catch return false;
        defer self.app.core_app.alloc.free(message);
        self.setBanner(.info, message) catch {};
        return true;
    }

    fn clearQuickSlotPins(self: *Host) bool {
        self.app.clearLauncherQuickSlotPreferences();
        self.setFocusedQuickSlot(null);
        self.setBanner(.info, "Cleared quick slot pins.") catch {};
        return true;
    }

    fn subclassButton(
        self: *Host,
        button_hwnd: HWND,
        proc: WNDPROC,
        prev_slot: *?*const anyopaque,
    ) void {
        _ = SetWindowLongPtrW(
            button_hwnd,
            GWLP_USERDATA,
            @as(LONG_PTR, @intCast(@intFromPtr(self))),
        );
        const previous = SetWindowLongPtrW(
            button_hwnd,
            GWLP_WNDPROC,
            @as(LONG_PTR, @intCast(@intFromPtr(proc))),
        );
        prev_slot.* = if (previous == 0)
            null
        else
            @ptrFromInt(@as(usize, @intCast(previous)));
    }

    fn setVisible(self: *Host, visible: bool) void {
        const hwnd = self.hwnd orelse return;
        if (!visible) {
            for (self.tabs.items) |*tab| {
                var it = tab.tree.iterator();
                while (it.next()) |entry| entry.view.setVisible(false);
            }
        }
        _ = ShowWindow(hwnd, if (visible) SW_SHOW else SW_HIDE);
    }

    fn present(self: *Host) void {
        const hwnd = self.hwnd orelse return;
        _ = ShowWindow(hwnd, hostPresentShowCommand(IsZoomed(hwnd) != 0));
        _ = SetForegroundWindow(hwnd);
        _ = SetFocus(hwnd);
    }

    fn setBanner(self: *Host, kind: HostBannerKind, text: ?[]const u8) !void {
        const next_kind: HostBannerKind = if (text == null) .none else kind;
        if (self.banner_kind == next_kind) {
            if (text) |value| {
                if (ownedStringEquals(self.banner_text, value)) return;
            } else if (self.banner_text == null) {
                return;
            }
        }

        self.banner_kind = next_kind;
        try appendOwnedString(self.app.core_app.alloc, &self.banner_text, text);
        self.invalidateBannerText();
    }

    fn clearUpdateActionRects(self: *Host) void {
        self.update_open_rect = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 };
        self.update_dismiss_rect = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 };
    }

    fn handleUpdateNoticeClick(self: *Host, point: POINT) bool {
        if (self.app.update_notice == null) return false;
        if (pointInRect(point, self.update_open_rect)) {
            self.app.openUpdateNotice() catch |err| {
                log.warn("failed to open release URL err={}", .{err});
            };
            return true;
        }
        if (pointInRect(point, self.update_dismiss_rect)) {
            self.app.dismissUpdateNotice();
            return true;
        }
        return false;
    }

    fn setOverlayDefaultBanner(self: *Host, mode: HostOverlayMode) !void {
        _ = mode;
        try self.setBanner(.none, null);
    }

    fn ensureOverlayControls(self: *Host) !void {
        const hwnd = self.hwnd orelse return;
        if (self.overlay_edit_hwnd != null) return;

        self.overlay_label_hwnd = CreateWindowExW(
            0,
            prompt_label_class,
            host_overlay_command_palette_label,
            WS_CHILD,
            0,
            0,
            80,
            host_overlay_height - 8,
            hwnd,
            @ptrFromInt(2001),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        self.overlay_edit_hwnd = CreateWindowExW(
            0,
            prompt_edit_class,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD | WS_TABSTOP | ES_AUTOHSCROLL,
            0,
            0,
            100,
            host_overlay_height - 8,
            hwnd,
            @ptrFromInt(2002),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        const edit_hwnd = self.overlay_edit_hwnd.?;
        _ = SetWindowLongPtrW(
            edit_hwnd,
            GWLP_USERDATA,
            @as(LONG_PTR, @intCast(@intFromPtr(self))),
        );
        const previous = SetWindowLongPtrW(
            edit_hwnd,
            GWLP_WNDPROC,
            @as(LONG_PTR, @intCast(@intFromPtr(&overlayEditProc))),
        );
        self.overlay_edit_prev_proc = if (previous == 0)
            null
        else
            @ptrFromInt(@as(usize, @intCast(previous)));
        const edit_margin = @as(u16, @intCast(@max(self.scaled(10), 6)));
        const packed_margins: isize = @intCast(@as(usize, edit_margin) | (@as(usize, edit_margin) << 16));
        _ = SendMessageW(
            edit_hwnd,
            EM_SETMARGINS,
            EC_LEFTMARGIN | EC_RIGHTMARGIN,
            packed_margins,
        );

        self.overlay_hint_hwnd = CreateWindowExW(
            0,
            prompt_label_class,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD,
            0,
            0,
            100,
            18,
            hwnd,
            @ptrFromInt(2005),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        self.overlay_accept_hwnd = CreateWindowExW(
            0,
            prompt_button_class,
            prompt_ok_label,
            WS_CHILD | WS_TABSTOP | BS_OWNERDRAW,
            0,
            0,
            70,
            host_overlay_height - 8,
            hwnd,
            @ptrFromInt(2003),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        self.subclassButton(self.overlay_accept_hwnd.?, &hostButtonProc, &self.overlay_button_prev_proc);

        self.overlay_cancel_hwnd = CreateWindowExW(
            0,
            prompt_button_class,
            prompt_cancel_label,
            WS_CHILD | WS_TABSTOP | BS_OWNERDRAW,
            0,
            0,
            80,
            host_overlay_height - 8,
            hwnd,
            @ptrFromInt(2004),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        self.subclassButton(self.overlay_cancel_hwnd.?, &hostButtonProc, &self.overlay_button_prev_proc);

        // Palette list — shown only when overlay_mode == .command_palette.
        // Stamped with a pointer to the Host via GWLP_USERDATA so the
        // wndproc can dispatch clicks back to `host.invokePaletteRow`.
        self.palette_list_hwnd = CreateWindowExW(
            0,
            palette_list_class_name,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD,
            0,
            0,
            320,
            palette_row_height * @as(i32, palette_max_visible_rows),
            hwnd,
            @ptrFromInt(2006),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        _ = SetWindowLongPtrW(
            self.palette_list_hwnd.?,
            GWLP_USERDATA,
            @as(LONG_PTR, @intCast(@intFromPtr(self))),
        );

        self.hideOverlay();
    }

    fn ensureChromeButtons(self: *Host) !void {
        const hwnd = self.hwnd orelse return;

        if (self.new_tab_hwnd == null) {
            self.new_tab_hwnd = CreateWindowExW(
                0,
                prompt_button_class,
                host_tab_new_button_label,
                WS_CHILD | WS_VISIBLE | WS_TABSTOP | BS_OWNERDRAW,
                0,
                0,
                host_tab_small_button_width,
                host_tab_height - 8,
                hwnd,
                @ptrFromInt(1904),
                self.app.hinstance,
                null,
            ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
            self.subclassButton(self.new_tab_hwnd.?, &hostButtonProc, &self.chrome_button_prev_proc);
        }

        if (self.overflow_hwnd == null) {
            self.overflow_hwnd = CreateWindowExW(
                0,
                prompt_button_class,
                host_tab_dropdown_button_label,
                WS_CHILD | WS_VISIBLE | WS_TABSTOP | BS_OWNERDRAW,
                0,
                0,
                host_tab_overflow_button_width,
                host_tab_height - 8,
                hwnd,
                @ptrFromInt(1911),
                self.app.hinstance,
                null,
            ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
            self.subclassButton(self.overflow_hwnd.?, &hostButtonProc, &self.chrome_button_prev_proc);
        }
    }

    fn showOverlay(self: *Host, mode: HostOverlayMode, initial: ?[]const u8) !void {
        try self.ensureOverlayControls();
        self.overlay_mode = mode;
        self.clearOverlayCompletion();
        try self.setOverlayDefaultBanner(mode);

        if (self.overlay_label_hwnd) |label_hwnd| {
            _ = applyChildVisibility(label_hwnd, &self.overlay_label_placement, false);
        }
        const edit_hwnd = self.overlay_edit_hwnd orelse return;
        if (self.overlay_hint_hwnd) |hint_hwnd| {
            _ = applyChildVisibility(hint_hwnd, &self.overlay_hint_placement, false);
        }
        const accept_hwnd = self.overlay_accept_hwnd orelse return;
        const cancel_hwnd = self.overlay_cancel_hwnd orelse return;

        // Confirm overlays are message-only: they carry the payload's
        // body as read-only explanatory text (the hint HWND) rather
        // than an editable query. Hiding the EDIT removes the blank-
        // textbox-UX-trap and puts keyboard focus on the Accept
        // button by default (Enter = accept, Esc = cancel per the
        // overlayEditProc key handlers; we still capture keys there
        // so focus on the button is just the initial landing spot).
        const is_confirm = mode == .confirm;
        const show_accept = overlayAcceptButtonVisible(mode);
        _ = applyChildVisibility(edit_hwnd, &self.overlay_edit_placement, !is_confirm);
        _ = applyChildVisibility(accept_hwnd, &self.overlay_accept_placement, show_accept);
        _ = applyChildVisibility(cancel_hwnd, &self.overlay_cancel_placement, true);
        self.invalidateOverlayTransitionPlacementCache();

        const initial_text = initial orelse "";
        _ = try self.setOverlayEditText(initial_text);

        _ = try self.syncOverlayLabel();
        _ = try self.syncOverlayHint();
        _ = try self.syncOverlayButtons();
        // The command palette gets a scrollable list below the EDIT;
        // rebuild it for the initial (usually empty) query so the
        // ranker's "show all" path has something visible to draw.
        if (mode == .command_palette) self.rebuildPaletteList();
        try self.layout();
        if (is_confirm) {
            // Show body as hint label. Prefer the Accept button as
            // the keyboard-focus target so the destructive action is
            // one explicit click/Enter away — never auto-triggered.
            _ = SetFocus(accept_hwnd);
        } else {
            _ = SetFocus(edit_hwnd);
            _ = SendMessageW(edit_hwnd, EM_SETSEL, 0, -1);
        }
        self.forceOverlayTransitionPaint();
    }

    fn hideOverlay(self: *Host) void {
        self.overlay_mode = .none;
        self.clearOverlayCompletion();
        self.setBanner(.none, null) catch {};
        // Drop any active confirm payload. Both accept and cancel
        // paths route through hideOverlay, so this is the one place
        // the owned byte slices get freed. Callbacks were already
        // dispatched in invokeConfirm{Accept,Cancel} before reaching
        // this point.
        if (self.confirm_payload) |*p| {
            p.deinit(self.app.core_app.alloc);
            self.confirm_payload = null;
        }
        if (self.overlay_label_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.overlay_label_placement, false);
        if (self.overlay_edit_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.overlay_edit_placement, false);
        if (self.overlay_hint_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.overlay_hint_placement, false);
        if (self.overlay_accept_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.overlay_accept_placement, false);
        if (self.overlay_cancel_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.overlay_cancel_placement, false);
        if (self.palette_list_hwnd) |hwnd| _ = applyChildVisibility(hwnd, &self.palette_list_placement, false);
        self.palette_list_ranked_count = 0;
        self.palette_list_scroll = 0;
        self.invalidateOverlayTransitionPlacementCache();
        self.forceHostCompositionPaint();
    }

    fn invalidateOverlayTransitionPlacementCache(self: *Host) void {
        self.overlay_edit_placement.rect_known = false;
        self.overlay_accept_placement.rect_known = false;
        self.overlay_cancel_placement.rect_known = false;
        self.palette_list_placement.rect_known = false;
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                entry.view.placement.rect_known = false;
            }
        }
    }

    /// Bring up a non-modal confirmation prompt. Ownership of the
    /// four string slices (`title`, `body`, `accept_label`,
    /// `cancel_label`) transfers to the Host — the Host frees them
    /// when the overlay closes. Opening a confirm while another
    /// overlay is active closes the previous one first (policy:
    /// confirm is mutually exclusive with palette / search /
    /// profile).
    fn showConfirm(
        self: *Host,
        title: []const u8,
        body: []const u8,
        accept_label: []const u8,
        cancel_label: []const u8,
        on_accept: *const fn (userdata: ?*anyopaque) void,
        on_cancel: ?*const fn (userdata: ?*anyopaque) void,
        userdata: ?*anyopaque,
    ) !void {
        const alloc = self.app.core_app.alloc;
        // Deep-copy every string so the caller doesn't need to keep
        // the source alive.
        const title_owned = try alloc.dupe(u8, title);
        errdefer alloc.free(title_owned);
        const body_owned = try alloc.dupe(u8, body);
        errdefer alloc.free(body_owned);
        const accept_owned = try alloc.dupe(u8, accept_label);
        errdefer alloc.free(accept_owned);
        const cancel_owned = try alloc.dupe(u8, cancel_label);
        errdefer alloc.free(cancel_owned);

        // Close any previous overlay so we don't stack. `hideOverlay`
        // frees an existing `confirm_payload` via its own deinit
        // branch, so we don't leak here.
        if (self.overlay_mode != .none) self.hideOverlay();

        self.confirm_payload = .{
            .title = title_owned,
            .body = body_owned,
            .accept_label = accept_owned,
            .cancel_label = cancel_owned,
            .on_accept = on_accept,
            .on_cancel = on_cancel,
            .userdata = userdata,
        };

        try self.showOverlay(.confirm, null);
    }

    /// Fire the accept callback and close the overlay. Critical
    /// ordering: hide the overlay + free the payload FIRST, then
    /// dispatch the callback. The accept handler can synchronously
    /// destroy this Host (e.g. the confirm-close-surface path calls
    /// `DestroyWindow` which triggers the Host's `WM_DESTROY` +
    /// teardown) — touching `self` after that is a use-after-free.
    /// Snapshot the callback into locals, null out the payload,
    /// hide the overlay state, THEN call the callback.
    fn invokeConfirmAccept(self: *Host) void {
        const captured = self.confirm_payload orelse {
            self.hideOverlay();
            self.layout() catch {};
            return;
        };
        const cb = captured.on_accept;
        const userdata = captured.userdata;
        // hideOverlay deinits the payload (frees the owned byte
        // slices) and clears `confirm_payload = null`. After this
        // point, no Host-mutating call may touch fields the
        // callback might also reach.
        self.hideOverlay();
        self.layout() catch {};
        cb(userdata);
    }

    fn invokeConfirmCancel(self: *Host) void {
        const captured = self.confirm_payload orelse {
            self.hideOverlay();
            self.layout() catch {};
            return;
        };
        const cb = captured.on_cancel;
        const userdata = captured.userdata;
        self.hideOverlay();
        self.layout() catch {};
        if (cb) |f| f(userdata);
    }

    /// If an active confirm overlay was opened with `ud` as its
    /// userdata, hide + deinit it WITHOUT dispatching the cancel
    /// callback. Called from `Surface.destroy` so a close-while-
    /// confirming doesn't leave the overlay with a dangling Surface
    /// pointer — a later Accept click would otherwise UAF into the
    /// freed surface. Skipping the cancel callback is correct here:
    /// the Surface is already tearing down, nothing to roll back.
    fn cancelConfirmIfOwnedBy(self: *Host, ud: *anyopaque) void {
        const payload = self.confirm_payload orelse return;
        const payload_ud = payload.userdata orelse return;
        if (payload_ud != ud) return;
        // `hideOverlay` deinits the payload (frees owned string
        // bytes and clears `confirm_payload = null`) without
        // invoking on_accept/on_cancel. The Host itself stays live.
        self.hideOverlay();
        self.layout() catch {};
    }

    fn overlayInitialText(self: *Host, mode: HostOverlayMode) ?[]const u8 {
        const surface = self.activeSurface() orelse return null;
        return switch (mode) {
            .none => null,
            .command_palette => null,
            .profile => if (self.selectedProfile()) |profile|
                self.app.core_app.alloc.dupe(u8, profile.key) catch null
            else
                self.app.core_app.alloc.dupe(u8, "") catch null,
            .search => if (surface.search_needle) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else
                self.app.core_app.alloc.dupe(u8, "") catch null,
            .surface_title => if (surface.title_override) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else if (surface.title) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else
                self.app.core_app.alloc.dupe(u8, "") catch null,
            .tab_title => if (surface.tab_title_override) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else if (surface.title_override) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else if (surface.title) |value|
                self.app.core_app.alloc.dupe(u8, value) catch null
            else
                self.app.core_app.alloc.dupe(u8, "") catch null,
            .tab_overview => blk: {
                const status = self.app.hostTabStatus(surface);
                break :blk std.fmt.allocPrint(self.app.core_app.alloc, "{d}", .{status.index + 1}) catch null;
            },
            // Confirm overlays don't carry editable text — the body is
            // held by `confirm_payload.body` and painted by the paint
            // branch. Returning null leaves the hidden EDIT empty.
            .confirm => null,
        };
    }

    fn syncOverlayLabel(self: *Host) !bool {
        const label_hwnd = self.overlay_label_hwnd orelse return false;
        const alloc = self.app.core_app.alloc;
        switch (self.overlay_mode) {
            .none => return try syncWindowTextUtf8Cached(
                alloc,
                label_hwnd,
                &self.cached_overlay_label,
                host_overlay_command_palette_label_utf8,
            ),
            .profile => {
                if (!(try self.ensureProfiles())) {
                    return try syncWindowTextUtf8Cached(
                        alloc,
                        label_hwnd,
                        &self.cached_overlay_label,
                        host_overlay_profile_label_utf8,
                    );
                }
                const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
                const label = try buildProfileOverlayLabel(
                    alloc,
                    self.profiles.?,
                    text,
                    self.selectedProfileIndex() orelse 0,
                );
                defer alloc.free(label);
                return try syncWindowTextUtf8Cached(
                    alloc,
                    label_hwnd,
                    &self.cached_overlay_label,
                    label,
                );
            },
            .surface_title => return try syncWindowTextUtf8Cached(
                alloc,
                label_hwnd,
                &self.cached_overlay_label,
                host_overlay_surface_title_label_utf8,
            ),
            .tab_title => return try syncWindowTextUtf8Cached(
                alloc,
                label_hwnd,
                &self.cached_overlay_label,
                host_overlay_tab_title_label_utf8,
            ),
            .command_palette => {
                const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
                const label = try buildCommandPaletteOverlayLabel(alloc, self.paletteSnapshot(), text);
                defer alloc.free(label);
                return try syncWindowTextUtf8Cached(
                    alloc,
                    label_hwnd,
                    &self.cached_overlay_label,
                    label,
                );
            },
            .search => {
                const surface = self.activeSurface();
                const label = try buildSearchOverlayLabel(
                    alloc,
                    if (surface) |value| value.search_total else null,
                    if (surface) |value| value.search_selected else null,
                );
                defer alloc.free(label);
                return try syncWindowTextUtf8Cached(
                    alloc,
                    label_hwnd,
                    &self.cached_overlay_label,
                    label,
                );
            },
            .tab_overview => {
                const surface = self.activeSurface();
                const status = if (surface) |value| self.app.hostTabStatus(value) else HostTabStatus{};
                const label = try buildTabOverviewOverlayLabel(alloc, status.index, status.total);
                defer alloc.free(label);
                return try syncWindowTextUtf8Cached(
                    alloc,
                    label_hwnd,
                    &self.cached_overlay_label,
                    label,
                );
            },
            .confirm => {
                // Confirm overlays use the payload's title as the
                // label text. Falls back to a sensible default if
                // payload is missing (shouldn't happen; showConfirm
                // guarantees it).
                const title = if (self.confirm_payload) |p|
                    p.title
                else
                    "Confirm";
                return try syncWindowTextUtf8Cached(
                    alloc,
                    label_hwnd,
                    &self.cached_overlay_label,
                    title,
                );
            },
        }
    }

    fn syncOverlayButtons(self: *Host) !bool {
        const accept_hwnd = self.overlay_accept_hwnd orelse return false;
        const cancel_hwnd = self.overlay_cancel_hwnd orelse return false;
        const alloc = self.app.core_app.alloc;
        var changed = false;
        // Confirm overlays pull labels from the payload directly so
        // users get the exact wording the caller chose (e.g. "Close"
        // as a destructive Accept). Skip the generic EDIT-text-driven
        // label computation below since there is no EDIT input.
        if (self.overlay_mode == .confirm) {
            if (self.confirm_payload) |p| {
                changed = (try syncWindowTextUtf8Cached(
                    alloc,
                    accept_hwnd,
                    &self.cached_overlay_accept,
                    p.accept_label,
                )) or changed;
                changed = (try syncWindowTextUtf8Cached(
                    alloc,
                    cancel_hwnd,
                    &self.cached_overlay_cancel,
                    p.cancel_label,
                )) or changed;
            }
            return changed;
        }
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        const surface = self.activeSurface();
        if (self.overlay_mode == .profile) {
            const accept = try buildProfileAcceptLabel(
                alloc,
                self.profiles,
                text,
                self.selectedProfileIndex() orelse 0,
                self.app.launcher_profile_target,
            );
            defer alloc.free(accept);
            changed = (try syncWindowTextUtf8Cached(
                alloc,
                accept_hwnd,
                &self.cached_overlay_accept,
                accept,
            )) or changed;
            changed = (try syncWindowTextUtf8Cached(
                alloc,
                cancel_hwnd,
                &self.cached_overlay_cancel,
                overlayCancelLabel(self.overlay_mode),
            )) or changed;
            return changed;
        }
        const accept = try buildOverlayAcceptLabel(
            alloc,
            self.overlay_mode,
            text,
            if (surface) |value| value.search_needle else null,
            if (surface) |value| value.search_total else null,
            if (surface) |value| value.search_selected else null,
            self.paletteSnapshot(),
        );
        defer alloc.free(accept);
        changed = (try syncWindowTextUtf8Cached(
            alloc,
            accept_hwnd,
            &self.cached_overlay_accept,
            accept,
        )) or changed;
        changed = (try syncWindowTextUtf8Cached(
            alloc,
            cancel_hwnd,
            &self.cached_overlay_cancel,
            overlayCancelLabel(self.overlay_mode),
        )) or changed;
        return changed;
    }

    fn syncOverlayHint(self: *Host) !bool {
        const hint_hwnd = self.overlay_hint_hwnd orelse return false;
        const alloc = self.app.core_app.alloc;
        // Confirm overlays use the hint HWND to render the payload
        // body — the explanatory text ("A process is still running…").
        // Make it visible and write the body; bypass the generic
        // EDIT-driven hint composition.
        if (self.overlay_mode == .confirm) {
            const body = if (self.confirm_payload) |p| p.body else "";
            _ = applyChildVisibility(hint_hwnd, &self.overlay_hint_placement, true);
            return try syncWindowTextUtf8Cached(
                alloc,
                hint_hwnd,
                &self.cached_overlay_hint,
                body,
            );
        }
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        if (self.overlay_mode == .profile) {
            const hint = try buildProfileHintText(
                alloc,
                self.profiles,
                text,
                self.selectedProfileIndex() orelse 0,
                self.app.launcher_profile_target,
                self.app.launcher_quick_slot_keys,
            );
            defer alloc.free(hint);
            return try syncWindowTextUtf8Cached(
                alloc,
                hint_hwnd,
                &self.cached_overlay_hint,
                hint,
            );
        }
        const surface = self.activeSurface();
        var mru_buf: [5][]const u8 = undefined;
        const mru = self.app.paletteMruSlice(&mru_buf);
        const hint = try buildOverlayHintText(
            alloc,
            self.overlay_mode,
            text,
            if (surface) |value| value.search_needle else null,
            if (surface) |value| value.search_total else null,
            if (surface) |value| value.search_selected else null,
            if (surface) |value| self.app.hostTabStatus(value) else .{},
            if (self.activeTab()) |tab| tab.leafCount() else 1,
            self.paletteSnapshot(),
            mru,
        );
        defer alloc.free(hint);
        return try syncWindowTextUtf8Cached(
            alloc,
            hint_hwnd,
            &self.cached_overlay_hint,
            hint,
        );
    }

    fn clearOverlayCompletion(self: *Host) void {
        if (self.overlay_completion_seed) |value| self.app.core_app.alloc.free(value);
        if (self.overlay_completion_value) |value| self.app.core_app.alloc.free(value);
        self.overlay_completion_seed = null;
        self.overlay_completion_value = null;
    }

    fn ensureThemeBrushes(self: *Host) !void {
        const theme = &self.app.resolved_theme;
        if (self.chrome_brush == null) {
            self.chrome_brush = CreateSolidBrush(theme.chrome_bg) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        if (self.overlay_brush == null) {
            self.overlay_brush = CreateSolidBrush(theme.overlay_bg) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        if (self.edit_brush == null) {
            self.edit_brush = CreateSolidBrush(theme.edit_bg) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn rebuildThemeBrushes(self: *Host) void {
        if (self.chrome_brush) |brush| _ = DeleteObject(brush);
        if (self.overlay_brush) |brush| _ = DeleteObject(brush);
        if (self.edit_brush) |brush| _ = DeleteObject(brush);
        self.chrome_brush = null;
        self.overlay_brush = null;
        self.edit_brush = null;
        self.ensureThemeBrushes() catch {};
    }

    fn createChromeFont(self: *Host) ?*anyopaque {
        var lf: LOGFONTW = .{};
        lf.lfHeight = -self.scaled(14);
        lf.lfWeight = FW_NORMAL;

        // Try config font family first
        if (self.app.config.@"window-title-font-family") |family| {
            const name_w = std.unicode.utf8ToUtf16LeAllocZ(self.app.core_app.alloc, family) catch return null;
            defer self.app.core_app.alloc.free(name_w);
            const copy_len = @min(name_w.len, LF_FACESIZE - 1);
            @memcpy(lf.lfFaceName[0..copy_len], name_w[0..copy_len]);
        } else {
            // Fallback: system UI font via NONCLIENTMETRICS
            var ncm: NONCLIENTMETRICSW = undefined;
            ncm.cbSize = @sizeOf(NONCLIENTMETRICSW);
            if (SystemParametersInfoW(SPI_GETNONCLIENTMETRICS, @sizeOf(NONCLIENTMETRICSW), @ptrCast(&ncm), 0) != 0) {
                lf = ncm.lfMessageFont;
                lf.lfHeight = -self.scaled(14);
                lf.lfQuality = CLEARTYPE_QUALITY;
            }
        }

        return CreateFontIndirectW(&lf);
    }

    fn createTitlebarIconFont(self: *Host, logical_px: i32) ?*anyopaque {
        return self.createTitlebarIconFontForFace(titlebar_icon_font_fluent, logical_px) orelse
            self.createTitlebarIconFontForFace(titlebar_icon_font_mdl2, logical_px);
    }

    fn createTitlebarIconFontForFace(
        self: *Host,
        face: [*:0]const u16,
        logical_px: i32,
    ) ?*anyopaque {
        var lf: LOGFONTW = .{};
        lf.lfHeight = -self.scaled(logical_px);
        lf.lfWeight = FW_NORMAL;
        lf.lfQuality = CLEARTYPE_QUALITY;
        const name = std.mem.span(face);
        const copy_len = @min(name.len, LF_FACESIZE - 1);
        @memcpy(lf.lfFaceName[0..copy_len], name[0..copy_len]);
        return CreateFontIndirectW(&lf);
    }

    fn recreateTitlebarIconFonts(self: *Host) void {
        if (self.titlebar_caption_icon_font) |old| _ = DeleteObject(old);
        if (self.titlebar_action_icon_font) |old| _ = DeleteObject(old);
        self.titlebar_caption_icon_font = self.createTitlebarIconFont(10);
        self.titlebar_action_icon_font = self.createTitlebarIconFont(12);
    }

    fn recreateChromeFont(self: *Host) void {
        if (self.chrome_font) |old| _ = DeleteObject(old);
        self.chrome_font = self.createChromeFont();
        self.recreateTitlebarIconFonts();
        // Send WM_SETFONT to child controls
        if (self.chrome_font) |font| {
            if (self.overlay_edit_hwnd) |edit| _ = SendMessageW(edit, WM_SETFONT, @intFromPtr(font), 1);
            if (self.overlay_label_hwnd) |label| _ = SendMessageW(label, WM_SETFONT, @intFromPtr(font), 1);
            if (self.overlay_hint_hwnd) |hint| _ = SendMessageW(hint, WM_SETFONT, @intFromPtr(font), 1);
            for (self.app.windows.items) |surface| {
                if (surface.host != self) continue;
                surface.applySearchBarFont(font);
            }
        }
    }

    fn ensureSearchTimer(self: *Host) void {
        if (self.search_timer_active) return;
        const hwnd = self.hwnd orelse return;
        _ = SetTimer(hwnd, SEARCH_TIMER_ID, SEARCH_TIMER_INTERVAL_MS, null);
        self.search_timer_active = true;
    }

    fn killSearchTimer(self: *Host) void {
        if (!self.search_timer_active) return;
        if (self.hwnd) |hwnd| _ = KillTimer(hwnd, SEARCH_TIMER_ID);
        self.search_timer_active = false;
    }

    fn refreshSearchTimerState(self: *Host) void {
        const tab = self.activeTab() orelse {
            self.killSearchTimer();
            return;
        };

        var wants_timer = false;
        var it = tab.tree.iterator();
        while (it.next()) |entry| {
            if (!entry.view.search_bar.visible) continue;
            if (entry.view.search_bar.query.len == 0) continue;
            if (!entry.view.search_bar.searched) {
                wants_timer = true;
                break;
            }
        }

        if (wants_timer) self.ensureSearchTimer() else self.killSearchTimer();
    }

    fn tickSearchBars(self: *Host) void {
        const now_ms: i64 = @intCast(GetTickCount64());
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                if (!entry.view.search_bar.visible) continue;
                if (!entry.view.search_bar.shouldRunSearch(now_ms)) continue;
                _ = entry.view.runPendingSearchNow() catch |err| {
                    log.warn("win32 search refresh failed err={}", .{err});
                    continue;
                };
            }
        }
        self.refreshSearchTimerState();
    }

    fn ensureScrollbarTimer(self: *Host) void {
        if (self.scrollbar_timer_active) return;
        const hwnd = self.hwnd orelse return;
        _ = SetTimer(hwnd, SCROLLBAR_TIMER_ID, SCROLLBAR_TIMER_INTERVAL_MS, null);
        self.scrollbar_timer_active = true;
    }

    fn killScrollbarTimer(self: *Host) void {
        if (!self.scrollbar_timer_active) return;
        if (self.hwnd) |hwnd| _ = KillTimer(hwnd, SCROLLBAR_TIMER_ID);
        self.scrollbar_timer_active = false;
    }

    fn refreshScrollbarTimerState(self: *Host) void {
        const tab = self.activeTab() orelse {
            self.killScrollbarTimer();
            return;
        };

        var wants_timer = false;
        var it = tab.tree.iterator();
        while (it.next()) |entry| {
            if (entry.view.scrollbarNeedsHeartbeat()) {
                wants_timer = true;
                break;
            }
        }

        if (wants_timer) self.ensureScrollbarTimer() else self.killScrollbarTimer();
    }

    fn tickScrollbars(self: *Host) void {
        const now_ms = GetTickCount64();
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                entry.view.tickScrollbar(now_ms);
            }
        }
        self.refreshScrollbarTimerState();
    }

    fn showContextMenu(self: *Host, screen_x: i32, screen_y: i32) void {
        const hwnd = self.hwnd orelse return;
        const menu = CreatePopupMenu() orelse return;
        defer _ = DestroyMenu(menu);

        // Check if active surface has a selection
        const has_selection = if (self.activeSurface()) |s| blk: {
            if (!s.core_initialized) break :blk false;
            break :blk s.core_surface.hasSelection();
        } else false;

        _ = AppendMenuW(menu, if (has_selection) MF_STRING else MF_GRAYED, CTX_COPY, std.unicode.utf8ToUtf16LeStringLiteral("Copy\tCtrl+Shift+C"));
        _ = AppendMenuW(menu, MF_STRING, CTX_PASTE, std.unicode.utf8ToUtf16LeStringLiteral("Paste\tCtrl+Shift+V"));
        _ = AppendMenuW(menu, MF_STRING, CTX_SELECT_ALL, std.unicode.utf8ToUtf16LeStringLiteral("Select All"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        _ = AppendMenuW(menu, MF_STRING, CTX_FIND, std.unicode.utf8ToUtf16LeStringLiteral("Find...\tCtrl+Shift+F"));
        _ = AppendMenuW(menu, MF_STRING, CTX_COMMAND_PALETTE, std.unicode.utf8ToUtf16LeStringLiteral("Command Palette\tCtrl+Shift+P"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        _ = AppendMenuW(menu, MF_STRING, CTX_NEW_TAB, std.unicode.utf8ToUtf16LeStringLiteral("New Tab"));

        // Split submenu with all four directions
        const split_menu = CreatePopupMenu() orelse return;
        _ = AppendMenuW(split_menu, MF_STRING, CTX_SPLIT_RIGHT, std.unicode.utf8ToUtf16LeStringLiteral("Split Right"));
        _ = AppendMenuW(split_menu, MF_STRING, CTX_SPLIT_DOWN, std.unicode.utf8ToUtf16LeStringLiteral("Split Down"));
        _ = AppendMenuW(split_menu, MF_STRING, CTX_SPLIT_LEFT, std.unicode.utf8ToUtf16LeStringLiteral("Split Left"));
        _ = AppendMenuW(split_menu, MF_STRING, CTX_SPLIT_UP, std.unicode.utf8ToUtf16LeStringLiteral("Split Up"));
        _ = AppendMenuW(menu, MF_POPUP, @intFromPtr(split_menu), std.unicode.utf8ToUtf16LeStringLiteral("Split"));

        _ = AppendMenuW(menu, MF_STRING, CTX_NEW_WINDOW, std.unicode.utf8ToUtf16LeStringLiteral("New Window"));

        // Menu must be owned by top-level host HWND to avoid dismiss bugs
        _ = SetForegroundWindow(hwnd);
        const cmd = TrackPopupMenu(menu, TPM_RETURNCMD | TPM_RIGHTBUTTON | TPM_LEFTALIGN | TPM_TOPALIGN, screen_x, screen_y, 0, hwnd, null);
        _ = PostMessageW(hwnd, WM_NULL, 0, 0);

        // Dispatch command (cmd is 0 on cancel)
        self.handleContextMenuCommand(cmd);
    }

    fn handleContextMenuCommand(self: *Host, cmd: BOOL) void {
        if (cmd <= 0) return; // 0 = cancel/dismiss
        const surface = self.activeSurface() orelse return;
        if (!surface.core_initialized) return;

        switch (@as(usize, @intCast(cmd))) {
            CTX_COPY => {
                _ = surface.core_surface.performBindingAction(.{ .copy_to_clipboard = .mixed }) catch {};
            },
            CTX_PASTE => {
                _ = surface.core_surface.performBindingAction(.{ .paste_from_clipboard = {} }) catch {};
            },
            CTX_SELECT_ALL => {
                _ = surface.core_surface.performBindingAction(.{ .select_all = {} }) catch {};
            },
            CTX_FIND => {
                surface.showSearchOverlay("") catch {};
            },
            CTX_COMMAND_PALETTE => {
                _ = surface.toggleCommandPalette() catch {};
            },
            CTX_NEW_TAB => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_tab, {}) catch {};
            },
            CTX_SPLIT_RIGHT => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_split, .right) catch {};
            },
            CTX_SPLIT_DOWN => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_split, .down) catch {};
            },
            CTX_SPLIT_LEFT => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_split, .left) catch {};
            },
            CTX_SPLIT_UP => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_split, .up) catch {};
            },
            CTX_NEW_WINDOW => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_window, .{}) catch {};
            },
            else => {}, // 0 = cancel, ignore
        }
    }

    fn showTabContextMenu(self: *Host, button_hwnd: HWND, tab_index: usize) void {
        const hwnd = self.hwnd orelse return;
        const menu = CreatePopupMenu() orelse return;
        defer _ = DestroyMenu(menu);

        _ = AppendMenuW(menu, MF_STRING, CTX_TAB_RENAME, std.unicode.utf8ToUtf16LeStringLiteral("Rename Tab"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        _ = AppendMenuW(menu, MF_STRING, CTX_TAB_MOVE_LEFT, std.unicode.utf8ToUtf16LeStringLiteral("Move Tab Left"));
        _ = AppendMenuW(menu, MF_STRING, CTX_TAB_MOVE_RIGHT, std.unicode.utf8ToUtf16LeStringLiteral("Move Tab Right"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);

        // Only allow closing if there's more than one tab
        const close_flag: UINT = if (self.tabs.items.len > 1) MF_STRING else MF_GRAYED;
        _ = AppendMenuW(menu, close_flag, CTX_TAB_CLOSE, std.unicode.utf8ToUtf16LeStringLiteral("Close Tab"));
        _ = AppendMenuW(menu, if (self.tabs.items.len > 1) MF_STRING else MF_GRAYED, CTX_TAB_CLOSE_OTHERS, std.unicode.utf8ToUtf16LeStringLiteral("Close Other Tabs"));

        // Position below the tab button
        var rect: RECT = undefined;
        if (GetWindowRect(button_hwnd, &rect) == 0) return;

        _ = SetForegroundWindow(hwnd);
        const cmd = TrackPopupMenu(menu, TPM_RETURNCMD | TPM_RIGHTBUTTON | TPM_LEFTALIGN | TPM_TOPALIGN, rect.left, rect.bottom, 0, hwnd, null);
        _ = PostMessageW(hwnd, WM_NULL, 0, 0);

        if (cmd <= 0) return;
        const surface = self.activeSurface() orelse return;
        if (!surface.core_initialized) return;

        switch (@as(usize, @intCast(cmd))) {
            CTX_TAB_RENAME => {
                surface.promptTitle(.tab) catch {};
            },
            CTX_TAB_CLOSE => {
                _ = self.app.closeTab(.{ .surface = surface.core() }, .this) catch |err| {
                    log.warn("close_tab action failed err={}", .{err});
                };
            },
            CTX_TAB_CLOSE_OTHERS => {
                _ = self.app.closeTab(.{ .surface = surface.core() }, .other) catch |err| {
                    log.warn("close_tab other action failed err={}", .{err});
                };
            },
            CTX_TAB_MOVE_LEFT => {
                _ = self.app.moveTab(.{ .surface = surface.core() }, .{ .amount = -1 }) catch {};
            },
            CTX_TAB_MOVE_RIGHT => {
                _ = self.app.moveTab(.{ .surface = surface.core() }, .{ .amount = 1 }) catch {};
            },
            else => {},
        }
        _ = tab_index;
    }

    fn showOverflowMenu(self: *Host) void {
        const alloc = self.app.core_app.alloc;
        const hwnd = self.hwnd orelse return;
        const button = self.overflow_hwnd orelse return;

        // Ensure profiles are loaded before building the menu
        _ = self.ensureProfiles() catch {};

        // Position menu below the dropdown chevron button
        var rect: RECT = undefined;
        if (GetWindowRect(button, &rect) == 0) return;

        const menu = CreatePopupMenu() orelse return;
        defer _ = DestroyMenu(menu);

        // Profile list — each profile gets a numbered shortcut hint
        const selected_idx = self.selectedProfileIndex();
        if (self.profiles) |profiles| {
            for (profiles, 0..) |*profile, i| {
                const label_utf8 = buildDropdownProfileLabel(alloc, profile, i) catch continue;
                defer alloc.free(label_utf8);
                const label_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, label_utf8) catch continue;
                defer alloc.free(label_w);
                const is_selected = selected_idx != null and selected_idx.? == i;
                const flags: UINT = if (is_selected) MF_STRING | MF_CHECKED else MF_STRING;
                _ = AppendMenuW(menu, flags, CTX_PROFILE_BASE + i, label_w.ptr);
            }
            if (profiles.len > 0) _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        }

        // Utility items
        _ = AppendMenuW(menu, MF_STRING, CTX_NEW_TAB, std.unicode.utf8ToUtf16LeStringLiteral("Open a new tab"));
        _ = AppendMenuW(menu, MF_STRING, CTX_NEW_WINDOW, std.unicode.utf8ToUtf16LeStringLiteral("New Window"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        _ = AppendMenuW(menu, MF_STRING, CTX_COMMAND_PALETTE, std.unicode.utf8ToUtf16LeStringLiteral("Command Palette\tCtrl+Shift+P"));
        _ = AppendMenuW(menu, MF_STRING, CTX_FIND, std.unicode.utf8ToUtf16LeStringLiteral("Find...\tCtrl+Shift+F"));
        _ = AppendMenuW(menu, MF_SEPARATOR, 0, null);
        _ = AppendMenuW(menu, MF_STRING, CTX_INSPECTOR, std.unicode.utf8ToUtf16LeStringLiteral("Toggle Inspector"));

        _ = SetForegroundWindow(hwnd);
        const cmd = TrackPopupMenu(menu, TPM_RETURNCMD | TPM_RIGHTBUTTON | TPM_LEFTALIGN | TPM_TOPALIGN, rect.left, rect.bottom, 0, hwnd, null);
        _ = PostMessageW(hwnd, WM_NULL, 0, 0);

        // Guard: host may have been destroyed during the modal menu loop
        if (self.hwnd == null) return;
        self.handleOverflowMenuCommand(cmd);
    }

    fn handleOverflowMenuCommand(self: *Host, cmd: BOOL) void {
        if (cmd <= 0) return;
        const cmd_id = @as(usize, @intCast(cmd));

        // Profile item dispatch — open the selected profile in a new tab
        if (cmd_id >= CTX_PROFILE_BASE and cmd_id < CTX_PROFILE_BASE + 100) {
            const profile_index = cmd_id - CTX_PROFILE_BASE;
            // Validate index against current profiles (may have changed during modal menu)
            if (self.profiles) |profiles| {
                if (profile_index < profiles.len) {
                    _ = self.quickOpenProfileIndex(profile_index, .tab);
                }
            }
            return;
        }

        const surface = self.activeSurface() orelse return;
        if (!surface.core_initialized) return;

        switch (cmd_id) {
            CTX_COMMAND_PALETTE => {
                _ = surface.toggleCommandPalette() catch {};
            },
            CTX_FIND => {
                surface.showSearchOverlay("") catch {};
            },
            CTX_NEW_TAB => {
                _ = self.openSelectedProfileOrFallback(.tab);
            },
            CTX_NEW_WINDOW => {
                _ = self.app.performAction(.{ .surface = surface.core() }, .new_window, .{}) catch {};
            },
            CTX_INSPECTOR => {
                _ = self.app.toggleInspectorForSurface(surface) catch {};
            },
            else => {},
        }
    }

    fn isOverlayButton(self: *const Host, child: HWND) bool {
        return (self.overlay_accept_hwnd != null and child == self.overlay_accept_hwnd.?) or
            (self.overlay_cancel_hwnd != null and child == self.overlay_cancel_hwnd.?);
    }

    fn searchControlSurface(self: *const Host, child: HWND) ?*Surface {
        for (self.app.windows.items) |surface| {
            if (surface.host != self) continue;
            if (surface.ownsSearchBarControl(child)) return surface;
        }
        return null;
    }

    fn searchBarBackgroundSurface(self: *const Host, child: HWND) ?*Surface {
        for (self.app.windows.items) |surface| {
            if (surface.host != self) continue;
            if (surface.search_bar_bg_hwnd != null and child == surface.search_bar_bg_hwnd.?) {
                return surface;
            }
        }
        return null;
    }

    fn isSearchBarButton(self: *const Host, child: HWND) bool {
        const surface = self.searchControlSurface(child) orelse return false;
        return surface.searchBarButtonRole(child) != null;
    }

    fn isSearchBarResultsLabel(self: *const Host, child: HWND) bool {
        const surface = self.searchControlSurface(child) orelse return false;
        return surface.search_bar_results_hwnd != null and child == surface.search_bar_results_hwnd.?;
    }

    fn searchBarButtonRole(self: *const Host, child: HWND) ?SearchBarButtonRole {
        const surface = self.searchControlSurface(child) orelse return null;
        return surface.searchBarButtonRole(child);
    }

    fn searchBarButtonIcon(self: *const Host, child: HWND) ?win32_icons.Kind {
        return switch (self.searchBarButtonRole(child) orelse return null) {
            .prev => .arrow_up,
            .next => .arrow_down,
            .regex => .regex,
            .case_sensitive => .case_sens,
            .whole_word => .whole_word,
            .close => .close,
        };
    }

    fn searchBarButtonColors(
        self: *const Host,
        role: SearchBarButtonRole,
        active: bool,
        hovered: bool,
        pressed: bool,
        disabled: bool,
    ) ButtonColors {
        const theme = &self.app.resolved_theme;
        if (disabled) return buttonColorsFromTheme(theme, active, true, hovered, pressed, true, false);

        const accent = overlayAccentColor(.search, theme.is_dark);
        const toolbar = searchBarToolbarVisual(theme);
        var colors: ButtonColors = .{
            .bg = searchBarButtonParentBg(theme, role),
            .border = searchBarButtonParentBg(theme, role),
            .fg = theme.text_secondary,
        };
        switch (role) {
            .prev, .next => {},
            .regex, .case_sensitive, .whole_word => {
                if (active) {
                    colors.bg = if (pressed)
                        blendColorRGB(accent, toolbar.bg, if (theme.is_dark) 0.42 else 0.28)
                    else if (hovered)
                        blendColorRGB(accent, toolbar.bg, if (theme.is_dark) 0.36 else 0.22)
                    else
                        blendColorRGB(accent, toolbar.bg, if (theme.is_dark) 0.30 else 0.18);
                    colors.border = colors.bg;
                    colors.fg = theme.text_primary;
                } else {
                    colors.bg = if (pressed)
                        adjustColor(toolbar.bg, -10, -8, -8)
                    else if (hovered)
                        adjustColor(toolbar.bg, 6, 8, 8)
                    else
                        toolbar.bg;
                    colors.border = colors.bg;
                    colors.fg = if (hovered) theme.text_primary else theme.text_secondary;
                }
            },
            .close => {
                colors.bg = if (pressed)
                    blendColorRGB(theme.error_fg, theme.overlay_bg, if (theme.is_dark) 0.18 else 0.12)
                else if (hovered)
                    blendColorRGB(theme.error_fg, theme.overlay_bg, if (theme.is_dark) 0.12 else 0.08)
                else
                    theme.overlay_bg;
                colors.border = colors.bg;
                colors.fg = if (hovered or pressed) theme.error_fg else theme.text_secondary;
            },
        }
        if (role == .prev or role == .next) {
            colors.bg = if (pressed)
                adjustColor(toolbar.bg, -10, -8, -8)
            else if (hovered)
                adjustColor(toolbar.bg, 6, 8, 8)
            else
                toolbar.bg;
            colors.border = colors.bg;
            colors.fg = if (hovered or pressed) theme.text_primary else theme.text_secondary;
        }
        return colors;
    }

    fn drawSearchBarBackground(self: *Host, draw: *const DRAWITEMSTRUCT) bool {
        if (draw.CtlType != ODT_STATIC) return false;
        const surface = self.searchBarBackgroundSurface(draw.hwndItem) orelse return false;

        const theme = &self.app.resolved_theme;
        const frame_rect = draw.rcItem;
        fillSolidRect(draw.hDC, frame_rect, theme.chrome_bg);
        drawRoundedRect(
            draw.hDC,
            frame_rect,
            searchBarFrameBg(theme),
            searchBarFrameBorder(theme),
            self.scaled(8),
        );
        fillSolidRect(draw.hDC, .{
            .left = frame_rect.left + self.scaled(8),
            .top = frame_rect.bottom - 1,
            .right = frame_rect.right - self.scaled(8),
            .bottom = frame_rect.bottom,
        }, searchBarBottomLine(theme));

        const origin_x = surface.search_bar_frame_rect.left;
        const origin_y = surface.search_bar_frame_rect.top;
        if (searchBarGroupRect(&[_]ChildPlacement{
            surface.search_bar_results_placement,
            surface.search_bar_prev_placement,
            surface.search_bar_next_placement,
            surface.search_bar_regex_placement,
            surface.search_bar_case_placement,
            surface.search_bar_word_placement,
        }, self.scaled(4), self.scaled(2))) |host_toolbar_rect| {
            const toolbar_rect = rectOffset(host_toolbar_rect, -origin_x, -origin_y);
            const toolbar = searchBarToolbarVisual(theme);
            drawRoundedRect(
                draw.hDC,
                toolbar_rect,
                toolbar.bg,
                toolbar.border,
                self.scaled(7),
            );

            const sep_top = toolbar_rect.top + self.scaled(6);
            const sep_bottom = toolbar_rect.bottom - self.scaled(6);
            if (sep_bottom > sep_top) {
                if (searchBarSeparatorX(
                    surface.search_bar_results_placement,
                    surface.search_bar_prev_placement,
                )) |host_sep_x| {
                    const sep_x = host_sep_x - origin_x;
                    fillSolidRect(draw.hDC, .{
                        .left = sep_x,
                        .top = sep_top,
                        .right = sep_x + 1,
                        .bottom = sep_bottom,
                    }, toolbar.separator);
                }
                if (searchBarSeparatorX(
                    surface.search_bar_prev_placement,
                    surface.search_bar_next_placement,
                )) |host_sep_x| {
                    const sep_x = host_sep_x - origin_x;
                    fillSolidRect(draw.hDC, .{
                        .left = sep_x,
                        .top = sep_top,
                        .right = sep_x + 1,
                        .bottom = sep_bottom,
                    }, toolbar.separator);
                }
                if (searchBarSeparatorX(
                    surface.search_bar_next_placement,
                    surface.search_bar_regex_placement,
                )) |host_sep_x| {
                    const sep_x = host_sep_x - origin_x;
                    fillSolidRect(draw.hDC, .{
                        .left = sep_x,
                        .top = sep_top,
                        .right = sep_x + 1,
                        .bottom = sep_bottom,
                    }, toolbar.separator);
                }
            }
        }

        if (surface.search_bar_edit_placement.rect_known) {
            const edit_rect = rectOffset(surface.search_bar_edit_placement.rect, -origin_x, -origin_y);
            const edit_focused = if (surface.search_bar_edit_hwnd) |edit_hwnd|
                GetFocus() == edit_hwnd
            else
                false;
            const edit_frame_rect = RECT{
                .left = edit_rect.left - self.scaled(1),
                .top = edit_rect.top - self.scaled(1),
                .right = edit_rect.right + self.scaled(1),
                .bottom = edit_rect.bottom + self.scaled(1),
            };
            drawRoundedRect(
                draw.hDC,
                edit_frame_rect,
                theme.edit_frame_bg,
                theme.edit_frame_bg,
                self.scaled(6),
            );
            if (edit_focused) {
                fillSolidRect(draw.hDC, .{
                    .left = edit_frame_rect.left + self.scaled(8),
                    .top = edit_frame_rect.bottom - self.scaled(2),
                    .right = edit_frame_rect.right - self.scaled(8),
                    .bottom = edit_frame_rect.bottom,
                }, overlayAccentColor(.search, theme.is_dark));
            }
        }

        return true;
    }

    fn drawSearchBarButton(
        self: *Host,
        draw: *const DRAWITEMSTRUCT,
        role: SearchBarButtonRole,
        icon: win32_icons.Kind,
        disabled: bool,
        pressed: bool,
        focused: bool,
        hovered: bool,
        active: bool,
    ) void {
        const theme = &self.app.resolved_theme;
        const colors = self.searchBarButtonColors(role, active, hovered, pressed, disabled);
        const show_label = searchBarButtonShowsLabel(role, draw.rcItem.right - draw.rcItem.left);
        const bg_rect = rectInset(draw.rcItem, self.scaled(2), self.scaled(2));
        const parent_bg = searchBarButtonParentBg(theme, role);

        fillSolidRect(draw.hDC, draw.rcItem, parent_bg);
        drawRoundedRect(draw.hDC, bg_rect, colors.bg, colors.border, self.scaled(4));

        if (focused and !disabled) {
            drawRoundedRect(
                draw.hDC,
                rectInset(bg_rect, self.scaled(2), self.scaled(2)),
                colors.bg,
                overlayAccentColor(.search, theme.is_dark),
                self.scaled(3),
            );
        }

        const content_rect = rectInset(bg_rect, self.scaled(7), self.scaled(5));
        _ = SetBkMode(draw.hDC, TRANSPARENT);
        _ = SetTextColor(draw.hDC, colors.fg);

        if (show_label) {
            var text_buf: [160]u16 = undefined;
            const text_len = GetWindowTextW(draw.hwndItem, &text_buf, text_buf.len);
            const icon_box_w = @min(content_rect.bottom - content_rect.top, self.scaled(18));
            const icon_rect = RECT{
                .left = content_rect.left,
                .top = content_rect.top,
                .right = content_rect.left + icon_box_w,
                .bottom = content_rect.bottom,
            };
            win32_icons.drawIcon(icon, draw.hDC.?, .{
                .left = icon_rect.left,
                .top = icon_rect.top,
                .right = icon_rect.right,
                .bottom = icon_rect.bottom,
            }, colors.fg, isHighContrastActive());

            var label_rect = content_rect;
            label_rect.left = icon_rect.right + self.scaled(5);
            _ = DrawTextW(
                draw.hDC,
                @ptrCast(&text_buf),
                text_len,
                &label_rect,
                DT_LEFT | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
            );
            return;
        }

        win32_icons.drawIcon(icon, draw.hDC.?, .{
            .left = content_rect.left,
            .top = content_rect.top,
            .right = content_rect.right,
            .bottom = content_rect.bottom,
        }, colors.fg, isHighContrastActive());

        if (active and (role == .regex or role == .case_sensitive or role == .whole_word)) {
            fillSolidRect(draw.hDC, .{
                .left = bg_rect.left + self.scaled(6),
                .top = bg_rect.bottom - self.scaled(3),
                .right = bg_rect.right - self.scaled(6),
                .bottom = bg_rect.bottom - self.scaled(1),
            }, overlayAccentColor(.search, theme.is_dark));
        }
    }

    fn isOverlayStyledButton(self: *const Host, child: HWND) bool {
        return self.isOverlayButton(child) or self.isSearchBarButton(child);
    }

    fn isActiveChromeButton(self: *Host, child: HWND) bool {
        if (self.isActiveTabButton(child)) return true;
        const surface = self.searchControlSurface(child) orelse return false;
        const role = surface.searchBarButtonRole(child) orelse return false;
        return surface.searchBarButtonActive(role);
    }

    fn drawTitlebarActionButton(
        self: *Host,
        draw: *const DRAWITEMSTRUCT,
        role: TitlebarButtonRole,
        disabled: bool,
        pressed: bool,
        focused: bool,
        hovered: bool,
    ) void {
        const theme = &self.app.resolved_theme;
        const parent_bg = theme.chrome_bg;
        const is_hc = isHighContrastActive();
        fillSolidRect(draw.hDC, draw.rcItem, parent_bg);

        var visual = titlebarButtonVisual(
            theme,
            role,
            parent_bg,
            self.titlebarHoverAlpha(role, hovered, GetTickCount64()),
            pressed,
            is_hc,
        );
        if (disabled) {
            visual = .{ .bg = null, .glyph = theme.text_disabled };
        }

        if (visual.bg) |bg| {
            drawRoundedRect(draw.hDC, draw.rcItem, bg, bg, self.scaled(4));
        }
        if (focused and !disabled) {
            drawRoundedRect(
                draw.hDC,
                rectInset(draw.rcItem, self.scaled(2), self.scaled(2)),
                visual.bg orelse parent_bg,
                theme.button_focus_ring,
                self.scaled(3),
            );
        }

        const glyph: TitlebarGlyphKind = switch (role) {
            .new_tab => .new_tab,
            .dropdown => .dropdown,
            else => return,
        };
        self.drawTitlebarGlyph(draw.hDC, draw.rcItem, glyph, visual.glyph, false);
    }

    fn drawButton(self: *Host, draw: *const DRAWITEMSTRUCT) void {
        if (draw.CtlType != ODT_BUTTON) return;
        self.ensureThemeBrushes() catch return;
        if (self.chrome_font) |font| _ = SelectObject(draw.hDC, font);

        const disabled = (draw.itemState & ODS_DISABLED) != 0;
        const pressed = (draw.itemState & ODS_SELECTED) != 0;
        const focused = (draw.itemState & ODS_FOCUS) != 0 or GetFocus() == draw.hwndItem;
        const active = self.isActiveChromeButton(draw.hwndItem);
        const overlay = self.isOverlayStyledButton(draw.hwndItem);
        const hovered = self.isHoveredButton(draw.hwndItem);
        const accept = draw.hwndItem == self.overlay_accept_hwnd;
        const profile_kind = self.buttonProfileKind(draw.hwndItem);
        const pinned_slot_ordinal = self.buttonPinnedSlotOrdinal(draw.hwndItem);
        const launcher_target = self.buttonLauncherTarget(draw.hwndItem);
        const tab_button = self.isTabButton(draw.hwndItem);
        const search_role = self.searchBarButtonRole(draw.hwndItem);
        const icon = self.searchBarButtonIcon(draw.hwndItem);
        const theme = &self.app.resolved_theme;
        if (search_role) |role| {
            self.drawSearchBarButton(
                draw,
                role,
                icon.?,
                disabled,
                pressed,
                focused,
                hovered,
                active,
            );
            return;
        }
        const titlebar_role = self.titlebarActionButtonRole(draw.hwndItem);
        if (titlebar_role != .none) {
            self.drawTitlebarActionButton(
                draw,
                titlebar_role,
                disabled,
                pressed,
                focused,
                hovered,
            );
            return;
        }
        var colors = buttonColorsFromTheme(
            theme,
            active,
            overlay,
            hovered,
            pressed,
            disabled,
            accept,
        );
        if (profile_kind) |kind| {
            colors = applyProfileChromeAccent(colors, kind, theme.is_dark, active, hovered, pressed, disabled);
        }
        if (tab_button and !disabled) {
            colors.fg = if (active or hovered) theme.text_primary else theme.button_chrome_fg;
            if (active) {
                colors.bg = if (theme.is_dark)
                    adjustColor(theme.chrome_bg, 18, 18, 22)
                else
                    adjustColor(theme.chrome_bg, 12, 12, 12);
                colors.border = if (theme.is_dark)
                    adjustColor(theme.accent, -10, -6, -2)
                else
                    theme.accent;
            } else if (hovered) {
                colors.bg = if (theme.is_dark)
                    adjustColor(theme.chrome_bg, 10, 10, 12)
                else
                    adjustColor(theme.chrome_bg, 7, 7, 7);
                colors.border = if (theme.is_dark)
                    adjustColor(theme.chrome_border, 20, 20, 22)
                else
                    adjustColor(theme.chrome_border, -22, -22, -22);
            } else {
                colors.bg = if (theme.is_dark)
                    adjustColor(theme.chrome_bg, 4, 4, 6)
                else
                    adjustColor(theme.chrome_bg, 3, 3, 3);
                colors.border = if (theme.is_dark)
                    adjustColor(theme.chrome_border, 8, 8, 10)
                else
                    adjustColor(theme.chrome_border, -14, -14, -14);
            }
        }
        const bg = colors.bg;
        const border = colors.border;
        const fg = colors.fg;

        // Erase with parent background, then draw rounded button
        const parent_bg = if (overlay) theme.overlay_bg else theme.chrome_bg;
        fillSolidRect(draw.hDC, draw.rcItem, parent_bg);
        drawRoundedRect(draw.hDC, draw.rcItem, bg, border, self.scaled(4));
        if (profile_kind) |kind| {
            const stripe = profileChromeStripeColor(kind, theme.is_dark, active, hovered, pressed, disabled);
            // Inset stripe to fit inside rounded corners
            const corner_inset = self.scaled(4);
            fillSolidRect(draw.hDC, .{
                .left = draw.rcItem.left + 2,
                .top = draw.rcItem.top + corner_inset,
                .right = draw.rcItem.left + self.scaled(4),
                .bottom = draw.rcItem.bottom - corner_inset,
            }, stripe);
            if (pinnedSlotBadgeDigit(pinned_slot_ordinal)) |digit| {
                paintPinnedSlotBadge(
                    draw.hDC,
                    draw.rcItem,
                    digit,
                    colors.border,
                    colors.bg,
                    profileKindLabelColor(kind, theme.is_dark),
                    self.current_dpi,
                );
            }
            if (launcher_target) |target| {
                paintTargetButtonBadge(
                    draw.hDC,
                    draw.rcItem,
                    profileOpenTargetBadgeGlyph(target),
                    colors.border,
                    colors.bg,
                    profileOpenTargetMarkerColor(target),
                    self.current_dpi,
                );
            }
        }
        if (tab_button and !overlay and !disabled and hovered and !active) {
            fillSolidRect(draw.hDC, .{
                .left = draw.rcItem.left + self.scaled(5),
                .top = draw.rcItem.top + self.scaled(3),
                .right = draw.rcItem.right - self.scaled(5),
                .bottom = draw.rcItem.top + self.scaled(5),
            }, border);
        }
        if (focused and !disabled) {
            const focus = if (profile_kind) |kind|
                profileKindFocusRingColor(kind, theme.is_dark)
            else if (accept)
                theme.button_accept_focus_ring
            else if (active)
                theme.button_active_focus_ring
            else if (overlay)
                theme.button_overlay_focus_ring
            else
                theme.button_focus_ring;
            // Rounded focus ring inset inside the button, matching corner radius
            const inset_rect = RECT{
                .left = draw.rcItem.left + self.scaled(2),
                .top = draw.rcItem.top + self.scaled(2),
                .right = draw.rcItem.right - self.scaled(2),
                .bottom = draw.rcItem.bottom - self.scaled(2),
            };
            drawRoundedRect(draw.hDC, inset_rect, bg, focus, self.scaled(3));
        }

        // Per-tab close button: reserve space and determine if close zone is active
        const can_close_tab = tab_button and !overlay and self.tabs.items.len > 1;
        const close_zone_width = if (can_close_tab) self.scaled(host_tab_close_zone_width) else 0;

        var text_buf: [160]u16 = undefined;
        const text_len = GetWindowTextW(draw.hwndItem, &text_buf, text_buf.len);
        _ = SetBkMode(draw.hDC, TRANSPARENT);
        _ = SetTextColor(draw.hDC, fg);
        var text_rect = draw.rcItem;
        if (!overlay) {
            text_rect.left += self.scaled(6);
            text_rect.right -= self.scaled(6);
        }
        if (profile_kind != null) {
            text_rect.left += self.scaled(4);
        }
        text_rect.right -= buttonLabelRightInset(pinned_slot_ordinal, launcher_target);
        text_rect.right -= close_zone_width; // leave room for per-tab close X
        if (icon) |kind| {
            win32_icons.drawIcon(
                kind,
                draw.hDC.?,
                .{
                    .left = text_rect.left,
                    .top = text_rect.top,
                    .right = text_rect.right,
                    .bottom = text_rect.bottom,
                },
                fg,
                isHighContrastActive(),
            );
        } else {
            _ = DrawTextW(
                draw.hDC,
                @ptrCast(&text_buf),
                text_len,
                &text_rect,
                DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
            );
        }

        // Per-tab close X glyph. Active tabs keep the X fully opaque
        // (it's a permanent affordance the user can always click).
        // Inactive tabs fade the X in/out based on hover via
        // `win32_tab_visual.CloseState` — matches Windows Terminal's
        // hover treatment. On non-hovered + non-active tabs the alpha
        // drops to 0 so the X vanishes entirely.
        if (can_close_tab) {
            const now = GetTickCount64();
            // Two animation slots: the incoming hover target
            // (`tab_close_hover_*` fades 0 → 1) and the departing tab
            // on adjacent transitions (`tab_close_prev_*` fades
            // 1 → 0). Tabs that match neither slot use alpha 0 for
            // idle and 1 for active.
            const is_hover_target = self.tab_close_hover_hwnd != null and
                self.tab_close_hover_hwnd.? == draw.hwndItem;
            const is_prev_target = self.tab_close_prev_hwnd != null and
                self.tab_close_prev_hwnd.? == draw.hwndItem;
            const alpha: f32 = if (active)
                1.0
            else if (is_hover_target)
                self.tab_close_hover.alphaAt(now)
            else if (is_prev_target)
                self.tab_close_prev.alphaAt(now)
            else if (hovered)
                1.0 // hovered but not via CloseState (e.g. first paint)
            else
                0.0;
            if (alpha > 0.01) {
                const close_glyph = comptime std.unicode.utf8ToUtf16LeStringLiteral("\u{00D7}"); // ×
                const close_fg_full = if (hovered or active) theme.text_primary else theme.text_secondary;
                // Alpha-blend the glyph colour against the tab bg —
                // GDI's DrawTextW has no alpha channel, so we
                // pre-composite.
                const blended = blendColorRGB(bg, close_fg_full, alpha);
                _ = SetTextColor(draw.hDC, blended);
                var close_rect = RECT{
                    .left = draw.rcItem.right - close_zone_width,
                    .top = draw.rcItem.top,
                    .right = draw.rcItem.right - self.scaled(2),
                    .bottom = draw.rcItem.bottom,
                };
                _ = DrawTextW(
                    draw.hDC,
                    close_glyph,
                    1,
                    &close_rect,
                    DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX,
                );
            }
        }

        // Focused-tab underline is painted on the PARENT HWND in
        // `paintChrome` so that the single accent rect can slide
        // between tab buttons over `win32_tab_visual.underline_slide_ms`.
        // Painting it inside the child button would produce a hard cut
        // on focus change.
    }

    fn buttonProfileKind(self: *Host, hwnd: HWND) ?windows_shell.ProfileKind {
        const profile = self.selectedProfile() orelse return null;
        if (self.overlay_mode == .profile and self.overlay_accept_hwnd != null and hwnd == self.overlay_accept_hwnd.?) {
            return profile.kind;
        }
        return null;
    }

    fn buttonPinnedSlotOrdinal(self: *Host, hwnd: HWND) ?usize {
        const profile = self.selectedProfile() orelse return null;
        if (self.overlay_mode == .profile and self.overlay_accept_hwnd != null and hwnd == self.overlay_accept_hwnd.?) {
            return self.app.launcherQuickSlotOrdinal(profile.key);
        }
        return null;
    }

    fn buttonLauncherTarget(self: *Host, hwnd: HWND) ?ProfileOpenTarget {
        if (self.overlay_mode == .profile and self.overlay_accept_hwnd != null and hwnd == self.overlay_accept_hwnd.?) {
            return self.app.launcher_profile_target;
        }
        return null;
    }

    fn syncOverlayCompletionState(self: *Host) !void {
        if (self.overlay_mode != .command_palette) {
            self.clearOverlayCompletion();
            return;
        }
        _ = self.overlay_edit_hwnd orelse {
            self.clearOverlayCompletion();
            return;
        };
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        if (self.overlay_completion_value) |value| {
            if (std.mem.eql(u8, value, text)) return;
        }
        self.clearOverlayCompletion();
    }

    fn completeCommandPalette(self: *Host, reverse: bool) !bool {
        if (self.overlay_mode != .command_palette) return false;
        const edit_hwnd = self.overlay_edit_hwnd orelse return false;
        const alloc = self.app.core_app.alloc;

        // `setOverlayEditText` replaces `cached_overlay_edit`; own the
        // query slices before deriving completion state from them.
        const text_raw = try overlayEditText(self);
        const trimmed = std.mem.trim(u8, text_raw, " \t\r\n");
        const text_owned = try alloc.dupe(u8, trimmed);
        defer alloc.free(text_owned);

        const seed_owned: []const u8 = blk: {
            if (self.overlay_completion_seed) |value| {
                if (self.overlay_completion_value) |current| {
                    if (std.mem.eql(u8, current, text_owned)) {
                        break :blk try alloc.dupe(u8, value);
                    }
                }
            }
            break :blk try alloc.dupe(u8, text_owned);
        };
        defer alloc.free(seed_owned);

        const candidate = commandPaletteCompletionCandidate(
            self.paletteSnapshot(),
            seed_owned,
            text_owned,
            reverse,
        ) orelse return false;
        // `candidate` borrows from `snap.cvals` (config-owned,
        // stable for this synchronous call's lifetime).
        _ = try self.setOverlayEditText(candidate);
        _ = SendMessageW(edit_hwnd, EM_SETSEL, 0, -1);
        if (!ownedStringEquals(self.overlay_completion_seed, seed_owned)) {
            try appendOwnedString(alloc, &self.overlay_completion_seed, seed_owned);
        }
        if (!ownedStringEquals(self.overlay_completion_value, candidate)) {
            try appendOwnedString(alloc, &self.overlay_completion_value, candidate);
        }
        _ = try self.syncCommandPaletteBanner();
        return true;
    }

    fn stepTabOverviewSelection(self: *Host, reverse: bool) !bool {
        if (self.overlay_mode != .tab_overview) return false;
        const edit_hwnd = self.overlay_edit_hwnd orelse return false;
        const total = self.tabs.items.len;
        if (total == 0) return false;

        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");

        const current: usize = std.fmt.parseUnsigned(usize, text, 10) catch self.active_tab + 1;
        const next = nextTabOverviewSelection(current, total, reverse);
        const next_text = try std.fmt.allocPrint(self.app.core_app.alloc, "{d}", .{next});
        defer self.app.core_app.alloc.free(next_text);
        _ = try self.setOverlayEditText(next_text);
        _ = SendMessageW(edit_hwnd, EM_SETSEL, 0, -1);
        _ = try self.syncOverlayLabel();
        _ = try self.syncOverlayHint();
        _ = try self.syncOverlayButtons();
        return true;
    }

    fn navigateSearchOverlay(self: *Host, dir: input.Binding.Action.NavigateSearch) !bool {
        if (self.overlay_mode != .search) return false;
        const surface = self.activeSurface() orelse return false;
        if (surface.search_total == null or surface.search_selected == null) return false;
        _ = try surface.core_surface.performBindingAction(.{ .navigate_search = dir });
        return true;
    }

    fn syncSearchOverlay(self: *Host) !bool {
        _ = self.overlay_edit_hwnd orelse return false;
        const surface = self.activeSurface() orelse return false;
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        _ = try surface.core_surface.setSearchText(text);
        try surface.setSearchActive(text.len > 0, text);
        _ = try self.syncOverlayLabel();
        _ = try self.syncOverlayHint();
        _ = try self.syncOverlayButtons();
        return true;
    }

    fn syncCommandPaletteBanner(self: *Host) !bool {
        if (self.overlay_mode != .command_palette) return false;
        _ = self.overlay_edit_hwnd orelse return false;
        self.rebuildPaletteList();
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        var mru_buf: [5][]const u8 = undefined;
        const mru = self.app.paletteMruSlice(&mru_buf);
        const banner = try commandPaletteBannerText(self.app.core_app.alloc, self.paletteSnapshot(), text, mru);
        defer if (banner) |value| self.app.core_app.alloc.free(value);
        if (banner) |value| {
            try self.setBanner(.info, value);
        } else {
            try self.setBanner(.none, null);
        }
        _ = try self.syncOverlayLabel();
        _ = try self.syncOverlayHint();
        _ = try self.syncOverlayButtons();
        return true;
    }

    fn submitOverlay(self: *Host) !bool {
        _ = self.overlay_edit_hwnd orelse return false;
        const text = std.mem.trim(u8, try overlayEditText(self), " \t\r\n");
        if (text.len == 0 and self.overlay_mode != .search and self.overlay_mode != .profile) {
            self.hideOverlay();
            try self.layout();
            return false;
        }

        const surface = self.activeSurface() orelse return false;
        switch (self.overlay_mode) {
            .none => return false,
            .command_palette => {
                // Prefer the currently-selected list row (what the user
                // sees highlighted). Fall back to parsing the raw query
                // so users who type a full action name and press Enter
                // before the list rebuild completes still get dispatch.
                if (self.palette_list_ranked_count > 0) {
                    const row = @min(
                        self.palette_list_selected,
                        self.palette_list_ranked_count - 1,
                    );
                    try self.invokePaletteRow(row);
                    // Do NOT access `self` after dispatch.
                    return true;
                }
                const action = input.Binding.Action.parse(text) catch |err| {
                    log.warn("win32 command palette invalid action action={s} err={}", .{ text, err });
                    try self.setBanner(.err, "Unknown Ghostty action. Example: new_tab or toggle_fullscreen");
                    return false;
                };
                self.app.pushPaletteMru(text) catch |err| {
                    std.log.warn("palette MRU push failed err={}", .{err});
                };
                self.hideOverlay();
                self.layout() catch {};
                _ = try surface.core_surface.performBindingAction(action);
                return true;
            },
            .profile => {
                return try self.submitProfileOverlay(self.app.launcher_profile_target);
            },
            .search => {
                const same_needle = if (surface.search_needle) |needle|
                    std.mem.eql(u8, needle, text)
                else
                    false;
                if (text.len > 0 and same_needle and surface.search_selected != null and surface.search_total != null) {
                    _ = try surface.core_surface.performBindingAction(.{ .navigate_search = .next });
                } else {
                    _ = try surface.core_surface.setSearchText(text);
                    try surface.setSearchActive(text.len > 0, text);
                }
            },
            .surface_title => {
                try surface.setTitleOverride(if (text.len == 0) null else text);
            },
            .tab_title => {
                try surface.setTabTitleOverride(if (text.len == 0) null else text);
            },
            .tab_overview => {
                const requested = std.fmt.parseUnsigned(usize, text, 10) catch |err| {
                    log.warn("win32 tab overview invalid selection value={s} err={}", .{ text, err });
                    try self.setBanner(.err, "Enter a numeric tab index.");
                    return false;
                };
                if (requested == 0 or requested > self.tabs.items.len) {
                    const message = try std.fmt.allocPrint(self.app.core_app.alloc, "Tab index out of range. Valid range: 1 to {d}.", .{self.tabs.items.len});
                    defer self.app.core_app.alloc.free(message);
                    try self.setBanner(.err, message);
                    return false;
                }
                self.active_tab = requested - 1;
                if (self.tabs.items[self.active_tab].focusedSurface()) |next_surface| {
                    self.app.activateSurface(next_surface);
                }
            },
            .confirm => {
                // Enter maps to Accept.
                self.invokeConfirmAccept();
                return true;
            },
        }

        self.hideOverlay();
        try self.layout();
        try self.setBanner(.none, null);
        return true;
    }

    fn shouldShowTabBar(self: *const Host) bool {
        return switch (self.app.config.@"window-show-tab-bar") {
            .always, .auto => true, // always show: tab bar has essential controls (+, ▾ dropdown)
            .never => false,
        };
    }

    /// Host-local view of the integrated-titlebar state. The app
    /// carries the build/config floor, but host-side non-client
    /// handling must also respect whether this host is actually
    /// reserving a visible caption/tab row.
    fn usingIntegratedTitlebar(self: *const Host) bool {
        return self.app.use_integrated_titlebar and self.shouldShowTabBar();
    }

    fn tabBarHeight(self: *Host) i32 {
        if (!self.shouldShowTabBar()) return 0;
        // Win11 integrated titlebar: tab row is 40 px tall so it
        // matches the caption-button row height — gives the
        // "tabs-in-caption" look. On Win10 / build < 22000 we keep
        // the compact 32 px height since the DWM caption still sits
        // above.
        const base = if (self.usingIntegratedTitlebar())
            host_tab_height_integrated
        else
            host_tab_height;
        return self.scaled(base);
    }

    fn rightButtonsWidth(self: *const Host) i32 {
        if (self.app.use_integrated_titlebar) {
            return self.scaled(host_titlebar_action_button_size) * 2 + self.scaled(12);
        }
        return self.scaled(host_tab_small_button_width) + // new tab (+)
            self.scaled(host_tab_overflow_button_width) + // dropdown chevron (▾)
            self.scaled(12); // gap + margins
    }

    /// Pixels reserved for the 3 caption buttons (min / max / close)
    /// when the integrated titlebar is active. Returns 0 otherwise.
    /// Buttons are painted by `paintChrome`; this reservation keeps
    /// the [+][▾] cluster and tab strip from colliding with them.
    fn captionButtonsWidth(self: *const Host) i32 {
        if (!self.usingIntegratedTitlebar()) return 0;
        return self.scaled(host_caption_button_w) * 3;
    }

    fn scaled(self: *const Host, base: i32) i32 {
        if (self.current_dpi <= 96) return base;
        return @divTrunc(base * @as(i32, @intCast(self.current_dpi)), 96);
    }

    /// DPI-scale helper usable from free functions that lack a Host pointer.
    fn scaledBy(base: i32, dpi: u32) i32 {
        if (dpi <= 96) return base;
        return @divTrunc(base * @as(i32, @intCast(dpi)), 96);
    }

    fn hasVisibleStatus(self: *const Host) bool {
        // Status bar shows: profile chips, status text, banner info
        if (self.cached_status_w != null) return true;
        if (self.cached_detail_w != null) return true;
        if (self.banner_text != null) return true;
        if (self.profiles != null) return true;
        if (self.overlay_mode != .none) return true;
        return false;
    }

    fn statusBarHeight(self: *Host) i32 {
        // Status bar is disabled; banners and overlays carry transient
        // status feedback without reserving terminal rows.
        _ = self;
        return 0;
    }

    fn estimateLauncherLaneRight(self: *Host) i32 {
        var x = self.scaled(16);
        const selected_profile_index = self.selectedProfileIndex();

        if (self.selectedProfile()) |profile| {
            const pinned_slot_ordinal = self.app.launcherQuickSlotOrdinal(profile.key);
            const chip_len = profileStatusBadgeTextLen(
                profile,
                selected_profile_index,
                pinned_slot_ordinal,
            );
            const chip_width = self.scaled(16) + @as(i32, @intCast(chip_len * @as(usize, @intCast(self.scaled(7)))));
            x += chip_width + self.scaled(10);
        }

        if (self.profiles) |profiles| {
            var drawn: usize = 0;
            for (profiles, 0..) |*profile, index| {
                if (drawn >= 3) break;
                if (selected_profile_index != null and index == selected_profile_index.?) continue;
                const pinned_slot_ordinal = self.app.launcherQuickSlotOrdinal(profile.key);
                const chip_len = profileQuickSlotChipTextLen(
                    profile,
                    index,
                    pinned_slot_ordinal,
                );
                const chip_width = self.scaled(12) + @as(i32, @intCast(chip_len * @as(usize, @intCast(self.scaled(7)))));
                x += chip_width + self.scaled(6);
                drawn += 1;
            }
        }

        return x;
    }

    fn contentRect(self: *Host) !RECT {
        const hwnd = self.hwnd orelse return error.InvalidHost;
        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        const tab_offset: i32 = self.tabBarHeight();
        const overlay_offset: i32 = if (self.overlay_mode == .none) 0 else self.scaled(host_overlay_height);
        const inspector_offset: i32 = if (self.inspectorPanelVisible()) self.scaled(host_inspector_panel_height) else 0;
        return .{
            .left = 0,
            .top = tab_offset + overlay_offset + inspector_offset,
            .right = rect.right,
            .bottom = @max(tab_offset + 1, rect.bottom - self.statusBarHeight()),
        };
    }

    fn close(self: *Host) void {
        const alloc = self.app.core_app.alloc;
        const fallback_hwnd = self.hwnd;
        var surfaces: std.ArrayListUnmanaged(*Surface) = .empty;
        defer surfaces.deinit(alloc);

        for (self.tabs.items) |*tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| surfaces.append(alloc, entry.view) catch {
                if (fallback_hwnd) |hwnd| _ = DestroyWindow(hwnd);
                return;
            };
        }

        if (surfaces.items.len == 0) {
            self.clearStructuralHistory(.normal);
            if (fallback_hwnd) |hwnd| _ = DestroyWindow(hwnd);
            self.app.removeHost(self);
            return;
        }
        for (surfaces.items) |surface| surface.close(false);
    }

    fn statusText(self: *Host, alloc: Allocator) !?[]u8 {
        const surface = self.activeSurface() orelse return null;
        const tab = self.activeTab() orelse return null;
        var parts: std.ArrayListUnmanaged(u8) = .empty;
        errdefer parts.deinit(alloc);

        const append = struct {
            fn raw(buf: *std.ArrayListUnmanaged(u8), alloc_: Allocator, value: []const u8) !void {
                if (buf.items.len > 0) try buf.appendSlice(alloc_, " | ");
                try buf.appendSlice(alloc_, value);
            }
            fn fmt(
                buf: *std.ArrayListUnmanaged(u8),
                alloc_: Allocator,
                comptime format: []const u8,
                args: anytype,
            ) !void {
                if (buf.items.len > 0) try buf.appendSlice(alloc_, " | ");
                try buf.writer(alloc_).print(format, args);
            }
        };

        const host_status = self.app.hostTabStatus(surface);
        try append.fmt(&parts, alloc, "Tab {d}/{d}", .{ host_status.index + 1, host_status.total });
        const pane_count = tab.leafCount();
        if (pane_count > 1) {
            try append.fmt(&parts, alloc, "Panes {d}", .{pane_count});
        }
        if (surface.readonly) try append.raw(&parts, alloc, "readonly");
        if (surface.secure_input) try append.raw(&parts, alloc, "secure input");
        if (surface.inspector_visible) {
            if (tab.tree.zoomed != null and pane_count > 1) {
                try append.fmt(&parts, alloc, "Inspect {d} zoom", .{pane_count});
            } else if (pane_count > 1) {
                try append.fmt(&parts, alloc, "Inspect {d}", .{pane_count});
            } else {
                try append.raw(&parts, alloc, "Inspect");
            }
        }
        if (surface.key_sequence_active) try append.raw(&parts, alloc, "keys");
        if (surface.key_table_name) |value| {
            try append.fmt(&parts, alloc, "Table {s}", .{value});
        }
        if (surface.search_active) {
            if (surface.search_needle) |needle| {
                if (surface.search_selected) |selected| {
                    if (surface.search_total) |total| {
                        try append.fmt(&parts, alloc, "Find {s} ({d}/{d})", .{ needle, selected, total });
                    } else {
                        try append.fmt(&parts, alloc, "Find {s} ({d})", .{ needle, selected });
                    }
                } else if (surface.search_total) |total| {
                    try append.fmt(&parts, alloc, "Find {s} ({d})", .{ needle, total });
                } else {
                    try append.fmt(&parts, alloc, "Find {s}", .{needle});
                }
            } else {
                try append.raw(&parts, alloc, "Find");
            }
        }
        // Show scroll position when not at the bottom
        if (surface.scrollbar.total > surface.scrollbar.len and
            surface.scrollbar.offset + surface.scrollbar.len < surface.scrollbar.total)
        {
            const pct = if (surface.scrollbar.total > 0)
                (surface.scrollbar.offset * 100) / surface.scrollbar.total
            else
                0;
            try append.fmt(&parts, alloc, "\u{2191}{d}%", .{pct});
        }
        if (surface.progress_status) |value| try append.raw(&parts, alloc, value);
        if (parts.items.len == 0) return null;
        return try parts.toOwnedSlice(alloc);
    }

    fn detailText(self: *Host, alloc: Allocator) !?[]u8 {
        const surface = self.activeSurface() orelse return null;
        const tab = self.activeTab() orelse return null;
        const host_status = self.app.hostTabStatus(surface);
        const pane_count = tab.leafCount();

        if (self.overlay_mode == .profile) {
            if (self.selectedProfile()) |profile| {
                return try buildProfileDetailText(
                    alloc,
                    profile,
                    self.profiles,
                    true,
                    self.app.launcher_profile_target,
                    self.app.launcher_profile_order_hint,
                    self.app.launcher_quick_slot_keys,
                );
            }
            return null;
        }

        if (surface.inspector_visible) {
            return try buildInspectorDetailText(alloc, host_status, pane_count, tab.tree.zoomed != null);
        }

        if (surface.search_active) {
            return try buildSearchDetailText(
                alloc,
                surface.search_needle,
                surface.search_total,
                surface.search_selected,
            );
        }

        if (surface.key_sequence_active) {
            return try alloc.dupe(u8, "Key sequence capture is active. Finish the sequence or press Escape to cancel.");
        }

        if (surface.key_table_name) |value| {
            return try std.fmt.allocPrint(
                alloc,
                "Key table {s} is active for this tab.",
                .{value},
            );
        }

        if (self.selectedProfile()) |profile| {
            return try buildProfileDetailText(
                alloc,
                profile,
                self.profiles,
                false,
                self.app.launcher_profile_target,
                self.app.launcher_profile_order_hint,
                self.app.launcher_quick_slot_keys,
            );
        }

        return null;
    }

    fn refreshChrome(self: *Host) !void {
        var invalidate = self.chrome_repaint_dirty;
        _ = try self.syncWindowTitle();
        invalidate = (try self.syncTabButtons()) or invalidate;
        try self.syncChromeButtons();
        if (self.overlay_mode != .none) {
            invalidate = (try self.syncOverlayLabel()) or invalidate;
            invalidate = (try self.syncOverlayHint()) or invalidate;
            _ = try self.syncOverlayButtons();
        }
        if (invalidate) {
            if (chromeTextNeedsFullInvalidation(self.statusBarHeight())) {
                self.invalidateChromeText();
            } else {
                self.invalidateTopChromeText();
            }
        }
    }

    fn repaintChrome(self: *Host) void {
        var mask: ChromeRepaintMask = .{};
        mask.markChrome();
        self.queueChromeRepaint(mask);
    }

    fn repaintFullHost(self: *Host) void {
        self.queueChromeRepaint(.{
            .top = true,
            .content = true,
            .status = true,
        });
    }

    fn invalidateChromeMask(self: *Host, hwnd: HWND, mask: ChromeRepaintMask) void {
        if (mask.isEmpty()) return;
        var client_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) return;
        const content_rect = self.contentRect() catch return;

        if (mask.top) {
            const top_rect = RECT{
                .left = client_rect.left,
                .top = client_rect.top,
                .right = client_rect.right,
                .bottom = @max(client_rect.top, content_rect.top),
            };
            if (top_rect.bottom > top_rect.top) {
                _ = InvalidateRect(hwnd, &top_rect, 0);
            }
        }

        if (mask.content) {
            if (content_rect.bottom > content_rect.top) {
                _ = InvalidateRect(hwnd, &content_rect, 0);
            }
        } else if (mask.search_frames) {
            if (self.activeTab()) |tab| {
                var it = tab.tree.iterator();
                while (it.next()) |entry| {
                    if (!entry.view.search_bar_frame_visible) continue;
                    _ = InvalidateRect(hwnd, &entry.view.search_bar_frame_rect, 0);
                }
            }
        }

        if (mask.status) {
            const bottom_rect = RECT{
                .left = client_rect.left,
                .top = @min(client_rect.bottom, content_rect.bottom),
                .right = client_rect.right,
                .bottom = client_rect.bottom,
            };
            if (bottom_rect.bottom > bottom_rect.top) {
                _ = InvalidateRect(hwnd, &bottom_rect, 0);
            }
        }
    }

    fn queueChromeRepaint(self: *Host, mask: ChromeRepaintMask) void {
        self.chrome_repaint_dirty = true;
        const hwnd = self.hwnd orelse return;
        const added = mergeChromeRepaintMask(&self.chrome_paint_mask, mask);
        if (added.isEmpty()) return;
        self.chrome_paint_pending = true;
        self.invalidateChromeMask(hwnd, added);
    }

    fn repaintTopChrome(self: *Host) void {
        self.queueChromeRepaint(.{ .top = true });
    }

    fn repaintContentChrome(self: *Host) void {
        self.queueChromeRepaint(.{ .content = true });
    }

    fn repaintStatusBar(self: *Host) void {
        const status_h = self.statusBarHeight();
        if (status_h <= 0) return;
        self.queueChromeRepaint(.{ .status = true });
    }

    fn invalidateStatusBarText(self: *Host) void {
        if (self.statusBarHeight() <= 0) return;
        self.chrome_text_dirty.status = true;
        self.repaintStatusBar();
    }

    fn invalidateBannerText(self: *Host) void {
        self.chrome_text_dirty.banner = true;
        self.repaintTopChrome();
    }

    fn invalidateOverlayText(self: *Host) void {
        self.chrome_text_dirty.overlay = true;
        self.repaintTopChrome();
    }

    fn invalidateChromeText(self: *Host) void {
        self.chrome_text_dirty.markAll();
        self.invalidateChrome();
    }

    fn invalidateTopChromeText(self: *Host) void {
        self.chrome_text_dirty.markTop();
        self.repaintTopChrome();
    }

    fn invalidateChrome(self: *Host) void {
        self.repaintChrome();
    }

    fn shouldDeferSurfaceRepaints(self: *const Host) bool {
        return self.is_live_resize.load(.acquire) or self.defer_surface_repaints_until_flush;
    }

    fn flushDeferredVisibleSurfaceRepaints(self: *Host) void {
        self.flushDeferredVisibleSurfaceRepaintsWith(struct {
            fn repaint(surface: *Surface) !void {
                try surface.queuePaintRequest(true);
            }
        }.repaint);
    }

    fn flushDeferredVisibleSurfaceRepaintsWith(self: *Host, repaint_fn: anytype) void {
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                if (!entry.view.window_visible) continue;
                _ = entry.view.flushDeferredLiveResizeRepaint(repaint_fn) catch |err| {
                    log.err("win32 deferred live-resize repaint flush failed err={}", .{err});
                };
            }
        }
    }

    /// `MoveWindow` / `SetWindowPos` with repaint suppressed does not reliably
    /// queue `WM_PAINT` on child HWNDs. Owner-draw tab controls always repaint
    /// immediately; WGL child surfaces repaint immediately outside live resize
    /// and defer to an explicit post-resize flush while the user is dragging.
    fn invalidateChromeChildPaint(self: *Host) void {
        const controls = [_]?HWND{
            self.new_tab_hwnd,
            self.overflow_hwnd,
            self.overlay_label_hwnd,
            self.overlay_edit_hwnd,
            self.overlay_hint_hwnd,
            self.overlay_accept_hwnd,
            self.overlay_cancel_hwnd,
            self.palette_list_hwnd,
        };
        for (controls) |maybe_hwnd| {
            if (maybe_hwnd) |h| _ = InvalidateRect(h, null, 0);
        }
        for (self.tabs.items) |*t| {
            if (t.button_hwnd) |h| {
                _ = InvalidateRect(h, null, 0);
            }
        }
    }

    fn updateChromeChildPaintNow(self: *Host) void {
        const controls = [_]?HWND{
            self.new_tab_hwnd,
            self.overflow_hwnd,
            self.overlay_label_hwnd,
            self.overlay_edit_hwnd,
            self.overlay_hint_hwnd,
            self.overlay_accept_hwnd,
            self.overlay_cancel_hwnd,
            self.palette_list_hwnd,
        };
        for (controls) |maybe_hwnd| {
            if (maybe_hwnd) |h| {
                if (IsWindowVisible(h) != 0) _ = UpdateWindow(h);
            }
        }
        for (self.tabs.items) |*t| {
            if (t.button_hwnd) |h| {
                if (IsWindowVisible(h) != 0) _ = UpdateWindow(h);
            }
        }
    }

    fn redrawHostWindowNow(self: *Host) void {
        const hwnd = self.hwnd orelse return;
        const flags = hostCompositionRedrawFlags();
        if (RedrawWindow(hwnd, null, null, flags) == 0) {
            _ = UpdateWindow(hwnd);
        }
    }

    fn forceHostCompositionPaint(self: *Host) void {
        self.repaintFullHost();
        self.invalidateChromeChildPaint();
        self.redrawHostWindowNow();
        self.updateChromeChildPaintNow();
    }

    fn forceOverlayTransitionPaint(self: *Host) void {
        self.forceHostCompositionPaint();
    }

    fn forceVisibleSurfaceRepaintsNow(self: *Host) void {
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                if (!entry.view.window_visible) continue;
                entry.view.syncCoreSizeFromClientRect();
                entry.view.invalidateSearchBarChildPaint();
                switch (resizeSettleSurfaceAction(entry.view.shouldDrawRendererPaintContent())) {
                    .present_renderer => entry.view.queuePaintRequest(true) catch |err| {
                        entry.view.cancelRendererRepaintRequest();
                        log.err("win32 resize-settle renderer paint request failed err={}", .{err});
                    },
                    .wake_renderer => entry.view.requestRendererFrameNow(),
                }
            }
        }
    }

    fn invalidateVisibleSurfaceChildPaint(
        self: *Host,
        repaint_hosted_child: bool,
        repaint_search_controls: bool,
    ) void {
        const defer_surface_repaints = repaint_hosted_child and self.shouldDeferSurfaceRepaints();
        if (self.activeTab()) |tab| {
            var it = tab.tree.iterator();
            while (it.next()) |entry| {
                if (!entry.view.window_visible) continue;

                if (repaint_hosted_child) {
                    if (defer_surface_repaints) {
                        entry.view.markLiveResizeRepaintDeferred();
                    } else {
                        entry.view.repaintHostedChild() catch |err| {
                            log.err("win32 hosted child repaint request failed err={}", .{err});
                        };
                    }
                }

                if (repaint_search_controls) entry.view.invalidateSearchBarChildPaint();
            }
        }
    }

    fn freeCachedChromeStrings(self: *Host) void {
        const alloc = self.app.core_app.alloc;
        self.chrome_text_dirty.markAll();
        if (self.cached_status_w) |w| alloc.free(w);
        if (self.cached_detail_w) |w| alloc.free(w);
        if (self.cached_banner_w) |w| alloc.free(w);
        if (self.cached_inspector_title_w) |w| alloc.free(w);
        if (self.cached_inspector_hint_w) |w| alloc.free(w);
        if (self.cached_overlay_paint_badge_w) |w| alloc.free(w);
        if (self.cached_overlay_paint_label_w) |w| alloc.free(w);
        if (self.cached_overlay_paint_feedback_w) |w| alloc.free(w);
        if (self.cached_launcher_selected_chip_w) |w| alloc.free(w);
        for (&self.cached_launcher_quick_slot_chip_w) |*slot| {
            if (slot.*) |w| alloc.free(w);
            slot.* = null;
        }
        self.cached_status_w = null;
        self.cached_detail_w = null;
        self.cached_banner_w = null;
        self.cached_inspector_title_w = null;
        self.cached_inspector_hint_w = null;
        self.cached_overlay_paint_badge_w = null;
        self.cached_overlay_paint_label_w = null;
        self.cached_overlay_paint_feedback_w = null;
        self.cached_launcher_selected_chip_w = null;
    }

    fn syncWindowTitle(self: *Host) !bool {
        const hwnd = self.hwnd orelse return false;
        const alloc = self.app.core_app.alloc;
        const surface = self.activeSurface() orelse {
            if (!windowTitleSyncChanged(self.cached_window_title, "winghostty")) return false;
            try appendOwnedString(alloc, &self.cached_window_title, "winghostty");
            _ = SetWindowTextW(hwnd, default_title);
            return true;
        };
        const host_base_title = try buildHostAwareBaseTitle(
            alloc,
            if (surface.effectiveTitle()) |value| value else null,
            self.app.hostTabStatus(surface),
        );
        defer alloc.free(host_base_title);
        if (!windowTitleSyncChanged(self.cached_window_title, host_base_title)) return false;
        try appendOwnedString(alloc, &self.cached_window_title, host_base_title);
        const title_w = try std.unicode.utf8ToUtf16LeAllocZ(alloc, host_base_title);
        defer alloc.free(title_w);
        _ = SetWindowTextW(hwnd, title_w.ptr);
        return true;
    }

    fn syncTabButtons(self: *Host) !bool {
        const hwnd = self.hwnd orelse return false;
        try self.ensureChromeButtons();
        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        const width = @max(0, rect.right - rect.left);
        const right_buttons_width = self.rightButtonsWidth();
        const caption_buttons_w = self.captionButtonsWidth();
        const tab_area_width = @max(1, width - right_buttons_width - caption_buttons_w);
        const tab_range = visibleTabRange(self.tabs.items.len, self.active_tab, tab_area_width);
        const visible_count = @max(@as(i32, 1), @as(i32, @intCast(tab_range.count)));
        const button_width = @max(1, @divTrunc(tab_area_width, visible_count));
        const label_max_len = hostTabLabelMaxLen(button_width);
        for (self.tabs.items, 0..) |*tab, i| {
            const surface = tab.focusedSurface() orelse continue;
            const title = if (surface.effectiveTitle()) |value| value else null;
            const active = i == self.active_tab;
            const pane_count = tab.leafCount();
            const show_pane_count = shouldShowPaneCount(button_width, pane_count);
            const title_unchanged = if (title) |value|
                ownedStringEquals(tab.cached_button_title, value)
            else
                tab.cached_button_title == null;
            const label_inputs_unchanged = tab.button_hwnd != null and
                tab.button_label_cache_valid and
                title_unchanged and
                tab.cached_button_index == i and
                tab.cached_button_active == active and
                tab.cached_button_pane_count == pane_count and
                tab.cached_button_label_max_len == label_max_len and
                tab.cached_button_show_pane_count == show_pane_count;
            if (label_inputs_unchanged) continue;
            const label = try buildTabButtonLabel(
                self.app.core_app.alloc,
                title,
                i,
                active,
                pane_count,
                label_max_len,
                show_pane_count,
            );
            defer self.app.core_app.alloc.free(label);
            if (tab.button_hwnd == null) {
                try appendOwnedString(self.app.core_app.alloc, &tab.cached_button_label, label);
                const label_w = try std.unicode.utf8ToUtf16LeAllocZ(self.app.core_app.alloc, label);
                defer self.app.core_app.alloc.free(label_w);
                tab.button_hwnd = CreateWindowExW(
                    0,
                    prompt_button_class,
                    label_w.ptr,
                    WS_CHILD | WS_VISIBLE | WS_TABSTOP | BS_OWNERDRAW,
                    0,
                    0,
                    100,
                    host_tab_height - 8,
                    hwnd,
                    @ptrFromInt(1000 + i),
                    self.app.hinstance,
                    null,
                ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
                self.subclassButton(tab.button_hwnd.?, &tabButtonProc, &tab.button_prev_proc);
            } else if (!ownedStringEquals(tab.cached_button_label, label)) {
                try appendOwnedString(self.app.core_app.alloc, &tab.cached_button_label, label);
                const label_w = try std.unicode.utf8ToUtf16LeAllocZ(self.app.core_app.alloc, label);
                defer self.app.core_app.alloc.free(label_w);
                _ = SetWindowTextW(tab.button_hwnd.?, label_w.ptr);
            }
            try appendOwnedString(self.app.core_app.alloc, &tab.cached_button_title, title);
            tab.cached_button_index = i;
            tab.cached_button_active = active;
            tab.cached_button_pane_count = pane_count;
            tab.cached_button_label_max_len = label_max_len;
            tab.cached_button_show_pane_count = show_pane_count;
            tab.button_label_cache_valid = true;
        }
        var chrome_changed = false;
        if (!self.layoutChromeForRect(rect, &chrome_changed)) return chrome_changed;
        return chrome_changed;
    }

    fn syncChromeButtons(self: *Host) !void {
        try self.ensureChromeButtons();
    }

    fn layoutChromeForRect(self: *Host, rect: RECT, changed: *bool) bool {
        const width = @max(0, rect.right - rect.left);
        const right_buttons_width = self.rightButtonsWidth();
        // When integrated titlebar is active, reserve the rightmost
        // 3 × caption_button_w pixels for min/max/close so the
        // [+][▾] cluster and tab strip don't collide with them.
        const caption_buttons_w = self.captionButtonsWidth();
        const tab_area_width = @max(1, width - right_buttons_width - caption_buttons_w);
        const tab_range = visibleTabRange(self.tabs.items.len, self.active_tab, tab_area_width);
        const visible_count = @max(@as(i32, 1), @as(i32, @intCast(tab_range.count)));
        const button_width = @min(@max(1, @divTrunc(tab_area_width, visible_count)), self.scaled(host_tab_max_button_width));
        const button_y = self.scaled(3);
        // Scale button height with the actual tab-bar height so
        // buttons fill the integrated-titlebar row in Win11 (40 px)
        // without a dead gap above the underline.
        const button_height = @max(1, self.tabBarHeight() - self.scaled(6));
        var active_tab_left: ?i32 = null;
        for (self.tabs.items, 0..) |*tab, i| {
            if (tab.button_hwnd) |button_hwnd| {
                if (i >= tab_range.start and i < tab_range.start + tab_range.count) {
                    const visible_index: i32 = @intCast(i - tab_range.start);
                    const tab_left = visible_index * button_width;
                    changed.* = applyChildRect(
                        button_hwnd,
                        &tab.button_placement,
                        childRect(
                            tab_left,
                            button_y,
                            button_width,
                            button_height,
                        ),
                    ) or changed.*;
                    changed.* = applyChildVisibility(button_hwnd, &tab.button_placement, true) or changed.*;
                    if (i == self.active_tab) active_tab_left = tab_left;
                } else {
                    changed.* = applyChildVisibility(button_hwnd, &tab.button_placement, false) or changed.*;
                }
            }
        }

        // Animate the focused-tab underline toward the active tab's
        // on-screen rect. First retarget (slide_started_ms == 0) snaps
        // so the line doesn't slide in from the left on window open;
        // subsequent retargets slide over underline_slide_ms. Reduced-
        // motion collapses to a snap via `retargetTabUnderline`.
        if (active_tab_left) |left| {
            self.retargetTabUnderline(left, button_width);
        }

        // Right-side cluster: [+][▾] — new tab and dropdown chevron.
        // Shift left by the caption-buttons reservation (0 on Win10)
        // so the chevron doesn't land under the close button.
        const titlebar_actions = self.app.use_integrated_titlebar;
        const action_size = self.scaled(host_titlebar_action_button_size);
        const action_y = @max(0, @divTrunc(self.tabBarHeight() - action_size, 2));
        var button_x = width - self.scaled(if (titlebar_actions) 4 else 8) - caption_buttons_w;
        if (self.overflow_hwnd) |button_hwnd| {
            const overflow_width = if (titlebar_actions) action_size else self.scaled(host_tab_overflow_button_width);
            button_x -= overflow_width;
            changed.* = applyChildRect(
                button_hwnd,
                &self.overflow_placement,
                childRect(
                    button_x,
                    if (titlebar_actions) action_y else button_y,
                    overflow_width,
                    if (titlebar_actions) action_size else button_height,
                ),
            ) or changed.*;
            changed.* = applyChildVisibility(button_hwnd, &self.overflow_placement, true) or changed.*;
        }
        button_x -= self.scaled(4);
        if (self.new_tab_hwnd) |button_hwnd| {
            const new_tab_width = if (titlebar_actions) action_size else self.scaled(host_tab_small_button_width);
            button_x -= new_tab_width;
            changed.* = applyChildRect(
                button_hwnd,
                &self.new_tab_placement,
                childRect(
                    button_x,
                    if (titlebar_actions) action_y else button_y,
                    new_tab_width,
                    if (titlebar_actions) action_size else button_height,
                ),
            ) or changed.*;
            changed.* = applyChildVisibility(button_hwnd, &self.new_tab_placement, true) or changed.*;
        }

        if (self.overlay_mode != .none) {
            const edit_hwnd = self.overlay_edit_hwnd orelse return false;
            const accept_hwnd = self.overlay_accept_hwnd orelse return false;
            const cancel_hwnd = self.overlay_cancel_hwnd orelse return false;
            const overlay_y = self.tabBarHeight();
            const padding = self.scaled(host_overlay_padding);
            const label_w = self.scaled(host_overlay_label_width);
            const accept_visible = overlayAcceptButtonVisible(self.overlay_mode);
            const accept_w = if (accept_visible) self.scaled(host_overlay_accept_width) else 0;
            const cancel_w = self.scaled(host_overlay_cancel_width);
            const edit_frame = overlayEditFrameRect(
                width,
                overlay_y,
                padding,
                label_w,
                cancel_w,
                if (accept_visible) accept_w + padding else 0,
                self.scaled(host_overlay_row_height),
            );
            const edit_rect = overlayEditChildRectFromFrame(edit_frame, self.scaled(8), self.scaled(6));
            changed.* = applyChildRect(
                edit_hwnd,
                &self.overlay_edit_placement,
                edit_rect,
            ) or changed.*;
            if (accept_visible) {
                changed.* = applyChildRect(
                    accept_hwnd,
                    &self.overlay_accept_placement,
                    childRect(
                        width - cancel_w - accept_w - (padding * 2),
                        overlay_y + self.scaled(4),
                        accept_w,
                        self.scaled(host_overlay_row_height),
                    ),
                ) or changed.*;
                changed.* = applyChildVisibility(
                    accept_hwnd,
                    &self.overlay_accept_placement,
                    true,
                ) or changed.*;
            } else {
                changed.* = applyChildVisibility(
                    accept_hwnd,
                    &self.overlay_accept_placement,
                    false,
                ) or changed.*;
            }
            changed.* = applyChildRect(
                cancel_hwnd,
                &self.overlay_cancel_placement,
                childRect(
                    width - cancel_w - padding,
                    overlay_y + self.scaled(4),
                    cancel_w,
                    self.scaled(host_overlay_row_height),
                ),
            ) or changed.*;
            changed.* = applyChildVisibility(
                cancel_hwnd,
                &self.overlay_cancel_placement,
                true,
            ) or changed.*;

            if (self.overlay_mode == .command_palette) {
                if (self.palette_list_hwnd) |list_hwnd| {
                    // Anchor the list directly under the EDIT, left-
                    // aligned with it and right-aligned with the buttons
                    // so it reads as part of the same visual card.
                    const list_x = padding + label_w + self.scaled(8);
                    const list_width = @max(
                        self.scaled(120),
                        width - list_x - padding,
                    );
                    const list_y = overlay_y + self.scaled(host_overlay_row_height) + self.scaled(12);
                    const visible_rows: i32 = @intCast(@min(
                        self.palette_list_ranked_count,
                        palette_max_visible_rows,
                    ));
                    const list_height = @max(
                        self.scaled(palette_row_height),
                        visible_rows * self.scaled(palette_row_height),
                    );
                    changed.* = applyChildRect(
                        list_hwnd,
                        &self.palette_list_placement,
                        childRect(list_x, list_y, list_width, list_height),
                    ) or changed.*;
                    changed.* = applyChildVisibility(
                        list_hwnd,
                        &self.palette_list_placement,
                        self.palette_list_ranked_count > 0,
                    ) or changed.*;
                }
            } else if (self.palette_list_hwnd) |list_hwnd| {
                changed.* = applyChildVisibility(
                    list_hwnd,
                    &self.palette_list_placement,
                    false,
                ) or changed.*;
            }
        } else if (self.palette_list_hwnd) |list_hwnd| {
            changed.* = applyChildVisibility(
                list_hwnd,
                &self.palette_list_placement,
                false,
            ) or changed.*;
        }

        return true;
    }

    fn layout(self: *Host) !void {
        const hwnd = self.hwnd orelse return;
        var rect: RECT = undefined;
        if (GetClientRect(hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        var chrome_layout_changed = false;
        if (!self.layoutChromeForRect(rect, &chrome_layout_changed)) return;

        const content_rect = try self.contentRect();
        const content_y = content_rect.top;
        const content_width = @max(1, content_rect.right - content_rect.left);
        const content_height = @max(1, content_rect.bottom - content_rect.top);
        const active_tab = self.activeTab() orelse return;
        var content_layout_changed = false;

        // Hide non-active child GL surfaces before showing the active tab.
        // Briefly overlapping multiple WGL child windows under one host can
        // crash the NVIDIA present path when tabs are opened repeatedly.
        self.prepareActiveTabVisibility(self.active_tab);

        if (active_tab.tree.zoomed) |zoomed| {
            var it = active_tab.tree.iterator();
            while (it.next()) |entry| {
                const visible = entry.handle == zoomed;
                const visibility_changed = entry.view.window_visible != visible;
                content_layout_changed = content_layout_changed or visibility_changed;
                entry.view.setVisible(visible);
                if (visible) {
                    const frame_h: i32 = if (entry.view.search_bar.visible)
                        @min(self.scaled(host_search_bar_height), @max(0, content_height - 1))
                    else
                        0;
                    if (frame_h > 0) {
                        content_layout_changed = (try entry.view.layoutSearchBarControls(
                            childRect(content_rect.left, content_y, content_width, frame_h),
                            true,
                        )) or content_layout_changed;
                    } else {
                        content_layout_changed = entry.view.hideSearchBarControls() or content_layout_changed;
                    }
                    const pane_rect = childRect(
                        content_rect.left,
                        content_y + frame_h,
                        content_width,
                        @max(1, content_height - frame_h),
                    );
                    var pane_rect_changed = false;
                    if (entry.view.hwnd) |surface_hwnd| {
                        pane_rect_changed = applyChildRect(
                            surface_hwnd,
                            &entry.view.placement,
                            pane_rect,
                        );
                        content_layout_changed = pane_rect_changed or content_layout_changed;
                    }
                    const runtime_sync = surfaceLayoutRuntimeSync(visibility_changed, pane_rect_changed);
                    if (runtime_sync.scrollbar_refresh) {
                        try entry.view.refreshScrollbarWindow();
                    }
                    if (runtime_sync.core_size_sync) {
                        entry.view.syncCoreSizeFromClientRect();
                    }
                    // Update content_scale if DPI changed since surface was last visible
                    if (self.pending_dpi_update and entry.view.core_initialized) {
                        const scale_val: f32 = @as(f32, @floatFromInt(self.current_dpi)) / 96.0;
                        const new_scale: apprt.ContentScale = .{ .x = scale_val, .y = scale_val };
                        if (entry.view.content_scale.x != new_scale.x or entry.view.content_scale.y != new_scale.y) {
                            entry.view.content_scale = new_scale;
                            entry.view.core_surface.contentScaleCallback(new_scale) catch {};
                        }
                    }
                } else {
                    content_layout_changed = entry.view.hideSearchBarControls() or content_layout_changed;
                    if (visibility_changed) {
                        try entry.view.refreshScrollbarWindow();
                    }
                }
            }
        } else {
            var spatial = try active_tab.tree.spatial(self.app.core_app.alloc);
            defer spatial.deinit(self.app.core_app.alloc);
            var it = active_tab.tree.iterator();
            while (it.next()) |entry| {
                const visibility_changed = !entry.view.window_visible;
                content_layout_changed = content_layout_changed or visibility_changed;
                entry.view.setVisible(true);
                if (entry.view.hwnd) |surface_hwnd| {
                    const slot = spatial.slots[entry.handle.idx()];
                    var x: i32 = content_rect.left + @as(i32, @intFromFloat(@round(slot.x * @as(f16, @floatFromInt(content_width)))));
                    var y: i32 = content_y + @as(i32, @intFromFloat(@round(slot.y * @as(f16, @floatFromInt(content_height)))));
                    var w: i32 = @max(1, @as(i32, @intFromFloat(@round(slot.width * @as(f16, @floatFromInt(content_width))))));
                    var h: i32 = @max(1, @as(i32, @intFromFloat(@round(slot.height * @as(f16, @floatFromInt(content_height))))));
                    // Pane divider gap: inset internal edges only (pixel-space detection)
                    const has_multi_panes = active_tab.leafCount() > 1;
                    if (has_multi_panes) {
                        if (x > content_rect.left) {
                            x += 1;
                            w -= 1;
                        }
                        if (x + w < content_rect.left + content_width) {
                            w -= 1;
                        }
                        if (y > content_y) {
                            y += 1;
                            h -= 1;
                        }
                        if (y + h < content_y + content_height) {
                            h -= 1;
                        }
                        w = @max(1, w);
                        h = @max(1, h);
                    }
                    const frame_h: i32 = if (entry.view.search_bar.visible)
                        @min(self.scaled(host_search_bar_height), @max(0, h - 1))
                    else
                        0;
                    if (frame_h > 0) {
                        content_layout_changed = (try entry.view.layoutSearchBarControls(
                            childRect(x, y, w, frame_h),
                            true,
                        )) or content_layout_changed;
                    } else {
                        content_layout_changed = entry.view.hideSearchBarControls() or content_layout_changed;
                    }
                    const pane_rect = childRect(x, y + frame_h, w, @max(1, h - frame_h));
                    const pane_rect_changed = applyChildRect(
                        surface_hwnd,
                        &entry.view.placement,
                        pane_rect,
                    );
                    content_layout_changed = pane_rect_changed or content_layout_changed;
                    const runtime_sync = surfaceLayoutRuntimeSync(visibility_changed, pane_rect_changed);
                    if (runtime_sync.scrollbar_refresh) {
                        try entry.view.refreshScrollbarWindow();
                    }
                    if (runtime_sync.core_size_sync) {
                        entry.view.syncCoreSizeFromClientRect();
                    }
                }
                // Update content_scale if DPI changed since surface was last visible
                if (self.pending_dpi_update and entry.view.core_initialized) {
                    const scale_val: f32 = @as(f32, @floatFromInt(self.current_dpi)) / 96.0;
                    const new_scale: apprt.ContentScale = .{ .x = scale_val, .y = scale_val };
                    if (entry.view.content_scale.x != new_scale.x or entry.view.content_scale.y != new_scale.y) {
                        entry.view.content_scale = new_scale;
                        entry.view.core_surface.contentScaleCallback(new_scale) catch {};
                    }
                }
            }
        }
        self.pending_dpi_update = false;

        if (chrome_layout_changed or content_layout_changed) {
            // Batch-invalidate after actual positioning/visibility changes.
            self.repaintFullHost();
            const child_paint = layoutChildPaintPlan(chrome_layout_changed, content_layout_changed);
            if (child_paint.chrome) self.invalidateChromeChildPaint();
            if (child_paint.content or child_paint.native_content_controls) {
                self.invalidateVisibleSurfaceChildPaint(
                    child_paint.content,
                    child_paint.native_content_controls,
                );
            }
        }
    }

    /// Paint the 3 caption buttons (min / max-or-restore / close) at
    /// the top-right of the tab row. Called from `paintChrome` only
    /// when this host is actively using the integrated titlebar.
    fn drawTitlebarGlyph(
        self: *Host,
        hdc: HDC,
        rect: RECT,
        kind: TitlebarGlyphKind,
        color: u32,
        caption_button: bool,
    ) void {
        const hdc_nn: *anyopaque = hdc orelse return;
        const font = if (caption_button)
            self.titlebar_caption_icon_font
        else
            self.titlebar_action_icon_font;
        const glyph_size = self.scaled(if (caption_button) 10 else 12);
        var glyph_rect = centeredRect(rect, glyph_size, glyph_size);

        if (font) |font_handle| {
            if (SelectObject(hdc, font_handle)) |old_font| {
                defer _ = SelectObject(hdc, old_font);
                _ = SetBkMode(hdc, TRANSPARENT);
                _ = SetTextColor(hdc, color);
                if (DrawTextW(
                    hdc,
                    titlebarGlyphText(kind),
                    1,
                    &glyph_rect,
                    DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX,
                ) != 0) {
                    return;
                }
            }
        }

        win32_icons.drawIcon(
            titlebarFallbackIcon(kind),
            hdc_nn,
            .{
                .left = glyph_rect.left,
                .top = glyph_rect.top,
                .right = glyph_rect.right,
                .bottom = glyph_rect.bottom,
            },
            color,
            true,
        );
    }

    fn paintCaptionButton(
        self: *Host,
        hdc: HDC,
        rect: RECT,
        role: TitlebarButtonRole,
        glyph: TitlebarGlyphKind,
        now_ms: u64,
        high_contrast: bool,
        theme: *const win32_theme.ThemeColors,
    ) void {
        const caption = switch (role) {
            .minimize => CaptionButton.minimize,
            .maximize => CaptionButton.maximize,
            .close => CaptionButton.close,
            else => CaptionButton.none,
        };
        const visual = titlebarButtonVisual(
            theme,
            role,
            theme.chrome_bg,
            self.titlebarHoverAlpha(role, self.caption_hover == caption, now_ms),
            self.caption_pressed == caption,
            high_contrast,
        );
        if (visual.bg) |bg| fillSolidRect(hdc, rect, bg);
        self.drawTitlebarGlyph(hdc, rect, glyph, visual.glyph, true);
    }

    fn paintCaptionButtons(
        self: *Host,
        hdc: HDC,
        client_rect: RECT,
        theme: *const win32_theme.ThemeColors,
    ) void {
        const cb_w = self.scaled(host_caption_button_w);
        const cb_h = self.scaled(host_caption_button_h);
        if (cb_w <= 0 or cb_h <= 0) return;

        const maximized = if (self.hwnd) |h| IsZoomed(h) != 0 else false;
        const right = client_rect.right;

        const close_rect: RECT = .{
            .left = right - cb_w,
            .top = 0,
            .right = right,
            .bottom = cb_h,
        };
        const max_rect: RECT = .{
            .left = right - 2 * cb_w,
            .top = 0,
            .right = right - cb_w,
            .bottom = cb_h,
        };
        const min_rect: RECT = .{
            .left = right - 3 * cb_w,
            .top = 0,
            .right = right - 2 * cb_w,
            .bottom = cb_h,
        };

        const is_hc = isHighContrastActive();
        const now = GetTickCount64();
        self.paintCaptionButton(hdc, min_rect, .minimize, .minimize, now, is_hc, theme);
        self.paintCaptionButton(
            hdc,
            max_rect,
            .maximize,
            if (maximized) .restore else .maximize,
            now,
            is_hc,
            theme,
        );
        self.paintCaptionButton(hdc, close_rect, .close, .close, now, is_hc, theme);
    }

    fn paintChrome(self: *Host) void {
        const hwnd = self.hwnd orelse return;
        var ps: PAINTSTRUCT = undefined;
        const hdc = BeginPaint(hwnd, &ps) orelse return;
        defer _ = EndPaint(hwnd, &ps);

        const alloc = self.app.core_app.alloc;
        const theme = &self.app.resolved_theme;

        // Select chrome font, save previous for restore
        const prev_font = if (self.chrome_font) |font| SelectObject(hdc, font) else null;
        defer if (prev_font) |pf| {
            _ = SelectObject(hdc, pf);
        };

        var client_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) return;
        const tab_h = self.tabBarHeight();
        // Note: tab_h is already scaled via tabBarHeight()
        const overlay_offset: i32 = if (self.overlay_mode != .none) self.scaled(host_overlay_height) else 0;
        const inspector_panel_visible = self.inspectorPanelVisible();
        const inspector_offset: i32 = if (inspector_panel_visible) self.scaled(host_inspector_panel_height) else 0;
        const status_h = self.statusBarHeight();
        const content_rect = RECT{
            .left = 0,
            .top = tab_h + overlay_offset + inspector_offset,
            .right = client_rect.right,
            .bottom = @max(tab_h + 1, client_rect.bottom - status_h),
        };
        const top_rect = RECT{
            .left = client_rect.left,
            .top = client_rect.top,
            .right = client_rect.right,
            .bottom = @max(client_rect.top, content_rect.top),
        };
        const status_rect = RECT{
            .left = client_rect.left,
            .top = @min(client_rect.bottom, content_rect.bottom),
            .right = client_rect.right,
            .bottom = client_rect.bottom,
        };
        const paint_top = paintRectVisible(hdc, ps.rcPaint, top_rect);
        const paint_content = paintRectVisible(hdc, ps.rcPaint, content_rect);
        const paint_status = paintRectVisible(hdc, ps.rcPaint, status_rect);
        const banner_y: i32 = tab_h + overlay_offset + inspector_offset + self.scaled(2);

        // Tab bar (only when visible)
        if (paint_top and tab_h > 0) {
            const tab_rect = RECT{
                .left = 0,
                .top = 0,
                .right = client_rect.right,
                .bottom = tab_h,
            };
            fillSolidRect(hdc, tab_rect, theme.chrome_bg);

            // Focused-tab accent underline. Lives in the 2 px gap
            // between the tab button's bottom edge (button_height = tab_h
            // - scaled(6), starting at y=scaled(3)) and the tab bar's
            // 1 px bottom border. Drawn on the parent HWND so the single
            // rect can slide across child button boundaries; children
            // paint themselves above this region via WM_DRAWITEM and do
            // not occlude it. Inset 3 px on each horizontal edge to
            // match Windows Terminal's tab indicator treatment
            // (wt-chrome-reference.md §1).
            {
                const now_ms = GetTickCount64();
                const cur = self.tab_underline.currentRect(now_ms);
                const underline_left = @as(i32, @intFromFloat(@round(cur.left))) + self.scaled(3);
                const underline_right = @as(i32, @intFromFloat(@round(cur.left + cur.width))) - self.scaled(3);
                if (underline_right > underline_left and cur.width > 0.5) {
                    fillSolidRect(hdc, .{
                        .left = underline_left,
                        .top = tab_h - self.scaled(3),
                        .right = underline_right,
                        .bottom = tab_h - self.scaled(1),
                    }, theme.accent);
                }
            }

            fillSolidRect(
                hdc,
                .{
                    .left = 0,
                    .top = 0,
                    .right = client_rect.right,
                    .bottom = @max(1, self.scaled(2)),
                },
                if (theme.is_dark)
                    adjustColor(theme.accent, -12, -12, -12)
                else
                    adjustColor(theme.accent, 18, 18, 18),
            );
            if (!self.app.use_integrated_titlebar) {
                const cluster_left = @max(self.scaled(8), client_rect.right - self.rightButtonsWidth() - self.scaled(4));
                const cluster_rect = RECT{
                    .left = cluster_left,
                    .top = self.scaled(4),
                    .right = client_rect.right - self.scaled(6),
                    .bottom = tab_h - self.scaled(4),
                };
                if (cluster_rect.right > cluster_rect.left and cluster_rect.bottom > cluster_rect.top) {
                    drawRoundedRect(
                        hdc,
                        cluster_rect,
                        if (theme.is_dark)
                            adjustColor(theme.chrome_bg, 8, 8, 10)
                        else
                            adjustColor(theme.chrome_bg, 6, 6, 6),
                        if (theme.is_dark)
                            adjustColor(theme.chrome_border, 10, 10, 12)
                        else
                            adjustColor(theme.chrome_border, -16, -16, -16),
                        self.scaled(6),
                    );
                    if (cluster_left > self.scaled(14)) {
                        fillSolidRect(hdc, .{
                            .left = cluster_left - 1,
                            .top = self.scaled(8),
                            .right = cluster_left,
                            .bottom = tab_h - self.scaled(8),
                        }, theme.chrome_border);
                    }
                }
            }
            // Caption buttons (integrated titlebar only). Painted on
            // the parent HWND at the rightmost edge of the tab row;
            // hit-tested via `win32_nc_layout.hitTest` and dispatched
            // from our NC mouse handlers so Snap Layout hover remains
            // intact while the visuals stay app-owned.
            if (self.usingIntegratedTitlebar()) {
                self.paintCaptionButtons(hdc, client_rect, theme);
            }

            fillSolidRect(
                hdc,
                .{
                    .left = 0,
                    .top = tab_h - 1,
                    .right = client_rect.right,
                    .bottom = tab_h,
                },
                theme.chrome_border,
            );
        } // end tab bar painting

        if (paint_top and self.overlay_mode != .none) {
            const overlay_rect = RECT{
                .left = 0,
                .top = tab_h,
                .right = client_rect.right,
                .bottom = tab_h + self.scaled(host_overlay_height),
            };
            fillSolidRect(hdc, overlay_rect, theme.overlay_bg);
            const overlay_panel = RECT{
                .left = self.scaled(8),
                .top = overlay_rect.top + self.scaled(4),
                .right = client_rect.right - self.scaled(8),
                .bottom = overlay_rect.bottom - self.scaled(6),
            };
            if (overlay_panel.right > overlay_panel.left and overlay_panel.bottom > overlay_panel.top) {
                drawRoundedRect(
                    hdc,
                    overlay_panel,
                    if (theme.is_dark)
                        adjustColor(theme.overlay_bg, 4, 4, 6)
                    else
                        adjustColor(theme.overlay_bg, -4, -4, -4),
                    if (theme.is_dark)
                        adjustColor(theme.overlay_border, 10, 10, 12)
                    else
                        adjustColor(theme.overlay_border, -18, -18, -18),
                    self.scaled(7),
                );
                fillSolidRect(hdc, .{
                    .left = overlay_panel.left + self.scaled(6),
                    .top = overlay_panel.top + self.scaled(6),
                    .right = overlay_panel.left + self.scaled(9),
                    .bottom = overlay_panel.bottom - self.scaled(6),
                }, overlayAccentColor(self.overlay_mode, theme.is_dark));
            }
            fillSolidRect(
                hdc,
                .{
                    .left = 0,
                    .top = overlay_rect.bottom - 1,
                    .right = client_rect.right,
                    .bottom = overlay_rect.bottom,
                },
                theme.chrome_border,
            );

            const surface = self.activeSurface();
            const overlay_paint_dirty = overlayPaintCacheDirty(
                self.chrome_text_dirty.overlay,
                self.overlay_mode,
                self.cached_overlay_paint_label_w,
                self.cached_overlay_paint_feedback_w,
                self.cached_overlay_paint_badge_w,
            );
            if (overlay_paint_dirty) {
                const overlay_text = std.mem.trim(u8, overlayEditText(self) catch "", " \t\r\n");
                const overlay_status = if (surface) |value| self.app.hostTabStatus(value) else HostTabStatus{};
                const pane_count = if (self.activeTab()) |tab| tab.leafCount() else 1;
                const overlay_label = if (self.overlay_mode == .profile)
                    buildProfileOverlayLabel(
                        alloc,
                        self.profiles orelse &.{},
                        overlay_text,
                        self.selectedProfileIndex() orelse 0,
                    ) catch return
                else
                    buildOverlayPaintLabelText(
                        alloc,
                        self.overlay_mode,
                        overlay_text,
                        if (surface) |value| value.search_total else null,
                        if (surface) |value| value.search_selected else null,
                        overlay_status,
                        self.paletteSnapshot(),
                    ) catch return;
                defer alloc.free(overlay_label);
                if (self.cached_overlay_paint_label_w) |old| alloc.free(old);
                self.cached_overlay_paint_label_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, overlay_label) catch return;

                const overlay_feedback = if (self.overlay_mode == .profile)
                    if (self.banner_text) |value|
                        switch (self.banner_kind) {
                            .err => std.fmt.allocPrint(alloc, "Error: {s}", .{value}) catch return,
                            .info => std.fmt.allocPrint(alloc, "Info: {s}", .{value}) catch return,
                            .none => alloc.dupe(u8, value) catch return,
                        }
                    else
                        buildProfileHintText(
                            alloc,
                            self.profiles,
                            overlay_text,
                            self.selectedProfileIndex() orelse 0,
                            self.app.launcher_profile_target,
                            self.app.launcher_quick_slot_keys,
                        ) catch return
                else feedback: {
                    var mru_buf: [5][]const u8 = undefined;
                    const mru = self.app.paletteMruSlice(&mru_buf);
                    break :feedback buildOverlayFeedbackText(
                        alloc,
                        self.banner_kind,
                        self.banner_text,
                        self.overlay_mode,
                        overlay_text,
                        if (surface) |value| value.search_needle else null,
                        if (surface) |value| value.search_total else null,
                        if (surface) |value| value.search_selected else null,
                        overlay_status,
                        pane_count,
                        self.paletteSnapshot(),
                        mru,
                    ) catch return;
                };
                defer alloc.free(overlay_feedback);
                if (self.cached_overlay_paint_feedback_w) |old| alloc.free(old);
                self.cached_overlay_paint_feedback_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, overlay_feedback) catch return;

                if (self.overlay_mode == .profile) {
                    if (self.selectedProfile()) |profile| {
                        const badge = buildProfileChromeBadgeText(alloc, profile.kind) catch return;
                        defer alloc.free(badge);
                        if (self.cached_overlay_paint_badge_w) |old| alloc.free(old);
                        self.cached_overlay_paint_badge_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, badge) catch return;
                    } else {
                        if (self.cached_overlay_paint_badge_w) |old| alloc.free(old);
                        self.cached_overlay_paint_badge_w = null;
                    }
                } else {
                    if (self.cached_overlay_paint_badge_w) |old| alloc.free(old);
                    self.cached_overlay_paint_badge_w = null;
                }
                self.chrome_text_dirty.overlay = false;
            }
            _ = SetBkMode(hdc, TRANSPARENT);
            var overlay_label_x: i32 = self.scaled(host_overlay_padding) + self.scaled(10);
            var overlay_label_color: u32 = theme.overlay_label_fg;
            if (self.overlay_mode == .profile) {
                if (self.selectedProfile()) |profile| {
                    const badge_w = self.cached_overlay_paint_badge_w orelse return;
                    const badge_width = self.scaled(16) + @as(i32, @intCast(badge_w.len * @as(usize, @intCast(self.scaled(7)))));
                    const badge_rect = RECT{
                        .left = self.scaled(host_overlay_padding) + self.scaled(10),
                        .top = overlay_rect.top + self.scaled(5),
                        .right = self.scaled(host_overlay_padding) + self.scaled(10) + badge_width,
                        .bottom = overlay_rect.top + self.scaled(23),
                    };
                    const accent = profileChromeAccent(profile.kind, theme.is_dark);
                    drawRoundedRect(hdc, badge_rect, accent.idle_bg, accent.idle_border, self.scaled(3));
                    _ = SetTextColor(hdc, profileKindLabelColor(profile.kind, theme.is_dark));
                    var badge_text_rect = badge_rect;
                    badge_text_rect.left += self.scaled(6);
                    badge_text_rect.right -= self.scaled(6);
                    drawTextWz(
                        hdc,
                        badge_w,
                        &badge_text_rect,
                        DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX,
                    );
                    overlay_label_x = badge_rect.right + self.scaled(10);
                    overlay_label_color = profileKindLabelColor(profile.kind, theme.is_dark);
                }
            }
            _ = SetTextColor(hdc, overlay_label_color);
            if (self.cached_overlay_paint_label_w) |overlay_label_w| {
                textOutWz(hdc, overlay_label_x, overlay_rect.top + self.scaled(7), overlay_label_w);
            }

            const overlay_padding = self.scaled(host_overlay_padding);
            const overlay_accept_w = if (overlayAcceptButtonVisible(self.overlay_mode))
                self.scaled(host_overlay_accept_width) + overlay_padding
            else
                0;
            const edit_frame = overlayEditFrameRect(
                client_rect.right,
                tab_h,
                overlay_padding,
                self.scaled(host_overlay_label_width),
                self.scaled(host_overlay_cancel_width),
                overlay_accept_w,
                self.scaled(host_overlay_row_height),
            );
            const overlay_edit_focused = if (self.overlay_edit_hwnd) |edit_hwnd|
                GetFocus() == edit_hwnd
            else
                false;
            drawRoundedRect(hdc, edit_frame, theme.edit_frame_bg, overlayEditBorderColor(self.overlay_mode, overlay_edit_focused, theme.is_dark), self.scaled(4));

            _ = SetTextColor(hdc, if (self.overlay_mode == .profile and self.banner_text == null)
                if (self.selectedProfile()) |profile|
                    profileKindHintColor(profile.kind, theme.is_dark)
                else
                    theme.text_secondary
            else switch (if (self.banner_text != null) self.banner_kind else .none) {
                .none => theme.text_secondary,
                .info => theme.info_fg,
                .err => theme.error_fg,
            });
            if (self.cached_overlay_paint_feedback_w) |overlay_feedback_w| {
                textOutWz(hdc, self.scaled(host_overlay_padding) + self.scaled(10), overlay_rect.top + self.scaled(34), overlay_feedback_w);
            }
        }

        if (paint_content) {
            // Content-lane paints can arrive after search-frame or pane
            // geometry shrinks/moves. Clear the exposed parent-painted
            // lane first so stale owner-drawn frame/group chrome from the
            // previous layout does not linger until a later full repaint.
            //
            // This still respects the host clip region from BeginPaint, so
            // child GL surfaces are not brute-force repainted here.
            fillSolidRect(hdc, content_rect, theme.chrome_bg);

            if (self.activeTab()) |tab| {
                var it = tab.tree.iterator();
                while (it.next()) |entry| {
                    if (!entry.view.search_bar_frame_visible) continue;
                    const frame_rect = entry.view.search_bar_frame_rect;
                    if (frame_rect.right <= frame_rect.left or frame_rect.bottom <= frame_rect.top) continue;

                    drawRoundedRect(
                        hdc,
                        frame_rect,
                        if (theme.is_dark)
                            adjustColor(theme.overlay_bg, 3, 3, 5)
                        else
                            adjustColor(theme.overlay_bg, -2, -2, -1),
                        if (theme.is_dark)
                            adjustColor(theme.overlay_border, 10, 10, 12)
                        else
                            adjustColor(theme.overlay_border, -14, -14, -14),
                        self.scaled(8),
                    );
                    fillSolidRect(hdc, .{
                        .left = frame_rect.left + self.scaled(8),
                        .top = frame_rect.bottom,
                        .right = frame_rect.right - self.scaled(8),
                        .bottom = frame_rect.bottom + 1,
                    }, if (theme.is_dark)
                        adjustColor(theme.overlay_border, -10, -10, -8)
                    else
                        adjustColor(theme.overlay_border, 10, 10, 10));

                    if (searchBarGroupRect(&[_]ChildPlacement{
                        entry.view.search_bar_results_placement,
                        entry.view.search_bar_prev_placement,
                        entry.view.search_bar_next_placement,
                        entry.view.search_bar_regex_placement,
                        entry.view.search_bar_case_placement,
                        entry.view.search_bar_word_placement,
                    }, self.scaled(4), self.scaled(2))) |toolbar_rect| {
                        const toolbar = searchBarToolbarVisual(theme);
                        drawRoundedRect(
                            hdc,
                            toolbar_rect,
                            toolbar.bg,
                            toolbar.border,
                            self.scaled(7),
                        );

                        const sep_top = toolbar_rect.top + self.scaled(6);
                        const sep_bottom = toolbar_rect.bottom - self.scaled(6);
                        if (sep_bottom > sep_top) {
                            if (searchBarSeparatorX(
                                entry.view.search_bar_results_placement,
                                entry.view.search_bar_prev_placement,
                            )) |sep_x| {
                                fillSolidRect(hdc, .{
                                    .left = sep_x,
                                    .top = sep_top,
                                    .right = sep_x + 1,
                                    .bottom = sep_bottom,
                                }, toolbar.separator);
                            }
                            if (searchBarSeparatorX(
                                entry.view.search_bar_prev_placement,
                                entry.view.search_bar_next_placement,
                            )) |sep_x| {
                                fillSolidRect(hdc, .{
                                    .left = sep_x,
                                    .top = sep_top,
                                    .right = sep_x + 1,
                                    .bottom = sep_bottom,
                                }, toolbar.separator);
                            }
                            if (searchBarSeparatorX(
                                entry.view.search_bar_next_placement,
                                entry.view.search_bar_regex_placement,
                            )) |sep_x| {
                                fillSolidRect(hdc, .{
                                    .left = sep_x,
                                    .top = sep_top,
                                    .right = sep_x + 1,
                                    .bottom = sep_bottom,
                                }, toolbar.separator);
                            }
                        }
                    }
                    if (entry.view.search_bar_edit_placement.rect_known) {
                        const edit_rect = entry.view.search_bar_edit_placement.rect;
                        const edit_focused = if (entry.view.search_bar_edit_hwnd) |edit_hwnd|
                            GetFocus() == edit_hwnd
                        else
                            false;
                        const edit_frame_rect = RECT{
                            .left = edit_rect.left - self.scaled(1),
                            .top = edit_rect.top - self.scaled(1),
                            .right = edit_rect.right + self.scaled(1),
                            .bottom = edit_rect.bottom + self.scaled(1),
                        };
                        drawRoundedRect(
                            hdc,
                            edit_frame_rect,
                            theme.edit_frame_bg,
                            theme.edit_frame_bg,
                            self.scaled(6),
                        );
                        if (edit_focused) {
                            fillSolidRect(hdc, .{
                                .left = edit_frame_rect.left + self.scaled(8),
                                .top = edit_frame_rect.bottom - self.scaled(2),
                                .right = edit_frame_rect.right - self.scaled(8),
                                .bottom = edit_frame_rect.bottom,
                            }, overlayAccentColor(.search, theme.is_dark));
                        }
                    }
                }
            }
        }

        if (paint_top and inspector_panel_visible) {
            const panel_rect = RECT{
                .left = 0,
                .top = tab_h + overlay_offset,
                .right = client_rect.right,
                .bottom = tab_h + overlay_offset + self.scaled(host_inspector_panel_height),
            };
            fillSolidRect(hdc, panel_rect, theme.inspector_bg);
            fillSolidRect(
                hdc,
                .{
                    .left = 0,
                    .top = panel_rect.bottom - 1,
                    .right = client_rect.right,
                    .bottom = panel_rect.bottom,
                },
                theme.chrome_border,
            );

            if (self.activeSurface()) |surface| {
                if (self.chrome_text_dirty.inspector) {
                    const host_status = self.app.hostTabStatus(surface);
                    const pane_count = if (self.activeTab()) |tab| tab.leafCount() else 1;
                    const zoomed = if (self.activeTab()) |tab| tab.tree.zoomed != null else false;

                    if (self.cached_inspector_title_w) |old| alloc.free(old);
                    self.cached_inspector_title_w = blk: {
                        const utf8 = buildInspectorPanelTitleText(alloc, host_status, pane_count, zoomed) catch break :blk null;
                        defer alloc.free(utf8);
                        break :blk std.unicode.utf8ToUtf16LeAllocZ(alloc, utf8) catch null;
                    };

                    if (self.cached_inspector_hint_w) |old| alloc.free(old);
                    self.cached_inspector_hint_w = blk: {
                        const utf8 = buildInspectorPanelHintText(alloc, pane_count, zoomed) catch break :blk null;
                        defer alloc.free(utf8);
                        break :blk std.unicode.utf8ToUtf16LeAllocZ(alloc, utf8) catch null;
                    };
                    self.chrome_text_dirty.inspector = false;
                }

                _ = SetBkMode(hdc, TRANSPARENT);
                if (self.cached_inspector_title_w) |title_w| {
                    _ = SetTextColor(hdc, theme.overlay_label_fg);
                    textOutWz(hdc, self.scaled(16), panel_rect.top + self.scaled(6), title_w);
                }
                if (self.cached_inspector_hint_w) |hint_w| {
                    _ = SetTextColor(hdc, theme.text_secondary);
                    textOutWz(hdc, self.scaled(16), panel_rect.top + self.scaled(22), hint_w);
                }
            }
        }

        // Paint pane divider gaps between split panes
        if (paint_content) {
            if (self.activeTab()) |active_tab| {
                if (active_tab.leafCount() > 1) {
                    const c_rect = content_rect;
                    const c_width = @max(1, c_rect.right - c_rect.left);
                    const c_height = @max(1, c_rect.bottom - c_rect.top);
                    // Fill entire content area with divider color first (gap pixels)
                    fillSolidRect(hdc, c_rect, theme.pane_divider);
                    // Draw accent border around focused pane
                    const focused_surface = self.activeSurface();
                    if (focused_surface) |surface| {
                        if (surface.hwnd) |surface_hwnd| {
                            var sr: RECT = undefined;
                            if (GetWindowRect(surface_hwnd, &sr) != 0) {
                                var tl = POINT{ .x = sr.left, .y = sr.top };
                                var br = POINT{ .x = sr.right, .y = sr.bottom };
                                _ = ScreenToClient(hwnd, &tl);
                                _ = ScreenToClient(hwnd, &br);
                                // Only draw focus border if pane is within content area
                                if (tl.x >= c_rect.left and br.x <= c_rect.right and
                                    tl.y >= c_rect.top and br.y <= c_rect.bottom)
                                {
                                    const bw: i32 = 1; // border width for focus accent
                                    // Top
                                    if (tl.y > c_rect.top) fillSolidRect(hdc, .{ .left = tl.x - bw, .top = tl.y - bw, .right = br.x + bw, .bottom = tl.y }, theme.pane_divider_focused);
                                    // Bottom
                                    if (br.y < c_rect.bottom) fillSolidRect(hdc, .{ .left = tl.x - bw, .top = br.y, .right = br.x + bw, .bottom = br.y + bw }, theme.pane_divider_focused);
                                    // Left
                                    if (tl.x > c_rect.left) fillSolidRect(hdc, .{ .left = tl.x - bw, .top = tl.y, .right = tl.x, .bottom = br.y }, theme.pane_divider_focused);
                                    // Right
                                    if (br.x < c_rect.right) fillSolidRect(hdc, .{ .left = br.x, .top = tl.y, .right = br.x + bw, .bottom = br.y }, theme.pane_divider_focused);
                                }
                                _ = c_width;
                                _ = c_height;
                            }
                        }
                    }
                }
            }
        }

        const status_top = @max(tab_h + overlay_offset, client_rect.bottom - @max(1, status_h));
        if (paint_status and status_h > 0) {
            const status_bg_rect = RECT{
                .left = 0,
                .top = status_top,
                .right = client_rect.right,
                .bottom = client_rect.bottom,
            };
            fillSolidRect(hdc, status_bg_rect, theme.status_bg);
            fillSolidRect(
                hdc,
                .{
                    .left = 0,
                    .top = status_top,
                    .right = client_rect.right,
                    .bottom = status_top + 1,
                },
                theme.chrome_border,
            );
        }
        _ = SetBkMode(hdc, TRANSPARENT);
        _ = SetTextColor(hdc, theme.text_primary);

        const explicit_banner_text: ?[]const u8 = if (self.overlay_mode == .none)
            self.banner_text
        else
            null;
        const paint_inspector_banner = blk: {
            if (!paint_top) break :blk false;
            if (self.overlay_mode != .none) break :blk false;
            if (self.banner_text != null) break :blk false;
            if (inspector_panel_visible) break :blk false;
            break :blk self.activeTabHasInspector();
        };
        const banner_kind: HostBannerKind = if (explicit_banner_text != null)
            self.banner_kind
        else if (paint_inspector_banner)
            .info
        else
            .none;
        const paint_update_notice = paint_top and
            self.overlay_mode == .none and
            !inspector_panel_visible and
            self.banner_text == null and
            self.app.update_notice != null;
        if (paint_top and self.chrome_text_dirty.banner) {
            if (self.cached_banner_w) |old| alloc.free(old);
            self.cached_banner_w = null;

            if (paint_update_notice) {
                if (self.app.update_notice) |notice| {
                    if (notice.message_text) |message| {
                        self.cached_banner_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, message) catch return;
                    }
                }
            } else if (explicit_banner_text) |value| {
                const full = buildHostBannerText(alloc, banner_kind, value) catch return;
                defer alloc.free(full);
                self.cached_banner_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, full) catch return;
            } else if (paint_inspector_banner) {
                if (self.activeSurface()) |surface| {
                    const host_status = self.app.hostTabStatus(surface);
                    const pane_count = if (self.activeTab()) |tab| tab.leafCount() else 1;
                    const value = buildInspectorBannerText(
                        alloc,
                        host_status,
                        pane_count,
                        if (self.activeTab()) |tab| tab.tree.zoomed != null else false,
                    ) catch return;
                    defer alloc.free(value);
                    const full = buildHostBannerText(alloc, banner_kind, value) catch return;
                    defer alloc.free(full);
                    self.cached_banner_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, full) catch return;
                }
            }
            self.chrome_text_dirty.banner = false;
        }
        if (paint_top) self.clearUpdateActionRects();
        if (paint_top and self.overlay_mode == .none and !inspector_panel_visible and self.banner_text == null) {
            if (self.app.update_notice) |notice| {
                const open_label = std.unicode.utf8ToUtf16LeStringLiteral("Open Release");
                const dismiss_label = std.unicode.utf8ToUtf16LeStringLiteral("Dismiss");
                const button_height = self.scaled(22);
                const dismiss_width = self.scaled(72);
                const open_width = self.scaled(102);
                const button_gap = self.scaled(8);
                const dismiss_rect = RECT{
                    .left = client_rect.right - dismiss_width - self.scaled(16),
                    .top = banner_y - self.scaled(4),
                    .right = client_rect.right - self.scaled(16),
                    .bottom = banner_y - self.scaled(4) + button_height,
                };
                const open_rect = RECT{
                    .left = dismiss_rect.left - open_width - button_gap,
                    .top = dismiss_rect.top,
                    .right = dismiss_rect.left - button_gap,
                    .bottom = dismiss_rect.bottom,
                };
                self.update_open_rect = open_rect;
                self.update_dismiss_rect = dismiss_rect;

                const text_right = @max(self.scaled(120), open_rect.left - self.scaled(10));
                var text_rect = RECT{
                    .left = self.scaled(16),
                    .top = banner_y - self.scaled(2),
                    .right = text_right,
                    .bottom = banner_y + button_height,
                };

                _ = SetTextColor(hdc, theme.info_fg);
                _ = notice;
                if (self.cached_banner_w) |banner_w| {
                    drawTextWz(
                        hdc,
                        banner_w,
                        &text_rect,
                        DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
                    );
                }

                drawRoundedRect(
                    hdc,
                    open_rect,
                    if (theme.is_dark)
                        adjustColor(theme.overlay_bg, 10, 10, 12)
                    else
                        adjustColor(theme.overlay_bg, -4, -4, -4),
                    theme.info_fg,
                    self.scaled(5),
                );
                drawRoundedRect(
                    hdc,
                    dismiss_rect,
                    if (theme.is_dark)
                        adjustColor(theme.status_bg, 10, 10, 12)
                    else
                        adjustColor(theme.status_bg, -4, -4, -4),
                    theme.chrome_border,
                    self.scaled(5),
                );

                _ = SetTextColor(hdc, theme.text_primary);
                var open_text_rect = open_rect;
                open_text_rect.left += self.scaled(6);
                open_text_rect.right -= self.scaled(6);
                var dismiss_text_rect = dismiss_rect;
                dismiss_text_rect.left += self.scaled(6);
                dismiss_text_rect.right -= self.scaled(6);
                _ = DrawTextW(
                    hdc,
                    open_label,
                    @intCast(std.mem.sliceTo(open_label, 0).len),
                    &open_text_rect,
                    DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX,
                );
                _ = DrawTextW(
                    hdc,
                    dismiss_label,
                    @intCast(std.mem.sliceTo(dismiss_label, 0).len),
                    &dismiss_text_rect,
                    DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX,
                );
            } else if (paint_inspector_banner) {
                _ = SetTextColor(hdc, switch (banner_kind) {
                    .none => theme.text_primary,
                    .info => theme.info_fg,
                    .err => theme.error_fg,
                });
                if (self.cached_banner_w) |banner_w| {
                    textOutWz(hdc, self.scaled(16), banner_y, banner_w);
                }
            }
        } else if (explicit_banner_text != null) {
            _ = SetTextColor(hdc, switch (banner_kind) {
                .none => theme.text_primary,
                .info => theme.info_fg,
                .err => theme.error_fg,
            });
            if (self.cached_banner_w) |banner_w| {
                textOutWz(hdc, self.scaled(16), banner_y, banner_w);
            }
        }
        _ = SetTextColor(hdc, theme.text_primary);
        if (status_h <= 0) {
            self.chrome_repaint_dirty = false;
            return;
        }

        const status_y = @max(self.scaled(host_tab_height) + self.scaled(2), ps.rcPaint.bottom - @max(1, status_h) + self.scaled(4));
        var status_x: i32 = self.scaled(16);
        const launcher_lane_right: ?i32 = blk: {
            if (!(status_h > 0 and self.overlay_mode == .none and self.selectedProfile() != null)) break :blk null;
            const estimated = self.estimateLauncherLaneRight();
            const lane_right = @min(client_rect.right - self.scaled(18), estimated + self.scaled(6));
            if (lane_right <= self.scaled(24)) break :blk null;
            break :blk lane_right;
        };
        if (paint_status) {
            if (launcher_lane_right) |lane_right| {
                const lane_rect = RECT{
                    .left = self.scaled(10),
                    .top = status_y - self.scaled(5),
                    .right = lane_right,
                    .bottom = status_y + self.scaled(16),
                };
                drawRoundedRect(
                    hdc,
                    lane_rect,
                    if (theme.is_dark)
                        adjustColor(theme.status_bg, 8, 8, 10)
                    else
                        adjustColor(theme.status_bg, -6, -6, -6),
                    if (theme.is_dark)
                        adjustColor(theme.chrome_border, 12, 12, 14)
                    else
                        adjustColor(theme.chrome_border, -18, -18, -18),
                    self.scaled(6),
                );
                if (self.selectedProfile()) |profile| {
                    fillSolidRect(hdc, .{
                        .left = lane_rect.left + self.scaled(6),
                        .top = lane_rect.top + self.scaled(5),
                        .right = lane_rect.left + self.scaled(9),
                        .bottom = lane_rect.bottom - self.scaled(5),
                    }, profileKindHintColor(profile.kind, theme.is_dark));
                }
            }
        }
        if (paint_status and status_h > 0 and self.overlay_mode == .none) {
            const selected_profile_index = self.selectedProfileIndex();
            if (self.chrome_text_dirty.status) {
                if (self.cached_launcher_selected_chip_w) |old| alloc.free(old);
                self.cached_launcher_selected_chip_w = null;
                for (&self.cached_launcher_quick_slot_chip_w) |*slot| {
                    if (slot.*) |old| alloc.free(old);
                    slot.* = null;
                }

                if (self.selectedProfile()) |profile| {
                    const chip = buildProfileStatusBadgeText(
                        alloc,
                        profile,
                        selected_profile_index,
                        self.app.launcherQuickSlotOrdinal(profile.key),
                    ) catch return;
                    defer alloc.free(chip);
                    self.cached_launcher_selected_chip_w = std.unicode.utf8ToUtf16LeAllocZ(alloc, chip) catch return;
                }

                if (self.profiles) |profiles| {
                    var cached_slot: usize = 0;
                    for (profiles, 0..) |*profile, index| {
                        if (cached_slot >= self.cached_launcher_quick_slot_chip_w.len) break;
                        if (selected_profile_index != null and index == selected_profile_index.?) continue;
                        const chip = buildProfileQuickSlotChipText(
                            alloc,
                            profile,
                            index,
                            self.app.launcherQuickSlotOrdinal(profile.key),
                        ) catch return;
                        defer alloc.free(chip);
                        self.cached_launcher_quick_slot_chip_w[cached_slot] = std.unicode.utf8ToUtf16LeAllocZ(alloc, chip) catch return;
                        cached_slot += 1;
                    }
                }
            }

            if (self.selectedProfile()) |profile| {
                const pinned_slot_ordinal = self.app.launcherQuickSlotOrdinal(profile.key);
                const pinned_slot_digit = pinnedSlotBadgeDigit(pinned_slot_ordinal);
                const chip_w = self.cached_launcher_selected_chip_w orelse return;
                const accent = profileChromeAccent(profile.kind, theme.is_dark);
                const chip_width = self.scaled(16) + @as(i32, @intCast(profileStatusBadgeTextLen(
                    profile,
                    selected_profile_index,
                    pinned_slot_ordinal,
                ) * @as(usize, @intCast(self.scaled(7)))));
                const chip_rect = RECT{
                    .left = status_x,
                    .top = status_y - self.scaled(2),
                    .right = status_x + chip_width,
                    .bottom = status_y + self.scaled(14),
                };
                drawRoundedRect(hdc, chip_rect, accent.idle_bg, accent.idle_border, self.scaled(3));
                if (pinned_slot_digit) |digit| {
                    paintPinnedSlotBadge(
                        hdc,
                        chip_rect,
                        digit,
                        accent.idle_border,
                        accent.idle_bg,
                        profileKindLabelColor(profile.kind, theme.is_dark),
                        self.current_dpi,
                    );
                }
                paintTargetChipBadge(
                    hdc,
                    chip_rect,
                    profileOpenTargetBadgeGlyph(self.app.launcher_profile_target),
                    accent.idle_border,
                    accent.idle_bg,
                    profileOpenTargetMarkerColor(self.app.launcher_profile_target),
                    self.current_dpi,
                );
                _ = SetTextColor(hdc, profileKindLabelColor(profile.kind, theme.is_dark));
                var chip_text_rect = chip_rect;
                chip_text_rect.left += self.scaled(6);
                chip_text_rect.right -= launcherChipRightInset(pinned_slot_digit != null, true);
                drawTextWz(
                    hdc,
                    chip_w,
                    &chip_text_rect,
                    DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
                );
                status_x = chip_rect.right + self.scaled(10);
            }
            if (self.profiles) |profiles| {
                var drawn: usize = 0;
                for (profiles, 0..) |*profile, index| {
                    if (drawn >= 3) break;
                    if (selected_profile_index != null and index == selected_profile_index.?) continue;
                    const pinned_slot_ordinal = self.app.launcherQuickSlotOrdinal(profile.key);
                    const chip_w = self.cached_launcher_quick_slot_chip_w[drawn] orelse return;
                    const focused = self.focused_quick_slot != null and self.focused_quick_slot.? == index;
                    const hovered = self.hovered_quick_slot != null and self.hovered_quick_slot.? == index;
                    const target_marker = shouldPaintQuickSlotTargetMarker(hovered, focused);
                    const colors = quickSlotChipColors(profile.kind, theme.is_dark, hovered);
                    const chip_width = self.scaled(12) + @as(i32, @intCast(profileQuickSlotChipTextLen(
                        profile,
                        index,
                        pinned_slot_ordinal,
                    ) * @as(usize, @intCast(self.scaled(7)))));
                    const chip_rect = RECT{
                        .left = status_x,
                        .top = status_y - self.scaled(1),
                        .right = status_x + chip_width,
                        .bottom = status_y + self.scaled(13),
                    };
                    drawRoundedRect(hdc, chip_rect, colors.bg, colors.border, self.scaled(3));
                    if (pinned_slot_ordinal != null and pinned_slot_ordinal.? == index) {
                        paintPinnedChipMarker(
                            hdc,
                            chip_rect,
                            pinnedChipMarkerColor(profile.kind, theme.is_dark, hovered),
                            self.current_dpi,
                        );
                    }
                    if (target_marker) {
                        paintTargetChipBadge(
                            hdc,
                            chip_rect,
                            profileOpenTargetBadgeGlyph(self.app.launcher_profile_target),
                            colors.border,
                            colors.bg,
                            profileOpenTargetMarkerColor(self.app.launcher_profile_target),
                            self.current_dpi,
                        );
                    }
                    if (focused) {
                        const focus_ring = profileKindFocusRingColor(profile.kind, theme.is_dark);
                        fillSolidRect(hdc, .{
                            .left = chip_rect.left + self.scaled(2),
                            .top = chip_rect.top + self.scaled(2),
                            .right = chip_rect.right - self.scaled(2),
                            .bottom = chip_rect.top + self.scaled(4),
                        }, focus_ring);
                        fillSolidRect(hdc, .{
                            .left = chip_rect.left + self.scaled(2),
                            .top = chip_rect.bottom - self.scaled(4),
                            .right = chip_rect.right - self.scaled(2),
                            .bottom = chip_rect.bottom - self.scaled(2),
                        }, focus_ring);
                        fillSolidRect(hdc, .{
                            .left = chip_rect.left + self.scaled(2),
                            .top = chip_rect.top + self.scaled(2),
                            .right = chip_rect.left + self.scaled(4),
                            .bottom = chip_rect.bottom - self.scaled(2),
                        }, focus_ring);
                        fillSolidRect(hdc, .{
                            .left = chip_rect.right - self.scaled(4),
                            .top = chip_rect.top + self.scaled(2),
                            .right = chip_rect.right - self.scaled(2),
                            .bottom = chip_rect.bottom - self.scaled(2),
                        }, focus_ring);
                    }
                    _ = SetTextColor(hdc, colors.fg);
                    var chip_text_rect = chip_rect;
                    chip_text_rect.left += self.scaled(5);
                    chip_text_rect.right -= launcherChipRightInset(false, target_marker);
                    drawTextWz(
                        hdc,
                        chip_w,
                        &chip_text_rect,
                        DT_CENTER | DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
                    );
                    status_x = chip_rect.right + self.scaled(6);
                    drawn += 1;
                }
            }
        }
        if (launcher_lane_right) |lane_right| {
            status_x = @max(status_x, lane_right + self.scaled(10));
            fillSolidRect(hdc, .{
                .left = status_x - self.scaled(5),
                .top = status_y - self.scaled(1),
                .right = status_x - self.scaled(4),
                .bottom = status_y + self.scaled(12),
            }, theme.chrome_border);
        }
        if (paint_status and self.chrome_text_dirty.status) {
            if (self.cached_status_w) |old| alloc.free(old);
            self.cached_status_w = blk: {
                const utf8 = self.statusText(alloc) catch break :blk null;
                const owned = utf8 orelse break :blk null;
                defer alloc.free(owned);
                break :blk std.unicode.utf8ToUtf16LeAllocZ(alloc, owned) catch null;
            };

            if (self.cached_detail_w) |old| alloc.free(old);
            self.cached_detail_w = blk: {
                const utf8 = self.detailText(alloc) catch break :blk null;
                const owned = utf8 orelse break :blk null;
                defer alloc.free(owned);
                break :blk std.unicode.utf8ToUtf16LeAllocZ(alloc, owned) catch null;
            };

            self.chrome_text_dirty.status = false;
        }

        if (paint_status) {
            if (self.cached_status_w) |status_w| {
                textOutWz(hdc, status_x, status_y, status_w);
            }
        }
        if (paint_status) {
            if (self.cached_detail_w) |detail_w| {
                _ = SetTextColor(hdc, theme.text_secondary);
                textOutWz(hdc, status_x, status_y + self.scaled(18), detail_w);
            }
        }
        self.chrome_repaint_dirty = false;
    }
};

fn destroyChildWindow(hwnd_slot: *?HWND) void {
    const hwnd = hwnd_slot.* orelse return;

    hwnd_slot.* = null;
    if (IsWindow(hwnd) == 0) return;

    _ = SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
    _ = DestroyWindow(hwnd);
}

fn destroySubclassedWindowWithPrev(
    hwnd_slot: *?HWND,
    prev_proc: ?*const anyopaque,
) void {
    const hwnd = hwnd_slot.* orelse return;

    // Detach host state before destroying the control. DestroyWindow is
    // synchronous and can reenter our subclass proc during WM_DESTROY /
    // WM_NCDESTROY, so leaving the HWND discoverable via host tabs/buttons
    // risks callbacks touching half-torn state.
    hwnd_slot.* = null;
    if (IsWindow(hwnd) == 0) return;

    _ = SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
    if (prev_proc) |proc| {
        _ = SetWindowLongPtrW(
            hwnd,
            GWLP_WNDPROC,
            @as(LONG_PTR, @intCast(@intFromPtr(proc))),
        );
    }
    _ = DestroyWindow(hwnd);
}

fn destroySubclassedWindow(
    hwnd_slot: *?HWND,
    prev_proc_slot: *?*const anyopaque,
) void {
    const prev_proc = prev_proc_slot.*;
    prev_proc_slot.* = null;
    destroySubclassedWindowWithPrev(hwnd_slot, prev_proc);
}

const SurfaceInitOptions = struct {
    quick_terminal: bool = false,
    host_id: ?u32 = null,
    tab_id: ?u32 = null,
    clone_state_from: ?*const Surface = null,
    split_direction: SplitTreeSurface.Split.Direction = .right,
    /// Passive first-show: the newly-created host HWND is shown via
    /// `SW_SHOWNOACTIVATE` instead of `SW_SHOW`, so it becomes
    /// visible without stealing focus from the caller's current
    /// foreground window. Used by the quick-terminal passive mode
    /// (`quick-terminal-keyboard-interactivity = none`) on first
    /// toggle-on.
    passive_show: bool = false,
};

const SplitSurfaceAttachRollback = struct {
    tab: *Tab,
    tree: SplitTreeSurface,
    focused: SplitTreeSurface.Node.Handle,
};

fn rollbackFailedSurfaceAttach(
    tabs: *std.ArrayListUnmanaged(Tab),
    active_tab: *usize,
    prev_active_tab: usize,
    prev_tab_count: usize,
    split_rollback: *?SplitSurfaceAttachRollback,
) void {
    if (split_rollback.*) |state| {
        state.tab.tree.deinit();
        state.tab.tree = state.tree;
        state.tab.focused = state.focused;
        split_rollback.* = null;
    } else if (tabs.items.len > prev_tab_count) {
        var removed = tabs.orderedRemove(tabs.items.len - 1);
        removed.deinit();
    }

    active_tab.* = @min(prev_active_tab, if (tabs.items.len > 0) tabs.items.len - 1 else 0);
}

fn commitSplitSurfaceAttach(split_rollback: *?SplitSurfaceAttachRollback) void {
    if (split_rollback.*) |*state| {
        state.tree.deinit();
        split_rollback.* = null;
    }
}

const RestoredTerminalUndoState = struct {
    title: ?[]const u8 = null,
    pwd: ?[]const u8 = null,
    scrollbar: terminal.Scrollbar = .zero,
};

const undo_snapshot_magic = "WUH1";

fn captureTerminalUndoStateBytes(
    alloc: Allocator,
    terminal_state: *const terminal.Terminal,
) ![]u8 {
    var vt_buf: std.Io.Writer.Allocating = .init(alloc);
    defer vt_buf.deinit();

    var formatter = terminal.formatter.TerminalFormatter.init(
        terminal_state,
        .vt,
    );
    formatter.extra = .all;
    formatter.extra.pwd = false;
    try formatter.format(&vt_buf.writer);

    const vt_bytes = try vt_buf.toOwnedSlice();
    defer alloc.free(vt_bytes);

    const title = terminal_state.getTitle() orelse "";
    const pwd = terminal_state.getPwd() orelse "";

    var buf: std.Io.Writer.Allocating = .init(alloc);
    defer buf.deinit();
    try buf.writer.writeAll(undo_snapshot_magic);
    try buf.writer.writeInt(u32, @intCast(title.len), .little);
    try buf.writer.writeInt(u32, @intCast(pwd.len), .little);
    try buf.writer.writeAll(title);
    try buf.writer.writeAll(pwd);
    try buf.writer.writeAll(vt_bytes);
    return try buf.toOwnedSlice();
}

fn restoreTerminalUndoState(
    terminal_state: *terminal.Terminal,
    state_bytes: []const u8,
) RestoredTerminalUndoState {
    var title_bytes: []const u8 = "";
    var pwd_bytes: []const u8 = "";
    var vt_bytes = state_bytes;
    if (state_bytes.len >= 12 and std.mem.eql(u8, state_bytes[0..4], undo_snapshot_magic)) {
        const title_len: usize = std.mem.readInt(u32, state_bytes[4..8], .little);
        const pwd_len: usize = std.mem.readInt(u32, state_bytes[8..12], .little);
        const title_start = 12;
        const pwd_start = title_start + title_len;
        const vt_start = pwd_start + pwd_len;
        if (vt_start <= state_bytes.len) {
            title_bytes = state_bytes[title_start..pwd_start];
            pwd_bytes = state_bytes[pwd_start..vt_start];
            vt_bytes = state_bytes[vt_start..];
        }
    }

    terminal_state.fullReset();
    var stream = terminal_state.vtStream();
    defer stream.deinit();
    stream.nextSlice(vt_bytes);
    if (title_bytes.len > 0) {
        terminal_state.setTitle(title_bytes) catch |err| {
            log.warn("undo snapshot title restore failed err={}", .{err});
        };
    }
    if (pwd_bytes.len > 0) {
        terminal_state.setPwd(pwd_bytes) catch |err| {
            log.warn("undo snapshot pwd restore failed err={}", .{err});
        };
    }

    return .{
        .title = terminal_state.getTitle(),
        .pwd = terminal_state.getPwd(),
        .scrollbar = terminal_state.screens.active.pages.scrollbar(),
    };
}

