    none,
    info,
    err,
};

const TabButtonKeyAction = enum {
    previous,
    next,
    first,
    last,
    move_previous,
    move_next,
    move_first,
    move_last,
    rename,
    close,
    overview,
};

const SearchButtonKeyAction = enum {
    next,
    previous,
    dismiss,
};

const TabsButtonKeyAction = enum {
    previous,
    next,
    rename,
    overview,
};

const CommandButtonKeyAction = enum {
    toggle,
    previous,
    next,
    dismiss,
};

const ProfilesButtonKeyAction = enum {
    open,
    toggle,
    previous,
    next,
    first,
    last,
};

const QuickSlotFocusKeyAction = enum {
    previous,
    next,
    first,
    last,
    open,
};

const LaunchTargetButtonKeyAction = enum {
    previous,
    next,
    first,
    last,
};

const ProfileOpenTarget = enum {
    tab,
    window,
    split,
};

fn parseProfileOpenTarget(raw: []const u8) ?ProfileOpenTarget {
    if (std.ascii.eqlIgnoreCase(raw, "tab")) return .tab;
    if (std.ascii.eqlIgnoreCase(raw, "window") or std.ascii.eqlIgnoreCase(raw, "win")) return .window;
    if (std.ascii.eqlIgnoreCase(raw, "split") or std.ascii.eqlIgnoreCase(raw, "pane")) return .split;
    return null;
}

fn resolveProfileOpenTarget(default_target: ProfileOpenTarget, shift: bool, control: bool) ProfileOpenTarget {
    if (control) return .split;
    if (shift) return .window;
    return default_target;
}

fn cycleProfileOpenTarget(current: ProfileOpenTarget, reverse: bool) ProfileOpenTarget {
    return switch (current) {
        .tab => if (reverse) .split else .window,
        .window => if (reverse) .tab else .split,
        .split => if (reverse) .window else .tab,
    };
}

fn launchTargetButtonKeyAction(vk: WPARAM) ?LaunchTargetButtonKeyAction {
    return switch (vk) {
        VK_LEFT, VK_UP => .previous,
        VK_RIGHT, VK_DOWN, VK_RETURN, VK_SPACE => .next,
        VK_HOME => .first,
        VK_END => .last,
        else => null,
    };
}

fn appendOwnedString(
    alloc: Allocator,
    target: *?[:0]const u8,
    value: ?[]const u8,
) !void {
    if (value) |next_value| {
        if (target.*) |existing| {
            if (std.mem.eql(u8, existing, next_value)) return;
        }
    } else if (target.* == null) {
        return;
    }

    // Allocate first, then free the old slot. Reversing the order
    // means that (a) an OOM leaves `*target` holding a still-valid
    // previous allocation instead of a dangling freed pointer, and
    // (b) a caller passing a `value` that aliases the current slot
    // is copied to fresh storage before the free, avoiding UAF.
    const next: ?[:0]const u8 = if (value) |v| try alloc.dupeZ(u8, v) else null;
    if (target.*) |existing| alloc.free(existing);
    target.* = next;
}

fn ownedStringEquals(current: ?[:0]const u8, value: []const u8) bool {
    return if (current) |existing|
        std.mem.eql(u8, existing, value)
    else
        false;
}

fn ownedBytesEquals(current: ?[]const u8, value: []const u8) bool {
    return if (current) |existing|
        std.mem.eql(u8, existing, value)
    else
        false;
}

fn optionalOwnedStringEquals(current: ?[:0]const u8, value: ?[]const u8) bool {
    return if (value) |existing|
        ownedStringEquals(current, existing)
    else
        current == null;
}

fn syncWindowTextUtf8Cached(
    alloc: Allocator,
    hwnd: HWND,
    cached: *?[:0]const u8,
    value: []const u8,
) !bool {
    if (ownedStringEquals(cached.*, value)) return false;
    try appendOwnedString(alloc, cached, value);
    const value_w = try std.unicode.utf8ToUtf16LeAllocZ(alloc, value);
    defer alloc.free(value_w);
    _ = SetWindowTextW(hwnd, value_w.ptr);
    return true;
}

fn syncWindowTextUtf8CachedAfterSet(
    alloc: Allocator,
    hwnd: HWND,
    cached: *?[:0]const u8,
    value: []const u8,
) !bool {
    if (ownedStringEquals(cached.*, value)) return false;
    const value_w = try std.unicode.utf8ToUtf16LeAllocZ(alloc, value);
    defer alloc.free(value_w);
    _ = SetWindowTextW(hwnd, value_w.ptr);
    try appendOwnedString(alloc, cached, value);
    return true;
}

fn overlayEditText(self: *Host) ![]const u8 {
    const edit_hwnd = self.overlay_edit_hwnd orelse return "";
    if (self.cached_overlay_edit) |value| return value;

    const raw = try readWindowTextUtf8Alloc(self.app.core_app.alloc, edit_hwnd);
    defer self.app.core_app.alloc.free(raw);
    try appendOwnedString(self.app.core_app.alloc, &self.cached_overlay_edit, raw);
    return self.cached_overlay_edit orelse "";
}

fn rectEquals(a: RECT, b: RECT) bool {
    return a.left == b.left and
        a.top == b.top and
        a.right == b.right and
        a.bottom == b.bottom;
}

fn childRect(x: i32, y: i32, width: i32, height: i32) RECT {
    return .{
        .left = x,
        .top = y,
        .right = x + width,
        .bottom = y + height,
    };
}

fn centeredRect(rect: RECT, width: i32, height: i32) RECT {
    const outer_w = rect.right - rect.left;
    const outer_h = rect.bottom - rect.top;
    const left = rect.left + @divTrunc(outer_w - width, 2);
    const top = rect.top + @divTrunc(outer_h - height, 2);
    return childRect(left, top, width, height);
}

fn overlayEditFrameRect(
    width: i32,
    overlay_y: i32,
    padding: i32,
    label_w: i32,
    cancel_w: i32,
    accept_reservation_w: i32,
    row_h: i32,
) RECT {
    const left = padding + label_w;
    const right = width - cancel_w - accept_reservation_w - (padding * 2) - 6;
    return .{
        .left = left,
        .top = overlay_y + 4,
        .right = @max(left + 24, right),
        .bottom = overlay_y + 4 + row_h,
    };
}

fn overlayEditChildRectFromFrame(frame: RECT, inset_x: i32, inset_y: i32) RECT {
    return .{
        .left = frame.left + inset_x,
        .top = frame.top + inset_y,
        .right = @max(frame.left + inset_x + 1, frame.right - inset_x),
        .bottom = @max(frame.top + inset_y + 1, frame.bottom - inset_y),
    };
}

fn syncChildPlacementTarget(placement: *ChildPlacement, hwnd: HWND) void {
    if (placement.hwnd == null or placement.hwnd.? != hwnd) {
        placement.* = .{ .hwnd = hwnd };
    }
}

fn applyChildRect(hwnd: HWND, placement: *ChildPlacement, rect: RECT) bool {
    syncChildPlacementTarget(placement, hwnd);
    if (placement.rect_known and rectEquals(placement.rect, rect)) return false;
    _ = MoveWindow(
        hwnd,
        rect.left,
        rect.top,
        @max(0, rect.right - rect.left),
        @max(0, rect.bottom - rect.top),
        0,
    );
    placement.rect = rect;
    placement.rect_known = true;
    return true;
}

fn applyChildVisibility(hwnd: HWND, placement: *ChildPlacement, visible: bool) bool {
    syncChildPlacementTarget(placement, hwnd);
    if (placement.visible_known and placement.visible == visible) return false;
    _ = ShowWindow(hwnd, if (visible) SW_SHOW else SW_HIDE);
    placement.visible = visible;
    placement.visible_known = true;
    return true;
}

const SurfaceLayoutRuntimeSync = struct {
    scrollbar_refresh: bool,
    core_size_sync: bool,
};

const ScrollbarPaintKey = struct {
    rect: RECT,
    total: usize,
    len: usize,
    offset: usize,
    dpi: u32,
    hovered: bool,
    dragging: bool,
    marker_revision: u64,
};

fn surfaceLayoutRuntimeSync(visibility_changed: bool, pane_rect_changed: bool) SurfaceLayoutRuntimeSync {
    return .{
        .scrollbar_refresh = visibility_changed or pane_rect_changed,
        .core_size_sync = pane_rect_changed,
    };
}

const SurfaceRepaintRequestMode = enum {
    queue,
    update_now,
    defer_until_flush,
};

const ResizeSettleSurfaceAction = enum {
    wake_renderer,
    present_renderer,
};

fn surfaceRepaintRequestMode(host: ?*const Host) SurfaceRepaintRequestMode {
    const h = host orelse return .queue;
    if (h.is_live_resize.load(.acquire)) return .defer_until_flush;
    if (h.resize_settle_timer_active) return .update_now;
    return .queue;
}

fn surfaceSizeChangeRepaintMode(host: ?*const Host) SurfaceRepaintRequestMode {
    return surfaceRepaintRequestMode(host);
}

fn resizeSettleSurfaceAction(renderer_repaint_requested: bool) ResizeSettleSurfaceAction {
    return if (renderer_repaint_requested) .present_renderer else .wake_renderer;
}

fn surfacePixelSizeChanged(previous: apprt.SurfaceSize, next: apprt.SurfaceSize) bool {
    return previous.width != next.width or previous.height != next.height;
}

fn surfaceActivationNeedsHostSync(
    was_windows_hidden: bool,
    host_window_visible: bool,
    target_tab_index: usize,
    active_tab_index: usize,
    target_window_visible: bool,
) bool {
    return was_windows_hidden or
        !host_window_visible or
        target_tab_index != active_tab_index or
        !target_window_visible;
}

fn surfaceFocusedActivationNeedsHostSync(
    was_windows_hidden: bool,
    host_window_visible: bool,
    target_tab_index: usize,
    active_tab_index: usize,
    target_window_visible: bool,
    target_window_focused: bool,
) bool {
    return surfaceActivationNeedsHostSync(
        was_windows_hidden,
        host_window_visible,
        target_tab_index,
        active_tab_index,
        target_window_visible,
    ) or !target_window_focused;
}

fn surfaceFocusStateChanged(
    active_tab_index: usize,
    focused_handle: SplitTreeSurface.Node.Handle,
    target_tab_index: usize,
    target_handle: SplitTreeSurface.Node.Handle,
) bool {
    return active_tab_index != target_tab_index or focused_handle != target_handle;
}

fn hostChromeNeedsFocusRepaint(pane_count: usize) bool {
    return pane_count > 1;
}

fn scrollbarNeedsHeartbeatForState(
    policy: ScrollbarPolicy,
    window_visible: bool,
    scrollable: bool,
    visibility: win32_scrollbar_geometry.Visibility,
) bool {
    if (policy != .dynamic) return false;
    if (!window_visible or !scrollable) return false;
    return visibility != .hidden;
}

fn scrollbarPaintKeyChanged(previous: ?ScrollbarPaintKey, next: ScrollbarPaintKey) bool {
    const value = previous orelse return true;
    return !rectEquals(value.rect, next.rect) or
        value.total != next.total or
        value.len != next.len or
        value.offset != next.offset or
        value.dpi != next.dpi or
        value.hovered != next.hovered or
        value.dragging != next.dragging or
        value.marker_revision != next.marker_revision;
}

fn highContrastThemeFromSysColors() ThemeColors {
    const win_bg = GetSysColor(COLOR_WINDOW);
    const win_fg = GetSysColor(COLOR_WINDOWTEXT);
    const win_frame = GetSysColor(COLOR_WINDOWFRAME);
    const btn_bg = GetSysColor(COLOR_BTNFACE);
    const btn_fg = GetSysColor(COLOR_BTNTEXT);
    const hi_bg = GetSysColor(COLOR_HIGHLIGHT);
    const hi_fg = GetSysColor(COLOR_HIGHLIGHTTEXT);
    const gray = GetSysColor(COLOR_GRAYTEXT);

    return .{
        .chrome_bg = win_bg,
        .chrome_border = win_frame,
        .overlay_bg = win_bg,
        .overlay_border = win_frame,
        .edit_bg = win_bg,
        .edit_frame_bg = win_bg,
        .status_bg = win_bg,
        .inspector_bg = win_bg,

        .text_primary = win_fg,
        .text_secondary = win_fg,
        .text_disabled = gray,
        .edit_fg = win_fg,
        .overlay_label_fg = win_fg,
        .info_fg = win_fg,
        .error_fg = win_fg,

        .accent = hi_bg,
        .accent_hover = hi_bg,
        .chrome_accent_idle = win_frame,
        .edit_border_unfocused = win_frame,

        .button_bg = btn_bg,
        .button_border = btn_fg,
        .button_fg = btn_fg,

        .button_overlay_bg = btn_bg,
        .button_overlay_border = btn_fg,
        .button_overlay_fg = btn_fg,
        .button_chrome_fg = btn_fg,

        .button_active_bg = hi_bg,
        .button_active_border = hi_fg,
        .button_active_fg = hi_fg,

        .button_accept_bg = hi_bg,
        .button_accept_border = hi_fg,
        .button_accept_fg = hi_fg,

        .button_disabled_bg = btn_bg,
        .button_disabled_border = gray,
        .button_disabled_fg = gray,

        .button_focus_ring = hi_bg,
        .button_overlay_focus_ring = hi_bg,
        .button_active_focus_ring = hi_fg,
        .button_accept_focus_ring = hi_fg,

        // Unfocused dividers use COLOR_WINDOWFRAME
        // so multi-pane layouts stay visually separated; focused dividers
        // use COLOR_HIGHLIGHT to preserve the focus cue.
        .pane_divider = win_frame,
        .pane_divider_focused = hi_bg,

        .is_dark = false,
    };
}

fn isHighContrastActive() bool {
    const HIGHCONTRASTW = extern struct {
        cbSize: UINT,
        dwFlags: DWORD,
        lpszDefaultScheme: ?[*:0]u16,
    };
    var hc: HIGHCONTRASTW = .{
        .cbSize = @sizeOf(HIGHCONTRASTW),
        .dwFlags = 0,
        .lpszDefaultScheme = null,
    };
    if (SystemParametersInfoW(SPI_GETHIGHCONTRAST, @sizeOf(HIGHCONTRASTW), @ptrCast(&hc), 0) != 0) {
        return (hc.dwFlags & HCF_HIGHCONTRASTON) != 0;
    }
    return false;
}

fn isSystemDarkMode() bool {
    const subkey = std.unicode.utf8ToUtf16LeStringLiteral("Software\\Microsoft\\Windows\\CurrentVersion\\Themes\\Personalize");
    const value_name = std.unicode.utf8ToUtf16LeStringLiteral("AppsUseLightTheme");
    var hkey: usize = 0;
    if (RegOpenKeyExW(HKEY_CURRENT_USER, subkey, 0, KEY_READ, &hkey) != ERROR_SUCCESS) return true;
    defer _ = RegCloseKey(hkey);

    var data: u32 = 1;
    var data_size: DWORD = @sizeOf(u32);
    var reg_type: DWORD = 0;
    if (RegQueryValueExW(hkey, value_name, null, &reg_type, @ptrCast(&data), &data_size) != ERROR_SUCCESS) return true;
    if (reg_type != REG_DWORD or data_size != @sizeOf(u32)) return true;

    return data == 0; // 0 = dark mode, 1 = light mode
}

fn readDynamicScrollbars(default_value: bool) bool {
    const subkey = std.unicode.utf8ToUtf16LeStringLiteral("Control Panel\\Accessibility");
    const value_name = std.unicode.utf8ToUtf16LeStringLiteral("DynamicScrollbars");
    var hkey: usize = 0;
    if (RegOpenKeyExW(HKEY_CURRENT_USER, subkey, 0, KEY_READ, &hkey) != ERROR_SUCCESS) {
        return default_value;
    }
    defer _ = RegCloseKey(hkey);

    var data: u32 = if (default_value) 1 else 0;
    var data_size: DWORD = @sizeOf(u32);
    var reg_type: DWORD = 0;
    if (RegQueryValueExW(hkey, value_name, null, &reg_type, @ptrCast(&data), &data_size) != ERROR_SUCCESS) {
        return default_value;
    }
    if (reg_type != REG_DWORD or data_size != @sizeOf(u32)) return default_value;

    return data != 0;
}

/// Read the current Windows system accent colour from
/// `HKCU\Software\Microsoft\Windows\DWM\AccentColor`. DWM stores it as
/// a DWORD in 0xAABBGGRR order (alpha in the high byte). We discard
/// the alpha and return a COLORREF (0x00BBGGRR).
///
/// Returns null if the key is unreadable — callers then skip the
/// accent-follow blend and fall back to the hardcoded overlay accent.
fn resolveSystemAccentColor() ?u32 {
    const subkey = std.unicode.utf8ToUtf16LeStringLiteral("Software\\Microsoft\\Windows\\DWM");
    const value_name = std.unicode.utf8ToUtf16LeStringLiteral("AccentColor");
    var hkey: usize = 0;
    if (RegOpenKeyExW(HKEY_CURRENT_USER, subkey, 0, KEY_READ, &hkey) != ERROR_SUCCESS) return null;
    defer _ = RegCloseKey(hkey);

    var data: u32 = 0;
    var data_size: DWORD = @sizeOf(u32);
    var reg_type: DWORD = 0;
    if (RegQueryValueExW(hkey, value_name, null, &reg_type, @ptrCast(&data), &data_size) != ERROR_SUCCESS) return null;
    if (reg_type != REG_DWORD or data_size != @sizeOf(u32)) return null;

    // Drop alpha; keep 0x00BBGGRR.
    return data & 0x00FFFFFF;
}

fn resolveTheme(config: *const configpkg.Config) ThemeColors {
    if (isHighContrastActive()) return highContrastThemeFromSysColors();
    return switch (config.@"window-theme") {
        .dark => darkTheme(),
        .light => lightTheme(),
        .system => if (isSystemDarkMode()) darkTheme() else lightTheme(),
        .auto => if (isSystemDarkMode()) darkTheme() else lightTheme(),
        .ghostty => darkTheme(),
    };
}

fn shouldUseSystemBackdrop(config: *const configpkg.Config) bool {
    return config.@"background-opacity" < 1.0 and config.@"background-blur".enabled();
}

fn configuredHostWindowPosition(config: *const configpkg.Config) ?struct { x: i32, y: i32 } {
    const x = config.@"window-position-x" orelse return null;
    const y = config.@"window-position-y" orelse return null;
    return .{
        .x = x,
        .y = y,
    };
}

fn titlebarCaptionColor(theme: *const ThemeColors, config: *const configpkg.Config) u32 {
    if (config.@"window-theme" == .ghostty) {
        if (config.@"window-titlebar-background") |color| {
            return rgb(color.r, color.g, color.b);
        }
    }

    return theme.chrome_bg;
}

fn titlebarTextColor(theme: *const ThemeColors, config: *const configpkg.Config) u32 {
    if (config.@"window-theme" == .ghostty) {
        if (config.@"window-titlebar-foreground") |color| {
            return rgb(color.r, color.g, color.b);
        }
    }

    return theme.text_primary;
}

fn applyDwmThemeWithBuild(hwnd: HWND, theme: *const ThemeColors, config: *const configpkg.Config, os_build: u32) void {
    if (isHighContrastActive()) return; // Let system control title bar in HC mode
    const dark_mode: u32 = if (theme.is_dark) 1 else 0;
    // Try attribute 20 first (Win10 20H1+), fall back to 19 (Win10 1809-20H1)
    const hr = DwmSetWindowAttribute(hwnd, DWMWA_USE_IMMERSIVE_DARK_MODE, @ptrCast(&dark_mode), @sizeOf(u32));
    if (hr == @as(i32, @bitCast(@as(u32, 0x80070057)))) { // E_INVALIDARG
        _ = DwmSetWindowAttribute(hwnd, DWMWA_USE_IMMERSIVE_DARK_MODE_V1, @ptrCast(&dark_mode), @sizeOf(u32));
    }
    // Set caption color to match chrome (Win11 only; fails silently on Win10)
    const caption_color = titlebarCaptionColor(theme, config);
    const text_color = titlebarTextColor(theme, config);
    _ = DwmSetWindowAttribute(hwnd, DWMWA_CAPTION_COLOR, @ptrCast(&caption_color), @sizeOf(u32));
    _ = DwmSetWindowAttribute(hwnd, DWMWA_TEXT_COLOR, @ptrCast(&text_color), @sizeOf(u32));
    // Toggle system backdrop blur (Win11+; returns E_INVALIDARG on older
    // builds, discarded). Main-window backdrop picks the richest variant
    // the build supports:
    //   * Win11 22H2+ (build ≥ 22621): `DWMSBT_TABBEDWINDOW` for the Mica-
    //     with-tabs look that the new chrome expects. Older Win11 can't
    //     render `TABBEDWINDOW` (`DwmSetWindowAttribute` returns
    //     `E_INVALIDARG`); probing blindly there would spam the debug
    //     log on every theme apply, so the build-number gate filters.
    //   * Win11 < 22H2: `DWMSBT_MAINWINDOW` (plain Mica).
    //   * Win10 / older / `background-opacity = 1.0` / blur disabled:
    //     `DWMSBT_NONE`.
    const backdrop_type: u32 = if (shouldUseSystemBackdrop(config)) blk: {
        if (os_build >= OS_BUILD_WIN11_22H2) break :blk DWMSBT_TABBEDWINDOW;
        break :blk DWMSBT_MAINWINDOW;
    } else DWMSBT_NONE;
    _ = DwmSetWindowAttribute(hwnd, DWMWA_SYSTEMBACKDROP_TYPE, @ptrCast(&backdrop_type), @sizeOf(u32));
}

/// Linear-interpolate two `COLORREF`-shaped values (`0x00BBGGRR` on
/// Windows GDI) by `alpha` ∈ [0, 1]. `alpha = 0` returns `a`,
/// `alpha = 1` returns `b`. Used for pre-composited alpha on paths
/// where GDI can't render RGBA directly — specifically, `DrawTextW`
/// has no alpha channel, so the text colour must be pre-blended
/// against the surface background for fade effects to look right.
fn blendColorRGB(a: u32, b: u32, alpha: f32) u32 {
    const t: f32 = std.math.clamp(alpha, 0.0, 1.0);
    const inv: f32 = 1.0 - t;
    const ar: u32 = a & 0xFF;
    const ag: u32 = (a >> 8) & 0xFF;
    const ab: u32 = (a >> 16) & 0xFF;
    const br: u32 = b & 0xFF;
    const bg: u32 = (b >> 8) & 0xFF;
    const bb: u32 = (b >> 16) & 0xFF;
    const rr: u32 = @intFromFloat(@as(f32, @floatFromInt(ar)) * inv + @as(f32, @floatFromInt(br)) * t);
    const gg: u32 = @intFromFloat(@as(f32, @floatFromInt(ag)) * inv + @as(f32, @floatFromInt(bg)) * t);
    const bb2: u32 = @intFromFloat(@as(f32, @floatFromInt(ab)) * inv + @as(f32, @floatFromInt(bb)) * t);
    return (bb2 << 16) | (gg << 8) | rr;
}

fn fillSolidRect(hdc: HDC, rect: RECT, color: u32) void {
    const brush = GetStockObject(DC_BRUSH) orelse return;
    _ = SetDCBrushColor(hdc, color);
    _ = FillRect(hdc, &rect, brush);
}

fn utf16GdiTextLen(text: [:0]const u16) i32 {
    const max_len: usize = @intCast(std.math.maxInt(i32));
    return @intCast(@min(text.len, max_len));
}

fn textOutWz(hdc: HDC, x: i32, y: i32, text: [:0]const u16) void {
    const len = utf16GdiTextLen(text);
    if (len == 0) return;
    _ = TextOutW(hdc, x, y, text.ptr, len);
}

fn drawTextWz(hdc: HDC, text: [:0]const u16, rect: *RECT, format: UINT) void {
    const len = utf16GdiTextLen(text);
    if (len == 0) return;
    _ = DrawTextW(hdc, text.ptr, len, rect, format);
}

/// Draw a single-line, left-aligned, vertically-centred, ellipsized
/// string into the rect. Used by the palette list row painter.
fn drawPaletteRowText(hdc: HDC, text: []const u8, rect: RECT, color: u32) void {
    if (text.len == 0) return;
    // UTF-16 on the stack — palette titles / actions are short (well
    // under 256 chars); anything longer gets truncated rather than
    // allocating per paint.
    var buf: [256]u16 = undefined;
    const copied = std.unicode.utf8ToUtf16Le(&buf, text) catch buf.len;
    const n: usize = @min(copied, buf.len - 1);
    buf[n] = 0;

    _ = SetTextColor(hdc, color);
    var r = rect;
    _ = DrawTextW(
        hdc,
        @ptrCast(&buf),
        @intCast(n),
        &r,
        DT_LEFT | DT_VCENTER | DT_SINGLELINE | DT_END_ELLIPSIS | DT_NOPREFIX,
    );
}

fn getPaletteListHost(hwnd: HWND) ?*Host {
    const raw = GetWindowLongPtrW(hwnd, GWLP_USERDATA);
    if (raw == 0) return null;
    return @ptrFromInt(@as(usize, @intCast(raw)));
}

/// Trampoline bridging `PaletteListState.name` (C-compatible fn
/// pointer shape) into `Host.buildPaletteListName`. `ctx` is the
/// const-erased `*Host` stashed on `PaletteListState`; the provider
/// never mutates `self` so casting away const here is safe.
fn paletteListNameThunk(ctx: *anyopaque, buf: []u8) []const u8 {
    const host: *const Host = @ptrCast(@alignCast(ctx));
    return host.buildPaletteListName(buf);
}

/// Thunks adapting `*App` into the `AppHandle` callback shape used by
/// `win32_settings.SettingsWindow`. Kept inline so a theme swap is
/// picked up on the next paint without cache invalidation.
fn settingsChromeBgThunk(ctx: *anyopaque) u32 {
    const app: *const App = @ptrCast(@alignCast(ctx));
    return app.resolved_theme.chrome_bg;
}
fn settingsTextPrimaryThunk(ctx: *anyopaque) u32 {
    const app: *const App = @ptrCast(@alignCast(ctx));
    return app.resolved_theme.text_primary;
}
fn settingsOpenInEditorThunk(ctx: *anyopaque) void {
    const app: *App = @ptrCast(@alignCast(ctx));
    app.openConfigInEditor() catch |err| {
        std.log.warn("settings: open-in-editor failed err={}", .{err});
    };
}
fn settingsCurrentConfigThunk(ctx: *anyopaque) *const configpkg.Config {
    const app: *const App = @ptrCast(@alignCast(ctx));
    return &app.config;
}
fn settingsSaveAndReloadThunk(
    ctx: *anyopaque,
    pending: *const configpkg.Config,
    original: *const configpkg.Config,
) win32_settings.SaveError!void {
    const app: *App = @ptrCast(@alignCast(ctx));
    return app.settingsSaveAndReload(pending, original);
}
fn settingsOnClosedThunk(ctx: *anyopaque) void {
    const app: *App = @ptrCast(@alignCast(ctx));
    // Mirrors the kick after the last terminal window closes; the
    // quit timer observes `hasLiveUiWindows()` so this is a no-op
    // when any terminal HWND is still alive.
    if (app.running and !app.hasLiveUiWindows()) app.startQuitTimer();
}
fn settingsNotifySuccessThunk(ctx: *anyopaque, title: []const u8, body: []const u8) void {
    const app: *App = @ptrCast(@alignCast(ctx));
    // Always show local chrome feedback for the Save button, even
    // when system/reload notifications are disabled.
    const alloc = app.core_app.alloc;
    const banner_text = std.fmt.allocPrint(alloc, "{s}{s}{s}", .{
        title,
        if (body.len > 0) ": " else "",
        body,
    }) catch null;
    const banner_shown: bool = if (banner_text) |msg| blk: {
        defer alloc.free(msg);
        // `showHostBanner(.app, …)` routes through `primarySurface()`
        // and returns false when no terminal host is open (e.g.
        // settings window is the only UI window after the last tab
        // closed). Capture that so we know to fall back to the
        // always-visible in-settings confirm strip below.
        break :blk app.showHostBanner(.app, .info, msg) catch false;
    } else false;

    // System-level WinRT toast + local fallback. Gated on
    // `app-notifications.config-reload` because Settings save also
    // reloads config; users who disabled reload notifications should
    // not get a system toast on every Save. If no host banner can
    // render, force the fallback so settings-only saves still show
    // visible confirmation.
    if (!app.config.@"app-notifications".@"config-reload" and banner_shown) return;

    // WinRT notification strings must be sentinel-terminated. On
    // allocation failure, keep any banner already shown and skip the
    // system path.
    const title_z = alloc.dupeZ(u8, title) catch return;
    defer alloc.free(title_z);
    const body_z = alloc.dupeZ(u8, body) catch return;
    defer alloc.free(body_z);
    app.showDesktopNotification(.app, title_z, body_z) catch |err| {
        std.log.warn("settings: desktop notification failed err={}", .{err});
    };
}

fn buildToastLaunchForSurface(
    alloc: Allocator,
    surface: *Surface,
) Allocator.Error![]u8 {
    const tab_id = if (surface.host) |host| blk: {
        for (host.tabs.items) |*tab| {
            if (tab.findHandle(surface) != null) break :blk tab.id;
        }
        break :blk null;
    } else null;

    return try win32_toast_activation.buildLaunchArg(alloc, .{
        .surface_id = surface.core().id,
        .tab_id = tab_id,
        .window_id = surface.host_id,
        .action = .focus,
    });
}

/// Accept callback for the `confirm-close-surface` overlay. Fires
/// from the Host's overlay machinery once the user picks Accept /
/// presses Enter. `userdata` is the `*Surface` pointer passed into
/// `showConfirm`. The Surface's HWND may already be gone (defensive
/// null-check) — if so this is a no-op.
fn surfaceConfirmCloseAccept(userdata: ?*anyopaque) void {
    const ud = userdata orelse return;
    const surface: *Surface = @ptrCast(@alignCast(ud));
    surface.invalidateStructuralHistoryForClose();
    if (surface.hwnd) |hwnd| _ = DestroyWindow(hwnd);
}

/// Accept callback for a deferred paste confirm. Ownership of the
/// duplicated payload passes here and is released after synchronous
/// core ingestion.
fn surfaceConfirmPasteAccept(userdata: ?*anyopaque) void {
    const ud = userdata orelse return;
    const surface: *Surface = @ptrCast(@alignCast(ud));
    const op = surface.pending_clipboard_op orelse return;
    if (op != .paste) return;
    const pending = op.paste;
    // Snapshot the allocator by value BEFORE dispatching. If
    // `completeClipboardRequest` synchronously destroys the surface
    // (for example via close_surface), `surface.app` at defer
    // time is a dangling read. `std.mem.Allocator` is a pod value
    // (vtable + ctx ptr); the ctx is owned by the app arena which
    // outlives the surface, so the snapshot stays valid.
    const alloc = surface.app.core_app.alloc;
    surface.pending_clipboard_op = null;
    defer alloc.free(pending.data);
    surface.core_surface.completeClipboardRequest(
        pending.request,
        pending.data,
        true, // confirmed
    ) catch |err| {
        std.log.warn("pending clipboard paste accept failed err={}", .{err});
    };
}

fn surfaceConfirmPasteCancel(userdata: ?*anyopaque) void {
    const ud = userdata orelse return;
    const surface: *Surface = @ptrCast(@alignCast(ud));
    if (surface.pending_clipboard_op) |*op| op.deinit(surface.app.core_app.alloc);
    surface.pending_clipboard_op = null;
}

/// Accept callback for a deferred clipboard-write confirm. Mirrors
/// the body of `Surface.setClipboard` (html-first, then plain text)
/// because the confirm-write path only fires from the standard
/// clipboard — OSC 52 writes use a different code path.
fn surfaceConfirmWriteAccept(userdata: ?*anyopaque) void {
    const ud = userdata orelse return;
    const surface: *Surface = @ptrCast(@alignCast(ud));
    const op = surface.pending_clipboard_op orelse return;
    if (op != .write) return;
    const pending = op.write;
    const alloc = surface.app.core_app.alloc;
    surface.pending_clipboard_op = null;
    defer {
        for (pending.contents) |*c| {
            alloc.free(c.mime);
            alloc.free(c.data);
        }
        alloc.free(pending.contents);
    }
    if (pending.clipboard != .standard) return;
    var html_content: ?[]const u8 = null;
    var plain_content: ?[]const u8 = null;
    for (pending.contents) |c| {
        if (std.mem.eql(u8, c.mime, "text/html")) {
            html_content = c.data;
        } else if (std.mem.eql(u8, c.mime, "text/plain")) {
            plain_content = c.data;
        }
    }
    if (html_content) |html| {
        surface.writeClipboardHtml(html, plain_content) catch |err| {
            std.log.warn("pending clipboard html write failed err={}", .{err});
        };
        return;
    }
    if (plain_content) |plain| {
        surface.writeClipboardText(plain) catch |err| {
            std.log.warn("pending clipboard text write failed err={}", .{err});
        };
    }
}

fn surfaceConfirmWriteCancel(userdata: ?*anyopaque) void {
    const ud = userdata orelse return;
    const surface: *Surface = @ptrCast(@alignCast(ud));
    if (surface.pending_clipboard_op) |*op| op.deinit(surface.app.core_app.alloc);
    surface.pending_clipboard_op = null;
}

/// IDropTarget payload callback. Runs on the STA UI thread (COM
/// guarantees). `payload` is owned by the module and lives only for
/// the duration of this callback — the apprt must not retain it.
///
/// Route through `completeClipboardRequest(.paste, …, confirmed=false)`
/// rather than `textCallback` so `clipboard-paste-protection`
/// actually applies. `textCallback` hard-codes `allow_unsafe=true`
/// (it's the terminal-typed path, where newlines ARE the user's
/// intent), which would defeat paste protection for dropped content.
fn surfaceDropPayloadCallback(ctx: *anyopaque, payload: []const u8) void {
    const surface: *Surface = @ptrCast(@alignCast(ctx));
    if (payload.len == 0) return;
    const alloc = surface.app.core_app.alloc;
    const payload_z = alloc.dupeZ(u8, payload) catch |err| {
        std.log.warn("drop payload dupe failed err={}", .{err});
        return;
    };
    defer alloc.free(payload_z);

    // Defense-in-depth classifier pass.
    //
    // Core's `isSafe` only flags newlines + bracketed-paste-end
    // sequences. That's correct for generic clipboard pastes but
    // insufficient for drop payloads where a crafted filename like
    // `%USERPROFILE%\x.txt` (cmd `%VAR%`), `$HOME.txt` (PowerShell),
    // or a filename containing control bytes / a URL embedded in
    // other text would bypass confirmation. Consult the full
    // `win32_paste_protection.inspect` verdict — which covers
    // control_chars, shell_metachar, AND mixed_content — not just
    // `hasShellMetachar`. When the verdict isn't `.safe`, fire the
    // same confirm path as the core `.UnsafePaste` branch.
    if (surface.app.config.@"clipboard-paste-protection") {
        const verdict = win32_paste_protection.inspect(payload_z);
        if (verdict.severity != .safe) {
            std.log.info("drop payload flagged severity={s} reason={s}", .{
                @tagName(verdict.severity),
                verdict.reason,
            });
            // Non-modal confirm overlay; dupes payload so it survives
            // the callback teardown. Paste completes asynchronously
            // on accept via `surfaceConfirmPasteAccept`.
            surface.requestPasteConfirm(.paste, payload_z) catch |err| {
                std.log.warn("drop payload paste-protection confirm failed err={}", .{err});
            };
            return;
        }
    }

    surface.core_surface.completeClipboardRequest(.paste, payload_z, false) catch |err| switch (err) {
        error.UnsafePaste, error.UnauthorizedPaste => {
            // Unsafe content (newlines, control sequences, etc.).
            // Defer to the non-modal confirm overlay; the Accept
            // callback re-submits with `confirmed = true`.
            surface.requestPasteConfirm(.paste, payload_z) catch |inner| {
                std.log.warn("drop payload protected paste confirm failed err={}", .{inner});
            };
        },
        else => {
            std.log.warn("drop payload paste failed err={}", .{err});
        },
    };
}

/// Translate the core's `QuickTerminalSize` (primary + secondary,
/// each optional, percent or pixels) into our geometry-module's
/// single-dimension `SizePercent`. Picks the primary axis value;
/// secondary defaults fall to 25% when unset. If primary is unset,
/// defaults to 25% — matches the old hard-coded behaviour while
/// the geometry module awaits an expanded two-axis API.
fn sizeFromConfig(qts: configpkg.Config.QuickTerminalSize) win32_quick_terminal.SizePercent {
    const primary = qts.primary orelse return .{ .percent = 25 };
    return sizeToGeometry(primary);
}

fn sizeSecondaryFromConfig(qts: configpkg.Config.QuickTerminalSize) ?win32_quick_terminal.SizePercent {
    const secondary = qts.secondary orelse return null;
    return sizeToGeometry(secondary);
}

fn sizeToGeometry(sz: configpkg.Config.QuickTerminalSize.Size) win32_quick_terminal.SizePercent {
    return switch (sz) {
        .percentage => |v| .{ .percent = v },
        .pixels => |v| .{ .pixels = v },
    };
}

// Keep helper modules reachable from the exe's module graph. Zig prunes
// unreferenced module-level decls, so this block also keeps their tests
// and public entry points type-checked.
comptime {
    // Surface-level drag-drop payload parsing helpers.
    _ = win32_surface_drop.parentDir;
    _ = win32_surface_drop.requiresQuoting;
    _ = win32_surface_drop.formatFilePayload;
    _ = win32_surface_drop.formatTextPayload;
    _ = win32_surface_drop.extractShellUrl;
    _ = win32_surface_drop.extractHtmlFragment;
    // Tab-drag state machine helpers.
    _ = win32_tab_drag.insertionIndexAtX;
    _ = win32_tab_drag.isNoOpDrop;
    _ = win32_tab_drag.encodePayload;
    _ = win32_tab_drag.decodePayload;
    _ = win32_tab_drag.clipboard_format_name;
    // Tab-drag OLE adapter (IDataObject + IDropSource for DoDragDrop).
    _ = win32_tab_drag_ole.DataObject;
    _ = win32_tab_drag_ole.DragSource;
    _ = win32_tab_drag_ole.doDragDrop;
    // GDI icon helpers used by palette rows, search toggles, caption
    // buttons, and toast severity glyphs.
    _ = win32_icons.drawIcon;
    _ = win32_icons.insetRect;
    _ = win32_icons.centerSquare;
    _ = win32_icons.iconContentRect;
    _ = win32_icons.isDrawable;
    // Paste-protection severity classification.
    _ = win32_paste_protection.inspect;
    _ = win32_paste_protection.hasControlChars;
    _ = win32_paste_protection.hasNewline;
    _ = win32_paste_protection.hasShellMetachar;
    _ = win32_paste_protection.hasMixedContent;
    // Scrollbar geometry helpers.
    _ = win32_scrollbar_geometry.ScrollbarState;
    _ = win32_scrollbar_geometry.trackRect;
    _ = win32_scrollbar_geometry.thumbRect;
    _ = win32_scrollbar_geometry.rowFromCursor;
    _ = win32_scrollbar_geometry.pointOverTrack;
    _ = win32_scrollbar_geometry.pointOverThumb;
    // Integrated-titlebar NC layout helpers.
    _ = win32_nc_layout.calcNcClientRect;
    _ = win32_nc_layout.hitTest;
    _ = win32_nc_layout.captionButtonsRect;
    _ = win32_nc_layout.metricsDefault;
    // Status-bar composition helpers.
    _ = win32_status_bar.composeFragments;
    _ = win32_status_bar.truncateToFit;
    _ = win32_status_bar.isDigitRun;
    // Tab visual-state helpers.
    _ = win32_tab_visual.CloseState;
    _ = win32_tab_visual.UnderlineState;
    _ = win32_tab_visual.easeInOutCubic;
    _ = win32_tab_visual.closeHitRect;
    // Keyboard-focus-ring helpers.
    _ = win32_focus_ring.FocusRingTracker;
    _ = win32_focus_ring.ringRect;
    _ = win32_focus_ring.isDrawable;
}

/// Scan argv for a `wgh://activate?...` entry. Malformed activation
/// strings are swallowed so they cannot be misrouted as startup args.
fn scanToastActivationArg(alloc: std.mem.Allocator) ?win32_toast_activation.ActivationTarget {
    const argv = std.process.argsAlloc(alloc) catch return null;
    defer std.process.argsFree(alloc, argv);
    return win32_toast_activation.scanLaunchArgs(argv[1..]);
}

fn scanForwardedToastActivation(
    arguments: ?[]const [:0]const u8,
) win32_toast_activation.ScanLaunchArgsResult {
    const argv = arguments orelse return .none;
    return win32_toast_activation.scanLaunchArgsDetailed(argv);
}

fn forwardedActivationExtraArgCount(arguments: ?[]const [:0]const u8) usize {
    const argv = arguments orelse return 0;
    if (win32_toast_activation.scanLaunchArgs(argv) == null) return 0;
    return if (argv.len > 1) argv.len - 1 else 0;
}

/// Return the last CLI `--config-file` override as an absolute path.
/// Settings save targets the last file because later config files
/// override earlier ones.
fn cliConfigFileOverride(alloc: std.mem.Allocator) !?[]u8 {
    const argv = std.process.argsAlloc(alloc) catch return null;
    defer std.process.argsFree(alloc, argv);
    const key = "--config-file";
    // Pick the LAST `--config-file` occurrence, not the first:
    // `Config.loadRecursiveFiles` applies files in argv order and
    // later files override earlier ones. Saving into the first
    // file when a second exists would be the wrong layer — the
    // saved value would be masked on reload.
    var last_path: ?[]const u8 = null;
    var i: usize = 1; // skip argv[0]
    while (i < argv.len) : (i += 1) {
        const arg = argv[i];
        if (std.mem.eql(u8, arg, key)) {
            if (i + 1 < argv.len) {
                last_path = argv[i + 1];
                i += 1; // skip the path arg so we don't match it as a key
            }
            continue;
        }
        if (std.mem.startsWith(u8, arg, key ++ "=")) {
            last_path = arg[key.len + 1 ..];
            continue;
        }
    }
    if (last_path) |p| return try absolutizePath(alloc, p);
    return null;
}

/// Resolve a possibly-relative path to an absolute one WITHOUT
/// requiring the leaf to exist. `std.fs.realpathAlloc` calls
/// `GetFullPathNameW` + `CreateFileW` to canonicalise, which fails
/// with `FileNotFound` before the first save has written the file.
/// For the settings save path, we need an absolute path regardless
/// of whether the file exists yet — the atomic rename will create
/// it. `std.fs.path.isAbsolute` handles the already-absolute case;
/// otherwise join with cwd. No canonicalisation (symlink resolution
/// etc.) — that's not required for an atomic rename target.
fn absolutizePath(alloc: std.mem.Allocator, path: []const u8) ![]u8 {
    if (std.fs.path.isAbsolute(path)) {
        return try alloc.dupe(u8, path);
    }
    const cwd = try std.process.getCwdAlloc(alloc);
    defer alloc.free(cwd);
    return try std.fs.path.join(alloc, &.{ cwd, path });
}

/// Count the number of leading whitespace (space / tab) bytes.
fn leadingIndentLen(line: []const u8) usize {
    var i: usize = 0;
    while (i < line.len and (line[i] == ' ' or line[i] == '\t')) : (i += 1) {}
    return i;
}

/// Extract a trailing inline `#` / `;` comment from a key assignment.
/// The scan starts after `=` to match the config grammar.
fn trailingCommentOf(line: []const u8) []const u8 {
    const eq = std.mem.indexOfScalar(u8, line, '=') orelse return &.{};
    var i: usize = eq + 1;
    while (i < line.len) : (i += 1) {
        if (line[i] == '#' or line[i] == ';') {
            // Trim trailing \r (CRLF input) and trailing whitespace
            // from the comment — we'll add our own single-space
            // separator between value and comment.
            var end: usize = line.len;
            while (end > i and (line[end - 1] == '\r' or line[end - 1] == ' ' or line[end - 1] == '\t')) : (end -= 1) {}
            return line[i..end];
        }
    }
    return &.{};
}

/// Patch GUI-edited config keys while preserving unchanged source text.
///
/// A line matches `<name>` when its trimmed-left form starts with
/// `<name>` followed by optional whitespace and `=`. Comment lines are
/// ignored. Duplicate key lines preserve load semantics by rewriting
/// only the last occurrence; missing edited keys are appended.
fn patchOrAppendEdits(
    alloc: std.mem.Allocator,
    raw: []const u8,
    pending: *const configpkg.Config,
    user_edited: std.StaticBitSet(std.enums.values(@import("../config/key.zig").Key).len),
    out: *std.ArrayListUnmanaged(u8),
) !void {
    const ConfigKey = @import("../config/key.zig").Key;
    const ConfigFormatter = @import("../config/formatter.zig");

    // Pass 1: scan lines to find the LAST occurrence of each
    // user-edited key. Replacing only the LAST occurrence matches
    // `Config.loadRecursiveFiles`'s "last value wins" semantic — a
    // user who has two `font-size = 12` lines (e.g. one in a theme
    // section, one in an override block) keeps the earlier line
    // untouched and only sees the later one updated. Replacing
    // every occurrence would collapse intentional overrides.
    //
    // Line indices are 0-based; we store them in an array keyed on
    // `Config.Key`'s enum int. -1 / max-usize means "no match seen".
    const keys_total = comptime std.enums.values(ConfigKey).len;
    var last_line: [keys_total]usize = [_]usize{std.math.maxInt(usize)} ** keys_total;

    // Split into line slices once so we can index by line number
    // during the emit pass.
    var lines: std.ArrayListUnmanaged([]const u8) = .{};
    defer lines.deinit(alloc);
    {
        var it = std.mem.splitScalar(u8, raw, '\n');
        while (it.next()) |line| try lines.append(alloc, line);
    }

    for (lines.items, 0..) |line, line_idx| {
        const stripped = std.mem.trimLeft(u8, line, " \t");
        if (stripped.len == 0 or stripped[0] == '#' or stripped[0] == ';') continue;
        const eq_idx = std.mem.indexOfScalar(u8, stripped, '=') orelse continue;
        const key_slice = std.mem.trimRight(u8, stripped[0..eq_idx], " \t");
        inline for (@typeInfo(configpkg.Config).@"struct".fields) |field| {
            if (field.name[0] != '_' and std.mem.eql(u8, field.name, key_slice)) {
                const key = @field(ConfigKey, field.name);
                if (user_edited.isSet(@intFromEnum(key))) {
                    last_line[@intFromEnum(key)] = line_idx;
                }
            }
        }
    }

    // Track which keys we've emitted so the append pass can pick up
    // the leftovers.
    var written: std.StaticBitSet(std.enums.values(ConfigKey).len) = .initEmpty();

    // Pass 2: emit. Every line is written verbatim EXCEPT the
    // recorded last-occurrence lines for user-edited keys, which
    // get the fresh serialised value.
    for (lines.items, 0..) |line, line_idx| {
        if (line_idx > 0) try out.append(alloc, '\n');

        var replaced = false;
        inline for (@typeInfo(configpkg.Config).@"struct".fields) |field| {
            if (!replaced and field.name[0] != '_') {
                const key = @field(ConfigKey, field.name);
                if (user_edited.isSet(@intFromEnum(key)) and
                    last_line[@intFromEnum(key)] == line_idx)
                {
                    var scratch: std.Io.Writer.Allocating = .init(alloc);
                    defer scratch.deinit();
                    ConfigFormatter.formatEntry(
                        field.type,
                        field.name,
                        @field(pending, field.name),
                        &scratch.writer,
                    ) catch return error.OutOfMemory;
                    var payload = scratch.written();
                    if (payload.len > 0 and payload[payload.len - 1] == '\n') {
                        payload = payload[0 .. payload.len - 1];
                    }
                    // Preserve indentation and trailing inline comments
                    // from the original assignment.
                    const indent_end = leadingIndentLen(line);
                    const leading = line[0..indent_end];
                    const trailing = trailingCommentOf(line);
                    try out.appendSlice(alloc, leading);
                    try out.appendSlice(alloc, payload);
                    if (trailing.len > 0) {
                        try out.append(alloc, ' ');
                        try out.appendSlice(alloc, trailing);
                    }
                    written.set(@intFromEnum(key));
                    replaced = true;
                }
            }
        }
        if (!replaced) try out.appendSlice(alloc, line);
    }

    // Pass 3: append user-edited keys that didn't appear in the
    // source at all (first-save / new-key cases).
    inline for (@typeInfo(configpkg.Config).@"struct".fields) |field| {
        if (field.name[0] == '_') continue;
        const key = @field(ConfigKey, field.name);
        if (user_edited.isSet(@intFromEnum(key)) and !written.isSet(@intFromEnum(key))) {
            if (out.items.len > 0 and out.items[out.items.len - 1] != '\n') {
                try out.append(alloc, '\n');
            }
            var scratch: std.Io.Writer.Allocating = .init(alloc);
            defer scratch.deinit();
            ConfigFormatter.formatEntry(
                field.type,
                field.name,
                @field(pending, field.name),
                &scratch.writer,
            ) catch return error.OutOfMemory;
            try out.appendSlice(alloc, scratch.written());
        }
    }
}

/// Strip HTML tags for the CF_UNICODETEXT fallback when core only
/// supplies `text/html`. Plain consumers get readable text; entity
/// references are preserved verbatim.
fn stripHtmlTags(alloc: std.mem.Allocator, html: []const u8) ![]u8 {
    var buf: std.ArrayList(u8) = .{};
    defer buf.deinit(alloc);
    try buf.ensureTotalCapacity(alloc, html.len);
    var i: usize = 0;
    while (i < html.len) {
        const c = html[i];
        if (c == '<') {
            if (std.mem.indexOfScalarPos(u8, html, i, '>')) |end| {
                i = end + 1;
                continue;
            }
            try buf.appendSlice(alloc, html[i..]);
            break;
        }
        try buf.append(alloc, c);
        i += 1;
    }
    return buf.toOwnedSlice(alloc);
}

test "stripHtmlTags drops tag brackets" {
    const testing = std.testing;
    const out = try stripHtmlTags(
        testing.allocator,
        "<span style=\"color:red\">hello</span> <b>world</b>",
    );
    defer testing.allocator.free(out);
    try testing.expectEqualStrings("hello world", out);
}

test "stripHtmlTags handles malformed (unclosed tag)" {
    const testing = std.testing;
    const out = try stripHtmlTags(testing.allocator, "pre<broken");
    defer testing.allocator.free(out);
    try testing.expectEqualStrings("pre<broken", out);
}

test "stripHtmlTags malformed in middle preserves fallback tail" {
    const testing = std.testing;
    const out = try stripHtmlTags(testing.allocator, "hello <world tail");
    defer testing.allocator.free(out);
    try testing.expectEqualStrings("hello <world tail", out);
}

test "stripHtmlTags preserves plain text" {
    const testing = std.testing;
    const out = try stripHtmlTags(testing.allocator, "no tags here");
    defer testing.allocator.free(out);
    try testing.expectEqualStrings("no tags here", out);
}

test "win32 appendOwnedString replaces existing value and frees old allocation" {
    const testing = std.testing;
    var target: ?[:0]const u8 = null;
    try appendOwnedString(testing.allocator, &target, "alpha");
    try testing.expect(target != null);
    try testing.expectEqualStrings("alpha", target.?);

    try appendOwnedString(testing.allocator, &target, "beta");
    try testing.expect(target != null);
    try testing.expectEqualStrings("beta", target.?);

    try appendOwnedString(testing.allocator, &target, null);
    try testing.expect(target == null);
}

test "win32 appendOwnedString skips exact same-value reallocation" {
    const testing = std.testing;
    var target: ?[:0]const u8 = null;
    defer if (target) |value| testing.allocator.free(value);

    try appendOwnedString(testing.allocator, &target, "alpha");
    const before = target.?.ptr;
    try appendOwnedString(testing.allocator, &target, "alpha");
    try testing.expect(target != null);
    try testing.expect(target.?.ptr == before);

    try appendOwnedString(testing.allocator, &target, null);
    try testing.expect(target == null);
    try appendOwnedString(testing.allocator, &target, null);
    try testing.expect(target == null);
}

test "win32 appendOwnedString leaves target untouched on OOM" {
    // OOM must leave `target.*` pointing at the existing allocation.
    const testing = std.testing;
    var arena: [64]u8 = undefined;
    var fixed: std.heap.FixedBufferAllocator = .init(&arena);
    const alloc = fixed.allocator();

    var target: ?[:0]const u8 = null;
    try appendOwnedString(alloc, &target, "warm-up");
    try testing.expectEqualStrings("warm-up", target.?);

    // Force an allocation failure with a value too large to fit.
    const huge = "x" ** 512;
    const before = target.?.ptr;
    try testing.expectError(error.OutOfMemory, appendOwnedString(alloc, &target, huge));
    try testing.expect(target != null);
    try testing.expect(target.?.ptr == before);
    try testing.expectEqualStrings("warm-up", target.?);
}

test "win32 ChromeTextDirty splits top and status cache invalidation" {
    const testing = std.testing;

    var dirty: ChromeTextDirty = .{
        .overlay = false,
        .inspector = false,
        .banner = false,
        .status = false,
    };
    dirty.markTop();
    try testing.expect(dirty.overlay);
    try testing.expect(dirty.inspector);
    try testing.expect(dirty.banner);
    try testing.expect(!dirty.status);

    dirty = .{
        .overlay = false,
        .inspector = false,
        .banner = false,
        .status = false,
    };
    dirty.status = true;
    try testing.expect(!dirty.overlay);
    try testing.expect(!dirty.inspector);
    try testing.expect(!dirty.banner);
    try testing.expect(dirty.status);

    dirty = .{
        .overlay = false,
        .inspector = false,
        .banner = false,
        .status = false,
    };
    dirty.markAll();
    try testing.expect(dirty.overlay);
    try testing.expect(dirty.inspector);
    try testing.expect(dirty.banner);
    try testing.expect(dirty.status);
}

test "win32 mergeChromeRepaintMask only returns newly requested regions" {
    const testing = std.testing;

    var current: ChromeRepaintMask = .{};
    var added = mergeChromeRepaintMask(&current, .{ .top = true });
    try testing.expect(std.meta.eql(current, ChromeRepaintMask{ .top = true }));
    try testing.expect(std.meta.eql(added, ChromeRepaintMask{ .top = true }));

    added = mergeChromeRepaintMask(&current, .{ .top = true });
    try testing.expect(added.isEmpty());
    try testing.expect(std.meta.eql(current, ChromeRepaintMask{ .top = true }));

    added = mergeChromeRepaintMask(&current, .{ .status = true, .search_frames = true });
    try testing.expect(std.meta.eql(current, ChromeRepaintMask{
        .top = true,
        .status = true,
        .search_frames = true,
    }));
    try testing.expect(std.meta.eql(added, ChromeRepaintMask{
        .status = true,
        .search_frames = true,
    }));

    added = mergeChromeRepaintMask(&current, .{ .content = true, .search_frames = true });
    try testing.expect(std.meta.eql(current, ChromeRepaintMask{
        .top = true,
        .content = true,
        .status = true,
        .search_frames = true,
    }));
    try testing.expect(std.meta.eql(added, ChromeRepaintMask{ .content = true }));
}

test "win32 layoutChildPaintPlan keeps chrome and content invalidation separate" {
    const testing = std.testing;

    try testing.expectEqualDeep(
        LayoutChildPaintPlan{ .chrome = true, .content = false, .native_content_controls = false },
        layoutChildPaintPlan(true, false),
    );
    try testing.expectEqualDeep(
        LayoutChildPaintPlan{ .chrome = false, .content = true, .native_content_controls = true },
        layoutChildPaintPlan(false, true),
    );
    try testing.expectEqualDeep(
        LayoutChildPaintPlan{ .chrome = true, .content = true, .native_content_controls = true },
        layoutChildPaintPlan(true, true),
    );
}

fn rectIntersects(a: RECT, b: RECT) bool {
    return a.left < b.right and
        a.right > b.left and
        a.top < b.bottom and
        a.bottom > b.top;
}

test "win32 rectIntersects only trips on positive overlap" {
    const testing = std.testing;

    try testing.expect(rectIntersects(
        .{ .left = 0, .top = 0, .right = 10, .bottom = 10 },
        .{ .left = 5, .top = 5, .right = 15, .bottom = 15 },
    ));
    try testing.expect(!rectIntersects(
        .{ .left = 0, .top = 0, .right = 10, .bottom = 10 },
        .{ .left = 10, .top = 0, .right = 20, .bottom = 10 },
    ));
    try testing.expect(!rectIntersects(
        .{ .left = 0, .top = 0, .right = 10, .bottom = 10 },
        .{ .left = 0, .top = 10, .right = 10, .bottom = 20 },
    ));
}

test "win32 palette EN_CHANGE re-entry guard: suppress_edit_events gates sync cascade" {
    // Sentinel test — the Host struct MUST carry the
    // `suppress_edit_events: bool = false` flag. The palette edit
    // path relies on it gating the EN_CHANGE handler at
    // `hostWindowProc` (command_id 2002) and on `setOverlayEditText`
    // flipping it around programmatic `SetWindowTextW` calls. If a
    // refactor removes or renames the field this test fails
    // at compile time before anyone else hits the crash again.
    try std.testing.expect(@hasField(Host, "suppress_edit_events"));
    try std.testing.expectEqual(bool, @FieldType(Host, "suppress_edit_events"));
}

fn paletteListProc(
    hwnd: HWND,
    msg: UINT,
    wParam: WPARAM,
    lParam: LPARAM,
) callconv(.winapi) LRESULT {
    switch (msg) {
        WM_ERASEBKGND => return 1,
        WM_PAINT => {
            if (getPaletteListHost(hwnd)) |host| host.paintPaletteList();
            return 0;
        },
        WM_LBUTTONDOWN => {
            const host = getPaletteListHost(hwnd) orelse return DefWindowProcW(hwnd, msg, wParam, lParam);
            const y: i32 = signedHighWord(lParamBits(lParam));
            const row = host.paletteRowAtY(y);
            if (row) |r| host.invokePaletteRow(r) catch |err| {
                std.log.warn("palette row invoke failed err={}", .{err});
            };
            return 0;
        },
        WM_MOUSEWHEEL => {
            const host = getPaletteListHost(hwnd) orelse return DefWindowProcW(hwnd, msg, wParam, lParam);
            host.scrollPaletteList(wheelDeltaFromWParam(wParam));
            return 0;
        },
        WM_GETOBJECT => {
            const host = getPaletteListHost(hwnd) orelse return DefWindowProcW(hwnd, msg, wParam, lParam);
            const state = host.paletteListUiaState();
            if (win32_uia.handlePaletteListGetObject(
                host.app.core_app.alloc,
                hwnd,
                wParam,
                lParam,
                state,
            )) |lr| return lr;
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        else => return DefWindowProcW(hwnd, msg, wParam, lParam),
    }
}

fn scrollbarProc(
    hwnd: HWND,
    msg: UINT,
    wParam: WPARAM,
    lParam: LPARAM,
) callconv(.winapi) LRESULT {
    const surface = getSurface(hwnd);
    switch (msg) {
        WM_ERASEBKGND => return 1,
        WM_PAINT => {
            if (surface) |value| value.paintScrollbar();
            return 0;
        },
        WM_MOUSEMOVE => {
            if (surface) |value| value.handleScrollbarMouseMove(hwnd, lParam);
            return 0;
        },
        WM_MOUSELEAVE => {
            if (surface) |value| value.handleScrollbarMouseLeave();
            return 0;
        },
        WM_LBUTTONDOWN => {
            if (surface) |value| value.handleScrollbarLeftButtonDown(hwnd, lParam);
            return 0;
        },
        WM_LBUTTONUP => {
            if (surface) |value| value.handleScrollbarLeftButtonUp(lParam);
            return 0;
        },
        WM_CAPTURECHANGED => {
            if (surface) |value| value.handleScrollbarCaptureChanged();
            return 0;
        },
        WM_SETCURSOR => {
            _ = SetCursor(LoadCursorW(null, IDC_ARROW));
            return 1;
        },
        else => return DefWindowProcW(hwnd, msg, wParam, lParam),
    }
}

fn drawRoundedRect(hdc: HDC, rect: RECT, bg: u32, border: u32, radius: i32) void {
    const stock_brush = GetStockObject(DC_BRUSH) orelse return;
    const stock_pen = GetStockObject(DC_PEN) orelse return;
    _ = SetDCBrushColor(hdc, bg);
    _ = SetDCPenColor(hdc, border);
    const old_brush = SelectObject(hdc, stock_brush);
    const old_pen = SelectObject(hdc, stock_pen);
    // Inset by 1px — GDI strokes are centered, prevents clipping at edges
    _ = RoundRect(hdc, rect.left + 1, rect.top + 1, rect.right - 1, rect.bottom - 1, radius, radius);
    _ = SelectObject(hdc, old_pen);
    _ = SelectObject(hdc, old_brush);
    // Stock objects — never delete
}

fn paintRectVisible(hdc: HDC, paint_rect: RECT, rect: RECT) bool {
    if (rect.right <= rect.left or rect.bottom <= rect.top) return false;
    if (!rectIntersects(paint_rect, rect)) return false;
    return RectVisible(hdc, &rect) != 0;
}

fn tabButtonKeyAction(vk: WPARAM, ctrl_pressed: bool) ?TabButtonKeyAction {
    return switch (vk) {
        VK_LEFT => if (ctrl_pressed) .move_previous else .previous,
        VK_RIGHT => if (ctrl_pressed) .move_next else .next,
        VK_HOME => if (ctrl_pressed) .move_first else .first,
        VK_END => if (ctrl_pressed) .move_last else .last,
        VK_F2 => .rename,
        VK_DELETE => .close,
        VK_APPS => .overview,
        else => null,
    };
}

fn moveTabAmountToEdge(total: usize, current: usize, toward_start: bool) isize {
    if (total <= 1 or current >= total) return 0;
    if (toward_start) return -@as(isize, @intCast(current));
    return @as(isize, @intCast((total - 1) - current));
}

fn searchButtonKeyAction(vk: WPARAM, shift_pressed: bool) ?SearchButtonKeyAction {
    return switch (vk) {
        VK_F3 => if (shift_pressed) .previous else .next,
        VK_ESCAPE => .dismiss,
        else => null,
    };
}

fn dockedSearchCoreDirectionFromKeyAction(action: SearchButtonKeyAction) ?input.Binding.Action.NavigateSearch {
    return switch (action) {
        .previous => .previous,
        .next => .next,
        .dismiss => null,
    };
}

fn dockedSearchButtonDirection(command_id: usize) ?input.Binding.Action.NavigateSearch {
    // Core scrollback search indexes matches newest-first
    // (`.previous` => newer/down, `.next` => older/up). The docked
    // search bar is laid out as visible up/down navigation, so the
    // button IDs map to the opposite core enum.
    return switch (command_id) {
        SEARCH_PREV_ID => .next,
        SEARCH_NEXT_ID => .previous,
        else => null,
    };
}

fn dockedSearchEnterDirection(shift_pressed: bool) input.Binding.Action.NavigateSearch {
    return dockedSearchArrowDirection(if (shift_pressed) VK_UP else VK_DOWN).?;
}

fn dockedSearchArrowDirection(vk: WPARAM) ?input.Binding.Action.NavigateSearch {
    return switch (vk) {
        VK_UP => dockedSearchButtonDirection(SEARCH_PREV_ID),
        VK_DOWN => dockedSearchButtonDirection(SEARCH_NEXT_ID),
        else => null,
    };
}

fn searchDirectionFromWheelDelta(delta: i16) input.Binding.Action.NavigateSearch {
    return if (delta > 0)
        .next
    else
        .previous;
}

fn searchSelectedRawFromCoreDisplay(selected: ?usize) ?usize {
    const value = selected orelse return null;
    if (value == 0) return null;
    return value - 1;
}

fn searchSelectedDisplayFromRaw(raw: ?usize, total: ?usize) ?usize {
    const idx = raw orelse return null;
    const count = total orelse return null;
    if (count == 0 or idx >= count) return null;
    return idx + 1;
}

fn advanceSearchSelectedRaw(
    raw: ?usize,
    total: ?usize,
    dir: input.Binding.Action.NavigateSearch,
    wrap: bool,
) ?usize {
    const idx = raw orelse return null;
    const count = total orelse return null;
    if (count == 0 or idx >= count) return null;
    const last = count - 1;
    return switch (dir) {
        .next => if (idx >= last) if (wrap) 0 else idx else idx + 1,
        .previous => if (idx == 0) if (wrap) last else 0 else idx - 1,
    };
}

fn searchBarSearchedStateForTotal(total: ?usize) bool {
    return total != null;
}

fn searchBarSearchedStateForSelected(selected: ?usize, total: ?usize) bool {
    return selected != null or total != null;
}

fn searchBarDisplayStateChanged(
    search_bar: *const win32_search_bar.SearchBar,
    searched: bool,
    total: ?usize,
    selected: ?usize,
) bool {
    return search_bar.searched != searched or
        search_bar.total != total or
        search_bar.selected != selected;
}

fn profileChromeVisible(overlay_mode: HostOverlayMode, status_bar_height: i32) bool {
    return overlay_mode == .profile or status_bar_height > 0;
}

fn profileChromeNeedsFullTextInvalidation(overlay_mode: HostOverlayMode, status_bar_height: i32) bool {
    return overlay_mode != .profile and status_bar_height > 0;
}

fn chromeTextNeedsFullInvalidation(status_bar_height: i32) bool {
    return status_bar_height > 0;
}

fn inspectorVisibilityChangeNeedsHostRelayout(changed: bool) bool {
    return changed;
}

fn inspectorPanelVisibleForState(overlay_mode: HostOverlayMode, active_tab_has_inspector: bool) bool {
    return overlay_mode == .none and active_tab_has_inspector;
}

fn mergeChromeRepaintMask(current: *ChromeRepaintMask, next: ChromeRepaintMask) ChromeRepaintMask {
    const added: ChromeRepaintMask = .{
        .top = next.top and !current.top,
        .content = next.content and !current.content,
        .status = next.status and !current.status,
        .search_frames = next.search_frames and !current.search_frames,
    };
    current.* = .{
        .top = current.top or next.top,
        .content = current.content or next.content,
        .status = current.status or next.status,
        .search_frames = current.search_frames or next.search_frames,
    };
    return added;
}

const LayoutChildPaintPlan = struct {
    chrome: bool,
    content: bool,
    native_content_controls: bool,
};

fn layoutChildPaintPlan(chrome_changed: bool, content_changed: bool) LayoutChildPaintPlan {
    return .{
        .chrome = chrome_changed,
        .content = content_changed,
