fn buildProfileCommandPreviewText(
    alloc: Allocator,
    profile: *const windows_shell.Profile,
    max_len: usize,
) ![]u8 {
    const command = try profile.command.string(alloc);
    defer alloc.free(command);
    return try compactHostLabel(alloc, command, max_len);
}

fn buildProfileOrderSummaryText(
    alloc: Allocator,
    order_hint_opt: ?[]const u8,
    max_items: usize,
) !?[]u8 {
    const order_hint = order_hint_opt orelse return null;
    var parts: std.ArrayListUnmanaged(u8) = .empty;
    errdefer parts.deinit(alloc);

    var count: usize = 0;
    var more = false;
    var it = std.mem.splitAny(u8, order_hint, ",;");
    while (it.next()) |raw_token| {
        const token = std.mem.trim(u8, raw_token, " \t\r\n");
        if (token.len == 0) continue;
        if (count >= max_items) {
            more = true;
            break;
        }
        const compact = try compactHostLabel(alloc, token, 12);
        defer alloc.free(compact);
        if (parts.items.len > 0) try parts.appendSlice(alloc, " > ");
        try parts.appendSlice(alloc, compact);
        count += 1;
    }

    if (count == 0) return null;
    if (more) try parts.appendSlice(alloc, " > ...");
    return try parts.toOwnedSlice(alloc);
}

fn buildProfileQuickPickText(
    alloc: Allocator,
    profiles: []const windows_shell.Profile,
    max_items: usize,
    max_label_len: usize,
) !?[]u8 {
    if (profiles.len == 0 or max_items == 0) return null;

    var parts: std.ArrayListUnmanaged(u8) = .empty;
    errdefer parts.deinit(alloc);

    const limit = @min(@min(max_items, profiles.len), 9);
    var index: usize = 0;
    while (index < limit) : (index += 1) {
        const badge = try buildProfileChromeBadgeText(alloc, profiles[index].kind);
        defer alloc.free(badge);
        const label = try compactHostLabel(alloc, profiles[index].label, max_label_len);
        defer alloc.free(label);

        if (parts.items.len > 0) try parts.appendSlice(alloc, " | ");
        const item = try std.fmt.allocPrint(alloc, "{d} {s} {s}", .{
            index + 1,
            badge,
            label,
        });
        defer alloc.free(item);
        try parts.appendSlice(alloc, item);
    }

    if (limit < profiles.len) try parts.appendSlice(alloc, " | ...");
    return try parts.toOwnedSlice(alloc);
}

fn buildSearchButtonLabel(
    alloc: Allocator,
    active: bool,
    total: ?usize,
    selected: ?usize,
) ![]u8 {
    if (selected) |current| {
        if (total) |count| {
            return try std.fmt.allocPrint(alloc, "{s}{d}/{d}", .{
                if (active) "[F] " else "Find ",
                current,
                count,
            });
        }
    }
    if (total) |count| {
        return try std.fmt.allocPrint(alloc, "{s}{d}", .{
            if (active) "[F] " else "Find ",
            count,
        });
    }
    return try alloc.dupe(u8, if (active) "[Find]" else "Find");
}

fn buildProfileOverlayLabel(
    alloc: Allocator,
    profiles: []const windows_shell.Profile,
    input_text: []const u8,
    selected_index: usize,
) ![]u8 {
    if (profiles.len == 0) return try alloc.dupe(u8, "Profile");
    return switch (resolveProfileSelection(profiles, input_text, selected_index)) {
        .exact => |index| blk: {
            const badge = try buildProfileChromeBadgeText(alloc, profiles[index].kind);
            defer alloc.free(badge);
            break :blk try std.fmt.allocPrint(
                alloc,
                "Profile {d}/{d} {s}",
                .{ index + 1, profiles.len, badge },
            );
        },
        .ambiguous => |count| try std.fmt.allocPrint(alloc, "Profile {d}", .{count}),
        .invalid => try alloc.dupe(u8, "Profile ?"),
    };
}

fn buildProfileAcceptLabel(
    alloc: Allocator,
    profiles_opt: ?[]const windows_shell.Profile,
    input_text: []const u8,
    selected_index: usize,
    default_target: ProfileOpenTarget,
) ![]u8 {
    const profiles = profiles_opt orelse return try alloc.dupe(u8, "Check");
    if (profiles.len == 0) return try alloc.dupe(u8, "Check");
    return switch (resolveProfileSelection(profiles, input_text, selected_index)) {
        .exact => switch (default_target) {
            .tab => try alloc.dupe(u8, "Open Tab"),
            .window => try alloc.dupe(u8, "Open Win"),
            .split => try alloc.dupe(u8, "Split"),
        },
        .ambiguous => try alloc.dupe(u8, "Pick"),
        .invalid => try alloc.dupe(u8, "Check"),
    };
}

fn buildProfileHintText(
    alloc: Allocator,
    profiles_opt: ?[]const windows_shell.Profile,
    input_text: []const u8,
    selected_index: usize,
    default_target: ProfileOpenTarget,
    pinned_slot_keys: [3]?[:0]const u8,
) ![]u8 {
    const profiles = profiles_opt orelse return try alloc.dupe(u8, "No supported Windows profiles detected.");
    if (profiles.len == 0) return try alloc.dupe(u8, "No supported Windows profiles detected.");
    const quick_picks = try buildProfileQuickPickText(alloc, profiles, 4, 10);
    defer if (quick_picks) |value| alloc.free(value);
    const quick_suffix = if (quick_picks) |value|
        try std.fmt.allocPrint(alloc, " Quick picks: {s}.", .{value})
    else
        try alloc.dupe(u8, "");
    defer alloc.free(quick_suffix);
    return switch (resolveProfileSelection(profiles, input_text, selected_index)) {
        .exact => |index| blk: {
            const preview = try buildProfileCommandPreviewText(alloc, &profiles[index], 36);
            defer alloc.free(preview);
            const badge = try buildProfileChromeBadgeText(alloc, profiles[index].kind);
            defer alloc.free(badge);
            const pinned_slot = try buildPinnedProfileSlotText(
                alloc,
                findLauncherQuickSlotOrdinal(pinned_slot_keys, profiles[index].key),
            );
            defer alloc.free(pinned_slot);
            break :blk try std.fmt.allocPrint(
                alloc,
                "{s} {s} | key {s} | run {s}.{s} Enter opens a {s}. Ctrl+Enter splits here. Shift+Enter opens a new window. Ctrl+1-9 launches directly. Alt+1-3 launches visible slots. Alt+Shift+1-3 pins the current profile. Alt+Shift+0 clears pinning.{s}",
                .{
                    badge,
                    profiles[index].label,
                    profiles[index].key,
                    preview,
                    pinned_slot,
                    profileOpenTargetActionText(default_target),
                    quick_suffix,
                },
            );
        },
        .ambiguous => |count| try std.fmt.allocPrint(
            alloc,
            "{d} profiles match. Keep typing a name or use Up/Down to cycle the current selection. Ctrl+1-9 launches directly. Alt+1-3 launches visible slots. Alt+Shift+1-3 pins the current profile. Alt+Shift+0 clears pinning.{s}",
            .{ count, quick_suffix },
        ),
        .invalid => try std.fmt.allocPrint(
            alloc,
            "No matching profile. Try 1-{d} or a profile name like pwsh, ubuntu, git, or cmd. Ctrl+1-9 launches directly. Alt+1-3 launches visible slots. Alt+Shift+1-3 pins the current profile. Alt+Shift+0 clears pinning. Space keeps the picker open.{s}",
            .{ profiles.len, quick_suffix },
        ),
    };
}

fn buildProfileDetailText(
    alloc: Allocator,
    profile: *const windows_shell.Profile,
    profiles_opt: ?[]const windows_shell.Profile,
    overlay_open: bool,
    default_target: ProfileOpenTarget,
    order_hint: ?[]const u8,
    pinned_slot_keys: [3]?[:0]const u8,
) ![]u8 {
    const preview = try buildProfileCommandPreviewText(alloc, profile, 32);
    defer alloc.free(preview);
    const badge = try buildProfileChromeBadgeText(alloc, profile.kind);
    defer alloc.free(badge);
    const pinned_slot = try buildPinnedProfileSlotText(
        alloc,
        findLauncherQuickSlotOrdinal(pinned_slot_keys, profile.key),
    );
    defer alloc.free(pinned_slot);
    const quick_picks = if (overlay_open)
        try buildProfileQuickPickText(alloc, profiles_opt orelse &.{}, 4, 10)
    else
        try buildProfileQuickPickText(alloc, profiles_opt orelse &.{}, 3, 9);
    defer if (quick_picks) |value| alloc.free(value);
    const quick_suffix = if (overlay_open)
        if (quick_picks) |value|
            try std.fmt.allocPrint(alloc, " Quick picks: {s}.", .{value})
        else
            try alloc.dupe(u8, "")
    else if (quick_picks) |value|
        try std.fmt.allocPrint(alloc, " Top slots: {s}.", .{value})
    else
        try alloc.dupe(u8, "");
    defer alloc.free(quick_suffix);
    const order_summary = try buildProfileOrderSummaryText(alloc, order_hint, 4);
    defer if (order_summary) |value| alloc.free(value);
    const order_suffix = if (order_summary) |value|
        try std.fmt.allocPrint(alloc, " Order: {s}.", .{value})
    else
        try alloc.dupe(u8, "");
    defer alloc.free(order_suffix);
    const overlay_suffix = try std.fmt.allocPrint(alloc, "{s}{s}", .{ quick_suffix, order_suffix });
    defer alloc.free(overlay_suffix);
    const idle_suffix = try std.fmt.allocPrint(alloc, "{s}{s}", .{ quick_suffix, order_suffix });
    defer alloc.free(idle_suffix);
    return if (overlay_open)
        std.fmt.allocPrint(
            alloc,
            "Selected profile: {s} {s}. Run {s}.{s} Enter opens a {s}, Ctrl+Enter splits here, and Shift+Enter opens a new window. Alt+1-3 launches visible slots. Alt+Shift+1-3 pins the current profile. Alt+Shift+0 clears pinning.{s}",
            .{
                badge,
                profile.label,
                preview,
                pinned_slot,
                profileOpenTargetActionText(default_target),
                overlay_suffix,
            },
        )
    else
        std.fmt.allocPrint(
            alloc,
            "Default profile: {s} {s}. Run {s}.{s} New hosts inherit this {s}. + opens a {s}, middle-click + splits here, and right-click + opens a new window. Alt+1-3 launches visible slots. Alt+Shift+1-3 pins the current profile. Alt+Shift+0 clears pinning.{s}",
            .{
                badge,
                profile.label,
                preview,
                pinned_slot,
                profileKindDetail(profile.kind),
                profileOpenTargetActionText(default_target),
                idle_suffix,
            },
        );
}

fn buildPinnedProfileSlotText(alloc: Allocator, pinned_slot_ordinal: ?usize) ![]u8 {
    if (pinned_slot_ordinal) |ordinal| {
        return try std.fmt.allocPrint(alloc, " Pinned slot {d}.", .{ordinal + 1});
    }
    return try alloc.dupe(u8, "");
}

fn buildInspectorButtonLabel(
    alloc: Allocator,
    visible: bool,
    pane_count: usize,
) ![]u8 {
    if (visible and pane_count > 1) {
        return try std.fmt.allocPrint(alloc, "[Inspect {d}]", .{pane_count});
    }
    if (visible) return try alloc.dupe(u8, "[Inspect]");
    if (pane_count > 1) return try std.fmt.allocPrint(alloc, "Inspect {d}", .{pane_count});
    return try alloc.dupe(u8, "Inspect");
}

fn commandPaletteMatchCount(snap: PaletteSnapshot, input_text: []const u8) usize {
    return win32_palette.matchCount(snap, input_text);
}

/// Returns the top-ranked match for the query, or null if no entry
/// matches. Renamed-by-semantic — this used to mean "exactly one
/// prefix match"; with fuzzy ranking the right submit-on-Enter
/// semantic is "the best match".
fn commandPaletteUniqueMatch(snap: PaletteSnapshot, input_text: []const u8) ?[]const u8 {
    if (input_text.len == 0) return null;
    var buf: [palette_max_tokens][]const u8 = undefined;
    const tokens = tokenizePaletteQuery(input_text, &buf);
    if (tokens.len == 0) return null;

    var best_rank: f64 = std.math.inf(f64);
    var best_index: ?usize = null;
    for (snap.commands, snap.cvals, 0..) |cmd, c, i| {
        const r = rankPaletteEntry(cmd, c, tokens) orelse continue;
        if (r < best_rank) {
            best_rank = r;
            best_index = i;
        }
    }
    return if (best_index) |i| std.mem.span(snap.cvals[i].action) else null;
}

fn commandPaletteCompletionCandidate(
    snap: PaletteSnapshot,
    seed: []const u8,
    current_text: []const u8,
    reverse: bool,
) ?[]const u8 {
    var ranked_buf: [palette_max_ranked]RankedIndex = undefined;
    const ranked = rankedIndicesForQuery(snap, seed, &ranked_buf);
    if (ranked.len == 0) return null;
    if (ranked.len == 1) return std.mem.span(snap.cvals[ranked[0].index].action);

    var current_rank_index: ?usize = null;
    for (ranked, 0..) |r, i| {
        const action = std.mem.span(snap.cvals[r.index].action);
        if (std.mem.eql(u8, action, current_text)) {
            current_rank_index = i;
            break;
        }
    }

    const target = if (current_rank_index) |value|
        if (reverse)
            (value + ranked.len - 1) % ranked.len
        else
            (value + 1) % ranked.len
    else if (reverse)
        ranked.len - 1
    else
        0;
    return std.mem.span(snap.cvals[ranked[target].index].action);
}

/// Look up the Command.description for a given formatted action string.
/// Returns null if no entry matches or the description is empty.
fn commandPaletteDescriptionFor(snap: PaletteSnapshot, action_text: []const u8) ?[]const u8 {
    for (snap.commands, snap.cvals) |cmd, c| {
        const action = std.mem.span(c.action);
        if (!std.mem.eql(u8, action, action_text)) continue;
        const desc: []const u8 = cmd.description;
        return if (desc.len == 0) null else desc;
    }
    return null;
}

fn nextTabOverviewSelection(current: usize, total: usize, reverse: bool) usize {
    if (total == 0) return 0;
    const clamped = std.math.clamp(current, @as(usize, 1), total);
    if (reverse) {
        return if (clamped <= 1) total else clamped - 1;
    }
    return if (clamped >= total) 1 else clamped + 1;
}

fn tabDirectionFromWheelDelta(delta: i16) apprt.action.GotoTab {
    return if (delta > 0) .previous else .next;
}

fn buildCommandPaletteOverlayLabel(
    alloc: Allocator,
    snap: PaletteSnapshot,
    input_text: []const u8,
) ![]u8 {
    if (input_text.len == 0) return try alloc.dupe(u8, "Command");
    if (input.Binding.Action.parse(input_text)) |_| {
        return try alloc.dupe(u8, "Run action");
    } else |_| {}
    if (commandPaletteUniqueMatch(snap, input_text) != null) {
        return try alloc.dupe(u8, "Run action");
    }
    const matches = commandPaletteMatchCount(snap, input_text);
    if (matches > 0) return try std.fmt.allocPrint(alloc, "Command {d}", .{matches});
    return try alloc.dupe(u8, "Command ?");
}

fn commandPaletteBannerText(
    alloc: Allocator,
    snap: PaletteSnapshot,
    input_text: []const u8,
    mru: []const []const u8,
) !?[]u8 {
    if (input_text.len == 0) {
        if (mru.len == 0) {
            return try alloc.dupe(u8, "Try: new_tab (new tab), start_search (find), toggle_tab_overview (tab list)");
        }
        var buf: std.ArrayListUnmanaged(u8) = .empty;
        errdefer buf.deinit(alloc);
        try buf.appendSlice(alloc, "Recent: ");
        const visible = @min(mru.len, 5);
        for (mru[0..visible], 0..) |action, i| {
            if (i > 0) try buf.appendSlice(alloc, ", ");
            try buf.appendSlice(alloc, action);
        }
        return try buf.toOwnedSlice(alloc);
    }

    if (input.Binding.Action.parse(input_text)) |_| {
        if (commandPaletteDescriptionFor(snap, input_text)) |summary| {
            return try std.fmt.allocPrint(alloc, "Ready: {s} - {s}", .{ input_text, summary });
        }
        return try std.fmt.allocPrint(alloc, "Ready to run: {s}", .{input_text});
    } else |_| {}

    // Cap visible matches to keep the banner readable. With ~90
    // entries a bare query like "t" can rank dozens of matches;
    // showing all of them produces a wall of text.
    const max_visible: usize = 5;
    var ranked_buf: [palette_max_ranked]RankedIndex = undefined;
    const ranked = rankedIndicesForQuery(snap, input_text, &ranked_buf);
    if (ranked.len == 0) return null;

    // Single match → "Ready: {action} - {description}" so Enter
    // telegraphs what it'll run. Multi-match falls through to the
    // "Matches: …" list so the user sees the candidate set.
    if (ranked.len == 1) {
        const action = std.mem.span(snap.cvals[ranked[0].index].action);
        if (commandPaletteDescriptionFor(snap, action)) |summary| {
            return try std.fmt.allocPrint(alloc, "Ready: {s} - {s}", .{ action, summary });
        }
        return try std.fmt.allocPrint(alloc, "Ready to run: {s}", .{action});
    }

    var buf: std.ArrayListUnmanaged(u8) = .empty;
    errdefer buf.deinit(alloc);
    try buf.appendSlice(alloc, "Matches: ");
    const visible_len = @min(ranked.len, max_visible);
    for (ranked[0..visible_len], 0..) |r, i| {
        const action = std.mem.span(snap.cvals[r.index].action);
        if (i > 0) try buf.appendSlice(alloc, ", ");
        try buf.appendSlice(alloc, action);
        if (commandPaletteDescriptionFor(snap, action)) |summary| {
            try buf.appendSlice(alloc, " (");
            try buf.appendSlice(alloc, summary);
            try buf.appendSlice(alloc, ")");
        }
    }
    if (ranked.len > visible_len) {
        const rest = ranked.len - visible_len;
        try std.fmt.format(buf.writer(alloc), " + {d} more", .{rest});
    }
    return try buf.toOwnedSlice(alloc);
}

fn readWindowTextUtf8Alloc(alloc: Allocator, hwnd: HWND) ![:0]u8 {
    const len_w = GetWindowTextLengthW(hwnd);
    if (len_w <= 0) return try alloc.dupeZ(u8, "");

    const needed: usize = @intCast(len_w + 1);
    var buf_w = try alloc.alloc(u16, needed);
    defer alloc.free(buf_w);
    buf_w[needed - 1] = 0;

    const copied = GetWindowTextW(hwnd, buf_w.ptr, @intCast(needed));
    if (copied < 0) return windows.unexpectedError(windows.kernel32.GetLastError());

    return try std.unicode.utf16LeToUtf8AllocZ(alloc, buf_w[0..@intCast(copied)]);
}

fn wmCommandChildHwnd(lParam: LPARAM) ?HWND {
    if (lParam == 0) return null;
    return @ptrFromInt(@as(usize, @intCast(lParam)));
}

fn getHost(hwnd: HWND) ?*Host {
    const raw = GetWindowLongPtrW(hwnd, GWLP_USERDATA);
    if (raw == 0) return null;
    return @ptrFromInt(@as(usize, @intCast(raw)));
}

fn refocusActiveSurface(host: *Host) void {
    if (host.activeSurface()) |surface| {
        if (surface.hwnd) |surface_hwnd| _ = SetFocus(surface_hwnd);
    }
}

fn logUiActionError(comptime context: []const u8, err: anyerror) void {
    log.warn(context ++ " err={}", .{err});
}

fn hostButtonProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    const host = getHost(hwnd);
    if (host) |v| {
        // Keyboard routing for the overlay accept/cancel pair. In
        // confirm mode the EDIT control is hidden and focus lands on
        // the accept button; without this path Esc has no effect
        // because `overlayEditProc`'s Esc handler only runs when the
        // (hidden) EDIT has focus. Tab/Shift+Tab cycle between the
        // two buttons; arrow keys also cycle for screen-reader
        // users who navigate via arrows.
        if (msg == WM_KEYDOWN and v.isOverlayButton(hwnd)) {
            switch (wParam) {
                VK_ESCAPE => {
                    if (v.overlay_mode == .confirm) {
                        v.invokeConfirmCancel();
                    } else {
                        v.hideOverlay();
                    }
                    return 0;
                },
                VK_TAB, VK_LEFT, VK_RIGHT => {
                    const target: ?HWND = if (hwnd == v.overlay_accept_hwnd)
                        v.overlay_cancel_hwnd
                    else if (hwnd == v.overlay_cancel_hwnd)
                        v.overlay_accept_hwnd
                    else
                        null;
                    if (target) |t| _ = SetFocus(t);
                    return 0;
                },
                VK_RETURN, VK_SPACE => {
                    if (v.overlay_mode == .confirm) {
                        if (hwnd == v.overlay_accept_hwnd) {
                            v.invokeConfirmAccept();
                        } else if (hwnd == v.overlay_cancel_hwnd) {
                            v.invokeConfirmCancel();
                        }
                        return 0;
                    }
                },
                else => {},
            }
        }
        if (msg == WM_KEYDOWN and v.isSearchBarButton(hwnd)) {
            if (v.searchControlSurface(hwnd)) |surface| {
                if (searchButtonKeyAction(wParam, keyPressed(VK_SHIFT))) |action| {
                    if (dockedSearchCoreDirectionFromKeyAction(action)) |dir| {
                        _ = surface.navigateDockedSearch(dir) catch |err| {
                            logUiActionError("docked search button navigation failed", err);
                        };
                        return 0;
                    }
                    switch (action) {
                        .dismiss => {
                            _ = v.dismissActiveSearch();
                            return 0;
                        },
                        else => {},
                    }
                }
            }
        }
        switch (msg) {
            WM_SETFOCUS => {
                if (v.searchControlSurface(hwnd)) |surface| {
                    v.app.activateSurfaceNoFocus(surface);
                }
            },
            WM_KILLFOCUS => {
                v.setFocusedQuickSlot(null);
            },
            WM_MOUSEMOVE => {
                var track: TRACKMOUSEEVENT = .{
                    .cbSize = @sizeOf(TRACKMOUSEEVENT),
                    .dwFlags = TME_LEAVE,
                    .hwndTrack = hwnd,
                    .dwHoverTime = 0,
                };
                _ = TrackMouseEvent(&track);
                v.setHoveredButton(hwnd);
            },
            WM_MOUSELEAVE => {
                if (v.isHoveredButton(hwnd)) v.setHoveredButton(null);
            },
            WM_RBUTTONUP => {
                if (v.new_tab_hwnd != null and hwnd == v.new_tab_hwnd.?) {
                    if (v.openSelectedProfileOrFallback(.window)) return 0;
                }
            },
            WM_MBUTTONUP => {
                if (v.new_tab_hwnd != null and hwnd == v.new_tab_hwnd.?) {
                    if (v.openSelectedProfileOrFallback(.split)) return 0;
                }
            },
            else => {},
        }

        const prev = if (v.isOverlayButton(hwnd))
            v.overlay_button_prev_proc
        else if (v.searchControlSurface(hwnd)) |surface|
            surface.searchBarButtonPrevProc(hwnd)
        else
            v.chrome_button_prev_proc;
        if (prev) |proc| {
            return CallWindowProcW(proc, hwnd, msg, wParam, lParam);
        }
    }
    return DefWindowProcW(hwnd, msg, wParam, lParam);
}

fn tabButtonProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    const host = getHost(hwnd);
    if (host) |v| {
        if (v.tabIndexForButton(hwnd)) |index| {
            switch (msg) {
                WM_LBUTTONDOWN => {
                    const down_x = signedLowWord(lParamBits(lParam));
                    var btn_rect: RECT = undefined;
                    _ = GetClientRect(hwnd, &btn_rect);
                    const close_left = btn_rect.right - v.scaled(host_tab_close_zone_width);
                    if (down_x >= close_left and v.tabs.items.len > 1) {
                        // Click in close zone — capture for mouseup but don't start drag
                        _ = SetCapture(hwnd);
                    } else {
                        // Start potential drag: record origin
                        v.tab_drag_index = index;
                        v.tab_drag_start_x = down_x;
                        v.tab_drag_active = false;
                        _ = SetCapture(hwnd);
                    }
                    return 0;
                },
                WM_LBUTTONUP => {
                    const drag_index = v.tab_drag_index;
                    const was_drag = v.tab_drag_active;
                    v.tab_drag_index = null;
                    v.tab_drag_active = false;
                    _ = ReleaseCapture();
                    const click_x = signedLowWord(lParamBits(lParam));
                    var btn_rect: RECT = undefined;
                    _ = GetClientRect(hwnd, &btn_rect);
                    const close_left = btn_rect.right - v.scaled(host_tab_close_zone_width);
                    switch (tabButtonMouseUpAction(
                        drag_index,
                        was_drag,
                        click_x,
                        close_left,
                        v.tabs.items.len,
                    )) {
                        .activate => {
                            _ = v.activateTabIndex(index);
                        },
                        .close => {
                            if (v.activateTabIndex(index)) {
                                if (v.activeSurface()) |surface| {
                                    _ = v.app.closeTab(.{ .surface = surface.core() }, .this) catch |err| {
                                        log.warn("tab close button action failed err={}", .{err});
                                    };
                                }
                            }
                        },
                        .none => {},
                    }
                    return 0;
                },
                WM_CAPTURECHANGED => {
                    v.tab_drag_index = null;
                    v.tab_drag_active = false;
                },
                WM_MOUSEMOVE => {
                    var track: TRACKMOUSEEVENT = .{
                        .cbSize = @sizeOf(TRACKMOUSEEVENT),
                        .dwFlags = TME_LEAVE,
                        .hwndTrack = hwnd,
                        .dwHoverTime = 0,
                    };
                    _ = TrackMouseEvent(&track);
                    v.setHoveredButton(hwnd);

                    // Handle tab drag reorder
                    if (v.tab_drag_index) |drag_idx| {
                        const mouse_x = signedLowWord(lParamBits(lParam));
                        const dx = if (mouse_x > v.tab_drag_start_x)
                            mouse_x - v.tab_drag_start_x
                        else
                            v.tab_drag_start_x - mouse_x;

                        // Activate drag after 5px threshold
                        if (!v.tab_drag_active and dx > 5) {
                            v.tab_drag_active = true;
                        }

                        if (v.tab_drag_active) {
                            // Convert to screen coords, then find target tab
                            var pt: POINT = .{ .x = mouse_x, .y = 0 };
                            _ = ClientToScreen(hwnd, &pt);
                            if (v.tabIndexAtScreenX(pt.x)) |target_idx| {
                                if (target_idx != drag_idx and v.tabs.items.len > 1) {
                                    v.swapTabs(drag_idx, target_idx);
                                    v.tab_drag_index = target_idx;
                                    v.tab_drag_start_x = mouse_x;
                                }
                            }
                        }
                    }
                },
                WM_MOUSELEAVE => {
                    if (v.isHoveredButton(hwnd)) v.setHoveredButton(null);
                },
                WM_KEYDOWN => {
                    if (tabButtonKeyAction(wParam, keyPressed(VK_CONTROL))) |action| {
                        switch (action) {
                            .previous => {
                                _ = v.activateTabByDirection(.previous);
                                return 0;
                            },
                            .next => {
                                _ = v.activateTabByDirection(.next);
                                return 0;
                            },
                            .first => {
                                _ = v.activateTabByDirection(@enumFromInt(0));
                                return 0;
                            },
                            .last => {
                                _ = v.activateTabByDirection(.last);
                                return 0;
                            },
                            .move_previous => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        _ = v.app.moveTab(.{ .surface = surface.core() }, .{ .amount = -1 }) catch {};
                                        return 0;
                                    }
                                }
                            },
                            .move_next => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        _ = v.app.moveTab(.{ .surface = surface.core() }, .{ .amount = 1 }) catch {};
                                        return 0;
                                    }
                                }
                            },
                            .move_first => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        const amount = moveTabAmountToEdge(v.tabs.items.len, index, true);
                                        if (amount != 0) {
                                            _ = v.app.moveTab(.{ .surface = surface.core() }, .{ .amount = amount }) catch {};
                                        }
                                        return 0;
                                    }
                                }
                            },
                            .move_last => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        const amount = moveTabAmountToEdge(v.tabs.items.len, index, false);
                                        if (amount != 0) {
                                            _ = v.app.moveTab(.{ .surface = surface.core() }, .{ .amount = amount }) catch {};
                                        }
                                        return 0;
                                    }
                                }
                            },
                            .rename => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        surface.promptTitle(.tab) catch {};
                                        return 0;
                                    }
                                }
                            },
                            .close => {
                                if (v.tabs.items.len > 1 and v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        _ = v.app.closeTab(.{ .surface = surface.core() }, .this) catch |err| {
                                            log.warn("tab close key action failed err={}", .{err});
                                        };
                                        return 0;
                                    }
                                }
                            },
                            .overview => {
                                if (v.activateTabIndex(index)) {
                                    if (v.activeSurface()) |surface| {
                                        _ = surface.toggleTabOverview() catch {};
                                        return 0;
                                    }
                                }
                            },
                        }
                    }
                },
                WM_MBUTTONUP => {
                    if (v.tabs.items.len > 1 and v.activateTabIndex(index)) {
                        if (v.activeSurface()) |surface| {
                            _ = v.app.closeTab(.{ .surface = surface.core() }, .this) catch |err| {
                                log.warn("tab middle-click close action failed err={}", .{err});
                            };
                            return 0;
                        }
                    }
                },
                WM_LBUTTONDBLCLK => {
                    if (v.activateTabIndex(index)) {
                        if (v.activeSurface()) |surface| {
                            surface.promptTitle(.tab) catch {};
                            return 0;
                        }
                    }
                },
                WM_RBUTTONUP => {
                    if (v.activateTabIndex(index)) {
                        v.showTabContextMenu(hwnd, index);
                        return 0;
                    }
                },
                else => {},
            }

            if (v.tabs.items[index].button_prev_proc) |proc| {
                return CallWindowProcW(proc, hwnd, msg, wParam, lParam);
            }
        }
    }
    return DefWindowProcW(hwnd, msg, wParam, lParam);
}

fn searchEditProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    const host = getHost(hwnd);
    if (host) |v| {
        if (v.searchControlSurface(hwnd)) |surface| switch (msg) {
            WM_SETFOCUS => {
                v.app.activateSurfaceNoFocus(surface);
                surface.invalidateSearchBarChildPaint();
            },
            WM_KILLFOCUS => {
                surface.invalidateSearchBarChildPaint();
            },
            WM_CHAR => {
                if (wParam == VK_RETURN or wParam == VK_ESCAPE) return 0;
            },
            WM_KEYDOWN, WM_SYSKEYDOWN => {
                if (wParam == VK_RETURN) {
                    _ = surface.navigateDockedSearch(dockedSearchEnterDirection(keyPressed(VK_SHIFT))) catch |err| {
                        logUiActionError("docked search enter navigation failed", err);
                    };
                    return 0;
                }
                if (dockedSearchArrowDirection(wParam)) |dir| {
                    _ = surface.navigateDockedSearch(dir) catch |err| {
                        logUiActionError("docked search arrow navigation failed", err);
                    };
                    return 0;
                }
                if (searchButtonKeyAction(wParam, keyPressed(VK_SHIFT))) |action| {
                    if (dockedSearchCoreDirectionFromKeyAction(action)) |dir| {
                        _ = surface.navigateDockedSearch(dir) catch |err| {
                            logUiActionError("docked search key navigation failed", err);
                        };
                        return 0;
                    }
                    switch (action) {
                        .dismiss => {
                            surface.closeDockedSearchBar(true, true) catch |err| {
                                logUiActionError("docked search key close failed", err);
                            };
                            return 0;
                        },
                        else => {},
                    }
                }
            },
            else => {},
        };
    }

    if (host) |v| {
        if (v.searchControlSurface(hwnd)) |surface| {
            if (surface.search_bar_edit_prev_proc) |proc| {
                return CallWindowProcW(proc, hwnd, msg, wParam, lParam);
            }
        }
    }
    return DefWindowProcW(hwnd, msg, wParam, lParam);
}

fn overlayEditProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    const host = getHost(hwnd);
    if (host) |v| switch (msg) {
        WM_CHAR => {
            if (wParam == VK_ESCAPE) return 0;
            if (wParam == VK_RETURN) {
                if (v.overlay_mode != .profile) {
                    _ = v.submitOverlay() catch {};
                }
                return 0;
            }
        },

        WM_KEYDOWN, WM_SYSKEYDOWN => {
            if (v.overlay_mode == .command_palette) {
                if (wParam == VK_UP or wParam == VK_DOWN) {
                    // Up/Down drive list selection, not EDIT text
                    // completion — the live list shows the full candidate
                    // set now, so Tab-cycling-in-EDIT is obsolete UX.
                    if (v.moveListSelection(wParam == VK_UP)) return 0;
                }
                if (wParam == VK_TAB) {
                    const reverse = keyPressed(VK_SHIFT);
                    if ((v.completeCommandPalette(reverse) catch false)) return 0;
                }
            }
            if (v.overlay_mode == .tab_overview) {
                if (wParam == VK_UP or wParam == VK_DOWN) {
                    if ((v.stepTabOverviewSelection(wParam == VK_UP) catch false)) return 0;
                }
            }
            if (v.overlay_mode == .profile) {
                if ((v.ensureProfiles() catch false)) {
                    if (clearQuickSlotPinsRequested(wParam, keyPressed(VK_MENU), keyPressed(VK_SHIFT))) {
                        if (v.clearQuickSlotPins()) return 0;
                    }
                    if (quickSlotPinOrdinalFromKey(wParam, keyPressed(VK_MENU), keyPressed(VK_SHIFT))) |slot_ordinal| {
                        if (v.assignSelectedProfileToQuickSlot(slot_ordinal)) return 0;
                    }
                    if (quickSlotShortcutProfileIndex(v.profiles.?.len, v.selectedProfileIndex(), wParam, keyPressed(VK_MENU))) |index| {
                        if (v.quickOpenProfileIndex(index, v.app.launcher_profile_target)) return 0;
                    }
                }
                if (keyPressed(VK_CONTROL)) {
                    if (profileShortcutIndexFromKey(wParam)) |index| {
                        if (v.quickOpenProfileIndex(index, v.app.launcher_profile_target)) return 0;
                    }
                }
                if (wParam == VK_RETURN) {
                    _ = v.submitProfileOverlay(resolveProfileOpenTarget(
                        v.app.launcher_profile_target,
                        keyPressed(VK_SHIFT),
                        keyPressed(VK_CONTROL),
                    )) catch {};
                    return 0;
                }
                if (wParam == VK_UP or wParam == VK_DOWN) {
                    if ((v.stepProfileSelection(wParam == VK_UP) catch false)) return 0;
                }
            }
            if (v.overlay_mode == .search) {
                if (wParam == VK_UP) {
                    if ((v.navigateSearchOverlay(.previous) catch false)) return 0;
                }
                if (wParam == VK_DOWN) {
                    if ((v.navigateSearchOverlay(.next) catch false)) return 0;
                }
                if (wParam == VK_RETURN and keyPressed(VK_SHIFT)) {
                    if ((v.navigateSearchOverlay(.previous) catch false)) return 0;
                }
            }
            if (wParam == VK_ESCAPE) {
                if (v.overlay_mode == .confirm) {
                    // Same no-access-after-dispatch discipline as
                    // the mouse-click confirm paths — cancel
                    // callbacks may tear down the Host.
                    v.invokeConfirmCancel();
                    return 0;
                }
                if (v.overlay_mode == .search) {
                    _ = v.dismissActiveSearch();
                    return 0;
                }
                v.hideOverlay();
                v.layout() catch {};
                refocusActiveSurface(v);
                return 0;
            }
        },

        else => {},
    };

    if (host) |v| {
        if (v.overlay_edit_prev_proc) |proc| {
            return CallWindowProcW(proc, hwnd, msg, wParam, lParam);
        }
    }
    return DefWindowProcW(hwnd, msg, wParam, lParam);
}

fn hostWindowProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    if (msg == WM_NCCREATE) {
        const cs: *const CREATESTRUCTW = @ptrFromInt(@as(usize, @bitCast(lParam)));
        if (cs.lpCreateParams) |ptr| {
            _ = SetWindowLongPtrW(hwnd, GWLP_USERDATA, @as(LONG_PTR, @intCast(@intFromPtr(ptr))));
        }
    }

    const host = getHost(hwnd);
    switch (msg) {
        // Per-host tween heartbeat. Runs at ~16 ms while any chrome
        // animation is active; stops as soon as the scheduler empties.
        // Separate from the App-level quit timer, which uses
        // `SetTimer(null, …)` on the thread queue.
        WM_TIMER => {
            if (wParam == TWEEN_TIMER_ID) {
                if (host) |v| v.tickTweens();
                return 0;
            }
            if (wParam == SEARCH_TIMER_ID) {
                if (host) |v| v.tickSearchBars();
                return 0;
            }
            if (wParam == SCROLLBAR_TIMER_ID) {
                if (host) |v| v.tickScrollbars();
                return 0;
            }
            if (wParam == RESIZE_SETTLE_TIMER_ID) {
                if (host) |v| v.tickResizeSettleRepaint();
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_DRAWITEM => {
            if (host) |v| {
                const draw: *const DRAWITEMSTRUCT = @ptrFromInt(@as(usize, @bitCast(lParam)));
                if (v.drawSearchBarBackground(draw)) return 1;
                v.drawButton(draw);
                return 1;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_ERASEBKGND => return 1,
        // Integrated-titlebar non-client handlers. All gated on the
        // host actively using the integrated titlebar (Win11 build /
        // config gate + visible tab/caption row); otherwise they fall
        // through to DefWindowProcW and the system paints its default
        // caption.
        WM_NCCALCSIZE => {
            if (host) |v| {
                if (v.handleNcCalcSize(hwnd, wParam, lParam)) |lr| return lr;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_NCHITTEST => {
            if (host) |v| {
                if (v.usingIntegratedTitlebar()) {
                    if (dispatchDwmNcMessage(hwnd, msg, wParam, lParam)) |lr| return lr;
                }
                if (v.handleNcHitTest(hwnd, lParam)) |lr| return lr;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_NCMOUSEMOVE => {
            if (host) |v| {
                if (v.handleNcMouseMove(hwnd, wParam)) |lr| return lr;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_NCMOUSELEAVE => {
            if (host) |v| {
                const dwm_result = if (v.usingIntegratedTitlebar())
                    dispatchDwmNcMessage(hwnd, msg, wParam, lParam)
                else
                    null;
                v.handleNcMouseLeave();
                if (dwm_result) |lr| return lr;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        // Integrated-titlebar caption-button click dispatch. The
        // custom NC frame still returns HTMINBUTTON / HTMAXBUTTON for
        // shell affordances such as Snap Layout hover, but it cannot
        // rely on DefWindowProc owning the full caption-button mouse
        // loop once WM_NCCALCSIZE has removed the top NC margin.
        WM_NCLBUTTONDOWN => {
            if (host) |v| {
                if (v.usingIntegratedTitlebar()) {
                    const ht: i32 = @intCast(@as(i64, @bitCast(wParam)));
                    v.caption_pressed = titlebarCaptionFromHitTest(ht);
                    if (v.caption_pressed != .none) v.repaintTopChrome();
                    if (captionButtonSysCommand(ht, IsZoomed(hwnd) != 0)) |cmd| {
                        v.clearCaptionPressed();
                        _ = SendMessageW(hwnd, WM_SYSCOMMAND, cmd, lParam);
                        return 0;
                    }
                    if (ht == HTCLOSE) return 0;
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_NCLBUTTONUP => {
            if (host) |v| {
                if (v.usingIntegratedTitlebar()) {
                    if (dispatchDwmNcMessage(hwnd, msg, wParam, lParam)) |lr| return lr;
                    const ht: i32 = @intCast(@as(i64, @bitCast(wParam)));
                    if (captionButtonSysCommand(ht, IsZoomed(hwnd) != 0) != null) {
                        v.clearCaptionPressed();
                        return 0;
                    }
                    switch (ht) {
                        HTCLOSE => {
                            v.clearCaptionPressed();
                            _ = SendMessageW(hwnd, WM_SYSCOMMAND, SC_CLOSE, lParam);
                            return 0;
                        },
                        else => v.clearCaptionPressed(),
                    }
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        // UIA root object request. Screen readers (Narrator, NVDA) call
        // `AccessibleObjectFromWindow` which turns into WM_GETOBJECT on
        // the target HWND. We only handle the UIA root-object ID; MSAA
        // and other IDs fall through to the default proc.
        WM_GETOBJECT => {
            if (host) |v| {
                if (win32_uia.handleGetObject(v.app.core_app.alloc, hwnd, wParam, lParam)) |lr| {
                    return lr;
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_SETTINGCHANGE => {
            if (host) |v| {
                v.app.refreshSystemWheelSettings();
                v.app.refreshSystemScrollbarPreference();
                v.app.reconfigureTheme();
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_THEMECHANGED, WM_SYSCOLORCHANGE => {
            if (host) |v| {
                v.app.reconfigureTheme();
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        // Fired by DWM when the user's accent color changes. Re-resolve
        // the theme so any accent-derived tokens pick up the new value
        // without requiring a config reload.
        WM_DWMCOLORIZATIONCOLORCHANGED => {
            if (host) |v| {
                v.app.reconfigureTheme();
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_DPICHANGED => {
            if (host) |v| {
                const new_dpi = GetDpiForWindow(hwnd);
                if (new_dpi > 0) v.current_dpi = new_dpi;

                // Resize window to the suggested rectangle from lParam
                const suggested: *const RECT = @ptrFromInt(@as(usize, @bitCast(lParam)));
                _ = SetWindowPos(hwnd, null, suggested.left, suggested.top, suggested.right - suggested.left, suggested.bottom - suggested.top, SWP_NOZORDER | SWP_NOACTIVATE);

                // Update content_scale on active tab surfaces
                const scale_val: f32 = @as(f32, @floatFromInt(v.current_dpi)) / 96.0;
                const new_scale: apprt.ContentScale = .{ .x = scale_val, .y = scale_val };
                if (v.activeTab()) |tab| {
                    var it = tab.tree.iterator();
                    while (it.next()) |entry| {
                        entry.view.content_scale = new_scale;
                        if (entry.view.core_initialized) {
                            entry.view.core_surface.contentScaleCallback(new_scale) catch {};
                        }
                    }
                }
                v.pending_dpi_update = true;
                v.recreateChromeFont();

                // Relayout and repaint
                v.layout() catch {};
                if (chromeTextNeedsFullInvalidation(v.statusBarHeight())) {
                    v.invalidateChromeText();
                } else {
                    v.invalidateTopChromeText();
                }
            }
            return 0;
        },
        WM_CTLCOLOREDIT, WM_CTLCOLORSTATIC, WM_CTLCOLORBTN => {
            if (host) |v| {
                v.ensureThemeBrushes() catch return DefWindowProcW(hwnd, msg, wParam, lParam);
                const hdc: HDC = @ptrFromInt(@as(usize, @intCast(wParam)));
                const child: HWND = @ptrFromInt(@as(usize, @intCast(lParam)));
                switch (msg) {
                    WM_CTLCOLOREDIT => {
                        _ = SetBkMode(hdc, OPAQUE);
                        _ = SetBkColor(hdc, v.app.resolved_theme.edit_bg);
                        _ = SetTextColor(hdc, v.app.resolved_theme.edit_fg);
                        return @as(LRESULT, @bitCast(@as(usize, @intFromPtr(v.edit_brush.?))));
                    },
                    WM_CTLCOLORSTATIC => {
                        _ = SetBkMode(hdc, TRANSPARENT);
                        _ = SetTextColor(hdc, if (v.isSearchBarResultsLabel(child))
                            if (v.searchControlSurface(child)) |surface|
                                searchBarResultsVisual(&v.app.resolved_theme, &surface.search_bar).fg
                            else
                                v.app.resolved_theme.text_secondary
                        else if (v.overlay_hint_hwnd != null and child == v.overlay_hint_hwnd.?)
                            v.app.resolved_theme.text_secondary
                        else
                            v.app.resolved_theme.text_primary);
                        return @as(LRESULT, @bitCast(@as(usize, @intFromPtr(v.overlay_brush.?))));
                    },
                    WM_CTLCOLORBTN => {
                        _ = SetBkMode(hdc, TRANSPARENT);
                        if (v.isOverlayStyledButton(child)) {
                            _ = SetTextColor(hdc, v.app.resolved_theme.button_overlay_fg);
                            return @as(LRESULT, @bitCast(@as(usize, @intFromPtr(v.overlay_brush.?))));
                        }
                        _ = SetTextColor(hdc, if (v.isActiveChromeButton(child))
                            v.app.resolved_theme.button_active_fg
                        else
                            v.app.resolved_theme.button_chrome_fg);
                        return @as(LRESULT, @bitCast(@as(usize, @intFromPtr(v.chrome_brush.?))));
                    },
                    else => {},
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },
        WM_COMMAND => {
            if (host) |v| {
                const command_id = lowWord(wParam);
                const notify_code = highWord(wParam);
                const child_hwnd = wmCommandChildHwnd(lParam);
                switch (command_id) {
                    2002 => {
                        if (notify_code == EN_CHANGE) {
                            // Skip re-entry from our own programmatic
                            // `SetWindowTextW` on the edit HWND. The
                            // caller already wraps the write in
                            // `suppress_edit_events` and drives its
                            // own sync pass afterward; letting this
                            // handler run would invalidate
                            // `cached_overlay_edit` mid-write and
                            // racing borrows across the sync cascade
                            // caused palette edit re-entry crashes.
                            if (v.suppress_edit_events) return 0;
                            appendOwnedString(v.app.core_app.alloc, &v.cached_overlay_edit, null) catch {};
                            if (v.overlay_mode == .search) {
                                _ = v.syncSearchOverlay() catch {};
                            } else if (v.overlay_mode == .command_palette) {
                                v.syncOverlayCompletionState() catch {};
                                _ = v.syncCommandPaletteBanner() catch {};
                            } else {
                                _ = v.syncOverlayLabel() catch false;
                                _ = v.syncOverlayHint() catch false;
                                _ = v.syncOverlayButtons() catch false;
                            }
                            return 0;
                        }
                    },
                    SEARCH_EDIT_ID => {
                        if (notify_code == EN_CHANGE) {
                            if (v.suppress_edit_events) return 0;
                            if (child_hwnd) |child| {
                                if (v.searchControlSurface(child)) |surface| {
                                    _ = surface.handleSearchBarEditChanged() catch |err| {
                                        logUiActionError("docked search edit update failed", err);
                                    };
                                    return 0;
                                }
                            }
                        }
                    },
                    2003 => {
                        if (v.overlay_mode == .confirm) {
                            // MUST NOT touch `v` after the callback
                            // — a destructive accept (close-surface)
                            // fires `DestroyWindow`, which triggers
                            // the Host's WM_DESTROY path + frees the
                            // Host struct. `invokeConfirmAccept`
                            // itself documents this ordering invariant.
                            v.invokeConfirmAccept();
                            return 0;
                        }
                        if (v.overlay_mode == .profile) {
                            _ = v.submitProfileOverlay(resolveProfileOpenTarget(
                                v.app.launcher_profile_target,
                                keyPressed(VK_SHIFT),
                                keyPressed(VK_CONTROL),
                            )) catch {};
                        } else {
                            _ = v.submitOverlay() catch {};
                        }
                        return 0;
                    },
                    2004 => {
                        if (v.overlay_mode == .confirm) {
                            // Cancel callbacks can mutate or destroy
                            // the Host. Use the same no-access-after
                            // discipline as the accept path for safety.
                            v.invokeConfirmCancel();
                            return 0;
                        }
                        if (v.overlay_mode == .search) {
                            _ = v.dismissActiveSearch();
                            return 0;
                        }
                        v.hideOverlay();
                        v.layout() catch {};
                        refocusActiveSurface(v);
                        return 0;
                    },
                    SEARCH_PREV_ID => {
                        if (notify_code == BN_CLICKED) {
                            if (child_hwnd) |child| {
                                if (v.searchControlSurface(child)) |surface| {
                                    if (dockedSearchButtonDirection(command_id)) |dir| {
                                        _ = surface.navigateDockedSearch(dir) catch |err| {
                                            logUiActionError("docked search previous failed", err);
                                        };
                                    }
                                    return 0;
                                }
                            }
                        }
                    },
                    SEARCH_NEXT_ID => {
                        if (notify_code == BN_CLICKED) {
                            if (child_hwnd) |child| {
                                if (v.searchControlSurface(child)) |surface| {
                                    if (dockedSearchButtonDirection(command_id)) |dir| {
                                        _ = surface.navigateDockedSearch(dir) catch |err| {
                                            logUiActionError("docked search next failed", err);
                                        };
                                    }
                                    return 0;
                                }
                            }
                        }
                    },
                    SEARCH_REGEX_ID, SEARCH_CASE_ID, SEARCH_WORD_ID => {
                        if (notify_code == BN_CLICKED) {
                            if (child_hwnd) |child| {
                                if (v.searchControlSurface(child)) |surface| {
                                    _ = surface.handleSearchToggleClick(command_id) catch |err| {
                                        logUiActionError("docked search toggle failed", err);
                                    };
                                    return 0;
                                }
                            }
                        }
                    },
                    SEARCH_CLOSE_ID => {
                        if (notify_code == BN_CLICKED) {
                            if (child_hwnd) |child| {
                                if (v.searchControlSurface(child)) |surface| {
                                    surface.closeDockedSearchBar(true, true) catch |err| {
                                        logUiActionError("docked search close failed", err);
                                    };
                                    return 0;
                                }
                            }
                        }
                    },
                    1901 => {
                        if (v.activeSurface()) |surface| {
                            _ = surface.toggleCommandPalette() catch {};
                        }
                        return 0;
                    },
                    1910 => {
                        _ = v.cycleLauncherProfileTarget(false);
                        return 0;
                    },
                    1907 => {
                        _ = v.activateTabByDirection(.previous);
                        return 0;
                    },
                    1908 => {
                        _ = v.activateTabByDirection(.next);
                        return 0;
                    },
                    1902 => {
                        if (v.activeSurface()) |surface| {
                            if (surface.search_bar.visible) {
                                surface.closeDockedSearchBar(true, true) catch |err| {
                                    logUiActionError("docked search close failed", err);
                                };
                            } else {
                                surface.showSearchOverlay("") catch |err| {
                                    logUiActionError("docked search open failed", err);
                                };
                            }
                        }
                        return 0;
                    },
                    1903 => {
                        if (v.activeSurface()) |surface| {
                            _ = v.app.toggleInspectorForSurface(surface) catch {};
                        }
                        return 0;
                    },
                    1904 => {
                        _ = v.openSelectedProfileOrFallback(.tab);
                        return 0;
                    },
                    1911 => {
                        v.showOverflowMenu();
                        return 0;
                    },
                    else => {},
                }
                for (v.tabs.items, 0..) |*tab, i| {
                    if (child_hwnd) |child| {
                        if (tab.button_hwnd == child) {
                            v.active_tab = i;
                            if (tab.focusedSurface()) |surface| v.app.activateSurface(surface);
                            return 0;
                        }
                    }
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_SETFOCUS => {
            if (host) |v| {
                refocusActiveSurface(v);
            }
            return 0;
        },

        WM_KEYDOWN, WM_SYSKEYDOWN, WM_KEYUP, WM_SYSKEYUP => {
            if (host) |v| {
                if (v.handleEmptyHostKeyMessage(msg, wParam, lParam)) return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_GETMINMAXINFO => {
            if (host) |v| {
                if (v.activeSurface()) |surface| {
                    surface.updateMinMaxInfo(lParam);
                    return 0;
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_SIZE => {
            if (host) |v| {
                // Defensive: maximize / minimize jumps don't always
                // route through WM_ENTERSIZEMOVE → WM_EXITSIZEMOVE, so
                // a flag set on an earlier interactive drag might be
                // left stuck `true` after a window-button size change.
                // Clear it here so the renderer doesn't stay in
                // coarse-mode after the user clicks maximize.
                const size_kind: u32 = @truncate(wParam);
                if (size_kind == SIZE_MAXIMIZED or size_kind == SIZE_MINIMIZED) {
                    v.is_live_resize.store(false, .release);
                    // Win32 silently cancels NC mouse tracking when
                    // the window minimises or its maximised state
                    // flips — WM_NCMOUSELEAVE is NOT guaranteed to
                    // fire in those paths. Force-clear the caption
                    // state here so the next NC re-entry re-arms
                    // `TrackMouseEvent` and hover paint stays correct.
                    v.caption_track_armed = false;
                    if (v.caption_hover != .none or v.caption_pressed != .none) {
                        v.caption_hover = .none;
                        v.caption_pressed = .none;
                        v.repaintTopChrome();
                    }
                }
                v.layout() catch {};
                if (size_kind == SIZE_MAXIMIZED or
                    (size_kind == SIZE_RESTORED and !v.is_live_resize.load(.acquire)))
                {
                    v.startResizeSettleRepaints();
                }
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_ENTERSIZEMOVE => {
            // User started a drag-resize or drag-move. We don't know
            // which yet, but setting the flag on both is harmless —
            // pure move generates no WM_SIZE so the throttle has
            // nothing to coalesce. WM_EXITSIZEMOVE clears it either
            // way.
            if (host) |v| v.is_live_resize.store(true, .release);
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_EXITSIZEMOVE => {
            if (host) |v| {
                v.is_live_resize.store(false, .release);
                v.defer_surface_repaints_until_flush = true;
                v.layout() catch {};
                v.defer_surface_repaints_until_flush = false;
                v.flushDeferredVisibleSurfaceRepaints();
                v.startResizeSettleRepaints();
                v.forceVisibleSurfaceRepaintsNow();
                v.forceHostCompositionPaint();
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_MOUSEMOVE => {
            if (host) |v| {
                var track: TRACKMOUSEEVENT = .{
                    .cbSize = @sizeOf(TRACKMOUSEEVENT),
                    .dwFlags = TME_LEAVE,
                    .hwndTrack = hwnd,
                    .dwHoverTime = 0,
                };
                _ = TrackMouseEvent(&track);
                const point = POINT{
                    .x = signedLowWord(lParamBits(lParam)),
                    .y = signedHighWord(lParamBits(lParam)),
                };
                v.setHoveredQuickSlot(v.quickSlotProfileIndexAtPoint(point));
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_MOUSELEAVE => {
            if (host) |v| v.setHoveredQuickSlot(null);
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_MOUSEWHEEL, WM_MOUSEHWHEEL, WM_POINTERWHEEL, WM_POINTERHWHEEL => {
            if (host) |v| {
                var point = POINT{
                    .x = signedLowWord(lParamBits(lParam)),
                    .y = signedHighWord(lParamBits(lParam)),
                };
                if (ScreenToClient(hwnd, &point) != 0 and point.y >= 0 and point.y < v.tabBarHeight()) {
                    _ = v.activateTabByDirection(tabDirectionFromWheelDelta(signedHighWord(wParam)));
                    return 0;
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_LBUTTONUP, WM_MBUTTONUP, WM_RBUTTONUP => {
            if (host) |v| {
                const point = POINT{
                    .x = signedLowWord(lParamBits(lParam)),
                    .y = signedHighWord(lParamBits(lParam)),
                };
                if (msg == WM_LBUTTONUP and v.handleUpdateNoticeClick(point)) {
                    return 0;
                }
                if (v.quickSlotProfileIndexAtPoint(point)) |profile_index| {
                    _ = v.setSelectedProfileIndex(profile_index) catch return 0;
                    const open_target = switch (msg) {
                        WM_MBUTTONUP => ProfileOpenTarget.split,
                        WM_RBUTTONUP => ProfileOpenTarget.window,
                        else => v.app.launcher_profile_target,
                    };
                    if (v.openSelectedProfile(open_target)) return 0;
                    return 0;
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_PAINT => {
            if (host) |v| {
                v.chrome_paint_pending = false;
                v.chrome_paint_mask = .{};
                v.paintChrome();
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_CLOSE => {
            if (host) |v| {
                v.close();
                return 0;
            }
            _ = DestroyWindow(hwnd);
            return 0;
        },

        WM_DESTROY => {
            if (host) |v| v.hwnd = null;
            return 0;
        },

        else => return DefWindowProcW(hwnd, msg, wParam, lParam),
    }
}

fn desiredTabIndex(total: usize, current: usize, goto: apprt.action.GotoTab) ?usize {
    if (total == 0 or current >= total) return null;

    return switch (goto) {
        .previous => if (current == 0) total - 1 else current - 1,
        .next => (current + 1) % total,
        .last => total - 1,
        _ => blk: {
            const raw: c_int = @intFromEnum(goto);
            if (raw < 0) return null;
            const idx: usize = @intCast(raw);
            break :blk @min(idx, total - 1);
        },
    };
}

const TabButtonMouseUpAction = enum {
    none,
    activate,
    close,
};

fn tabButtonMouseUpAction(
    drag_index: ?usize,
    was_drag: bool,
    click_x: i32,
    close_left: i32,
    tab_count: usize,
) TabButtonMouseUpAction {
    if (drag_index != null) {
        return if (was_drag) .none else .activate;
    }
    if (tab_count > 1 and click_x >= close_left) return .close;
    return .none;
}

fn desiredMoveIndex(total: usize, current: usize, amount: isize) ?usize {
    if (total <= 1 or current >= total or amount == 0) return null;
    const total_i: isize = @intCast(total);
    const current_i: isize = @intCast(current);
    const normalized = @mod(current_i + amount, total_i);
    return @intCast(normalized);
}

fn quickSlotProfileIndex(
    profiles_len: usize,
    selected_index: ?usize,
    slot_ordinal: usize,
    max_slots: usize,
) ?usize {
    if (profiles_len == 0 or slot_ordinal >= max_slots) return null;
    var drawn: usize = 0;
    var index: usize = 0;
    while (index < profiles_len) : (index += 1) {
        if (selected_index != null and index == selected_index.?) continue;
        if (drawn == slot_ordinal) return index;
        drawn += 1;
        if (drawn >= max_slots) break;
    }
    return null;
}

fn nextQuickSlotFocus(
    profiles_len: usize,
    selected_index: ?usize,
    current_profile_index: ?usize,
    reverse: bool,
    max_slots: usize,
) ?usize {
    var visible_count: usize = 0;
    var slot_ordinal: usize = 0;
    while (slot_ordinal < max_slots) : (slot_ordinal += 1) {
        if (quickSlotProfileIndex(profiles_len, selected_index, slot_ordinal, max_slots)) |_| {
            visible_count += 1;
        } else break;
    }
    if (visible_count == 0) return null;

    if (current_profile_index) |current| {
        var current_ordinal: ?usize = null;
        slot_ordinal = 0;
        while (slot_ordinal < visible_count) : (slot_ordinal += 1) {
            if (quickSlotProfileIndex(profiles_len, selected_index, slot_ordinal, max_slots)) |index| {
                if (index == current) {
                    current_ordinal = slot_ordinal;
                    break;
                }
            }
        }
        if (current_ordinal) |ordinal| {
            const next_ordinal = if (reverse)
                if (ordinal == 0) visible_count - 1 else ordinal - 1
            else
                (ordinal + 1) % visible_count;
            return quickSlotProfileIndex(profiles_len, selected_index, next_ordinal, max_slots);
        }
    }

    return quickSlotProfileIndex(
        profiles_len,
        selected_index,
        if (reverse) visible_count - 1 else 0,
        max_slots,
    );
}

fn applyQuickSlotPreferenceOrder(
    profiles: []windows_shell.Profile,
    slot_keys: [3]?[]const u8,
) void {
    var insert_at: usize = 0;
    for (slot_keys) |key_opt| {
        const key = key_opt orelse continue;
        var found: ?usize = null;
        for (profiles, 0..) |profile, index| {
            if (std.ascii.eqlIgnoreCase(profile.key, key)) {
                found = index;
                break;
            }
        }
        const found_index = found orelse continue;
        if (found_index == insert_at) {
            insert_at += 1;
            continue;
        }
        const chosen = profiles[found_index];
        var move_index = found_index;
        while (move_index > insert_at) : (move_index -= 1) {
            profiles[move_index] = profiles[move_index - 1];
        }
        profiles[insert_at] = chosen;
        insert_at += 1;
    }
}

fn findLauncherQuickSlotOrdinal(slot_keys: [3]?[:0]const u8, key: []const u8) ?usize {
    for (slot_keys, 0..) |slot_key, index| {
        if (slot_key) |value| {
            if (std.ascii.eqlIgnoreCase(value, key)) return index;
        }
    }
    return null;
}

fn launcherQuickSlotAssignmentNeedsChange(
    slot_keys: [3]?[:0]const u8,
    slot_ordinal: usize,
    key: []const u8,
) bool {
    if (slot_ordinal >= slot_keys.len) return false;
    return findLauncherQuickSlotOrdinal(slot_keys, key) != slot_ordinal;
}

fn launcherQuickSlotPinsAlreadyClear(slot_keys: [3]?[:0]const u8) bool {
    for (slot_keys) |slot_key| {
        if (slot_key != null) return false;
    }
    return true;
}

fn selectedProfileSelectionNeedsChange(
    current_index: usize,
    next_index: usize,
    focused_quick_slot: ?usize,
    selected_profile_key: ?[:0]const u8,
    launcher_profile_key: ?[:0]const u8,
    next_key: []const u8,
) bool {
    return current_index != next_index or
        focused_quick_slot != null or
        !ownedStringEquals(selected_profile_key, next_key) or
        !ownedStringEquals(launcher_profile_key, next_key);
}

fn startupProfilePickerEnabled(raw: []const u8) bool {
    return std.mem.eql(u8, raw, "1") or
        std.ascii.eqlIgnoreCase(raw, "true") or
        std.ascii.eqlIgnoreCase(raw, "yes") or
        std.ascii.eqlIgnoreCase(raw, "on");
}

fn detectStartupProfilePicker(alloc: Allocator) bool {
    const raw = std.process.getEnvVarOwned(alloc, "WINGHOSTTY_WIN32_STARTUP_PROFILE_PICKER") catch
        return false;
    defer alloc.free(raw);
    return startupProfilePickerEnabled(raw);
}

fn detectDefaultProfileHint(alloc: Allocator) ?[:0]const u8 {
    const raw = std.process.getEnvVarOwned(alloc, "WINGHOSTTY_WIN32_DEFAULT_PROFILE") catch
        return null;
    if (raw.len == 0) {
        alloc.free(raw);
        return null;
    }
    const value = alloc.dupeZ(u8, raw) catch {
        alloc.free(raw);
        return null;
    };
    alloc.free(raw);
    return value;
}

fn detectDefaultProfileTarget(alloc: Allocator) ProfileOpenTarget {
    const raw = std.process.getEnvVarOwned(alloc, "WINGHOSTTY_WIN32_DEFAULT_PROFILE_TARGET") catch
        return .tab;
    defer alloc.free(raw);
    return parseProfileOpenTarget(raw) orelse .tab;
}

fn isSafeStartupCwd(path: []const u8) bool {
    return path.len >= 3 and
        std.ascii.isAlphabetic(path[0]) and
        path[1] == ':' and
        (path[2] == '\\' or path[2] == '/');
}

fn pointInRect(point: POINT, rect: RECT) bool {
    return point.x >= rect.left and
        point.x < rect.right and
        point.y >= rect.top and
        point.y < rect.bottom;
}

fn lParamBits(lParam: LPARAM) usize {
    return @as(usize, @bitCast(lParam));
}

fn lowWord(value: usize) u16 {
    return @truncate(value & 0xFFFF);
}

fn highWord(value: usize) u16 {
    return @truncate((value >> 16) & 0xFFFF);
}

fn signedLowWord(value: usize) i16 {
    return @bitCast(lowWord(value));
}

fn signedHighWord(value: usize) i16 {
    return @bitCast(highWord(value));
}

fn scanCodeFromLParam(lParam: LPARAM) u32 {
    return @as(u32, highWord(lParamBits(lParam))) & 0xFF;
}

fn isExtendedKey(lParam: LPARAM) bool {
    return (lParamBits(lParam) & KF_EXTENDED) != 0;
}

fn isRepeatedKey(lParam: LPARAM) bool {
    return (lParamBits(lParam) & KF_REPEAT) != 0;
}

fn cursorPosFromLParam(lParam: LPARAM) apprt.CursorPos {
    const bits = lParamBits(lParam);
    return .{
        .x = @floatFromInt(signedLowWord(bits)),
        .y = @floatFromInt(signedHighWord(bits)),
    };
}

fn readSystemWheelSetting(action: UINT, fallback: u32) u32 {
    var value: UINT = fallback;
    if (SystemParametersInfoW(action, 0, @ptrCast(&value), 0) == 0) {
        return fallback;
    }
    return value;
}

fn wheelDeltaFromWParam(wParam: WPARAM) i16 {
    const bits = @as(usize, @intCast(wParam));
    return @bitCast(highWord(bits));
}

fn wheelSettingForAxis(settings: SystemWheelSettings, axis: MouseWheelAxis) u32 {
    return switch (axis) {
        .vertical => settings.lines,
        .horizontal => settings.chars,
    };
}

fn wheelUnitSize(ctx: WheelNormalizationContext, axis: MouseWheelAxis) f64 {
    const dim: u32 = switch (axis) {
        .vertical => ctx.cell_size.height,
        .horizontal => ctx.cell_size.width,
    };
    return @floatFromInt(@max(dim, 1));
}

fn wheelViewportSize(ctx: WheelNormalizationContext, axis: MouseWheelAxis) f64 {
    const dim: u32 = switch (axis) {
        .vertical => ctx.viewport.height,
        .horizontal => ctx.viewport.width,
    };
    const viewport: f64 = @floatFromInt(@max(dim, 1));
    const unit = wheelUnitSize(ctx, axis);
    return @max(unit, viewport - unit);
}

fn normalizeWheelDelta(
    ctx: WheelNormalizationContext,
    axis: MouseWheelAxis,
    delta: i16,
) NormalizedWheelScroll {
    if (delta == 0) return .{};

    const precision = @rem(delta, WHEEL_DELTA) != 0;
    const notch_delta = @as(f64, @floatFromInt(delta)) / WHEEL_DELTA;
    const pixels = if (precision)
        notch_delta * wheelUnitSize(ctx, axis)
    else discrete: {
        const setting = wheelSettingForAxis(ctx.settings, axis);
        if (setting == 0) return .{};

        break :discrete if (setting == WHEEL_PAGESCROLL)
            notch_delta * wheelViewportSize(ctx, axis)
        else
            notch_delta * @as(f64, @floatFromInt(setting)) * wheelUnitSize(ctx, axis);
    };

    return switch (axis) {
        .vertical => .{
            .yoff = pixels,
            .mods = .{
                .precision = precision,
                .pixel_delta = true,
            },
        },
        .horizontal => .{
            .xoff = pixels,
            .mods = .{
                .precision = precision,
                .pixel_delta = true,
            },
        },
    };
}

fn keyPressed(vk: i32) bool {
    return GetKeyState(vk) < 0;
}

fn keyToggled(vk: i32) bool {
    return (GetKeyState(vk) & 1) != 0;
}

fn modsFromKeyboardState(state: *const [256]u8) input.Mods {
    const pressed = struct {
        fn check(state_: *const [256]u8, vk: usize) bool {
            return (state_[vk] & 0x80) != 0;
        }
    };

    return .{
        .shift = pressed.check(state, VK_SHIFT),
        .ctrl = pressed.check(state, VK_CONTROL),
        .alt = pressed.check(state, VK_MENU),
        .super = pressed.check(state, VK_LWIN) or pressed.check(state, VK_RWIN),
        .caps_lock = (state[VK_CAPITAL] & 1) != 0,
        .num_lock = (state[VK_NUMLOCK] & 1) != 0,
        .sides = .{
            .shift = if (pressed.check(state, VK_RSHIFT)) .right else .left,
            .ctrl = if (pressed.check(state, VK_RCONTROL)) .right else .left,
            .alt = if (pressed.check(state, VK_RMENU)) .right else .left,
            .super = if (pressed.check(state, VK_RWIN)) .right else .left,
        },
    };
}

fn fallbackMods() input.Mods {
    return .{
        .shift = keyPressed(VK_SHIFT),
        .ctrl = keyPressed(VK_CONTROL),
        .alt = keyPressed(VK_MENU),
        .super = keyPressed(VK_LWIN) or keyPressed(VK_RWIN),
        .caps_lock = keyToggled(VK_CAPITAL),
        .num_lock = keyToggled(VK_NUMLOCK),
        .sides = .{
            .shift = if (keyPressed(VK_RSHIFT)) .right else .left,
            .ctrl = if (keyPressed(VK_RCONTROL)) .right else .left,
            .alt = if (keyPressed(VK_RMENU)) .right else .left,
            .super = if (keyPressed(VK_RWIN)) .right else .left,
        },
    };
}

fn currentKeyboardState(state: *[256]u8) ?*const [256]u8 {
    if (GetKeyboardState(state) == 0) return null;
    return state;
}

fn currentModsFromKeyboardState(state: ?*const [256]u8) input.Mods {
    return if (state) |keyboard_state| modsFromKeyboardState(keyboard_state) else fallbackMods();
}

fn currentMods() input.Mods {
    var state: [256]u8 = [_]u8{0} ** 256;
    return currentModsFromKeyboardState(currentKeyboardState(&state));
}

fn keyFromVirtualKey(vk: UINT, lParam: LPARAM) input.Key {
    return switch (vk) {
        VK_BACK => .backspace,
        VK_TAB => .tab,
        VK_RETURN => if (isExtendedKey(lParam)) .numpad_enter else .enter,
        VK_SHIFT => if (scanCodeFromLParam(lParam) == 0x36) .shift_right else .shift_left,
        VK_LSHIFT => .shift_left,
        VK_RSHIFT => .shift_right,
        VK_CONTROL, VK_LCONTROL => if (isExtendedKey(lParam) or vk == VK_RCONTROL) .control_right else .control_left,
        VK_RCONTROL => .control_right,
        VK_MENU, VK_LMENU => if (isExtendedKey(lParam) or vk == VK_RMENU) .alt_right else .alt_left,
        VK_RMENU => .alt_right,
        VK_PAUSE => .pause,
        VK_CAPITAL => .caps_lock,
        VK_ESCAPE => .escape,
        VK_SPACE => .space,
        VK_PRIOR => .page_up,
        VK_NEXT => .page_down,
        VK_END => .end,
        VK_HOME => .home,
        VK_LEFT => .arrow_left,
        VK_UP => .arrow_up,
        VK_RIGHT => .arrow_right,
        VK_DOWN => .arrow_down,
        VK_SNAPSHOT => .print_screen,
        VK_INSERT => .insert,
        VK_DELETE => .delete,
        VK_LWIN => .meta_left,
        VK_RWIN => .meta_right,
        VK_APPS => .context_menu,
        VK_MULTIPLY => .numpad_multiply,
        VK_ADD => .numpad_add,
        VK_SEPARATOR => .numpad_separator,
        VK_SUBTRACT => .numpad_subtract,
        VK_DECIMAL => .numpad_decimal,
        VK_DIVIDE => .numpad_divide,
        VK_NUMLOCK => .num_lock,
        VK_SCROLL => .scroll_lock,
        VK_OEM_1 => .semicolon,
        VK_OEM_PLUS => .equal,
        VK_OEM_COMMA => .comma,
        VK_OEM_MINUS => .minus,
        VK_OEM_PERIOD => .period,
        VK_OEM_2 => .slash,
        VK_OEM_3 => .backquote,
        VK_OEM_4 => .bracket_left,
        VK_OEM_5 => .backslash,
        VK_OEM_6 => .bracket_right,
        VK_OEM_7 => .quote,
        VK_0...VK_9 => input.Key.fromASCII(@as(u8, @intCast('0' + (vk - VK_0)))) orelse .unidentified,
        VK_A...VK_Z => input.Key.fromASCII(@as(u8, @intCast('a' + (vk - VK_A)))) orelse .unidentified,
        VK_NUMPAD0...VK_NUMPAD9 => @enumFromInt(
            @intFromEnum(input.Key.numpad_0) + @as(c_int, @intCast(vk - VK_NUMPAD0)),
        ),
        VK_F1...VK_F24 => @enumFromInt(
            @intFromEnum(input.Key.f1) + @as(c_int, @intCast(vk - VK_F1)),
        ),
        else => .unidentified,
    };
}

fn unshiftedCodepointForVirtualKey(vk: UINT) u21 {
    return switch (vk) {
        VK_0...VK_9 => @as(u21, @intCast('0' + (vk - VK_0))),
        VK_A...VK_Z => @as(u21, @intCast('a' + (vk - VK_A))),
        VK_SPACE => ' ',
        VK_OEM_1 => ';',
        VK_OEM_PLUS => '=',
        VK_OEM_COMMA => ',',
        VK_OEM_MINUS => '-',
        VK_OEM_PERIOD => '.',
        VK_OEM_2 => '/',
        VK_OEM_3 => '`',
        VK_OEM_4 => '[',
        VK_OEM_5 => '\\',
        VK_OEM_6 => ']',
        VK_OEM_7 => '\'',
        else => 0,
    };
}

fn hotkeyModifiers(mods: input.Mods) UINT {
    var result: UINT = 0;
    if (mods.alt) result |= MOD_ALT;
    if (mods.ctrl) result |= MOD_CONTROL;
    if (mods.shift) result |= MOD_SHIFT;
    if (mods.super) result |= MOD_WIN;
    return result;
}

fn hotkeyPhysicalVirtualKey(key: input.Key) ?UINT {
    const key_int = @intFromEnum(key);
    if (key_int >= @intFromEnum(input.Key.key_a) and key_int <= @intFromEnum(input.Key.key_z)) {
        return VK_A + @as(UINT, @intCast(key_int - @intFromEnum(input.Key.key_a)));
    }
    if (key_int >= @intFromEnum(input.Key.digit_0) and key_int <= @intFromEnum(input.Key.digit_9)) {
        return VK_0 + @as(UINT, @intCast(key_int - @intFromEnum(input.Key.digit_0)));
    }
    if (key_int >= @intFromEnum(input.Key.numpad_0) and key_int <= @intFromEnum(input.Key.numpad_9)) {
        return VK_NUMPAD0 + @as(UINT, @intCast(key_int - @intFromEnum(input.Key.numpad_0)));
    }
    if (key_int >= @intFromEnum(input.Key.f1) and key_int <= @intFromEnum(input.Key.f24)) {
        return VK_F1 + @as(UINT, @intCast(key_int - @intFromEnum(input.Key.f1)));
    }

    return switch (key) {
        .backspace => VK_BACK,
        .tab => VK_TAB,
        .enter, .numpad_enter => VK_RETURN,
        .escape => VK_ESCAPE,
        .space => VK_SPACE,
        .page_up, .numpad_page_up => VK_PRIOR,
        .page_down, .numpad_page_down => VK_NEXT,
        .end, .numpad_end => VK_END,
        .home, .numpad_home => VK_HOME,
        .arrow_left, .numpad_left => VK_LEFT,
        .arrow_up, .numpad_up => VK_UP,
        .arrow_right, .numpad_right => VK_RIGHT,
        .arrow_down, .numpad_down => VK_DOWN,
        .print_screen => VK_SNAPSHOT,
        .insert, .numpad_insert => VK_INSERT,
        .delete, .numpad_delete => VK_DELETE,
        .meta_left => VK_LWIN,
        .meta_right => VK_RWIN,
        .context_menu => VK_APPS,
        .numpad_multiply => VK_MULTIPLY,
        .numpad_add => VK_ADD,
        .numpad_separator => VK_SEPARATOR,
        .numpad_subtract => VK_SUBTRACT,
        .numpad_decimal => VK_DECIMAL,
        .numpad_divide => VK_DIVIDE,
        .num_lock => VK_NUMLOCK,
        .scroll_lock => VK_SCROLL,
        .semicolon => VK_OEM_1,
        .equal => VK_OEM_PLUS,
        .comma => VK_OEM_COMMA,
        .minus => VK_OEM_MINUS,
        .period => VK_OEM_PERIOD,
        .slash => VK_OEM_2,
        .backquote => VK_OEM_3,
        .bracket_left => VK_OEM_4,
        .backslash => VK_OEM_5,
        .bracket_right => VK_OEM_6,
        .quote => VK_OEM_7,
        else => null,
    };
}

fn hotkeyUnicodeVirtualKey(cp: u21) ?struct { vk: UINT, shift: bool } {
    return switch (cp) {
        'a'...'z' => .{ .vk = VK_A + @as(UINT, @intCast(cp - 'a')), .shift = false },
        'A'...'Z' => .{ .vk = VK_A + @as(UINT, @intCast(cp - 'A')), .shift = true },
        '0'...'9' => .{ .vk = VK_0 + @as(UINT, @intCast(cp - '0')), .shift = false },
        ')' => .{ .vk = VK_0, .shift = true },
        '!' => .{ .vk = VK_0 + 1, .shift = true },
        '@' => .{ .vk = VK_0 + 2, .shift = true },
        '#' => .{ .vk = VK_0 + 3, .shift = true },
        '$' => .{ .vk = VK_0 + 4, .shift = true },
        '%' => .{ .vk = VK_0 + 5, .shift = true },
        '^' => .{ .vk = VK_0 + 6, .shift = true },
        '&' => .{ .vk = VK_0 + 7, .shift = true },
        '*' => .{ .vk = VK_0 + 8, .shift = true },
        '(' => .{ .vk = VK_0 + 9, .shift = true },
        ' ' => .{ .vk = VK_SPACE, .shift = false },
        ';' => .{ .vk = VK_OEM_1, .shift = false },
        ':' => .{ .vk = VK_OEM_1, .shift = true },
        '=' => .{ .vk = VK_OEM_PLUS, .shift = false },
        '+' => .{ .vk = VK_OEM_PLUS, .shift = true },
        ',' => .{ .vk = VK_OEM_COMMA, .shift = false },
        '<' => .{ .vk = VK_OEM_COMMA, .shift = true },
        '-' => .{ .vk = VK_OEM_MINUS, .shift = false },
        '_' => .{ .vk = VK_OEM_MINUS, .shift = true },
        '.' => .{ .vk = VK_OEM_PERIOD, .shift = false },
        '>' => .{ .vk = VK_OEM_PERIOD, .shift = true },
        '/' => .{ .vk = VK_OEM_2, .shift = false },
        '?' => .{ .vk = VK_OEM_2, .shift = true },
        '`' => .{ .vk = VK_OEM_3, .shift = false },
        '~' => .{ .vk = VK_OEM_3, .shift = true },
        '[' => .{ .vk = VK_OEM_4, .shift = false },
        '{' => .{ .vk = VK_OEM_4, .shift = true },
        '\\' => .{ .vk = VK_OEM_5, .shift = false },
        '|' => .{ .vk = VK_OEM_5, .shift = true },
        ']' => .{ .vk = VK_OEM_6, .shift = false },
        '}' => .{ .vk = VK_OEM_6, .shift = true },
        '\'' => .{ .vk = VK_OEM_7, .shift = false },
        '"' => .{ .vk = VK_OEM_7, .shift = true },
        else => null,
    };
}

fn hotkeySpecForTrigger(trigger: input.Binding.Trigger) ?GlobalHotkeySpec {
    var mods = trigger.mods.binding();
    const vk = switch (trigger.key) {
        .catch_all => return null,
        .physical => |key| hotkeyPhysicalVirtualKey(key) orelse return null,
        .unicode => |cp| unicode: {
            const mapped = hotkeyUnicodeVirtualKey(cp) orelse return null;
            if (mapped.shift) mods.shift = true;
            break :unicode mapped.vk;
        },
    };

    return .{
        .modifiers = hotkeyModifiers(mods),
        .vk = vk,
    };
}

fn quitTimerDelayMs(delay: configpkg.Config.Duration) UINT {
    const clamped_ns = @max(delay.duration, std.time.ns_per_s);
    const delay_ms_u64 = @max(1, std.math.divCeil(u64, clamped_ns, std.time.ns_per_ms) catch std.math.maxInt(u64));
    return @intCast(@min(delay_ms_u64, std.math.maxInt(UINT)));
}

fn mouseButtonFromMessage(msg: UINT) ?input.MouseButton {
    return switch (msg) {
        WM_LBUTTONDOWN, WM_LBUTTONUP => .left,
        WM_RBUTTONDOWN, WM_RBUTTONUP => .right,
        WM_MBUTTONDOWN, WM_MBUTTONUP => .middle,
        else => null,
    };
}

fn mouseButtonStateFromMessage(msg: UINT) ?input.MouseButtonState {
    return switch (msg) {
        WM_LBUTTONDOWN, WM_RBUTTONDOWN, WM_MBUTTONDOWN => .press,
        WM_LBUTTONUP, WM_RBUTTONUP, WM_MBUTTONUP => .release,
        else => null,
    };
}

fn mouseModsFromWParam(wParam: WPARAM) input.Mods {
    const bits = @as(usize, @intCast(wParam));
    var mods = currentMods();
    if ((bits & MK_SHIFT) != 0) mods.shift = true;
    if ((bits & MK_CONTROL) != 0) mods.ctrl = true;
    _ = bits & (MK_LBUTTON | MK_RBUTTON | MK_MBUTTON);
    return mods;
}

const ScrollbarProxyPoint = struct {
    local_x: f32,
    local_y: f32,
    over_band: bool,
};

fn scrollbarProxyPointFromSurfaceCoords(
    pane_rect: RECT,
    hover_width: i32,
    surface_x: i32,
    surface_y: i32,
) ScrollbarProxyPoint {
    const pane_width: i32 = @max(@as(i32, 1), pane_rect.right - pane_rect.left);
    const pane_height: i32 = @max(@as(i32, 1), pane_rect.bottom - pane_rect.top);
    const band_left: i32 = @max(@as(i32, 0), pane_width - @max(@as(i32, 1), hover_width));
    return .{
        .local_x = @floatFromInt(surface_x - band_left),
        .local_y = @floatFromInt(surface_y),
        .over_band = surface_x >= band_left and surface_x <= pane_width and
            surface_y >= 0 and surface_y <= pane_height,
    };
}

fn scrollbarProxyPointFromSurfaceCursor(
    pane_rect: RECT,
    hover_width: i32,
    lParam: LPARAM,
) ScrollbarProxyPoint {
    return scrollbarProxyPointFromSurfaceCoords(
        pane_rect,
        hover_width,
        signedLowWord(lParamBits(lParam)),
        signedHighWord(lParamBits(lParam)),
    );
}

const KeyText = struct {
    utf8: [8]u8 = [_]u8{0} ** 8,
    len: usize = 0,
    consumed_mods: input.Mods = .{},
    unshifted_codepoint: u21 = 0,
};

fn translateKeyText(
    vk: UINT,
    lParam: LPARAM,
    mods: input.Mods,
    keyboard_state: ?*const [256]u8,
) KeyText {
    const state = keyboard_state orelse {
        return .{ .unshifted_codepoint = unshiftedCodepointForVirtualKey(vk) };
    };

    var utf16: [4]u16 = [_]u16{0} ** 4;
    const count = ToUnicode(vk, scanCodeFromLParam(lParam), state, &utf16, utf16.len, 0);
    if (count <= 0) {
        return .{ .unshifted_codepoint = unshiftedCodepointForVirtualKey(vk) };
    }

    var result: KeyText = .{
        .unshifted_codepoint = unshiftedCodepointForVirtualKey(vk),
    };

    const codepoint: u21 = cp: {
        if (count >= 2 and std.unicode.utf16IsHighSurrogate(utf16[0]) and std.unicode.utf16IsLowSurrogate(utf16[1])) {
            break :cp std.unicode.utf16DecodeSurrogatePair(&.{ utf16[0], utf16[1] }) catch return result;
        }
        if (utf16[0] < 0x20 or utf16[0] == 0x7F) return result;
        break :cp utf16[0];
    };

    result.len = std.unicode.utf8Encode(codepoint, &result.utf8) catch 0;
    if (result.len > 0) {
        result.consumed_mods = .{
            .shift = mods.shift,
        };
    }

    return result;
}

fn keyEventFromWin32Message(
    msg: UINT,
    wParam: WPARAM,
    lParam: LPARAM,
) ?input.KeyEvent {
    const action: input.Action = switch (msg) {
        WM_KEYUP, WM_SYSKEYUP => .release,
        WM_KEYDOWN, WM_SYSKEYDOWN => if (isRepeatedKey(lParam)) .repeat else .press,
        else => return null,
    };

    const vk: UINT = @intCast(wParam & 0xFFFF);
    const key = keyFromVirtualKey(vk, lParam);
    var keyboard_state_storage: [256]u8 = [_]u8{0} ** 256;
    const keyboard_state = currentKeyboardState(&keyboard_state_storage);
    const mods = currentModsFromKeyboardState(keyboard_state);

    var event: input.KeyEvent = .{
        .action = action,
        .key = key,
        .mods = mods,
        .unshifted_codepoint = unshiftedCodepointForVirtualKey(vk),
    };

    if (action != .release) {
        const translated = translateKeyText(vk, lParam, mods, keyboard_state);
        event.utf8 = translated.utf8[0..translated.len];
        event.consumed_mods = translated.consumed_mods;
        if (translated.unshifted_codepoint != 0) {
            event.unshifted_codepoint = translated.unshifted_codepoint;
        }
    }

    return event;
}

fn windowProc(hwnd: HWND, msg: UINT, wParam: WPARAM, lParam: LPARAM) callconv(.winapi) LRESULT {
    if (msg == WM_NCCREATE) {
        const cs: *const CREATESTRUCTW = @ptrFromInt(@as(usize, @bitCast(lParam)));
        if (cs.lpCreateParams) |ptr| {
            _ = SetWindowLongPtrW(hwnd, GWLP_USERDATA, @as(LONG_PTR, @intCast(@intFromPtr(ptr))));
        }
    }

    const surface = getSurface(hwnd);

    switch (msg) {
        WM_WINHOSTTY_WAKE => return 0,

        WM_SETFOCUS => {
            if (surface) |v| v.focusChanged(true);
            return 0;
        },

        WM_KILLFOCUS => {
            if (surface) |v| v.focusChanged(false);
            return 0;
        },

        WM_SIZE => {
            if (surface) |v| v.windowSizeChanged();
            return 0;
        },

        WM_GETMINMAXINFO => {
            if (surface) |v| {
                v.updateMinMaxInfo(lParam);
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_KEYDOWN, WM_SYSKEYDOWN, WM_KEYUP, WM_SYSKEYUP => {
            if (surface) |v| {
                // VK_APPS (Menu key) -> show context menu when not mouse reporting
                const vk: UINT = @intCast(wParam & 0xFFFF);
                if (vk == VK_APPS and (msg == WM_KEYDOWN or msg == WM_SYSKEYDOWN)) {
                    if (!v.core_initialized or v.core_surface.io.terminal.flags.mouse_event == .none) {
                        if (v.host) |h| {
                            // Keyboard invoke: use center of surface
                            var rect: RECT = undefined;
                            if (GetClientRect(hwnd, &rect) != 0) {
                                var pt: POINT = .{
                                    .x = @divTrunc(rect.right, 2),
                                    .y = @divTrunc(rect.bottom, 2),
                                };
                                _ = ClientToScreen(hwnd, &pt);
                                h.showContextMenu(pt.x, pt.y);
                            }
                        }
                        return 0;
                    }
                }
                v.handleKeyMessage(msg, wParam, lParam);
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_IME_STARTCOMPOSITION => {
            if (surface) |v| {
                v.ime_composing = true;
                v.positionImeWindow();
            }
            return 0;
        },

        WM_IME_COMPOSITION => {
            if (surface) |v| {
                // Handle finalized (committed) text first
                if ((@as(u32, @intCast(lParam)) & GCS_RESULTSTR) != 0) {
                    v.handleImeResult();
                }
                // Then handle in-progress composition text
                if ((@as(u32, @intCast(lParam)) & GCS_COMPSTR) != 0) {
                    v.handleImeComposition();
                }
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_IME_ENDCOMPOSITION => {
            if (surface) |v| {
                v.ime_composing = false;
                v.core_surface.preeditCallback(null) catch {};
            }
            return 0;
        },

        WM_IME_SETCONTEXT => {
            // Mask out the default composition window; we handle preedit via the core renderer
            const masked_lParam = lParam & ~ISC_SHOWUICOMPOSITIONWINDOW;
            return DefWindowProcW(hwnd, msg, wParam, masked_lParam);
        },

        WM_CHAR => {
            return 0;
        },

        WM_MOUSEMOVE => {
            if (surface) |v| {
                if (v.handleScrollbarProxyMouseMove(hwnd, lParam)) return 0;
                v.handleMouseMove(lParam, mouseModsFromWParam(wParam));
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_MOUSELEAVE => {
            if (surface) |v| {
                v.handleScrollbarMouseLeave();
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_RBUTTONUP => {
            if (surface) |v| {
                // If terminal has mouse reporting active and Shift is not held,
                // pass through as a mouse event. Shift+Right-Click always opens
                // the context menu (standard terminal behavior).
                const mods = mouseModsFromWParam(wParam);
                if (v.core_initialized and v.core_surface.io.terminal.flags.mouse_event != .none and !mods.shift) {
                    v.handleMouseButton(msg, wParam, lParam);
                    return 0;
                }
                // Otherwise show context menu
                _ = ReleaseCapture();
                if (v.host) |h| {
                    var pt: POINT = .{
                        .x = signedLowWord(lParamBits(lParam)),
                        .y = signedHighWord(lParamBits(lParam)),
                    };
                    _ = ClientToScreen(hwnd, &pt);
                    h.showContextMenu(pt.x, pt.y);
                }
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_LBUTTONDOWN, WM_LBUTTONUP => {
            if (surface) |v| {
                if (v.handleScrollbarProxyButton(hwnd, msg, lParam)) return 0;
                v.handleMouseButton(msg, wParam, lParam);
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_RBUTTONDOWN, WM_MBUTTONDOWN, WM_MBUTTONUP => {
            if (surface) |v| {
                v.handleMouseButton(msg, wParam, lParam);
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_XBUTTONDOWN, WM_XBUTTONUP => {
            if (surface) |v| {
                v.handleXMouseButton(msg, wParam, lParam);
            }
            // Windows requires TRUE for XButton messages
            return 1;
        },

        WM_DROPFILES => {
            if (surface) |v| {
                v.handleDropFiles(wParam);
            }
            return 0;
        },

        WM_MOUSEWHEEL, WM_POINTERWHEEL => {
            if (surface) |v| {
                v.handleMouseWheel(normalizeWheelDelta(
                    v.wheelNormalizationContext(),
                    .vertical,
                    wheelDeltaFromWParam(wParam),
                ));
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_MOUSEHWHEEL, WM_POINTERHWHEEL => {
            if (surface) |v| {
                v.handleMouseWheel(normalizeWheelDelta(
                    v.wheelNormalizationContext(),
                    .horizontal,
                    wheelDeltaFromWParam(wParam),
                ));
                return 0;
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_ERASEBKGND => return 1,

        WM_SETTINGCHANGE => {
            if (surface) |v| v.app.refreshSystemWheelSettings();
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_SETCURSOR => {
            if (surface) |v| {
                if (lowWord(@as(usize, @intCast(lParam))) == HTCLIENT) {
                    const now_ms = GetTickCount64();
                    const was_hovered = v.scrollbar_state.hovered;
                    const was_visibility = v.scrollbar_state.visibility;
                    const over_scrollbar = v.updateScrollbarHoverFromScreenCursor(hwnd, now_ms);
                    if (over_scrollbar or
                        v.scrollbar_state.hovered != was_hovered or
                        v.scrollbar_state.visibility != was_visibility)
                    {
                        v.syncScrollbarWindowNow(now_ms) catch |err| {
                            log.warn("win32 scrollbar cursor refresh failed err={}", .{err});
                        };
                    }
                    if (over_scrollbar or v.scrollbar_state.dragging) {
                        _ = SetCursor(LoadCursorW(null, IDC_ARROW));
                        return 1;
                    }
                    if (v.applyCursor()) {
                        return 1;
                    }
                }
            }
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_CAPTURECHANGED => {
            if (surface) |v| v.handleScrollbarCaptureChanged();
            return DefWindowProcW(hwnd, msg, wParam, lParam);
        },

        WM_PAINT => {
            var ps: PAINTSTRUCT = undefined;
            _ = BeginPaint(hwnd, &ps) orelse return 0;
            defer _ = EndPaint(hwnd, &ps);

            if (surface) |v| {
                const draw_content = v.shouldDrawRendererPaintContent();
                v.paint_pending = false;
                if (draw_content) {
                    defer v.finishRendererRepaintRequest();
                    v.redraw() catch |err| {
                        log.err("win32 paint redraw failed err={}", .{err});
                    };
                } else {
                    v.requestRendererFrameNow();
                }
            }

            return 0;
        },

        WM_CLOSE => {
            if (surface) |v| v.invalidateStructuralHistoryForClose();
            _ = DestroyWindow(hwnd);
            return 0;
        },

        WM_DESTROY => {
            if (surface) |v| {
                if (v.destroy_on_wm_destroy) {
                    v.destroy();
                } else if (v.hwnd == hwnd) {
                    v.hwnd = null;
                }
            }
            return 0;
        },

        else => return DefWindowProcW(hwnd, msg, wParam, lParam),
    }
}

fn getSurface(hwnd: HWND) ?*Surface {
    const raw = GetWindowLongPtrW(hwnd, GWLP_USERDATA);
    if (raw == 0) return null;
    return @ptrFromInt(@as(usize, @intCast(raw)));
}

pub const Surface = struct {
    app: *App,
    host: ?*Host = null,
    host_id: u32 = 0,
    host_active: bool = true,
    window_visible: bool = false,
    occlusion_visible: ?bool = null,
    hwnd: ?HWND = null,
    placement: ChildPlacement = .{},
    hdc: HDC = null,
    hglrc: HGLRC = null,
    core_surface: CoreSurface = undefined,
    core_initialized: bool = false,
    destroy_on_wm_destroy: bool = false,
    content_scale: apprt.ContentScale = .{ .x = 1, .y = 1 },
    size: apprt.SurfaceSize = .{ .width = 800, .height = 600 },
    cursor_pos: apprt.CursorPos = .{ .x = -1, .y = -1 },
    title: ?[:0]const u8 = null,
    title_override: ?[:0]const u8 = null,
    tab_title_override: ?[:0]const u8 = null,
    launch_profile_key: ?[:0]const u8 = null,
    mouse_shape: terminal.MouseShape = .text,
    mouse_visible: bool = true,
    hovered_link: ?[:0]const u8 = null,
    window_focused: bool = false,
    quick_terminal: bool = false,
    decorations_visible: bool = true,
    fullscreen: bool = false,
    topmost: bool = false,
    restore_rect: RECT = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
    restore_maximized: bool = false,
    default_client_size: ?apprt.SurfaceSize = null,
    cell_size_pixels: apprt.action.CellSize = .{ .width = 0, .height = 0 },
    background_opacity_default: f64 = 1.0,
    background_opacity_force_opaque: bool = false,
    scrollbar_config: configpkg.Config.Scrollbar = .system,
    size_limit: apprt.action.SizeLimit = .{
        .min_width = 0,
        .min_height = 0,
        .max_width = 0,
        .max_height = 0,
    },
    readonly: bool = false,
    secure_input: bool = false,
    key_sequence_active: bool = false,
    key_table_name: ?[:0]const u8 = null,
    search_active: bool = false,
    search_needle: ?[:0]const u8 = null,
    search_total: ?usize = null,
    search_selected_raw: ?usize = null,
    search_selected: ?usize = null,
    search_match_rows: []const u32 = &.{},
    scrollbar: terminal.Scrollbar = .zero,
    scrollbar_state: win32_scrollbar_geometry.ScrollbarState = .{},
    scrollbar_hwnd: ?HWND = null,
    scrollbar_placement: ChildPlacement = .{},
    scrollbar_leave_armed: bool = false,
    scrollbar_leave_hwnd: ?HWND = null,
    scrollbar_drag_anchor_offset: f32 = 0,
    scrollbar_alpha_cache: BYTE = 0,
    scrollbar_markers: []const f32 = &.{},
    scrollbar_marker_revision: u64 = 0,
    scrollbar_marker_budget: usize = 0,
    scrollbar_paint_cache: ?ScrollbarPaintKey = null,
    pwd: ?[:0]const u8 = null,
    progress_status: ?[:0]const u8 = null,
    taskbar_progress: ?win32_taskbar_progress.ProgressReport = null,
    inspector_visible: bool = false,
    paint_pending: bool = false,
    live_resize_repaint_deferred: bool = false,
    renderer_repaint_requested: std.atomic.Value(bool) = .init(false),
    renderer_repaint_retry_pending: std.atomic.Value(bool) = .init(false),
    draw_in_progress: bool = false,
    ime_composing: bool = false,
    undo_capture_suspended: bool = false,
    /// Per-surface bounded undo stack for terminal-local replayable
    /// actions (`clear_screen`, `reset`). Structural history that
    /// retains live tabs/surfaces lives on `Host` because it crosses
    /// pane boundaries and outlives the triggering surface.
    undo_stack: win32_undo.UndoStack = undefined,
    /// Per-pane docked search bar state. The pure state machine
    /// lives in `win32_search_bar.zig`; HWNDs below are the live
    /// child controls docked above the pane content.
    search_bar: win32_search_bar.SearchBar = undefined,
    search_bar_frame_rect: RECT = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
    search_bar_frame_visible: bool = false,
    search_bar_bg_hwnd: ?HWND = null,
    search_bar_bg_placement: ChildPlacement = .{},
    search_bar_edit_hwnd: ?HWND = null,
    search_bar_edit_prev_proc: ?*const anyopaque = null,
    search_bar_edit_placement: ChildPlacement = .{},
    search_bar_prev_hwnd: ?HWND = null,
    search_bar_next_hwnd: ?HWND = null,
    search_bar_regex_hwnd: ?HWND = null,
    search_bar_case_hwnd: ?HWND = null,
    search_bar_word_hwnd: ?HWND = null,
    search_bar_close_hwnd: ?HWND = null,
    search_bar_button_prev_procs: [6]?*const anyopaque = [_]?*const anyopaque{null} ** 6,
    search_bar_prev_placement: ChildPlacement = .{},
    search_bar_next_placement: ChildPlacement = .{},
    search_bar_regex_placement: ChildPlacement = .{},
    search_bar_case_placement: ChildPlacement = .{},
    search_bar_word_placement: ChildPlacement = .{},
    search_bar_close_placement: ChildPlacement = .{},
    search_bar_results_hwnd: ?HWND = null,
    search_bar_results_placement: ChildPlacement = .{},
    search_bar_results_cache: ?[:0]const u8 = null,
    /// OLE drop target registered on the surface HWND. `null` when
    /// the module's `ensureCustomFormats` fails or Ole32 is absent
    /// (extremely unlikely on Win10+). Lifetime: created in
    /// `Surface.init` after the HWND is ready, revoked + deinited
    /// in `Surface.destroyWindow`. Storage is INLINE on Surface so
    /// the COM v-table pointer stays stable — Surface itself is
    /// heap-allocated via core_app.alloc and never moves.
    drop_target: win32_surface_drop_target.DropTarget = undefined,
    drop_target_registered: bool = false,
    /// Clipboard operation parked on `HostOverlayMode.confirm` — the
    /// owning `Surface` holds deep-copied payload bytes so the async
    /// accept / cancel callback sees valid data regardless of the
    /// original caller's buffer lifetime. Non-null exactly while an
    /// overlay is pending. Drained by `surfaceConfirmPasteAccept` /
    /// `surfaceConfirmWriteAccept` / the matching cancel callbacks,
    /// and by `Surface.destroyWindow` so a close-while-pending doesn't
    /// leak.
    pending_clipboard_op: ?PendingClipboardOp = null,

    fn searchBarButtonHwnd(self: *const Surface, role: SearchBarButtonRole) ?HWND {
        return switch (role) {
            .prev => self.search_bar_prev_hwnd,
            .next => self.search_bar_next_hwnd,
            .regex => self.search_bar_regex_hwnd,
            .case_sensitive => self.search_bar_case_hwnd,
            .whole_word => self.search_bar_word_hwnd,
            .close => self.search_bar_close_hwnd,
        };
    }

    fn searchBarButtonPlacement(self: *Surface, role: SearchBarButtonRole) *ChildPlacement {
        return switch (role) {
            .prev => &self.search_bar_prev_placement,
            .next => &self.search_bar_next_placement,
            .regex => &self.search_bar_regex_placement,
            .case_sensitive => &self.search_bar_case_placement,
            .whole_word => &self.search_bar_word_placement,
            .close => &self.search_bar_close_placement,
        };
    }

    fn searchBarButtonRole(self: *const Surface, hwnd: HWND) ?SearchBarButtonRole {
        for (search_bar_button_roles) |role| {
            if (self.searchBarButtonHwnd(role)) |button_hwnd| {
                if (hwnd == button_hwnd) return role;
            }
        }
        return null;
    }

    fn searchBarButtonActive(self: *const Surface, role: SearchBarButtonRole) bool {
        return switch (role) {
            .regex => self.search_bar.toggles.regex,
            .case_sensitive => self.search_bar.toggles.case_sensitive,
            .whole_word => self.search_bar.toggles.whole_word,
            else => false,
        };
    }

    fn ownsSearchBarControl(self: *const Surface, hwnd: HWND) bool {
        if (self.search_bar_edit_hwnd != null and hwnd == self.search_bar_edit_hwnd.?) return true;
        if (self.search_bar_results_hwnd != null and hwnd == self.search_bar_results_hwnd.?) return true;
        return self.searchBarButtonRole(hwnd) != null;
    }

    fn searchBarButtonPrevProc(self: *const Surface, hwnd: HWND) ?*const anyopaque {
        const role = self.searchBarButtonRole(hwnd) orelse return null;
        return self.search_bar_button_prev_procs[@intFromEnum(role)];
    }

    pub fn init(
        self: *Surface,
        app: *App,
        title: LPCWSTR,
        config: *const configpkg.Config,
        opts: SurfaceInitOptions,
    ) !void {
        log.debug("surface.init begin", .{});
        const host = if (opts.host_id) |host_id|
            app.findHostById(host_id) orelse return error.InvalidHost
        else
            try app.createHost(title, opts.clone_state_from, opts.passive_show);
        self.* = .{
            .app = app,
            .host = host,
            .quick_terminal = opts.quick_terminal,
            .host_id = host.id,
            .host_active = true,
            .window_visible = false,
            .scrollbar_config = config.scrollbar,
            .undo_stack = win32_undo.UndoStack.init(app.core_app.alloc),
            .search_bar = win32_search_bar.SearchBar.init(app.core_app.alloc),
            .drop_target = win32_surface_drop_target.DropTarget.init(
                app.core_app.alloc,
                undefined, // surface_ctx — fixed up below after the address stabilises
                &surfaceDropPayloadCallback,
            ),
        };
        // The DropTarget's surface_ctx must be `self`, but we can't
        // initialise it until `self.*` has been fully assigned above
        // (taking the address of an in-progress struct literal is
        // undefined). Patch it in now, before the HWND is created so
        // the first COM callback has a valid context.
        self.drop_target.surface_ctx = @ptrCast(self);
        self.background_opacity_default = normalizedBackgroundOpacity(config.@"background-opacity");

        const hwnd = CreateWindowExW(
            0,
            class_name,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            surfaceWindowStyle(),
            0,
            0,
            10,
            10,
            host.hwnd,
            null,
            app.hinstance,
            self,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        errdefer _ = DestroyWindow(hwnd);
        self.hwnd = hwnd;

        // Register the OLE drop target so Explorer / browser drops
        // land as typed input in the terminal. Failure is non-fatal:
        // the user loses the feature but the terminal still works.
        // Requires the STA apartment that `App.init` brought up via
        // `CoInitializeEx`.
        self.drop_target.register(hwnd) catch |err| {
            std.log.warn("drop target register failed hwnd={*} err={}", .{ hwnd, err });
        };
        self.drop_target_registered = true;
        // `errdefer` below revokes on failure.  Explicit revoke also
        // happens in `destroyWindow` via the same helper.
        errdefer if (self.drop_target_registered) {
            self.drop_target.revoke(hwnd);
            self.drop_target_registered = false;
        };

        const content_rect: RECT = host.contentRect() catch .{
            .left = 0,
            .top = host_tab_height,
            .right = 1280,
            .bottom = 800 - host_status_height,
        };
        _ = applyChildRect(hwnd, &self.placement, content_rect);
        self.placement.visible = false;
        self.placement.visible_known = true;
        log.debug("surface.init hwnd created", .{});

        const gl = try app.createGLContext(hwnd);
        self.hdc = gl.hdc;
        self.hglrc = gl.hglrc;
        errdefer self.destroyGL();
        log.debug("surface.init gl context created", .{});

        self.size = try app.clientSize(hwnd);
        log.debug("surface.init client size width={} height={}", .{ self.size.width, self.size.height });

        try app.windows.append(app.core_app.alloc, self);
        errdefer app.removeWindow(self);
        log.debug("surface.init appended to app windows", .{});
        try app.core_app.addSurface(self);
        errdefer app.core_app.deleteSurface(self);
        log.debug("surface.init added to core app", .{});

        const prev_active_tab = host.active_tab;
        const prev_tab_count = host.tabs.items.len;
        var split_rollback: ?SplitSurfaceAttachRollback = null;
        defer commitSplitSurfaceAttach(&split_rollback);
        if (opts.tab_id) |tab_id| {
            for (host.tabs.items) |*tab| {
                if (tab.id == tab_id) {
                    const inserted = try SplitTreeSurface.init(app.core_app.alloc, self);
                    defer {
                        var cleanup = inserted;
                        cleanup.deinit();
                    }
                    const focus_handle = tab.findHandle(@constCast(opts.clone_state_from.?)) orelse tab.focused;
                    const next_tree = try tab.tree.split(
                        app.core_app.alloc,
                        focus_handle,
                        opts.split_direction,
                        0.5,
                        &inserted,
                    );
                    const prev_tree = tab.tree;
                    const prev_focused = tab.focused;
                    tab.tree = next_tree;
                    tab.focused = tab.findHandle(self) orelse focus_handle;
                    split_rollback = .{
                        .tab = tab,
                        .tree = prev_tree,
                        .focused = prev_focused,
                    };
                    break;
                }
            } else return error.InvalidTab;
        } else {
            const tab_id = host.nextTabId();
            try host.tabs.append(app.core_app.alloc, try Tab.init(app.core_app.alloc, tab_id, self));
            host.active_tab = host.tabs.items.len - 1;
        }
        // Rollback the tab entry if core_surface.init or later init steps fail.
        // Without this, a zombie tab with a dangling surface pointer would remain
        // in host.tabs, causing use-after-free on subsequent refreshChrome/layout.
        errdefer {
            rollbackFailedSurfaceAttach(
                &host.tabs,
                &host.active_tab,
                prev_active_tab,
                prev_tab_count,
                &split_rollback,
            );
        }

        // Set initial content_scale from host DPI before core init
        self.content_scale = .{
            .x = @as(f32, @floatFromInt(host.current_dpi)) / 96.0,
            .y = @as(f32, @floatFromInt(host.current_dpi)) / 96.0,
        };

        try self.core_surface.init(
            app.core_app.alloc,
            config,
            app.core_app,
            app,
            self,
        );
        self.core_initialized = true;
        self.destroy_on_wm_destroy = true;
        log.debug("surface.init core surface initialized", .{});

        // Same-host tabs/splits must stay hidden through init, but they still
        // need an initial occlusion sync so hidden child GL surfaces stop
        // rendering before activation ordering runs.
        const activate_during_init = shouldShowSurfaceImmediately(opts.host_id);
        self.setVisible(activate_during_init);
        DragAcceptFiles(hwnd, 1);

        if (GetFocus() == hwnd) {
            self.window_focused = true;
        }
        if (self.window_focused) {
            self.focusChanged(true);
        }
        if (activate_during_init) {
            try host.refreshChrome();
            try host.layout();
            try self.requestRepaint();
        }

        if (opts.clone_state_from) |source| {
            if (!shouldApplyInheritedWindowState(self.host_id, source.host_id)) return;
            try self.inheritWindowStateFrom(source);
        }
    }

    pub fn deinit(self: *Surface) void {
        self.destroy();
    }

    pub fn core(self: *Surface) *CoreSurface {
        return &self.core_surface;
    }

    pub fn ref(self: *Surface, alloc: Allocator) !*Surface {
        _ = alloc;
        return self;
    }

    pub fn unref(self: *Surface, alloc: Allocator) void {
        _ = self;
        _ = alloc;
    }

    pub fn eql(a: *const Surface, b: *const Surface) bool {
        return a == b;
    }

    pub fn rtApp(self: *const Surface) *App {
        return self.app;
    }

    pub fn close(self: *const Surface, process_active: bool) void {
        // Core routes `process_active = true` here when
        // `config.confirm-close-surface` is set AND the terminal
        // cursor is not at a shell prompt — see
        // `Surface.needsConfirmQuit()`. Honour it with the non-modal
        // `HostOverlayMode.confirm` overlay: a chrome-themed Accept /
        // Cancel pair, focus trap, Esc cancels, Enter accepts. No
        // pump re-entry (unlike `MessageBoxW`).
        //
        // Cannot be `*const self` in practice: the overlay owns a
        // callback pointer back to this Surface for the accept
        // path, so we need the address. Zig lets us take `@constCast`
        // here — the stored pointer is only dereferenced back on the
        // UI thread, exactly where the core caller already ran.
        if (process_active) {
            const mutable: *Surface = @constCast(self);
            const host = mutable.host orelse {
                // No host = no overlay available = fall back to the
                // direct destroy. Shouldn't happen in practice; the
                // Win32 apprt always attaches a Host before close
                // paths fire.
                if (self.hwnd) |hwnd| _ = DestroyWindow(hwnd);
                return;
            };
            host.showConfirm(
                "Close this terminal?",
                "A process is still running. Closing this surface will terminate it.",
                "Close",
                "Cancel",
                &surfaceConfirmCloseAccept,
                null,
                @ptrCast(mutable),
            ) catch |err| {
                // Cannot bypass the confirmation on overlay setup
                // failure — core asked us to protect a running
                // process, and unilaterally destroying the HWND here
                // would defeat `confirm-close-surface` every time
                // the overlay couldn't render. Leave the surface
                // alive; the user can retry the close action, and
                // if the overlay keeps failing that's a separate
                // (and loud) bug to file.
                std.log.warn("confirm overlay unavailable err={}; declining close to honour confirm-close-surface", .{err});
            };
            return;
        }
        const mutable: *Surface = @constCast(self);
        mutable.invalidateStructuralHistoryForClose();
        if (self.hwnd) |hwnd| _ = DestroyWindow(hwnd);
    }

    pub fn captureUndoClearScreen(self: *Surface) !void {
        try self.captureUndoTerminalState(.clear_screen);
    }

    pub fn captureUndoReset(self: *Surface) !void {
        try self.captureUndoTerminalState(.reset);
    }

    fn invalidateRedoForNewLocalAction(self: *Surface) void {
        if (self.host) |host| host.clearStructuralRedo();
    }

    fn invalidateRedoForUnsupportedStructuralAction(self: *Surface) void {
        self.undo_stack.clearRedo();
        if (self.host) |host| host.clearStructuralRedo();
    }

    fn invalidateRedoForUnsupportedTabStructuralAction(self: *Surface) void {
        const found = self.app.findTabForSurface(self) orelse {
            self.invalidateRedoForUnsupportedStructuralAction();
            return;
        };
        found.tab.clearRedoHistory();
        found.host.clearStructuralRedo();
    }

    fn invalidateStructuralHistoryForClose(self: *Surface) void {
        const found = self.app.findTabForSurface(self) orelse return;
        found.tab.clearRedoHistory();
        if (found.tab.tree.nodes.len == 1) {
            found.host.clearStructuralHistory(.normal);
            return;
        }
        found.host.clearStructuralRedo();
    }

    fn invalidateStructuralHistoryForDestroy(self: *Surface) void {
        const found = self.app.findTabForSurface(self) orelse return;
        found.tab.clearRedoHistoryExcept(self);
        if (found.tab.tree.nodes.len == 1) {
            found.host.clearStructuralHistory(.normal);
            return;
        }
        found.host.clearStructuralRedo();
    }

    fn pushUndoEntryAndInvalidateRedo(
        self: *Surface,
        entry: win32_undo.Entry,
    ) !void {
        // Redo invalidation must happen AFTER the new undo entry is
        // committed. If the push fails, the action is aborted and the
        // existing redo branch must remain reachable.
        try self.undo_stack.push(entry);
        self.invalidateRedoForNewLocalAction();
        self.app.scheduleUndoPruneTimer();
    }

    fn captureUndoTerminalState(self: *Surface, kind: win32_undo.Kind) !void {
        if (self.undo_capture_suspended) return;

        self.undo_stack.discardExpired(self.app.undoCutoffTimestampMs());
        const state_bytes = try self.captureTerminalStateBytes();
        errdefer self.app.core_app.alloc.free(state_bytes);

        var entry: win32_undo.Entry = .{
            .kind = kind,
            .snapshot = switch (kind) {
                .clear_screen => .{ .clear_screen = .{ .state_bytes = state_bytes } },
                .reset => .{ .reset = .{ .state_bytes = state_bytes } },
            },
            .timestamp_ms = GetTickCount64(),
        };
        errdefer entry.deinit(self.app.core_app.alloc);
        try self.pushUndoEntryAndInvalidateRedo(entry);
    }

    fn captureTerminalStateBytes(self: *Surface) ![]u8 {
        self.core_surface.renderer_state.mutex.lock();
        defer self.core_surface.renderer_state.mutex.unlock();
        return try captureTerminalUndoStateBytes(
            self.app.core_app.alloc,
            self.core_surface.renderer_state.terminal,
        );
    }

    fn restoreUndoSnapshot(self: *Surface, entry: *const win32_undo.Entry) void {
        const alloc = self.app.core_app.alloc;
        const state_bytes = switch (entry.snapshot) {
            .clear_screen => |value| value.state_bytes,
            .reset => |value| value.state_bytes,
        };
        var restored: RestoredTerminalUndoState = .{};

        {
            self.core_surface.renderer_state.mutex.lock();
            defer self.core_surface.renderer_state.mutex.unlock();
            restored = restoreTerminalUndoState(
                self.core_surface.renderer_state.terminal,
                state_bytes,
            );
        }

        appendOwnedString(alloc, &self.title, restored.title) catch |err| {
            log.warn("undo snapshot title cache sync failed err={}", .{err});
        };
        appendOwnedString(alloc, &self.pwd, restored.pwd) catch |err| {
            log.warn("undo snapshot pwd cache sync failed err={}", .{err});
        };
        self.setScrollbar(restored.scrollbar) catch |err| {
            log.warn("undo snapshot scrollbar sync failed err={}", .{err});
        };
        self.refreshWindowTitle() catch |err| {
            log.warn("undo snapshot window title refresh failed err={}", .{err});
        };
        self.requestRepaint() catch |err| {
            log.warn("undo snapshot repaint request failed err={}", .{err});
        };
    }

    fn applyLocalUndoEntry(
        self: *Surface,
        entry: *const win32_undo.Entry,
        mode: enum { undo, redo },
    ) ?[]const u8 {
        switch (mode) {
            .undo => {
                self.restoreUndoSnapshot(entry);
                return switch (entry.kind) {
                    .clear_screen => "Clear screen undone.",
                    .reset => "Terminal reset undone.",
                };
            },

            .redo => {
                self.undo_capture_suspended = true;
                defer self.undo_capture_suspended = false;

                if (!self.reapplyUndoableAction(entry.kind)) return null;
                return switch (entry.kind) {
                    .clear_screen => "Clear screen redone.",
                    .reset => "Terminal reset redone.",
                };
            },
        }
    }

    fn reapplyUndoableAction(self: *Surface, kind: win32_undo.Kind) bool {
        switch (kind) {
            .clear_screen => {
                {
                    self.core_surface.renderer_state.mutex.lock();
                    defer self.core_surface.renderer_state.mutex.unlock();
                    if (self.core_surface.io.terminal.screens.active_key == .alternate) return false;
                }
                self.core_surface.io.queueMessage(
                    .{ .clear_screen = .{ .history = true } },
                    .unlocked,
                );
                return true;
            },

            .reset => {
                var scrollbar: terminal.Scrollbar = .zero;
                {
                    self.core_surface.renderer_state.mutex.lock();
                    defer self.core_surface.renderer_state.mutex.unlock();
                    self.core_surface.renderer_state.terminal.fullReset();
                    scrollbar = self.core_surface.renderer_state.terminal.screens.active.pages.scrollbar();
                }

                appendOwnedString(self.app.core_app.alloc, &self.title, null) catch |err| {
                    log.warn("redo reset title cache clear failed err={}", .{err});
                };
                appendOwnedString(self.app.core_app.alloc, &self.pwd, null) catch |err| {
                    log.warn("redo reset pwd cache clear failed err={}", .{err});
                };
                self.setScrollbar(scrollbar) catch |err| {
                    log.warn("redo reset scrollbar sync failed err={}", .{err});
                };
                self.refreshWindowTitle() catch |err| {
                    log.warn("redo reset window title refresh failed err={}", .{err});
                };
                self.requestRepaint() catch |err| {
                    log.warn("redo reset repaint request failed err={}", .{err});
                };
                return true;
            },
        }
    }

    fn canReapplyUndoableAction(self: *Surface, kind: win32_undo.Kind) bool {
        switch (kind) {
            .clear_screen => {
                self.core_surface.renderer_state.mutex.lock();
                defer self.core_surface.renderer_state.mutex.unlock();
                return self.core_surface.io.terminal.screens.active_key != .alternate;
            },
            .reset => return true,
        }
    }

    fn localRedoUnavailableMessage(kind: win32_undo.Kind) []const u8 {
        return switch (kind) {
            .clear_screen => "Redo unavailable in alternate screen.",
            .reset => unreachable,
        };
    }

    fn applyLatestLocalUndo(self: *Surface) !?[]const u8 {
        const entry = (try self.undo_stack.popForUndo()) orelse return null;
        return self.applyLocalUndoEntry(entry, .undo);
    }

    fn applyLatestLocalRedo(self: *Surface) !?[]const u8 {
        const next = self.undo_stack.peekRedo() orelse return null;
        if (!self.canReapplyUndoableAction(next.kind)) return localRedoUnavailableMessage(next.kind);

        const entry = (try self.undo_stack.popForRedo()) orelse return null;
        const kind = entry.kind;
        const message = self.applyLocalUndoEntry(entry, .redo);
        if (message == null) {
            self.undo_stack.restoreLastRedoPop();
            return localRedoUnavailableMessage(kind);
        }
        return message;
    }

    fn present(self: *Surface) void {
        self.app.activateSurface(self);
    }

    fn presentWindow(self: *Surface) void {
        if (self.host) |host| {
            host.present();
            if (self.hwnd) |hwnd| _ = SetFocus(hwnd);
            return;
        }
        const hwnd = self.hwnd orelse return;
        _ = ShowWindow(hwnd, SW_SHOW);
        _ = SetForegroundWindow(hwnd);
        _ = SetFocus(hwnd);
    }

    fn windowHwnd(self: *const Surface) ?HWND {
        if (self.host) |host| return host.hwnd;
        return self.hwnd;
    }

    pub fn getTitle(self: *Surface) ?[:0]const u8 {
        return self.effectiveTitle();
    }

    pub fn getContentScale(self: *const Surface) !apprt.ContentScale {
        return self.content_scale;
    }

    pub fn getSize(self: *const Surface) !apprt.SurfaceSize {
        return try App.resolveSurfaceSizeWithContext(
            self.app,
            self.size,
            self.hwnd,
            App.clientSize,
        );
    }

    pub fn getCursorPos(self: *const Surface) !apprt.CursorPos {
        return self.cursor_pos;
    }

    pub fn supportsClipboard(
        self: *const Surface,
        clipboard_type: apprt.Clipboard,
    ) bool {
        _ = self;
        return clipboard_type == .standard;
    }

    pub fn clipboardRequest(
        self: *Surface,
        clipboard_type: apprt.Clipboard,
        state: apprt.ClipboardRequest,
    ) !bool {
        if (clipboard_type != .standard) return false;

        // `str` is always owned by `core_app.alloc` — either taken
        // from `readClipboardText` (which returns `[:0]u8`) or a
        // fresh `dupeZ("")` fallback for the osc_52_read empty-clipboard
        // case. Single-owner + single defer ensures the fallback
        // allocation is freed too.
        const str: [:0]u8 = (try self.readClipboardText()) orelse switch (state) {
            .paste => return false,
            .osc_52_read => try self.app.core_app.alloc.dupeZ(u8, ""),
            .osc_52_write => unreachable,
        };
        defer self.app.core_app.alloc.free(str);

        self.core_surface.completeClipboardRequest(
            state,
            str,
            false,
        ) catch |err| switch (err) {
            error.UnsafePaste,
            error.UnauthorizedPaste,
            => {
                // Defer to the non-modal confirm overlay; dupes
                // `str` into surface-owned storage so the local
                // `text` lifetime doesn't need to span the async
                // gap. On accept `surfaceConfirmPasteAccept` calls
                // `completeClipboardRequest(state, …, true)`.
                self.requestPasteConfirm(state, str) catch |inner| {
                    std.log.warn("paste confirm dispatch failed err={}", .{inner});
                    return false;
                };
            },

            else => return err,
        };

        return true;
    }

    pub fn setClipboard(
        self: *Surface,
        clipboard_type: apprt.Clipboard,
        contents: []const apprt.ClipboardContent,
        confirm: bool,
    ) !void {
        if (clipboard_type != .standard) return;
        if (confirm) {
            // Non-modal confirm path: dup `contents` into surface-owned
            // storage + show the overlay. On accept
            // `surfaceConfirmWriteAccept` runs the same html-then-
            // plain branch as below; on cancel the dup is freed and
            // no write happens. Fire-and-forget from core's POV.
            self.requestWriteConfirm(clipboard_type, contents) catch |err| {
                std.log.warn("clipboard write confirm dispatch failed err={}", .{err});
            };
            return;
        }

        // Scan for text/html and text/plain. When both are offered
        // (e.g. `copy_to_clipboard = .html` emits both), write them
        // in a single OpenClipboard/EmptyClipboard/Close cycle so
        // consumers that understand CF_HTML (Word, WordPad, OneNote)
        // get the styled fragment and consumers that don't (Notepad,
        // cmd.exe) still get usable plain text.
        var html_content: ?[]const u8 = null;
        var plain_content: ?[]const u8 = null;
        for (contents) |content| {
            if (std.mem.eql(u8, content.mime, "text/html")) {
                html_content = content.data;
            } else if (std.mem.eql(u8, content.mime, "text/plain")) {
                plain_content = content.data;
            }
        }

        if (html_content) |html| {
            try self.writeClipboardHtml(html, plain_content);
            return;
        }
        if (plain_content) |plain| {
            try self.writeClipboardText(plain);
            return;
        }
    }

    pub fn defaultTermioEnv(self: *const Surface) !std.process.EnvMap {
        var env = try internal_os.getEnvMap(self.app.core_app.alloc);
        errdefer env.deinit();

        if (env.get("USERPROFILE") == null) {
            var buf: [std.fs.max_path_bytes]u8 = undefined;
            if (try internal_os.windows.knownFolderPathUtf8(
                &internal_os.windows.FOLDERID_Profile,
                &buf,
            )) |profile| {
                try env.put("USERPROFILE", profile);
            }
        }

        if (env.get("LOCALAPPDATA") == null) {
            var buf: [std.fs.max_path_bytes]u8 = undefined;
            if (try internal_os.windows.knownFolderPathUtf8(
                &internal_os.windows.FOLDERID_LocalAppData,
                &buf,
            )) |local_appdata| {
                try env.put("LOCALAPPDATA", local_appdata);
            }
        }

        return env;
    }

    pub fn redrawInspector(self: *Surface) void {
        if (!self.inspector_visible) return;
        self.requestRepaint() catch |err| {
            log.err("win32 inspector repaint request failed err={}", .{err});
        };
    }

    pub fn beginRendererRepaintRequest(self: *Surface) bool {
        if (!self.renderer_repaint_requested.swap(true, .acq_rel)) return true;
        self.renderer_repaint_retry_pending.store(true, .release);
        return false;
    }

    pub fn cancelRendererRepaintRequest(self: *Surface) void {
        self.renderer_repaint_requested.store(false, .release);
        self.renderer_repaint_retry_pending.store(false, .release);
    }

    fn consumeRendererRepaintRetryPending(self: *Surface) bool {
        return self.renderer_repaint_retry_pending.swap(false, .acq_rel);
    }

    fn shouldDrawRendererPaintContent(self: *Surface) bool {
        return self.renderer_repaint_requested.load(.acquire);
    }

    fn finishRendererRepaintRequest(self: *Surface) void {
        self.renderer_repaint_requested.store(false, .release);
        if (self.consumeRendererRepaintRetryPending()) {
            self.core_surface.renderer_thread.wakeup.notify() catch |err| {
                log.warn("win32 renderer repaint retry wake failed err={}", .{err});
            };
        }
    }

    fn requestRendererFrameNow(self: *Surface) void {
        if (!self.core_initialized) return;
        self.core_surface.renderer_thread.wakeup.notify() catch |err| {
            log.warn("win32 renderer frame wake failed err={}", .{err});
        };
    }

    fn markLiveResizeRepaintDeferred(self: *Surface) void {
        self.live_resize_repaint_deferred = true;
    }

    fn queuePaintRequest(self: *Surface, update_now: bool) !void {
        const hwnd = self.hwnd orelse return error.NoWindow;
        if (self.paint_pending) {
            if (update_now) {
                self.requestRendererFrameNow();
                try self.forcePaintRequestNow();
            }
            return;
        }

        self.paint_pending = true;
        errdefer self.paint_pending = false;

        if (InvalidateRect(hwnd, null, 0) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        if (update_now) _ = UpdateWindow(hwnd);
    }

    fn forcePaintRequestNow(self: *Surface) !void {
        const hwnd = self.hwnd orelse return error.NoWindow;
        self.paint_pending = false;
        const flags: UINT = RDW_INVALIDATE | RDW_INTERNALPAINT | RDW_UPDATENOW;
        if (RedrawWindow(hwnd, null, null, flags) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn flushDeferredLiveResizeRepaint(self: *Surface, repaint_fn: anytype) !bool {
        if (!self.live_resize_repaint_deferred) return false;
        if (self.paint_pending) {
            self.live_resize_repaint_deferred = false;
            return true;
        }

        try repaint_fn(self);
        self.live_resize_repaint_deferred = false;
        return true;
    }

    fn repaintHostedChild(self: *Surface) !void {
        if (self.live_resize_repaint_deferred) {
            _ = try self.flushDeferredLiveResizeRepaint(struct {
                fn repaint(surface: *Surface) !void {
                    try surface.queuePaintRequest(true);
                }
            }.repaint);
            return;
        }

        try self.queuePaintRequest(true);
    }

    fn requestRepaintWithMode(self: *Surface, repaint_mode: SurfaceRepaintRequestMode) !void {
        _ = self.hwnd orelse return;
        if (repaint_mode == .defer_until_flush) {
            self.markLiveResizeRepaintDeferred();
            return;
        }
        self.queuePaintRequest(repaint_mode == .update_now) catch |err| {
            self.cancelRendererRepaintRequest();
            return err;
        };
    }

    pub fn requestRepaint(self: *Surface) !void {
        // During an interactive drag-resize the OS drives WM_SIZE →
        // WM_PAINT on every mouse-delta; stacking additional
        // InvalidateRect calls from the renderer thread just piles
        // pressure onto the pump without producing extra visible
        // frames. Drop the wake and let the WM_SIZE-driven cadence
        // own pacing. WM_EXITSIZEMOVE and layout finish with
        // `InvalidateRect` on the host plus hosted child HWNDs so nothing
        // is permanently lost.
        //
        // Gate on THIS surface's own Host — an App-wide flag would
        // freeze background windows whenever any foreground window
        // enters a drag. Surfaces outside a Host (quick-terminal
        // pre-host-attach, pre-init paint) fall through without
        // gating.
        const repaint_mode = surfaceRepaintRequestMode(self.host);
        try self.requestRepaintWithMode(repaint_mode);
    }

    pub fn redraw(self: *Surface) !void {
        if (!self.core_initialized) return;
        const hwnd = self.hwnd orelse return;
        if (IsWindowVisible(hwnd) == 0) return;
        if (self.size.width == 0 or self.size.height == 0) return;
        if (self.hdc == null or self.hglrc == null) return;
        if (self.draw_in_progress) return;
        self.draw_in_progress = true;
        defer self.draw_in_progress = false;
        try self.makeGLContextCurrent();
        try self.core_surface.draw();
    }

    pub fn makeGLContextCurrent(self: *Surface) !void {
        const hdc = self.hdc orelse return error.NoDeviceContext;
        const hglrc = self.hglrc orelse return error.NoOpenGLContext;

        if (wglGetCurrentContext() == hglrc and wglGetCurrentDC() == hdc) {
            return;
        }

        if (wglMakeCurrent(hdc, hglrc) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    pub fn clearGLContextCurrent(self: *Surface) void {
        const hdc = self.hdc orelse return;
        const hglrc = self.hglrc orelse return;

        if (wglGetCurrentContext() != hglrc or wglGetCurrentDC() != hdc) {
            return;
        }

        _ = wglMakeCurrent(null, null);
    }

    pub fn swapGLBuffers(self: *Surface) !void {
        const hdc = self.hdc orelse return error.NoDeviceContext;
        _ = self.hglrc orelse return error.NoOpenGLContext;

        if (SwapBuffers(hdc) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn setTitle(self: *Surface, title: []const u8) !void {
        if (ownedStringEquals(self.title, title)) return;
        const alloc = self.app.core_app.alloc;
        try appendOwnedString(alloc, &self.title, title);
        try self.refreshWindowTitle();
    }

    fn setTitleOverride(self: *Surface, title: ?[]const u8) !void {
        if (optionalOwnedStringEquals(self.title_override, title)) return;
        const alloc = self.app.core_app.alloc;
        try appendOwnedString(alloc, &self.title_override, title);
        try self.refreshWindowTitle();
    }

    fn setTabTitleOverride(self: *Surface, title: ?[]const u8) !void {
        if (optionalOwnedStringEquals(self.tab_title_override, title)) return;
        const alloc = self.app.core_app.alloc;
        try appendOwnedString(alloc, &self.tab_title_override, title);
        try self.refreshWindowTitle();
    }

    fn effectiveTitle(self: *const Surface) ?[:0]const u8 {
        return resolveWindowBaseTitle(self.title, self.title_override, self.tab_title_override);
    }

    fn promptTitle(self: *Surface, kind: apprt.action.PromptTitle) !void {
        const host = self.host orelse return;
        const mode: HostOverlayMode = switch (kind) {
            .surface => .surface_title,
            .tab => .tab_title,
        };
        if (host.overlay_mode == mode) {
            host.hideOverlay();
            try host.layout();
            return;
        }
        const initial = host.overlayInitialText(mode);
        defer if (initial) |value| self.app.core_app.alloc.free(value);
        host.hideOverlay();
        try host.showOverlay(mode, initial);
    }

    fn toggleCommandPalette(self: *Surface) !bool {
        const host = self.host orelse return false;
        if (host.overlay_mode == .command_palette) {
            host.hideOverlay();
            try host.layout();
            return true;
        }
        host.hideOverlay();
        try host.showOverlay(.command_palette, null);
        return true;
    }

    fn toggleTabOverview(self: *Surface) !bool {
        const host = self.host orelse return false;
        if (host.overlay_mode == .tab_overview) {
            host.hideOverlay();
            try host.layout();
            return true;
        }
        const initial = host.overlayInitialText(.tab_overview);
        defer if (initial) |value| self.app.core_app.alloc.free(value);
        try host.showOverlay(.tab_overview, initial);
        return true;
    }

    fn scrollbarPolicy(self: *const Surface) ScrollbarPolicy {
        return switch (self.scrollbar_config) {
            .never => .never,
            .system => if (isHighContrastActive() or !self.app.system_dynamic_scrollbars)
                .always
            else
                .dynamic,
        };
    }

    fn scrollbarScrollable(self: *const Surface) bool {
        return self.scrollbar.total > self.scrollbar.len and self.scrollbar.len > 0;
    }

    fn scrollbarAnimationsEnabled(self: *const Surface) bool {
        _ = self;
        return Host.clientAnimationsEnabled() and !isHighContrastActive();
    }

    fn scrollbarHoverWidthPx(self: *const Surface) i32 {
        if (self.host) |host| return @max(1, host.scaled(10));
        return @max(1, @as(i32, @intFromFloat(@ceil(
            win32_scrollbar_geometry.track_width_hover_dp * self.content_scale.x,
        ))));
    }

    fn scrollbarMarkerBudgetForHeight(height: i32) usize {
        if (height <= 0) return 0;
        return @min(128, @max(8, @as(usize, @intCast(@max(1, @divTrunc(height, 4))))));
    }

    fn scrollbarChildRect(self: *const Surface, pane_rect: RECT) RECT {
        const width = self.scrollbarHoverWidthPx();
        return childRect(
            pane_rect.right - width,
            pane_rect.top,
            width,
            @max(1, pane_rect.bottom - pane_rect.top),
        );
    }

    fn scrollbarLocalLayout(self: *const Surface) ?win32_scrollbar_geometry.Layout {
        if (!self.scrollbar_placement.rect_known) return null;
        const rect = self.scrollbar_placement.rect;
        const width = @max(1, rect.right - rect.left);
        const height = @max(1, rect.bottom - rect.top);
        const max_top = if (self.scrollbar.total > self.scrollbar.len)
            self.scrollbar.total - self.scrollbar.len
        else
            0;
        return .{
            .pane = .{
                .left = 0,
                .top = 0,
                .right = @floatFromInt(width),
                .bottom = @floatFromInt(height),
            },
            .total_rows = self.scrollbar.total,
            .viewport_rows = self.scrollbar.len,
            .top_row = @min(self.scrollbar.offset, max_top),
            .dpi_scale = if (self.host) |host|
                @as(f32, @floatFromInt(host.current_dpi)) / 96.0
            else
                self.content_scale.x,
            .hovered = self.scrollbar_state.hovered,
            .dragging = self.scrollbar_state.dragging,
        };
    }

    fn scrollbarRectToRect(value: win32_scrollbar_geometry.Rect) RECT {
        const left: i32 = @intFromFloat(@floor(value.left));
        const top: i32 = @intFromFloat(@floor(value.top));
        const right: i32 = @max(left + 1, @as(i32, @intFromFloat(@ceil(value.right))));
        const bottom: i32 = @max(top + 1, @as(i32, @intFromFloat(@ceil(value.bottom))));
        return .{
            .left = left,
            .top = top,
            .right = right,
            .bottom = bottom,
        };
    }

    fn scrollbarPaintKey(self: *const Surface, rect: RECT) ScrollbarPaintKey {
        return .{
            .rect = rect,
            .total = self.scrollbar.total,
            .len = self.scrollbar.len,
            .offset = self.scrollbar.offset,
            .dpi = if (self.host) |host| host.current_dpi else 96,
            .hovered = self.scrollbar_state.hovered,
            .dragging = self.scrollbar_state.dragging,
            .marker_revision = self.scrollbar_marker_revision,
        };
    }

    fn clearScrollbarMarkers(self: *Surface) void {
        if (self.scrollbar_markers.len > 0) {
            self.app.core_app.alloc.free(self.scrollbar_markers);
            self.scrollbar_markers = &.{};
            self.scrollbar_marker_revision +%= 1;
        }
        self.scrollbar_marker_budget = 0;
    }

    fn rebuildScrollbarMarkers(self: *Surface, marker_budget: usize) !void {
        self.clearScrollbarMarkers();
        if (marker_budget == 0 or self.search_match_rows.len == 0 or self.scrollbar.total == 0) return;

        const alloc = self.app.core_app.alloc;
        const rows = try alloc.alloc(usize, self.search_match_rows.len);
        defer alloc.free(rows);
        for (self.search_match_rows, 0..) |row, i| rows[i] = @intCast(row);

        self.scrollbar_markers = try win32_search_bar.downsampleMarkers(
            alloc,
            rows,
            self.scrollbar.total,
            marker_budget,
        );
        self.scrollbar_marker_budget = marker_budget;
        self.scrollbar_marker_revision +%= 1;
    }

    fn ensureScrollbarWindow(self: *Surface) !void {
        if (self.scrollbar_hwnd != null) return;

        const host = self.host orelse return;
        const hwnd = host.hwnd orelse return;
        self.scrollbar_hwnd = CreateWindowExW(
            WS_EX_LAYERED,
            scrollbar_class_name,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD,
            0,
            0,
            self.scrollbarHoverWidthPx(),
            32,
            hwnd,
            null,
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        const scrollbar_hwnd = self.scrollbar_hwnd.?;
        _ = SetWindowLongPtrW(
            scrollbar_hwnd,
            GWLP_USERDATA,
            @as(LONG_PTR, @intCast(@intFromPtr(self))),
        );
        if (SetLayeredWindowAttributes(
            scrollbar_hwnd,
            scrollbar_transparent_key,
            0,
            LWA_ALPHA | LWA_COLORKEY,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn destroyScrollbarWindow(self: *Surface) void {
        if (self.scrollbar_state.dragging) _ = ReleaseCapture();
        self.clearScrollbarMarkers();
        if (self.scrollbar_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        self.scrollbar_hwnd = null;
        self.scrollbar_placement = .{};
        self.scrollbar_leave_armed = false;
        self.scrollbar_leave_hwnd = null;
        self.scrollbar_drag_anchor_offset = 0;
        self.scrollbar_alpha_cache = 0;
        self.scrollbar_paint_cache = null;
        self.scrollbar_state = .{};
    }

    fn invalidateScrollbarWindow(self: *Surface) void {
        if (self.scrollbar_hwnd) |hwnd| _ = InvalidateRect(hwnd, null, 0);
    }

    fn settleReducedScrollbarState(self: *Surface, now_ms: u64) void {
        if (self.scrollbarAnimationsEnabled()) return;
        switch (self.scrollbar_state.visibility) {
            .fading_in, .fading_out => _ = self.scrollbar_state.tick(
                now_ms + win32_scrollbar_geometry.auto_hide_fade_ms,
            ),
            else => {},
        }
    }

    fn noteScrollbarActivity(self: *Surface, now_ms: u64) void {
        if (self.scrollbarPolicy() != .dynamic) return;
        self.scrollbar_state.onScrollActivity(now_ms);
        self.settleReducedScrollbarState(now_ms);
    }

    fn armScrollbarLeaveTracking(self: *Surface, hwnd: HWND) void {
        if (self.scrollbar_leave_armed and self.scrollbar_leave_hwnd == hwnd) return;
        var track: TRACKMOUSEEVENT = .{
            .cbSize = @sizeOf(TRACKMOUSEEVENT),
            .dwFlags = TME_LEAVE,
            .hwndTrack = hwnd,
            .dwHoverTime = 0,
        };
        _ = TrackMouseEvent(&track);
        self.scrollbar_leave_armed = true;
        self.scrollbar_leave_hwnd = hwnd;
    }

    fn updateScrollbarFromLocalCursor(
        self: *Surface,
        tracking_hwnd: ?HWND,
        x: f32,
        y: f32,
        now_ms: u64,
    ) bool {
        const layout = self.scrollbarLocalLayout() orelse return false;
        const over_track = win32_scrollbar_geometry.pointOverTrack(layout, x, y);

        if (tracking_hwnd) |value| self.armScrollbarLeaveTracking(value);
        self.setScrollbarHovered(over_track, now_ms);

        if (self.scrollbar_state.dragging) {
            self.noteScrollbarActivity(now_ms);
            self.scrollbarScrollToRow(win32_scrollbar_geometry.rowFromCursor(
                layout,
                y,
                self.scrollbar_drag_anchor_offset,
            )) catch |err| {
                log.warn("win32 scrollbar drag failed err={}", .{err});
            };
        }
        return over_track;
    }

    fn handleScrollbarMouseMoveLocal(self: *Surface, tracking_hwnd: HWND, x: f32, y: f32) void {
        const now_ms = GetTickCount64();
        _ = self.updateScrollbarFromLocalCursor(tracking_hwnd, x, y, now_ms);
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar move failed err={}", .{err});
        };
    }

    fn handleScrollbarLeftButtonDownLocal(self: *Surface, hwnd: HWND, x: f32, y: f32) void {
        const layout = self.scrollbarLocalLayout() orelse return;
        const now_ms = GetTickCount64();
        const thumb = win32_scrollbar_geometry.thumbRect(layout);
        self.setScrollbarHovered(true, now_ms);
        self.setScrollbarDragging(true, now_ms);
        self.noteScrollbarActivity(now_ms);
        self.scrollbar_drag_anchor_offset = if (win32_scrollbar_geometry.pointOverThumb(layout, x, y))
            std.math.clamp(y - thumb.top, 0.0, thumb.bottom - thumb.top)
        else
            @max(0.0, (thumb.bottom - thumb.top) / 2.0);
        _ = SetCapture(hwnd);
        self.scrollbarScrollToRow(win32_scrollbar_geometry.rowFromCursor(
            layout,
            y,
            self.scrollbar_drag_anchor_offset,
        )) catch |err| {
            log.warn("win32 scrollbar click failed err={}", .{err});
        };
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar press failed err={}", .{err});
        };
    }

    fn handleScrollbarLeftButtonUpLocal(self: *Surface, x: f32, y: f32) void {
        const now_ms = GetTickCount64();
        const layout = self.scrollbarLocalLayout();
        _ = ReleaseCapture();
        self.setScrollbarDragging(false, now_ms);
        if (layout) |value| {
            self.setScrollbarHovered(
                win32_scrollbar_geometry.pointOverTrack(value, x, y),
                now_ms,
            );
        } else {
            self.setScrollbarHovered(false, now_ms);
        }
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar release failed err={}", .{err});
        };
    }

    fn setScrollbarHovered(self: *Surface, hovered: bool, now_ms: u64) void {
        if (self.scrollbar_state.hovered == hovered) return;
        self.scrollbar_state.setHovered(hovered, now_ms);
        self.settleReducedScrollbarState(now_ms);
    }

    fn setScrollbarDragging(self: *Surface, dragging: bool, now_ms: u64) void {
        if (self.scrollbar_state.dragging == dragging) return;
        self.scrollbar_state.setDragging(dragging, now_ms);
        self.settleReducedScrollbarState(now_ms);
    }

    fn syncScrollbarWindowNow(self: *Surface, now_ms: u64) !void {
        const host = self.host orelse return;
        const was_needing_heartbeat = self.scrollbarNeedsHeartbeat();
        const policy = self.scrollbarPolicy();
        const should_exist = self.window_visible and self.scrollbarScrollable() and
            self.placement.rect_known and self.placement.visible;

        if (!should_exist or policy == .never) {
            if (self.scrollbar_state.dragging) _ = ReleaseCapture();
            self.setScrollbarHovered(false, now_ms);
            self.setScrollbarDragging(false, now_ms);
            self.scrollbar_state.visibility = .hidden;
            self.scrollbar_alpha_cache = 0;
            self.scrollbar_paint_cache = null;
            if (self.scrollbar_hwnd) |hwnd| {
                _ = applyChildVisibility(hwnd, &self.scrollbar_placement, false);
            }
            if (was_needing_heartbeat != self.scrollbarNeedsHeartbeat()) {
                host.refreshScrollbarTimerState();
            }
            return;
        }

        try self.ensureScrollbarWindow();
        const scrollbar_hwnd = self.scrollbar_hwnd.?;
        const child_rect = self.scrollbarChildRect(self.placement.rect);
        _ = applyChildRect(scrollbar_hwnd, &self.scrollbar_placement, child_rect);
        _ = applyChildVisibility(scrollbar_hwnd, &self.scrollbar_placement, true);

        const marker_budget = scrollbarMarkerBudgetForHeight(child_rect.bottom - child_rect.top);
        if (marker_budget != self.scrollbar_marker_budget) {
            try self.rebuildScrollbarMarkers(marker_budget);
        }

        switch (policy) {
            .always => {
                self.scrollbar_state.visibility = .visible;
                self.scrollbar_state.last_activity_ms = now_ms;
                self.scrollbar_state.fade_started_ms = now_ms;
            },
            .dynamic => self.settleReducedScrollbarState(now_ms),
            .never => unreachable,
        }

        const alpha: BYTE = switch (policy) {
            .never => 0,
            .always => 255,
            .dynamic => alphaByteForOpacity(if (self.scrollbarAnimationsEnabled())
                @as(f64, @floatCast(self.scrollbar_state.alpha(now_ms)))
            else if (self.scrollbar_state.visibility == .hidden)
                @as(f64, @floatFromInt(hiddenScrollbarAlphaByte())) / 255.0
            else
                1),
        };
        const paint_key = self.scrollbarPaintKey(child_rect);
        const paint_changed = scrollbarPaintKeyChanged(self.scrollbar_paint_cache, paint_key);
        if (alpha != self.scrollbar_alpha_cache) {
            if (SetLayeredWindowAttributes(
                scrollbar_hwnd,
                scrollbar_transparent_key,
                alpha,
                LWA_ALPHA | LWA_COLORKEY,
            ) == 0) {
                return windows.unexpectedError(windows.kernel32.GetLastError());
            }
            self.scrollbar_alpha_cache = alpha;
        }

        if (paint_changed) {
            self.scrollbar_paint_cache = paint_key;
            self.invalidateScrollbarWindow();
        }
        if (was_needing_heartbeat != self.scrollbarNeedsHeartbeat()) {
            host.refreshScrollbarTimerState();
        }
    }

    fn refreshScrollbarWindow(self: *Surface) !void {
        try self.syncScrollbarWindowNow(GetTickCount64());
    }

    fn scrollbarNeedsHeartbeat(self: *const Surface) bool {
        return scrollbarNeedsHeartbeatForState(
            self.scrollbarPolicy(),
            self.window_visible,
            self.scrollbarScrollable(),
            self.scrollbar_state.visibility,
        );
    }

    fn tickScrollbar(self: *Surface, now_ms: u64) void {
        const prev_hovered = self.scrollbar_state.hovered;
        const prev_dragging = self.scrollbar_state.dragging;
        const prev_visibility = self.scrollbar_state.visibility;
        var over_scrollbar = false;
        if (self.hwnd) |hwnd| {
            over_scrollbar = self.updateScrollbarHoverFromScreenCursor(hwnd, now_ms);
        }
        if (self.scrollbarPolicy() == .dynamic and self.scrollbarScrollable()) {
            _ = self.scrollbar_state.tick(now_ms);
            self.settleReducedScrollbarState(now_ms);
        }
        if (!over_scrollbar and
            self.scrollbar_state.hovered == prev_hovered and
            self.scrollbar_state.dragging == prev_dragging and
            self.scrollbar_state.visibility == prev_visibility and
            self.scrollbar_state.visibility == .hidden)
        {
            return;
        }
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar tick failed err={}", .{err});
        };
    }

    fn scrollbarScrollToRow(self: *Surface, row: usize) !void {
        if (!self.core_initialized) return;
        self.app.activateSurfaceNoFocus(self);
        _ = try self.core_surface.performBindingAction(.{ .scroll_to_row = row });
    }

    fn handleScrollbarMouseMove(self: *Surface, hwnd: HWND, lParam: LPARAM) void {
        const x: f32 = @floatFromInt(signedLowWord(lParamBits(lParam)));
        const y: f32 = @floatFromInt(signedHighWord(lParamBits(lParam)));
        self.handleScrollbarMouseMoveLocal(hwnd, x, y);
    }

    fn handleScrollbarMouseLeave(self: *Surface) void {
        self.scrollbar_leave_armed = false;
        self.scrollbar_leave_hwnd = null;
        if (self.scrollbar_state.dragging) return;
        const now_ms = GetTickCount64();
        self.setScrollbarHovered(false, now_ms);
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar leave failed err={}", .{err});
        };
    }

    fn handleScrollbarLeftButtonDown(self: *Surface, hwnd: HWND, lParam: LPARAM) void {
        const x: f32 = @floatFromInt(signedLowWord(lParamBits(lParam)));
        const y: f32 = @floatFromInt(signedHighWord(lParamBits(lParam)));
        self.handleScrollbarLeftButtonDownLocal(hwnd, x, y);
    }

    fn handleScrollbarLeftButtonUp(self: *Surface, lParam: LPARAM) void {
        const x: f32 = @floatFromInt(signedLowWord(lParamBits(lParam)));
        const y: f32 = @floatFromInt(signedHighWord(lParamBits(lParam)));
        self.handleScrollbarLeftButtonUpLocal(x, y);
    }

    fn scrollbarProxyPointFromScreenCursor(self: *const Surface, hwnd: HWND) ?ScrollbarProxyPoint {
        if (!self.window_visible or !self.scrollbarScrollable()) return null;
        if (self.scrollbarPolicy() == .never or !self.placement.rect_known) return null;

        var point: POINT = .{ .x = 0, .y = 0 };
        if (GetCursorPos(&point) == 0) return null;
        if (ScreenToClient(hwnd, &point) == 0) return null;

        return scrollbarProxyPointFromSurfaceCoords(
            self.placement.rect,
            self.scrollbarHoverWidthPx(),
            point.x,
            point.y,
        );
    }

    fn updateScrollbarHoverFromScreenCursor(self: *Surface, hwnd: HWND, now_ms: u64) bool {
        const proxy = self.scrollbarProxyPointFromScreenCursor(hwnd) orelse {
            if (self.scrollbar_state.hovered and !self.scrollbar_state.dragging) {
                self.setScrollbarHovered(false, now_ms);
            }
            return false;
        };

        if (proxy.over_band or self.scrollbar_state.dragging) {
            return self.updateScrollbarFromLocalCursor(
                null,
                proxy.local_x,
                proxy.local_y,
                now_ms,
            );
        }

        if (self.scrollbar_state.hovered) {
            self.setScrollbarHovered(false, now_ms);
        }
        return false;
    }

    fn handleScrollbarProxyMouseMove(self: *Surface, hwnd: HWND, lParam: LPARAM) bool {
        if (!self.window_visible or !self.scrollbarScrollable()) return false;
        if (self.scrollbarPolicy() == .never or !self.placement.rect_known) return false;

        const proxy = scrollbarProxyPointFromSurfaceCursor(
            self.placement.rect,
            self.scrollbarHoverWidthPx(),
            lParam,
        );
        if (proxy.over_band or self.scrollbar_state.dragging) {
            self.handleScrollbarMouseMoveLocal(hwnd, proxy.local_x, proxy.local_y);
            return true;
        }

        if (self.scrollbar_state.hovered) {
            const now_ms = GetTickCount64();
            self.setScrollbarHovered(false, now_ms);
            self.syncScrollbarWindowNow(now_ms) catch |err| {
                log.warn("win32 scrollbar proxy leave failed err={}", .{err});
            };
        }
        return false;
    }

    fn handleScrollbarProxyButton(self: *Surface, hwnd: HWND, msg: UINT, lParam: LPARAM) bool {
        if (!self.window_visible or !self.scrollbarScrollable()) return false;
        if (self.scrollbarPolicy() == .never or !self.placement.rect_known) return false;

        const proxy = scrollbarProxyPointFromSurfaceCursor(
            self.placement.rect,
            self.scrollbarHoverWidthPx(),
            lParam,
        );
        return switch (msg) {
            WM_LBUTTONDOWN => blk: {
                if (!proxy.over_band) break :blk false;
                self.handleScrollbarLeftButtonDownLocal(hwnd, proxy.local_x, proxy.local_y);
                break :blk true;
            },
            WM_LBUTTONUP => blk: {
                if (!self.scrollbar_state.dragging and !proxy.over_band) break :blk false;
                self.handleScrollbarLeftButtonUpLocal(proxy.local_x, proxy.local_y);
                break :blk true;
            },
            else => false,
        };
    }

    fn handleScrollbarCaptureChanged(self: *Surface) void {
        if (!self.scrollbar_state.dragging) return;
        const now_ms = GetTickCount64();
        self.setScrollbarDragging(false, now_ms);
        self.syncScrollbarWindowNow(now_ms) catch |err| {
            log.warn("win32 scrollbar capture reset failed err={}", .{err});
        };
    }

    fn paintScrollbar(self: *Surface) void {
        const hwnd = self.scrollbar_hwnd orelse return;
        var ps: PAINTSTRUCT = undefined;
        const hdc = BeginPaint(hwnd, &ps) orelse return;
        defer _ = EndPaint(hwnd, &ps);

        var client_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) return;
        fillSolidRect(hdc, client_rect, scrollbar_transparent_key);
        if (!self.scrollbarScrollable()) return;

        const layout = self.scrollbarLocalLayout() orelse return;
        const theme = &self.app.resolved_theme;
        const is_hc = isHighContrastActive();
        const track = scrollbarRectToRect(win32_scrollbar_geometry.trackRect(layout));
        const thumb = scrollbarRectToRect(win32_scrollbar_geometry.thumbRect(layout));
        const track_bg = if (is_hc)
            theme.chrome_border
        else if (theme.is_dark)
            blendColorRGB(theme.chrome_bg, theme.chrome_border, 0.65)
        else
            blendColorRGB(theme.chrome_bg, theme.chrome_border, 0.35);
        const track_border = if (is_hc)
            theme.text_primary
        else if (theme.is_dark)
            adjustColor(track_bg, 20, 20, 24)
        else
            adjustColor(track_bg, -18, -18, -18);
        const thumb_bg = if (is_hc)
            theme.text_primary
        else if (self.scrollbar_state.dragging)
            theme.accent_hover
        else if (self.scrollbar_state.hovered)
            theme.accent
        else
            blendColorRGB(theme.text_secondary, theme.chrome_border, if (theme.is_dark) 0.30 else 0.45);
        const thumb_border = if (is_hc)
            theme.chrome_border
        else if (self.scrollbar_state.dragging or self.scrollbar_state.hovered)
            theme.accent_hover
        else if (theme.is_dark)
            adjustColor(thumb_bg, 16, 16, 18)
        else
            adjustColor(thumb_bg, -16, -16, -16);
        const marker_color = if (is_hc) theme.accent else blendColorRGB(theme.accent, thumb_bg, 0.20);
        const radius = if (is_hc) 0 else @max(2, @min(track.right - track.left, track.bottom - track.top));

        drawRoundedRect(hdc, track, track_bg, track_border, radius);

        const track_height = @max(1, track.bottom - track.top);
        const marker_height: i32 = if (is_hc) 3 else 2;
        const marker_left = track.left + 1;
        const marker_right = @max(marker_left + 1, track.right - 1);
        for (self.scrollbar_markers) |value| {
            const top = track.top + @as(i32, @intFromFloat(@round(
                value * @as(f32, @floatFromInt(@max(0, track_height - marker_height))),
            )));
            fillSolidRect(hdc, .{
                .left = marker_left,
                .top = top,
                .right = marker_right,
                .bottom = top + marker_height,
            }, marker_color);
        }

        drawRoundedRect(hdc, thumb, thumb_bg, thumb_border, radius);
    }

    fn searchQueryOptions(self: *const Surface) terminal.search.QueryOptions {
        return .{
            .regex = self.search_bar.toggles.regex,
            .case_sensitive = self.search_bar.toggles.case_sensitive,
            .whole_word = self.search_bar.toggles.whole_word,
        };
    }

    fn applySearchBarFont(self: *Surface, font: ?*anyopaque) void {
        const value = if (font) |f| @intFromPtr(f) else 0;
        if (self.search_bar_edit_hwnd) |hwnd| _ = SendMessageW(hwnd, WM_SETFONT, value, 1);
        for (search_bar_button_roles) |role| {
            if (self.searchBarButtonHwnd(role)) |hwnd| _ = SendMessageW(hwnd, WM_SETFONT, value, 1);
        }
        if (self.search_bar_results_hwnd) |hwnd| _ = SendMessageW(hwnd, WM_SETFONT, value, 1);
    }

    fn invalidateSearchButtons(self: *Surface) void {
        for (search_bar_button_roles) |role| {
            if (self.searchBarButtonHwnd(role)) |hwnd| _ = InvalidateRect(hwnd, null, 0);
        }
    }

    fn invalidateSearchBarChildPaint(self: *Surface) void {
        if (!self.search_bar_frame_visible) return;
        const handles = [_]?HWND{
            self.search_bar_bg_hwnd,
            self.search_bar_edit_hwnd,
            self.search_bar_prev_hwnd,
            self.search_bar_next_hwnd,
            self.search_bar_regex_hwnd,
            self.search_bar_case_hwnd,
            self.search_bar_word_hwnd,
            self.search_bar_close_hwnd,
            self.search_bar_results_hwnd,
        };
        for (handles) |maybe_hwnd| {
            if (maybe_hwnd) |hwnd| _ = InvalidateRect(hwnd, null, 0);
        }
    }

    fn invalidateSearchBarFrameRect(self: *Surface, rect: RECT) void {
        if (rect.right <= rect.left or rect.bottom <= rect.top) return;
        const host = self.host orelse return;
        const hwnd = host.hwnd orelse return;
        _ = InvalidateRect(hwnd, &rect, 0);
    }

    fn invalidateSearchBarFrame(self: *Surface) void {
        if (!self.search_bar_frame_visible) return;
        self.invalidateSearchBarFrameRect(self.search_bar_frame_rect);
    }

    fn updateSearchBarFrameRect(self: *Surface, frame_rect: RECT) void {
        const was_visible = self.search_bar_frame_visible;
        const old_rect = self.search_bar_frame_rect;
        self.search_bar_frame_rect = frame_rect;
        self.search_bar_frame_visible = true;
        if (!was_visible or !rectEquals(old_rect, frame_rect)) {
            if (was_visible) self.invalidateSearchBarFrameRect(old_rect);
            self.invalidateSearchBarFrameRect(frame_rect);
        }
    }

    fn invalidateSearchBarLayoutCache(self: *Surface) void {
        self.invalidateSearchBarFrame();
        self.search_bar_bg_placement.rect_known = false;
        self.search_bar_edit_placement.rect_known = false;
        self.search_bar_prev_placement.rect_known = false;
        self.search_bar_next_placement.rect_known = false;
        self.search_bar_regex_placement.rect_known = false;
        self.search_bar_case_placement.rect_known = false;
        self.search_bar_word_placement.rect_known = false;
        self.search_bar_close_placement.rect_known = false;
        self.search_bar_results_placement.rect_known = false;
        self.search_bar_frame_visible = false;
        self.search_bar_frame_rect = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 };
    }

    fn hideSearchBarControls(self: *Surface) bool {
        var changed = false;
        if (self.search_bar_frame_visible) {
            self.invalidateSearchBarFrame();
            changed = true;
        }
        if (self.search_bar_bg_hwnd) |hwnd| {
            changed = applyChildVisibility(hwnd, &self.search_bar_bg_placement, false) or changed;
        }
        if (self.search_bar_edit_hwnd) |hwnd| {
            changed = applyChildVisibility(hwnd, &self.search_bar_edit_placement, false) or changed;
        }
        for (search_bar_button_roles) |role| {
            if (self.searchBarButtonHwnd(role)) |hwnd| {
                changed = applyChildVisibility(hwnd, self.searchBarButtonPlacement(role), false) or changed;
            }
        }
        if (self.search_bar_results_hwnd) |hwnd| {
            changed = applyChildVisibility(hwnd, &self.search_bar_results_placement, false) or changed;
        }
        self.search_bar_frame_visible = false;
        self.search_bar_frame_rect = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 };
        return changed;
    }

    fn createSearchBarButton(self: *Surface, host: *Host, parent: HWND, role: SearchBarButtonRole) !HWND {
        const hwnd = CreateWindowExW(
            0,
            prompt_button_class,
            searchBarButtonLabel(role),
            WS_CHILD | WS_TABSTOP | BS_OWNERDRAW,
            0,
            0,
            28,
            host_search_bar_height - 10,
            parent,
            @ptrFromInt(searchBarButtonCommandId(role)),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());
        host.subclassButton(
            hwnd,
            &hostButtonProc,
            &self.search_bar_button_prev_procs[@intFromEnum(role)],
        );
        return hwnd;
    }

    fn ensureSearchBarControls(self: *Surface) !void {
        if (self.search_bar_edit_hwnd != null) return;

        const host = self.host orelse return;
        const hwnd = host.hwnd orelse return;

        self.search_bar_bg_hwnd = CreateWindowExW(
            0,
            prompt_label_class,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD | WS_CLIPSIBLINGS | SS_OWNERDRAW,
            0,
            0,
            160,
            host_search_bar_height,
            hwnd,
            @ptrFromInt(SEARCH_BG_ID),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        self.search_bar_edit_hwnd = CreateWindowExW(
            0,
            prompt_edit_class,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD | WS_TABSTOP | ES_AUTOHSCROLL,
            0,
            0,
            160,
            host_search_bar_height - 10,
            hwnd,
            @ptrFromInt(SEARCH_EDIT_ID),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        const edit_hwnd = self.search_bar_edit_hwnd.?;
        _ = SetWindowLongPtrW(
            edit_hwnd,
            GWLP_USERDATA,
            @as(LONG_PTR, @intCast(@intFromPtr(host))),
        );
        const edit_prev = SetWindowLongPtrW(
            edit_hwnd,
            GWLP_WNDPROC,
            @as(LONG_PTR, @intCast(@intFromPtr(&searchEditProc))),
        );
        self.search_bar_edit_prev_proc = if (edit_prev == 0)
            null
        else
            @ptrFromInt(@as(usize, @intCast(edit_prev)));
        const edit_margin = @as(u16, @intCast(@max(host.scaled(10), 6)));
        const packed_margins: isize = @intCast(@as(usize, edit_margin) | (@as(usize, edit_margin) << 16));
        _ = SendMessageW(
            edit_hwnd,
            EM_SETMARGINS,
            EC_LEFTMARGIN | EC_RIGHTMARGIN,
            packed_margins,
        );
        _ = SendMessageW(edit_hwnd, EM_SETCUEBANNER, 0, @as(LPARAM, @intCast(@intFromPtr(search_edit_cue.ptr))));

        self.search_bar_prev_hwnd = try self.createSearchBarButton(host, hwnd, .prev);
        self.search_bar_next_hwnd = try self.createSearchBarButton(host, hwnd, .next);
        self.search_bar_regex_hwnd = try self.createSearchBarButton(host, hwnd, .regex);
        self.search_bar_case_hwnd = try self.createSearchBarButton(host, hwnd, .case_sensitive);
        self.search_bar_word_hwnd = try self.createSearchBarButton(host, hwnd, .whole_word);
        self.search_bar_close_hwnd = try self.createSearchBarButton(host, hwnd, .close);

        self.search_bar_results_hwnd = CreateWindowExW(
            0,
            prompt_label_class,
            std.unicode.utf8ToUtf16LeStringLiteral(""),
            WS_CHILD | SS_RIGHT | SS_CENTERIMAGE,
            0,
            0,
            96,
            18,
            hwnd,
            @ptrFromInt(SEARCH_RESULTS_ID),
            self.app.hinstance,
            null,
        ) orelse return windows.unexpectedError(windows.kernel32.GetLastError());

        self.applySearchBarFont(host.chrome_font);
        _ = try self.syncSearchBarResultsText();
        _ = self.hideSearchBarControls();
    }

    fn destroySearchBarControls(self: *Surface) void {
        const alloc = self.app.core_app.alloc;
        if (self.search_bar_results_cache) |value| {
            alloc.free(value);
            self.search_bar_results_cache = null;
        }
        if (self.search_bar_results_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_close_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_word_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_case_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_regex_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_next_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_prev_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_edit_hwnd) |hwnd| _ = DestroyWindow(hwnd);
        if (self.search_bar_bg_hwnd) |hwnd| _ = DestroyWindow(hwnd);

        self.search_bar_results_hwnd = null;
        self.search_bar_close_hwnd = null;
        self.search_bar_word_hwnd = null;
        self.search_bar_case_hwnd = null;
        self.search_bar_regex_hwnd = null;
        self.search_bar_next_hwnd = null;
        self.search_bar_prev_hwnd = null;
        self.search_bar_edit_hwnd = null;
        self.search_bar_bg_hwnd = null;
        self.search_bar_edit_prev_proc = null;
        self.search_bar_button_prev_procs = [_]?*const anyopaque{null} ** 6;
        self.search_bar_bg_placement = .{};
        self.search_bar_edit_placement = .{};
        self.search_bar_prev_placement = .{};
        self.search_bar_next_placement = .{};
        self.search_bar_regex_placement = .{};
        self.search_bar_case_placement = .{};
        self.search_bar_word_placement = .{};
        self.search_bar_close_placement = .{};
        self.search_bar_results_placement = .{};
        self.search_bar_frame_visible = false;
        self.search_bar_frame_rect = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 };
    }

    fn layoutSearchBarControls(self: *Surface, frame_rect: RECT, visible: bool) !bool {
        if (!visible or !self.search_bar.visible) return self.hideSearchBarControls();

        try self.ensureSearchBarControls();
        const host = self.host orelse return false;

        var changed = false;
        var bg_changed = false;
        const layout = searchBarChromeLayout(host, frame_rect);
        const control_top = frame_rect.top + layout.pad_y;
        const left = frame_rect.left + layout.pad_x;
        var right = frame_rect.right - layout.pad_x;

        self.updateSearchBarFrameRect(frame_rect);
        bg_changed = applyChildRect(
            self.search_bar_bg_hwnd.?,
            &self.search_bar_bg_placement,
            frame_rect,
        );
        changed = bg_changed or changed;

        changed = applyChildRect(
            self.search_bar_close_hwnd.?,
            &self.search_bar_close_placement,
            childRect(right - layout.close_w, control_top, layout.close_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_close_hwnd.?,
            &self.search_bar_close_placement,
            true,
        ) or changed;
        right -= layout.close_w + layout.close_gap;

        changed = applyChildRect(
            self.search_bar_word_hwnd.?,
            &self.search_bar_word_placement,
            childRect(right - layout.toggle_w, control_top, layout.toggle_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_word_hwnd.?,
            &self.search_bar_word_placement,
            true,
        ) or changed;
        right -= layout.toggle_w + layout.gap;

        changed = applyChildRect(
            self.search_bar_case_hwnd.?,
            &self.search_bar_case_placement,
            childRect(right - layout.toggle_w, control_top, layout.toggle_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_case_hwnd.?,
            &self.search_bar_case_placement,
            true,
        ) or changed;
        right -= layout.toggle_w + layout.gap;

        changed = applyChildRect(
            self.search_bar_regex_hwnd.?,
            &self.search_bar_regex_placement,
            childRect(right - layout.toggle_w, control_top, layout.toggle_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_regex_hwnd.?,
            &self.search_bar_regex_placement,
            true,
        ) or changed;
        right -= layout.toggle_w + layout.section_gap;

        changed = applyChildRect(
            self.search_bar_next_hwnd.?,
            &self.search_bar_next_placement,
            childRect(right - layout.nav_w, control_top, layout.nav_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_next_hwnd.?,
            &self.search_bar_next_placement,
            true,
        ) or changed;
        right -= layout.nav_w + layout.gap;

        changed = applyChildRect(
            self.search_bar_prev_hwnd.?,
            &self.search_bar_prev_placement,
            childRect(right - layout.nav_w, control_top, layout.nav_w, layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_prev_hwnd.?,
            &self.search_bar_prev_placement,
            true,
        ) or changed;
        right -= layout.nav_w + layout.section_gap;

        const show_results = showSearchBarResults(&self.search_bar) and
            (right - layout.results_w - layout.section_gap - left) >= layout.min_edit_w;
        if (show_results) {
            changed = applyChildRect(
                self.search_bar_results_hwnd.?,
                &self.search_bar_results_placement,
                childRect(right - layout.results_w, control_top, layout.results_w, layout.control_h),
            ) or changed;
            changed = applyChildVisibility(
                self.search_bar_results_hwnd.?,
                &self.search_bar_results_placement,
                true,
            ) or changed;
            right -= layout.results_w + layout.section_gap;
        } else {
            changed = applyChildVisibility(
                self.search_bar_results_hwnd.?,
                &self.search_bar_results_placement,
                false,
            ) or changed;
        }

        changed = applyChildRect(
            self.search_bar_edit_hwnd.?,
            &self.search_bar_edit_placement,
            childRect(left, control_top, @max(1, right - left), layout.control_h),
        ) or changed;
        changed = applyChildVisibility(
            self.search_bar_edit_hwnd.?,
            &self.search_bar_edit_placement,
            true,
        ) or changed;
        const bg_visibility_changed = applyChildVisibility(
            self.search_bar_bg_hwnd.?,
            &self.search_bar_bg_placement,
            true,
        );
        changed = bg_visibility_changed or changed;
        if (changed) {
            if (self.search_bar_bg_hwnd) |bg_hwnd| _ = InvalidateRect(bg_hwnd, null, 0);
        }

        return changed;
    }

    fn setSearchBarEditText(self: *Surface, value: []const u8) !bool {
        const edit_hwnd = self.search_bar_edit_hwnd orelse return false;
        const host = self.host orelse return false;
        host.suppress_edit_events = true;
        defer host.suppress_edit_events = false;

        const value_w = try std.unicode.utf8ToUtf16LeAllocZ(self.app.core_app.alloc, value);
        defer self.app.core_app.alloc.free(value_w);
        _ = SetWindowTextW(edit_hwnd, value_w.ptr);
        return true;
    }

    fn readSearchBarEditText(self: *Surface) ![:0]u8 {
        const edit_hwnd = self.search_bar_edit_hwnd orelse return try self.app.core_app.alloc.dupeZ(u8, "");
        return try readWindowTextUtf8Alloc(self.app.core_app.alloc, edit_hwnd);
    }

    fn syncSearchBarResultsText(self: *Surface) !bool {
        const hwnd = self.search_bar_results_hwnd orelse return false;
        const alloc = self.app.core_app.alloc;
        const text = try buildSearchBarResultsText(alloc, &self.search_bar);
        defer alloc.free(text);
        return try syncWindowTextUtf8Cached(
            alloc,
            hwnd,
            &self.search_bar_results_cache,
            text,
        );
    }

    fn issueSearchNow(self: *Surface, force: bool) !bool {
        if (self.search_bar.query.len == 0) return false;
        if (!force and !self.search_bar.forceSearch()) return false;
        if (force) {
            self.search_bar.searched = true;
            self.search_bar.last_edit_ms = 0;
        }
        try self.setSearchActive(true, self.search_bar.query);
        _ = try self.core_surface.setSearchQuery(self.search_bar.query, self.searchQueryOptions());
        _ = try self.syncSearchBarResultsText();
        if (self.host) |host| {
            host.refreshSearchTimerState();
        }
        return true;
    }

    fn runPendingSearchNow(self: *Surface) !bool {
        return try self.issueSearchNow(false);
    }

    fn rerunSearchNow(self: *Surface) !bool {
        return try self.issueSearchNow(true);
    }

    fn handleSearchBarEditChanged(self: *Surface) !bool {
        const alloc = self.app.core_app.alloc;
        const text = try self.readSearchBarEditText();
        defer alloc.free(text);

        const previous_query_len = self.search_bar.query.len;
        const needs_layout = searchBarNeedsRelayoutForQueryChange(
            previous_query_len,
            text.len,
        );
        const invalidate_core_search = searchBarShouldInvalidateCoreSearchOnEdit(
            previous_query_len,
            text.len,
        );
        try self.search_bar.setQuery(text, @intCast(GetTickCount64()));
        if (invalidate_core_search) {
            if (text.len == 0) {
                _ = try self.core_surface.setSearchQuery("", self.searchQueryOptions());
            } else {
                _ = try self.core_surface.invalidateSearchResults();
            }
        }
        try self.setSearchActive(text.len > 0, text);
        if (self.host) |host| {
            if (needs_layout) try host.layout();
            host.refreshSearchTimerState();
        }
        return true;
    }

    fn navigateDockedSearch(self: *Surface, dir: input.Binding.Action.NavigateSearch) !bool {
        if (self.search_bar.query.len == 0) return false;

        const same_query = if (self.search_needle) |needle|
            std.mem.eql(u8, needle, self.search_bar.query)
        else
            false;
        if (!self.search_active or !same_query or !self.search_bar.searched) {
            return try self.rerunSearchNow();
        }

        _ = try self.core_surface.performBindingAction(.{ .navigate_search = dir });
        self.search_selected_raw = advanceSearchSelectedRaw(
            self.search_selected_raw,
            self.search_total,
            dir,
            self.search_bar.toggles.wrap,
        );
        try self.setSearchSelectedDisplay(searchSelectedDisplayFromRaw(self.search_selected_raw, self.search_total));
        return true;
    }

    fn handleSearchToggleClick(self: *Surface, command_id: usize) !bool {
        const now_ms: i64 = @intCast(GetTickCount64());
        switch (command_id) {
            SEARCH_REGEX_ID => self.search_bar.toggleRegex(now_ms),
            SEARCH_CASE_ID => self.search_bar.toggleCase(now_ms),
            SEARCH_WORD_ID => self.search_bar.toggleWord(now_ms),
            else => return false,
        }

        self.invalidateSearchButtons();
        if (self.search_bar.query.len > 0) {
            _ = try self.rerunSearchNow();
        } else {
            _ = try self.syncSearchBarResultsText();
        }
        return true;
    }

    fn closeDockedSearchBar(self: *Surface, stop_search: bool, refocus_terminal: bool) anyerror!void {
        if (stop_search) {
            _ = try self.core_surface.endSearch();
            if (refocus_terminal) {
                if (self.hwnd) |hwnd| _ = SetFocus(hwnd);
            }
            return;
        }

        const host = self.host orelse return;
        self.search_bar.close();
        self.search_bar.total = null;
        self.search_bar.selected = null;
        try self.setSearchActive(false, "");
        _ = self.hideSearchBarControls();
        if (host.overlay_mode == .search) host.hideOverlay();
        host.refreshSearchTimerState();
        try host.layout();
        host.forceHostCompositionPaint();
        if (refocus_terminal) {
            if (self.hwnd) |hwnd| _ = SetFocus(hwnd);
        }
    }

    fn showSearchOverlay(self: *Surface, needle: []const u8) !void {
        const host = self.host orelse return;
        if (host.overlay_mode != .none) host.hideOverlay();

        try self.ensureSearchBarControls();
        self.search_bar.open();

        const initial = if (needle.len > 0)
            needle
        else if (self.search_bar.query.len > 0)
            self.search_bar.query
        else if (self.search_needle) |value|
            value
        else
            "";
        const same_query = if (self.search_needle) |value|
            std.mem.eql(u8, value, initial)
        else
            false;
        const restore_live_results = initial.len > 0 and self.search_active and same_query;
        if (!std.mem.eql(u8, self.search_bar.query, initial)) {
            try self.search_bar.setQuery(initial, 0);
        }
        if (!restore_live_results) {
            self.search_bar.total = null;
            self.search_bar.selected = null;
        }
        self.search_bar.searched = initial.len == 0 or restore_live_results;
        self.search_bar.last_edit_ms = 0;

        _ = try self.setSearchBarEditText(initial);
        _ = try self.syncSearchBarResultsText();
        try host.layout();
        host.refreshSearchTimerState();
        host.forceHostCompositionPaint();

        if (self.search_bar_edit_hwnd) |edit_hwnd| {
            _ = SetFocus(edit_hwnd);
            _ = SendMessageW(edit_hwnd, EM_SETSEL, 0, -1);
        }

        if (initial.len > 0 and (!self.search_active or !same_query)) {
            _ = try self.rerunSearchNow();
        }
    }

    fn setInspectorVisible(self: *Surface, visible: bool) !bool {
        if (visible == self.inspector_visible) return false;
        if (!self.core_initialized) return false;
        const host = self.host;
        const panel_was_visible = if (host) |h| h.inspectorPanelVisible() else false;

        if (visible) {
            try self.core_surface.activateInspector();
        } else {
            self.core_surface.deactivateInspector();
        }
        self.inspector_visible = visible;
        if (host) |h| {
            const panel_now_visible = h.inspectorPanelVisible();
            var chrome_invalidated = false;
            if (h.overlay_mode == .none) {
                chrome_invalidated = inspectorBannerStateChanged(
                    h.overlay_mode,
                    h.banner_kind,
                    h.banner_text,
                    visible,
                );
                if (visible) {
                    try h.setBanner(.none, null);
                } else if (!panel_now_visible) {
                    try h.setBanner(.info, host_banner_inspector_inactive);
                } else {
                    try h.setBanner(.none, null);
                }
            }
            const status_h = h.statusBarHeight();
            if (!chrome_invalidated and inspectorChromeVisible(h.overlay_mode, status_h)) {
                if (chromeTextNeedsFullInvalidation(status_h)) {
                    h.invalidateChromeText();
                } else {
                    h.invalidateTopChromeText();
                }
            }
            if (inspectorVisibilityChangeNeedsHostRelayout(panel_was_visible != panel_now_visible)) {
                h.invalidateActiveSearchBarLayoutCaches();
                try h.layout();
                h.forceHostCompositionPaint();
            } else if (chrome_invalidated or inspectorChromeVisible(h.overlay_mode, status_h)) {
                h.forceHostCompositionPaint();
            }
        }
        try self.requestRepaint();
        try self.refreshWindowTitle();
        return true;
    }

    fn refreshWindowTitle(self: *Surface) !void {
        if (self.host) |host| {
            if (try host.syncWindowTitle()) host.invalidateTopChromeText();
            return;
        }
    }

    fn invalidateStatusBarState(self: *Surface) void {
        if (self.host) |host| host.invalidateStatusBarText();
    }

    fn toggleMaximize(self: *Surface) void {
        const hwnd = self.windowHwnd() orelse return;
        if (self.fullscreen) return;
        _ = ShowWindow(hwnd, if (IsZoomed(hwnd) != 0) SW_RESTORE else SW_MAXIMIZE);
    }

    fn applyRuntimeConfig(self: *Surface, config: *const configpkg.Config) !void {
        self.background_opacity_default = normalizedBackgroundOpacity(config.@"background-opacity");
        self.scrollbar_config = config.scrollbar;
        if (self.background_opacity_default >= 0.999) {
            self.background_opacity_force_opaque = false;
        }
        try self.applyBackgroundOpacity();
        try self.refreshScrollbarWindow();
    }

    fn toggleBackgroundOpacity(self: *Surface) !bool {
        if (self.background_opacity_default >= 0.999) return false;
        self.background_opacity_force_opaque = !self.background_opacity_force_opaque;
        try self.applyBackgroundOpacity();
        return true;
    }

    fn resizeSplitFallback(self: *Surface, value: apprt.action.ResizeSplit) !bool {
        const hwnd = self.hwnd orelse return false;
        var client_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        const delta = resizeSplitFallbackDelta(value);
        const current_width = client_rect.right - client_rect.left;
        const current_height = client_rect.bottom - client_rect.top;
        const next_width = @max(1, current_width + delta.width);
        const next_height = @max(1, current_height + delta.height);

        try self.resizeClientArea(@intCast(next_width), @intCast(next_height));
        return true;
    }

    fn toggleFullscreen(self: *Surface, mode: apprt.action.Fullscreen) !void {
        _ = mode;
        if (self.fullscreen) {
            try self.leaveFullscreen();
            return;
        }
        try self.enterFullscreen();
    }

    fn toggleDecorations(self: *Surface) !void {
        self.decorations_visible = !self.decorations_visible;
        try self.applyWindowStyle();
    }

    fn setInitialSize(self: *Surface, size: apprt.action.InitialSize) !void {
        self.default_client_size = .{
            .width = @intCast(size.width),
            .height = @intCast(size.height),
        };
        if (self.fullscreen or
            self.restore_maximized or
            !shouldResizeHostForInitialSize(self.hostSurfaceCount())) return;
        try self.resizeClientArea(size.width, size.height);
    }

    fn hostSurfaceCount(self: *const Surface) usize {
        const host = self.host orelse return 1;
        var count: usize = 0;
        for (host.tabs.items) |*tab| count += tab.leafCount();
        return count;
    }

    fn resetWindowSize(self: *Surface) !void {
        const size = self.default_client_size orelse return;
        if (self.fullscreen) try self.leaveFullscreen();
        if (self.windowHwnd()) |hwnd| _ = ShowWindow(hwnd, SW_RESTORE);
        try self.resizeClientArea(@intCast(size.width), @intCast(size.height));
    }

    fn setSizeLimit(self: *Surface, limit: apprt.action.SizeLimit) void {
        self.size_limit = limit;
        const hwnd = self.windowHwnd() orelse return;
        _ = SetWindowPos(
            hwnd,
            null,
            0,
            0,
            0,
            0,
            SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_NOACTIVATE | SWP_FRAMECHANGED,
        );
    }

    fn setCellSize(self: *Surface, size: apprt.action.CellSize) void {
        self.cell_size_pixels = size;
    }

    fn setFloatWindow(self: *Surface, mode: apprt.action.FloatWindow) !void {
        self.topmost = switch (mode) {
            .on => true,
            .off => false,
            .toggle => !self.topmost,
        };
        try self.applyTopmost();
    }

    fn enterFullscreen(self: *Surface) !void {
        const hwnd = self.windowHwnd() orelse return;
        self.captureRestoreState();
        self.fullscreen = true;
        try self.applyWindowStyle();

        const monitor = MonitorFromWindow(hwnd, MONITOR_DEFAULTTONEAREST) orelse
            return windows.unexpectedError(windows.kernel32.GetLastError());
        var info: MONITORINFO = .{
            .cbSize = @sizeOf(MONITORINFO),
            .rcMonitor = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
            .rcWork = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
            .dwFlags = 0,
        };
        if (GetMonitorInfoW(monitor, &info) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        if (SetWindowPos(
            hwnd,
            if (self.topmost) HWND_TOPMOST else null,
            info.rcMonitor.left,
            info.rcMonitor.top,
            info.rcMonitor.right - info.rcMonitor.left,
            info.rcMonitor.bottom - info.rcMonitor.top,
            SWP_FRAMECHANGED | SWP_NOACTIVATE,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn leaveFullscreen(self: *Surface) !void {
        const hwnd = self.windowHwnd() orelse return;
        self.fullscreen = false;
        try self.applyWindowStyle();

        if (SetWindowPos(
            hwnd,
            if (self.topmost) HWND_TOPMOST else HWND_NOTOPMOST,
            self.restore_rect.left,
            self.restore_rect.top,
            self.restore_rect.right - self.restore_rect.left,
            self.restore_rect.bottom - self.restore_rect.top,
            SWP_FRAMECHANGED | SWP_NOACTIVATE,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        if (self.restore_maximized) _ = ShowWindow(hwnd, SW_MAXIMIZE);
    }

    fn captureRestoreState(self: *Surface) void {
        const hwnd = self.windowHwnd() orelse return;
        self.restore_maximized = IsZoomed(hwnd) != 0;
        if (GetWindowRect(hwnd, &self.restore_rect) == 0) {
            self.restore_rect = .{ .left = 0, .top = 0, .right = 1280, .bottom = 800 };
        }
    }

    fn resizeClientArea(self: *Surface, client_width: u32, client_height: u32) !void {
        const hwnd = self.windowHwnd() orelse return;
        var client_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        var window_rect: RECT = undefined;
        if (GetWindowRect(hwnd, &window_rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        const current_client_width = client_rect.right - client_rect.left;
        const current_client_height = client_rect.bottom - client_rect.top;
        const current_window_width = window_rect.right - window_rect.left;
        const current_window_height = window_rect.bottom - window_rect.top;
        const frame_width = current_window_width - current_client_width;
        const frame_height = current_window_height - current_client_height;

        if (SetWindowPos(
            hwnd,
            null,
            0,
            0,
            @as(i32, @intCast(client_width)) + frame_width,
            @as(i32, @intCast(client_height)) + frame_height,
            SWP_NOMOVE | SWP_NOZORDER | SWP_NOACTIVATE,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn inheritWindowStateFrom(self: *Surface, source: *const Surface) !void {
        self.decorations_visible = source.decorations_visible;
        self.topmost = source.topmost;
        self.fullscreen = source.fullscreen;
        self.restore_rect = source.restore_rect;
        self.restore_maximized = source.restore_maximized;
        self.background_opacity_default = source.background_opacity_default;
        self.background_opacity_force_opaque = source.background_opacity_force_opaque;
        self.default_client_size = source.default_client_size;
        self.size_limit = source.size_limit;
        self.cell_size_pixels = source.cell_size_pixels;

        try self.applyWindowStyle();
        try self.applyTopmost();
        try self.applyBackgroundOpacity();

        const hwnd = self.windowHwnd() orelse return;
        const source_hwnd = source.windowHwnd() orelse return;
        var rect: RECT = undefined;
        if (GetWindowRect(source_hwnd, &rect) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        if (SetWindowPos(
            hwnd,
            if (self.topmost) HWND_TOPMOST else HWND_NOTOPMOST,
            rect.left,
            rect.top,
            rect.right - rect.left,
            rect.bottom - rect.top,
            SWP_NOACTIVATE | SWP_FRAMECHANGED,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        if (!self.fullscreen) {
            if (IsZoomed(source_hwnd) != 0) {
                _ = ShowWindow(hwnd, SW_MAXIMIZE);
            } else {
                _ = ShowWindow(hwnd, SW_RESTORE);
            }
        }
    }

    fn updateMinMaxInfo(self: *Surface, lParam: LPARAM) void {
        if (self.size_limit.min_width == 0 and
            self.size_limit.min_height == 0 and
            self.size_limit.max_width == 0 and
            self.size_limit.max_height == 0) return;

        const info: *MINMAXINFO = @ptrFromInt(@as(usize, @bitCast(lParam)));
        const hwnd = self.windowHwnd() orelse return;
        var client_rect: RECT = undefined;
        var window_rect: RECT = undefined;
        if (GetClientRect(hwnd, &client_rect) == 0) return;
        if (GetWindowRect(hwnd, &window_rect) == 0) return;

        const frame_width = (window_rect.right - window_rect.left) - (client_rect.right - client_rect.left);
        const frame_height = (window_rect.bottom - window_rect.top) - (client_rect.bottom - client_rect.top);

        if (self.size_limit.min_width > 0) {
            info.ptMinTrackSize.x = @as(i32, @intCast(self.size_limit.min_width)) + frame_width;
        }
        if (self.size_limit.min_height > 0) {
            info.ptMinTrackSize.y = @as(i32, @intCast(self.size_limit.min_height)) + frame_height;
        }
        if (self.size_limit.max_width > 0) {
            info.ptMaxTrackSize.x = @as(i32, @intCast(self.size_limit.max_width)) + frame_width;
        }
        if (self.size_limit.max_height > 0) {
            info.ptMaxTrackSize.y = @as(i32, @intCast(self.size_limit.max_height)) + frame_height;
        }
    }

    fn applyWindowStyle(self: *Surface) !void {
        const hwnd = self.windowHwnd() orelse return;
        const style = effectiveHostWindowStyle(
            self.decorations_visible,
            self.fullscreen,
            self.host != null,
        );

        _ = SetWindowLongPtrW(hwnd, GWL_STYLE, @bitCast(@as(isize, @intCast(style))));
        if (SetWindowPos(
            hwnd,
            null,
            0,
            0,
            0,
            0,
            SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_NOACTIVATE | SWP_FRAMECHANGED,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn applyBackgroundOpacity(self: *Surface) !void {
        const hwnd = self.windowHwnd() orelse return;
        const opacity = effectiveBackgroundOpacity(
            self.background_opacity_default,
            self.background_opacity_force_opaque,
        );
        const ex_style_raw = GetWindowLongPtrW(hwnd, GWL_EXSTYLE);
        var ex_style: u32 = @intCast(@as(usize, @bitCast(ex_style_raw)));

        if (opacity >= 0.999) {
            if ((ex_style & WS_EX_LAYERED) != 0) {
                ex_style &= ~@as(u32, WS_EX_LAYERED);
                _ = SetWindowLongPtrW(hwnd, GWL_EXSTYLE, @bitCast(@as(isize, @intCast(ex_style))));
                _ = SetWindowPos(
                    hwnd,
                    null,
                    0,
                    0,
                    0,
                    0,
                    SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_NOACTIVATE | SWP_FRAMECHANGED,
                );
            }
            return;
        }

        if ((ex_style & WS_EX_LAYERED) == 0) {
            ex_style |= WS_EX_LAYERED;
            _ = SetWindowLongPtrW(hwnd, GWL_EXSTYLE, @bitCast(@as(isize, @intCast(ex_style))));
        }

        if (SetLayeredWindowAttributes(hwnd, 0, alphaByteForOpacity(opacity), LWA_ALPHA) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    fn applyTopmost(self: *Surface) !void {
        const hwnd = self.windowHwnd() orelse return;
        if (SetWindowPos(
            hwnd,
            if (self.topmost) HWND_TOPMOST else HWND_NOTOPMOST,
            0,
            0,
            0,
            0,
            SWP_NOMOVE | SWP_NOSIZE | SWP_NOACTIVATE | SWP_FRAMECHANGED,
        ) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    /// Refresh `self.size` from `GetClientRect` and notify the core. Call this
    /// after `MoveWindow` from `Host.layout` as well as from `WM_SIZE`: with
    /// `bRepaint = false`, the child can receive `WM_PAINT` before `WM_SIZE`,
    /// leaving a stale screen size until the next resize event.
    fn syncCoreSizeFromClientRect(self: *Surface) void {
        const hwnd = self.hwnd orelse return;
        const next_size = self.app.clientSize(hwnd) catch return;
        if (!surfacePixelSizeChanged(self.size, next_size)) return;
        self.size = next_size;

        if (!self.core_initialized) return;
        self.core_surface.sizeCallback(self.size) catch |err| {
            log.err("win32 size callback failed err={}", .{err});
        };
    }

    fn windowSizeChanged(self: *Surface) void {
        self.syncCoreSizeFromClientRect();

        // `MoveWindow(..., bRepaint = false)` resizes the child HWND without
        // guaranteeing a follow-up paint for the newly exposed pixels. Request
        // one from the child itself after `WM_SIZE`, when the default
        // framebuffer and client rect have both advanced to the new size.
        self.requestRepaintWithMode(surfaceSizeChangeRepaintMode(self.host)) catch |err| {
            log.err("win32 size-change repaint request failed err={}", .{err});
        };
    }

    fn focusChanged(self: *Surface, focused: bool) void {
        self.window_focused = focused;
        const focus_state_changed = if (focused) self.app.noteSurfaceFocused(self) else false;
        if (!self.core_initialized) return;
        if (focused) self.app.core_app.focusSurface(self.core());
        self.core_surface.focusCallback(focused) catch |err| {
            log.err("win32 focus callback failed err={}", .{err});
        };
        // Host chrome only changes for split-pane focus borders.
        if (self.host) |host| {
            const pane_count = if (host.activeTab()) |tab| tab.leafCount() else 0;
            if (hostChromeNeedsFocusRepaint(pane_count)) host.repaintContentChrome();
            if (focus_state_changed) host.refreshChrome() catch {};
        }
    }

    fn handleKeyMessage(self: *Surface, msg: UINT, wParam: WPARAM, lParam: LPARAM) void {
        if (!self.core_initialized) return;

        const event = keyEventFromWin32Message(msg, wParam, lParam) orelse return;

        _ = self.core_surface.keyCallback(event) catch |err| {
            log.err("win32 key callback failed err={} vk={} action={} key={} mods={}", .{
                err,
                @as(UINT, @intCast(wParam & 0xFFFF)),
                event.action,
                event.key,
                event.mods,
            });
            return;
        };
    }

    fn positionImeWindow(self: *Surface) void {
        const surface_hwnd = self.hwnd orelse return;
        const himc = ImmGetContext(surface_hwnd) orelse return;
        defer _ = ImmReleaseContext(surface_hwnd, himc);

        // Position the IME candidate window at the terminal cursor cell
        const cursor_x: i32 = @intFromFloat(self.cursor_pos.x);
        const cursor_y: i32 = @intFromFloat(self.cursor_pos.y);
        const form = COMPOSITIONFORM{
            .dwStyle = CFS_POINT,
            .ptCurrentPos = .{ .x = cursor_x, .y = cursor_y },
            .rcArea = .{ .left = 0, .top = 0, .right = 0, .bottom = 0 },
        };
        _ = ImmSetCompositionWindow(himc, &form);
    }

    fn handleImeResult(self: *Surface) void {
        if (!self.core_initialized) return;
        const surface_hwnd = self.hwnd orelse return;
        const himc = ImmGetContext(surface_hwnd) orelse return;
        defer _ = ImmReleaseContext(surface_hwnd, himc);

        // Get the byte length of the result string
        const byte_len = ImmGetCompositionStringW(himc, GCS_RESULTSTR, null, 0);
        if (byte_len <= 0) return;
        const len: u32 = @intCast(byte_len);
        const wchar_count = len / 2;

        // Read the UTF-16 result into a stack buffer (most IME commits are short)
        var stack_buf: [128]u16 = undefined;
        const buf: []u16 = if (wchar_count <= stack_buf.len)
            stack_buf[0..wchar_count]
        else blk: {
            const allocated = self.app.core_app.alloc.alloc(u16, wchar_count) catch return;
            break :blk allocated;
        };
        defer if (wchar_count > stack_buf.len) self.app.core_app.alloc.free(buf);

        const read = ImmGetCompositionStringW(himc, GCS_RESULTSTR, buf.ptr, len);
        if (read <= 0) return;
        const actual_wchars: usize = @intCast(read);
        const result_slice = buf[0 .. actual_wchars / 2];

        // Convert UTF-16 to UTF-8
        var utf8_buf: [512]u8 = undefined;
        const utf8_len = std.unicode.utf16LeToUtf8(&utf8_buf, result_slice) catch return;
        if (utf8_len == 0) return;

        // Clear preedit display, then commit text via a synthetic key event
        self.core_surface.preeditCallback(null) catch {};

        var event: input.KeyEvent = .{
            .action = .press,
            .key = .unidentified,
            .mods = .{},
        };
        event.utf8 = utf8_buf[0..utf8_len];
        _ = self.core_surface.keyCallback(event) catch |err| {
            log.err("win32 IME commit failed err={}", .{err});
        };
    }

    fn handleImeComposition(self: *Surface) void {
        if (!self.core_initialized) return;
        const surface_hwnd = self.hwnd orelse return;
        const himc = ImmGetContext(surface_hwnd) orelse return;
        defer _ = ImmReleaseContext(surface_hwnd, himc);

        // Get the byte length of the composition string
        const byte_len = ImmGetCompositionStringW(himc, GCS_COMPSTR, null, 0);
        if (byte_len <= 0) {
            self.core_surface.preeditCallback(null) catch {};
            return;
        }
        const len: u32 = @intCast(byte_len);
        const wchar_count = len / 2;

        var stack_buf: [128]u16 = undefined;
        const buf: []u16 = if (wchar_count <= stack_buf.len)
            stack_buf[0..wchar_count]
        else blk: {
            const allocated = self.app.core_app.alloc.alloc(u16, wchar_count) catch return;
            break :blk allocated;
        };
        defer if (wchar_count > stack_buf.len) self.app.core_app.alloc.free(buf);

        const read = ImmGetCompositionStringW(himc, GCS_COMPSTR, buf.ptr, len);
        if (read <= 0) {
            self.core_surface.preeditCallback(null) catch {};
            return;
        }
        const actual_wchars: usize = @intCast(read);
        const comp_slice = buf[0 .. actual_wchars / 2];

        var utf8_buf: [512]u8 = undefined;
        const utf8_len = std.unicode.utf16LeToUtf8(&utf8_buf, comp_slice) catch {
            self.core_surface.preeditCallback(null) catch {};
            return;
        };

        // Update preedit display and reposition IME window
        self.core_surface.preeditCallback(utf8_buf[0..utf8_len]) catch {};
        self.positionImeWindow();
    }

    fn handleDropFiles(self: *Surface, wParam: WPARAM) void {
        if (!self.core_initialized) return;
        const hDrop: *anyopaque = @ptrFromInt(wParam);
        defer DragFinish(hDrop);

        const file_count = DragQueryFileW(hDrop, 0xFFFFFFFF, null, 0);
        if (file_count == 0) return;

        const alloc = self.app.core_app.alloc;
        var result: std.ArrayListUnmanaged(u8) = .empty;
        defer result.deinit(alloc);

        var i: UINT = 0;
        while (i < file_count) : (i += 1) {
            // Get required buffer length (not counting null terminator)
            const wchar_len = DragQueryFileW(hDrop, i, null, 0);
            if (wchar_len == 0) continue;

            // Allocate UTF-16 buffer (+1 for null)
            const buf = alloc.alloc(u16, wchar_len + 1) catch continue;
            defer alloc.free(buf);
            _ = DragQueryFileW(hDrop, i, buf.ptr, wchar_len + 1);

            // Convert UTF-16 to UTF-8
            var utf8_buf: [1024]u8 = undefined;
            const utf8_len = std.unicode.utf16LeToUtf8(&utf8_buf, buf[0..wchar_len]) catch continue;
            const path = utf8_buf[0..utf8_len];

            // Add separator between multiple files
            if (result.items.len > 0) {
                result.append(alloc, ' ') catch continue;
            }

            // Quote paths containing spaces or special characters
            const needs_quoting = std.mem.indexOfAny(u8, path, " \t'\"\\(){}[]$&;|<>!~`#") != null;
            if (needs_quoting) {
                result.append(alloc, '\'') catch continue;
                // Escape any existing single quotes within the path
                for (path) |c| {
                    if (c == '\'') {
                        result.appendSlice(alloc, "'\\''") catch continue;
                    } else {
                        result.append(alloc, c) catch continue;
                    }
                }
                result.append(alloc, '\'') catch continue;
            } else {
                result.appendSlice(alloc, path) catch continue;
            }
        }

        if (result.items.len == 0) return;

        // Write the path(s) to the terminal via a synthetic key event
        var event: input.KeyEvent = .{
            .action = .press,
            .key = .unidentified,
            .mods = .{},
        };
        event.utf8 = result.items;
        _ = self.core_surface.keyCallback(event) catch |err| {
            log.err("win32 drop files failed err={}", .{err});
        };
    }

    fn handleMouseMove(self: *Surface, lParam: LPARAM, mods: input.Mods) void {
        if (!self.core_initialized) return;
        self.cursor_pos = cursorPosFromLParam(lParam);
        self.core_surface.cursorPosCallback(self.cursor_pos, mods) catch |err| {
            log.err("win32 cursor pos callback failed err={}", .{err});
        };
    }

    fn handleMouseButton(self: *Surface, msg: UINT, wParam: WPARAM, lParam: LPARAM) void {
        if (!self.core_initialized) return;

        const button = mouseButtonFromMessage(msg) orelse return;
        const state = mouseButtonStateFromMessage(msg) orelse return;
        const mods = mouseModsFromWParam(wParam);

        self.cursor_pos = cursorPosFromLParam(lParam);
        if (state == .press) {
            if (self.hwnd) |hwnd| {
                _ = SetFocus(hwnd);
                _ = SetCapture(hwnd);
            }
        } else {
            _ = ReleaseCapture();
        }

        self.core_surface.cursorPosCallback(self.cursor_pos, mods) catch |err| {
            log.err("win32 cursor pos callback failed before button err={}", .{err});
        };
        _ = self.core_surface.mouseButtonCallback(state, button, mods) catch |err| {
            log.err("win32 mouse button callback failed err={} button={} state={}", .{
                err,
                button,
                state,
            });
            return;
        };
    }

    fn handleXMouseButton(self: *Surface, msg: UINT, wParam: WPARAM, lParam: LPARAM) void {
        if (!self.core_initialized) return;

        const hi = highWord(@as(usize, @intCast(wParam)));
        const button: input.MouseButton = switch (hi) {
            XBUTTON1 => .four,
            XBUTTON2 => .five,
            else => return,
        };
        const state: input.MouseButtonState = switch (msg) {
            WM_XBUTTONDOWN => .press,
            WM_XBUTTONUP => .release,
            else => return,
        };
        const mods = mouseModsFromWParam(wParam);

        self.cursor_pos = cursorPosFromLParam(lParam);
        if (state == .press) {
            if (self.hwnd) |h| {
                _ = SetFocus(h);
                _ = SetCapture(h);
            }
        } else {
            _ = ReleaseCapture();
        }

        self.core_surface.cursorPosCallback(self.cursor_pos, mods) catch |err| {
            log.err("win32 cursor pos callback failed before xbutton err={}", .{err});
        };
        _ = self.core_surface.mouseButtonCallback(state, button, mods) catch |err| {
            log.err("win32 xbutton callback failed err={} button={} state={}", .{ err, button, state });
        };
    }

    fn wheelNormalizationContext(self: *const Surface) WheelNormalizationContext {
        return .{
            .settings = self.app.wheel_settings,
            .cell_size = self.cell_size_pixels,
            .viewport = self.size,
        };
    }

    fn handleMouseWheel(self: *Surface, scroll: NormalizedWheelScroll) void {
        if (!self.core_initialized) return;
        if (self.scrollbarScrollable()) {
            const now_ms = GetTickCount64();
            self.noteScrollbarActivity(now_ms);
            self.syncScrollbarWindowNow(now_ms) catch |err| {
                log.warn("win32 scrollbar wheel refresh failed err={}", .{err});
            };
        }
        self.core_surface.scrollCallback(scroll.xoff, scroll.yoff, scroll.mods) catch |err| {
            log.err("win32 scroll callback failed err={} xoff={} yoff={} mods={}", .{
                err,
                scroll.xoff,
                scroll.yoff,
                scroll.mods,
            });
        };
    }

    fn destroy(self: *Surface) void {
        const alloc = self.app.core_app.alloc;
        self.destroy_on_wm_destroy = false;

        // Revoke the drop target BEFORE destroying the HWND — Ole
        // would otherwise hold a dangling HWND reference until the
        // process exits. Idempotent on already-revoked targets.
        if (self.drop_target_registered) {
            if (self.hwnd) |hwnd| self.drop_target.revoke(hwnd);
            self.drop_target_registered = false;
        }
        self.drop_target.deinit();

        if (self.core_initialized) {
            if (self.inspector_visible) {
                self.core_surface.deactivateInspector();
                self.inspector_visible = false;
            }
            self.app.core_app.deleteSurface(self);
            self.core_surface.deinit();
            self.core_initialized = false;
        }

        // Drain the undo stack. Entries own scrollback / title bytes
        // allocated via `app.core_app.alloc`; `deinit` frees each.
        self.undo_stack.deinit();
        self.destroyScrollbarWindow();
        self.destroySearchBarControls();
        // Drain the search bar's query allocation.
        self.search_bar.deinit();
        // Tear down any confirm overlay whose userdata points at
        // this Surface BEFORE we drain our own pending state. If we
        // skipped this, a user click on Accept / Cancel after the
        // Surface is freed would fire
        // `surfaceConfirmPasteAccept(&freed_surface)` → UAF. Hiding
        // the overlay here clears the Host's `confirm_payload`
        // entirely, so no later dispatch is possible.
        if (self.host) |host| host.cancelConfirmIfOwnedBy(@ptrCast(self));
        // Drop any pending clipboard-confirm op so a close-while-
        // pending doesn't leak the duplicated payload bytes.
        if (self.pending_clipboard_op) |*op| op.deinit(self.app.core_app.alloc);
        self.pending_clipboard_op = null;

        self.destroyGL();

        if (self.title) |title| {
            alloc.free(title);
            self.title = null;
        }
        if (self.title_override) |value| {
            alloc.free(value);
            self.title_override = null;
        }
        if (self.tab_title_override) |value| {
            alloc.free(value);
            self.tab_title_override = null;
        }
        if (self.launch_profile_key) |value| {
            alloc.free(value);
            self.launch_profile_key = null;
        }
        if (self.key_table_name) |value| {
            alloc.free(value);
            self.key_table_name = null;
        }
        if (self.search_needle) |value| {
            alloc.free(value);
            self.search_needle = null;
        }
        if (self.search_match_rows.len > 0) {
            alloc.free(self.search_match_rows);
            self.search_match_rows = &.{};
        }
        if (self.pwd) |value| {
            alloc.free(value);
            self.pwd = null;
        }
        if (self.progress_status) |value| {
            alloc.free(value);
            self.progress_status = null;
        }

        self.app.windowDestroyed(self);
        alloc.destroy(self);
    }

    fn setMouseShape(self: *Surface, shape: terminal.MouseShape) void {
        self.mouse_shape = shape;
        _ = self.applyCursor();
    }

    fn setMouseVisibility(self: *Surface, visibility: apprt.action.MouseVisibility) void {
        self.mouse_visible = visibility == .visible;
        _ = self.applyCursor();
    }

    fn setVisible(self: *Surface, visible: bool) void {
        const visibility_changed = self.window_visible != visible;
        self.window_visible = visible;

        const hwnd = self.hwnd orelse return;
        const child_visibility_changed = applyChildVisibility(hwnd, &self.placement, visible);
        if (visibility_changed or child_visibility_changed) {
            self.refreshScrollbarWindow() catch |err| {
                log.warn("win32 scrollbar visibility refresh failed err={}", .{err});
            };
        }

        if (!self.core_initialized) return;
        if (!shouldDispatchOcclusion(self.occlusion_visible, visible)) return;
        self.occlusion_visible = visible;
        self.core_surface.occlusionCallback(visible) catch |err| {
            log.err("win32 occlusion callback failed err={} visible={}", .{ err, visible });
        };
    }

    fn setReadonly(self: *Surface, enabled: bool) !void {
        if (self.readonly == enabled) return;
        self.readonly = enabled;
        self.invalidateStatusBarState();
    }

    fn setPwd(self: *Surface, pwd: []const u8) !void {
        if (ownedStringEquals(self.pwd, pwd)) return;
        const alloc = self.app.core_app.alloc;
        try appendOwnedString(alloc, &self.pwd, pwd);
        self.invalidateStatusBarState();
    }

    fn setSecureInput(self: *Surface, value: apprt.action.SecureInput) !void {
        const next = switch (value) {
            .on => true,
            .off => false,
            .toggle => !self.secure_input,
        };
        if (self.secure_input == next) return;
        self.secure_input = next;
        self.invalidateStatusBarState();
    }

    fn setKeySequenceActive(self: *Surface, active: bool) !void {
        if (self.key_sequence_active == active) return;
        self.key_sequence_active = active;
        self.invalidateStatusBarState();
    }

    fn setKeyTable(self: *Surface, value: apprt.action.KeyTable) !void {
        const next_name = switch (value) {
            .activate => |name| name,
            .deactivate, .deactivate_all => null,
        };
        if (optionalOwnedStringEquals(self.key_table_name, next_name)) return;
        const alloc = self.app.core_app.alloc;
        switch (value) {
            .activate => |name| try appendOwnedString(alloc, &self.key_table_name, name),
            .deactivate, .deactivate_all => try appendOwnedString(alloc, &self.key_table_name, null),
        }
        self.invalidateStatusBarState();
    }

    fn setSearchActive(self: *Surface, active: bool, needle: []const u8) !void {
        const alloc = self.app.core_app.alloc;
        self.search_active = active;
        self.search_total = null;
        self.search_selected_raw = null;
        self.search_selected = null;
        self.search_bar.total = null;
        self.search_bar.selected = null;
        if (!active) {
            self.search_bar.searched = self.search_bar.query.len == 0;
            self.search_bar.last_edit_ms = 0;
        } else if (needle.len > 0 and !std.mem.eql(u8, self.search_bar.query, needle)) {
            try self.search_bar.setQuery(needle, 0);
            self.search_bar.searched = true;
            self.search_bar.last_edit_ms = 0;
        }
        if (self.search_match_rows.len > 0) {
            alloc.free(self.search_match_rows);
            self.search_match_rows = &.{};
        }
        self.clearScrollbarMarkers();
        if (active and needle.len > 0) {
            try appendOwnedString(alloc, &self.search_needle, needle);
        } else if (!active) {
            try appendOwnedString(alloc, &self.search_needle, null);
        }
        _ = try self.syncSearchBarResultsText();
        try self.refreshScrollbarWindow();
        self.invalidateStatusBarState();
    }

    fn setSearchTotal(self: *Surface, total: ?usize) !void {
        if (!shouldAcceptCoreSearchUpdates(&self.search_bar)) return;
        const selected = searchSelectedDisplayFromRaw(self.search_selected_raw, total);
        const searched = searchBarSearchedStateForTotal(total);
        if (self.search_total == total and
            self.search_selected == selected and
            !searchBarDisplayStateChanged(&self.search_bar, searched, total, selected))
        {
            return;
        }
        self.search_total = total;
        self.search_bar.searched = searched;
        self.search_bar.total = total;
        self.search_selected = selected;
        self.search_bar.selected = selected;
        _ = try self.syncSearchBarResultsText();
        self.invalidateStatusBarState();
    }

    fn setSearchSelected(self: *Surface, selected: ?usize) !void {
        if (!shouldAcceptCoreSearchUpdates(&self.search_bar)) return;
        const raw = searchSelectedRawFromCoreDisplay(selected);
        const display = searchSelectedDisplayFromRaw(raw, self.search_total);
        const searched = searchBarSearchedStateForSelected(display, self.search_total);
        if (self.search_selected_raw == raw and
            self.search_selected == display and
            !searchBarDisplayStateChanged(&self.search_bar, searched, self.search_total, display))
        {
            return;
        }
        self.search_selected_raw = raw;
        self.search_selected = display;
        self.search_bar.searched = searched;
        self.search_bar.selected = display;
        _ = try self.syncSearchBarResultsText();
        self.invalidateStatusBarState();
    }

    fn setSearchSelectedDisplay(self: *Surface, selected: ?usize) !void {
        const searched = searchBarSearchedStateForSelected(selected, self.search_total);
        if (self.search_selected == selected and
            !searchBarDisplayStateChanged(&self.search_bar, searched, self.search_total, selected))
        {
            return;
        }
        self.search_selected = selected;
        self.search_bar.searched = searched;
        self.search_bar.selected = selected;
        _ = try self.syncSearchBarResultsText();
        self.invalidateStatusBarState();
    }

    fn setSearchMatchRows(self: *Surface, rows: []const u32) !void {
        if (!shouldAcceptCoreSearchUpdates(&self.search_bar)) return;
        if (std.mem.eql(u32, self.search_match_rows, rows)) return;

        const alloc = self.app.core_app.alloc;
        if (self.search_match_rows.len > 0) alloc.free(self.search_match_rows);
        self.search_match_rows = if (rows.len == 0)
            &.{}
        else
            try alloc.dupe(u32, rows);
        self.clearScrollbarMarkers();
        try self.refreshScrollbarWindow();
    }

    fn setScrollbar(self: *Surface, value: terminal.Scrollbar) !void {
        if (self.scrollbar.eql(value)) return;
        const old = self.scrollbar;
        const offset_changed = self.scrollbar.offset != value.offset;
        const status_changed = scrollStatusTextChanged(old, value);
        self.scrollbar = value;
        if (old.total != value.total or old.len != value.len) {
            self.clearScrollbarMarkers();
        }
        if (!self.scrollbarScrollable()) {
            self.scrollbar_state = .{};
        } else {
            const now_ms = GetTickCount64();
            switch (self.scrollbarPolicy()) {
                .always => self.scrollbar_state.visibility = .visible,
                .dynamic => if (offset_changed) self.noteScrollbarActivity(now_ms),
                .never => {},
            }
        }
        try self.refreshScrollbarWindow();
        if (status_changed) {
            // Refresh the bottom status only when the visible scroll
            // indicator actually changes (show/hide or rounded percent).
            if (self.host) |host| host.invalidateStatusBarText();
        }
    }

    fn setProgressReport(self: *Surface, value: terminal.osc.Command.ProgressReport) !void {
        const alloc = self.app.core_app.alloc;
        const progress = try formatProgressStatus(alloc, value);
        defer if (progress) |owned| alloc.free(owned);
        if (!optionalOwnedStringEquals(self.progress_status, progress)) {
            try appendOwnedString(alloc, &self.progress_status, progress);
            self.invalidateStatusBarState();
        }

        self.taskbar_progress = if (value.state == .remove) null else value;
        self.app.syncTaskbarProgressForHost(self.host_id);
    }

    fn applyCursor(self: *Surface) bool {
        if (!self.mouse_visible) {
            _ = SetCursor(null);
            return true;
        }

        const cursor_name: INTRESOURCE = switch (self.mouse_shape) {
            .default => IDC_ARROW,
            .help => @as(INTRESOURCE, @ptrFromInt(32651)),
            .pointer, .grab, .grabbing => @as(INTRESOURCE, @ptrFromInt(32649)),
            .progress => @as(INTRESOURCE, @ptrFromInt(32650)),
            .wait => @as(INTRESOURCE, @ptrFromInt(32514)),
            .crosshair => @as(INTRESOURCE, @ptrFromInt(32515)),
            .text, .vertical_text, .cell => @as(INTRESOURCE, @ptrFromInt(32513)),
            .move, .all_scroll => @as(INTRESOURCE, @ptrFromInt(32646)),
            .not_allowed, .no_drop => @as(INTRESOURCE, @ptrFromInt(32648)),
            .col_resize, .ew_resize, .e_resize, .w_resize => @as(INTRESOURCE, @ptrFromInt(32644)),
            .row_resize, .ns_resize, .n_resize, .s_resize => @as(INTRESOURCE, @ptrFromInt(32645)),
            .ne_resize, .sw_resize, .nesw_resize => @as(INTRESOURCE, @ptrFromInt(32643)),
            .nw_resize, .se_resize, .nwse_resize => @as(INTRESOURCE, @ptrFromInt(32642)),
            .context_menu,
            .alias,
            .copy,
            .zoom_in,
            .zoom_out,
            => IDC_ARROW,
        };

        _ = SetCursor(LoadCursorW(null, cursor_name));
        return true;
    }

    /// Queue a deferred clipboard-paste confirm. Dupes `data` into
    /// surface-owned storage, parks it as a `PendingClipboardOp.paste`,
    /// and shows the non-modal `HostOverlayMode.confirm` overlay. On
    /// accept `surfaceConfirmPasteAccept` completes the paste; on
    /// cancel `surfaceConfirmPasteCancel` frees the payload.
    ///
    /// Queues a non-modal clipboard confirmation.
    fn requestPasteConfirm(
        self: *Surface,
        request: apprt.ClipboardRequest,
        data: []const u8,
    ) !void {
        const host = self.host orelse return error.NoHost;
        const alloc = self.app.core_app.alloc;

        // Defensive: clear any leftover op before queuing a new one so
        // the destructor can't see a mixed state.
        if (self.pending_clipboard_op) |*old| old.deinit(alloc);
        self.pending_clipboard_op = null;

        const data_copy = try alloc.dupeZ(u8, data);
        // Single errdefer — if showConfirm fails we free the buffer
        // and leave `pending_clipboard_op` untouched (still null from
        // the defensive clear above). Committing the op BEFORE
        // showConfirm would produce a double-free if the operation
        // committed successfully and a later setup step failed.
        errdefer alloc.free(data_copy);

        try host.showConfirm(
            "Allow clipboard paste?",
            "winghostty needs confirmation before completing this clipboard paste or read request.",
            "Allow",
            "Cancel",
            surfaceConfirmPasteAccept,
            surfaceConfirmPasteCancel,
            self,
        );

        // showConfirm succeeded — the callback is registered and
        // fires async on user action (Enter / Esc / click), never
        // synchronously inside this call. Commit the pending op now
        // so the callback can pick it up.
        self.pending_clipboard_op = .{ .paste = .{
            .request = request,
            .data = data_copy,
        } };
    }

    /// Queue a deferred clipboard-write confirm. Dupes every
    /// `ClipboardContent` entry (mime + data both sentinel-terminated)
    /// into surface-owned storage. Same accept / cancel discipline as
    /// `requestPasteConfirm`.
    fn requestWriteConfirm(
        self: *Surface,
        clipboard: apprt.Clipboard,
        contents: []const apprt.ClipboardContent,
    ) !void {
        const host = self.host orelse return error.NoHost;
        const alloc = self.app.core_app.alloc;

        if (self.pending_clipboard_op) |*old| old.deinit(alloc);
        self.pending_clipboard_op = null;

        const owned = try alloc.alloc(OwnedClipboardContent, contents.len);
        var filled: usize = 0;
        // Outer errdefer frees committed entries plus the backing slice.
        // Per-iteration errdefer covers the mime-only partial allocation
        // before `filled` advances.
        errdefer {
            var i: usize = 0;
            while (i < filled) : (i += 1) {
                alloc.free(owned[i].mime);
                alloc.free(owned[i].data);
            }
            alloc.free(owned);
        }
        for (contents) |c| {
            const mime_copy = try alloc.dupeZ(u8, c.mime);
            errdefer alloc.free(mime_copy);
            const data_copy = try alloc.dupeZ(u8, c.data);
            // Both dupes succeeded — commit atomically into owned[]
            // and advance filled. The per-iter mime errdefer goes
            // out of scope without firing.
            owned[filled] = .{ .mime = mime_copy, .data = data_copy };
            filled += 1;
        }

        try host.showConfirm(
            "Allow clipboard write?",
            "winghostty needs confirmation before allowing this application to write to the Windows clipboard.",
            "Allow",
            "Cancel",
            surfaceConfirmWriteAccept,
            surfaceConfirmWriteCancel,
            self,
        );

        // showConfirm succeeded — commit the pending op. The async
        // accept callback picks it up; same race-free rationale as
        // `requestPasteConfirm` (showConfirm does not invoke
        // callbacks synchronously).
        self.pending_clipboard_op = .{ .write = .{
            .clipboard = clipboard,
            .contents = owned,
        } };
    }

    fn readClipboardText(self: *Surface) !?[:0]u8 {
        if (OpenClipboard(self.hwnd) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        defer _ = CloseClipboard();

        if (IsClipboardFormatAvailable(CF_UNICODETEXT) == 0) return null;

        const handle = GetClipboardData(CF_UNICODETEXT) orelse return null;
        const locked = GlobalLock(handle) orelse return null;
        defer _ = GlobalUnlock(handle);

        const text_w: [*:0]const u16 = @ptrCast(@alignCast(locked));
        const slice_w = std.mem.sliceTo(text_w, 0);
        return try std.unicode.utf16LeToUtf8AllocZ(self.app.core_app.alloc, slice_w);
    }

    fn writeClipboardText(self: *const Surface, text: []const u8) !void {
        const alloc = self.app.core_app.alloc;
        const text_w = try std.unicode.utf8ToUtf16LeAllocZ(alloc, text);
        defer alloc.free(text_w);

        if (OpenClipboard(self.hwnd) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        defer _ = CloseClipboard();

        if (EmptyClipboard() == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        const bytes = (text_w.len + 1) * @sizeOf(u16);
        const mem = GlobalAlloc(GMEM_MOVEABLE | GMEM_ZEROINIT, bytes) orelse
            return windows.unexpectedError(windows.kernel32.GetLastError());
        errdefer _ = GlobalFree(mem);

        const locked = GlobalLock(mem) orelse
            return windows.unexpectedError(windows.kernel32.GetLastError());
        defer _ = GlobalUnlock(mem);

        const dst: [*]u16 = @ptrCast(@alignCast(locked));
        @memcpy(dst[0 .. text_w.len + 1], text_w[0 .. text_w.len + 1]);

        if (SetClipboardData(CF_UNICODETEXT, mem) == null) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
    }

    /// Write both CF_HTML (styled fragment) and CF_UNICODETEXT
    /// (plain fallback) in a single clipboard cycle. CF_HTML
    /// consumers (Word / WordPad / OneNote) read the styled
    /// payload; plain-text consumers (Notepad / cmd / Terminal
    /// without HTML support) read the fallback.
    ///
    /// If `plain` is provided (core passes both `text/html` and
    /// `text/plain` when the action is, say, `copy_on_select`), we
    /// use it verbatim. Otherwise (e.g. explicit
    /// `copy_to_clipboard:html` which only provides `text/html`),
    /// we synthesize a plain fallback by stripping HTML tags so
    /// Notepad etc. get readable text instead of raw markup.
    fn writeClipboardHtml(self: *const Surface, html: []const u8, plain: ?[]const u8) !void {
        const alloc = self.app.core_app.alloc;

        // Lazily register CF_HTML once per App. The ID is process-
        // local and stable.
        if (self.app.cf_html_format == 0) {
            const id = RegisterClipboardFormatW(CF_HTML_NAME);
            if (id == 0) {
                return windows.unexpectedError(windows.kernel32.GetLastError());
            }
            self.app.cf_html_format = id;
        }
        const cf_html = self.app.cf_html_format;

        const wrapped = try win32_clipboard_html.wrapFragment(alloc, html);
        defer alloc.free(wrapped);

        // Pick the plain-text payload. Caller-supplied wins; else
        // derive a readable approximation from the HTML by walking
        // through the bytes and dropping anything between `<` and
        // `>`. Allocation lifetime: the stripped copy is owned by
        // `alloc`; the caller-supplied slice is borrowed and we
        // don't free it. `plain_owned_for_free` tracks ownership.
        var plain_owned_for_free: ?[]u8 = null;
        defer if (plain_owned_for_free) |owned| alloc.free(owned);
        const plain_src: []const u8 = if (plain) |p| p else blk: {
            const stripped = try stripHtmlTags(alloc, html);
            plain_owned_for_free = stripped;
            break :blk stripped;
        };
        const plain_w = try std.unicode.utf8ToUtf16LeAllocZ(alloc, plain_src);
        defer alloc.free(plain_w);

        if (OpenClipboard(self.hwnd) == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }
        defer _ = CloseClipboard();

        if (EmptyClipboard() == 0) {
            return windows.unexpectedError(windows.kernel32.GetLastError());
        }

        // CF_HTML payload: the wrapped byte stream + a trailing
        // null. `GMEM_MOVEABLE` is required for `SetClipboardData`;
        // the clipboard takes ownership on success, so we skip the
        // free on that path.
        {
            const bytes = wrapped.len + 1;
            const mem = GlobalAlloc(GMEM_MOVEABLE | GMEM_ZEROINIT, bytes) orelse
                return windows.unexpectedError(windows.kernel32.GetLastError());
            errdefer _ = GlobalFree(mem);
            const locked = GlobalLock(mem) orelse
                return windows.unexpectedError(windows.kernel32.GetLastError());
            {
                defer _ = GlobalUnlock(mem);
                const dst: [*]u8 = @ptrCast(locked);
                @memcpy(dst[0..wrapped.len], wrapped);
                dst[wrapped.len] = 0;
            }
            if (SetClipboardData(cf_html, mem) == null) {
                return windows.unexpectedError(windows.kernel32.GetLastError());
            }
        }

        // CF_UNICODETEXT fallback.
        {
            const bytes = (plain_w.len + 1) * @sizeOf(u16);
            const mem = GlobalAlloc(GMEM_MOVEABLE | GMEM_ZEROINIT, bytes) orelse
                return windows.unexpectedError(windows.kernel32.GetLastError());
            errdefer _ = GlobalFree(mem);
            const locked = GlobalLock(mem) orelse
                return windows.unexpectedError(windows.kernel32.GetLastError());
            {
                defer _ = GlobalUnlock(mem);
                const dst: [*]u16 = @ptrCast(@alignCast(locked));
                @memcpy(dst[0 .. plain_w.len + 1], plain_w[0 .. plain_w.len + 1]);
            }
            if (SetClipboardData(CF_UNICODETEXT, mem) == null) {
                return windows.unexpectedError(windows.kernel32.GetLastError());
            }
        }
    }

    fn destroyGL(self: *Surface) void {
        if (self.hglrc != null) {
            self.clearGLContextCurrent();
            _ = wglDeleteContext(self.hglrc);
            self.hglrc = null;
        }

        if (self.hdc != null) {
            if (self.hwnd) |hwnd| _ = ReleaseDC(hwnd, self.hdc);
            self.hdc = null;
        }

        self.hwnd = null;
    }
};

fn pushUndoAndRedoBranch(
    stack: *win32_undo.UndoStack,
    alloc: Allocator,
    seed: u8,
) !void {
    const first = try alloc.alloc(u8, 1);
    first[0] = seed;
    try stack.push(.{
        .kind = .clear_screen,
        .snapshot = .{ .clear_screen = .{ .state_bytes = first } },
        .timestamp_ms = seed,
    });

    const second = try alloc.alloc(u8, 1);
    second[0] = seed + 1;
    try stack.push(.{
        .kind = .reset,
        .snapshot = .{ .reset = .{ .state_bytes = second } },
        .timestamp_ms = seed + 1,
    });

    try std.testing.expect((try stack.popForUndo()) != null);
    try std.testing.expectEqual(@as(usize, 1), stack.undoDepth());
    try std.testing.expectEqual(@as(usize, 1), stack.redoDepth());
}

test "win32 undo prune expires local and structural histories" {
    if (builtin.os.tag != .windows) return error.SkipZigTest;

    var core_app: CoreApp = undefined;
    core_app.alloc = std.testing.allocator;

    var app: App = undefined;
    app.core_app = &core_app;
    app.windows = .empty;
    app.hosts = .empty;
    defer {
        app.windows.deinit(std.testing.allocator);
        app.hosts.deinit(std.testing.allocator);
    }

    var surface_a: Surface = undefined;
    surface_a.undo_stack = win32_undo.UndoStack.init(std.testing.allocator);
    defer surface_a.undo_stack.deinit();

    var surface_b: Surface = undefined;
    surface_b.undo_stack = win32_undo.UndoStack.init(std.testing.allocator);
    defer surface_b.undo_stack.deinit();

    var host: Host = .{
        .app = &app,
        .id = 1,
        .tabs = .empty,
        .structural_undo_entries = .empty,
        .structural_redo_entries = .empty,
    };
    defer {
        host.clearStructuralHistory(.normal);
        host.structural_undo_entries.deinit(std.testing.allocator);
        host.structural_redo_entries.deinit(std.testing.allocator);
        host.tabs.deinit(std.testing.allocator);
    }

    try app.windows.append(std.testing.allocator, &surface_a);
    try app.hosts.append(std.testing.allocator, &host);

    try surface_a.undo_stack.push(.{
        .kind = .clear_screen,
        .snapshot = .{ .clear_screen = .{ .state_bytes = try std.testing.allocator.alloc(u8, 1) } },
        .timestamp_ms = 10,
    });
    try surface_a.undo_stack.push(.{
        .kind = .reset,
        .snapshot = .{ .reset = .{ .state_bytes = try std.testing.allocator.alloc(u8, 1) } },
        .timestamp_ms = 200,
    });
    _ = try surface_a.undo_stack.popForUndo();

    try host.structural_undo_entries.append(std.testing.allocator, .{
        .kind = .split_create,
        .timestamp_ms = 20,
        .payload = .{ .split_create = .{
            .source_surface = &surface_a,
            .created_surface = &surface_b,
        } },
    });
    try host.structural_undo_entries.append(std.testing.allocator, .{
        .kind = .split_create,
        .timestamp_ms = 220,
        .payload = .{ .split_create = .{
            .source_surface = &surface_a,
            .created_surface = &surface_b,
        } },
    });
    try host.structural_redo_entries.append(std.testing.allocator, .{
        .kind = .split_create,
        .timestamp_ms = 30,
        .payload = .{ .split_create = .{
            .source_surface = &surface_a,
            .created_surface = &surface_b,
        } },
    });
    try host.structural_redo_entries.append(std.testing.allocator, .{
        .kind = .split_create,
        .timestamp_ms = 230,
        .payload = .{ .split_create = .{
