    defer other.undo_stack.deinit();

    var created: Surface = undefined;
    created.app = &app;
    created.host = &host;
    created.host_id = host.id;
    created.hwnd = null;
    created.core_initialized = false;
    created.window_visible = false;
    created.host_active = false;
