    try std.testing.expect(surface.beginRendererRepaintRequest());
    try std.testing.expect(!surface.beginRendererRepaintRequest());
    try std.testing.expect(surface.consumeRendererRepaintRetryPending());
    try std.testing.expect(!surface.consumeRendererRepaintRetryPending());

    surface.cancelRendererRepaintRequest();
    try std.testing.expect(surface.beginRendererRepaintRequest());

    surface.finishRendererRepaintRequest();
    try std.testing.expect(surface.beginRendererRepaintRequest());
}

